        private async Task RefreshNewContentDotsAsync()
        {
            if (_currentSettings == null) return;
            try
            {
                if (!_currentSettings.EnableNewContentIndicators)
                {
                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        SetDotVisible("NewsNotifDot", false);
                        SetDotVisible("VersionsNotifDot", false);
                        SetBadge("CosmeticsNotifDot", "CosmeticsNotifText", 0);
                        SetBadge("StoreNotifDot", "StoreNotifText", 0);
                        SetBadge("ScreenshotsNotifDot", "ScreenshotsNotifText", 0);
                    });
                    return;
                }

                var newsTask = LeafClient.Services.LeafApiService.GetNewsAsync();
                var cosmeticsTask = LeafClient.Services.LeafApiService.GetCosmeticsCatalogAsync();
                await Task.WhenAll(newsTask, cosmeticsTask);

                var seenNews = new HashSet<string>(_currentSettings.SeenNewsTitles ?? new List<string>(), StringComparer.OrdinalIgnoreCase);
                var seenStore = new HashSet<string>(_currentSettings.SeenCosmeticIds ?? new List<string>(), StringComparer.OrdinalIgnoreCase);
                var seenVer = new HashSet<string>(_currentSettings.SeenMcVersions ?? new List<string>(), StringComparer.OrdinalIgnoreCase);
                var seenInv = new HashSet<string>(_currentSettings.SeenInventoryCosmeticIds ?? new List<string>(), StringComparer.OrdinalIgnoreCase);
                var seenShots = new HashSet<string>(_currentSettings.SeenScreenshotPaths ?? new List<string>(), StringComparer.Ordinal);

                bool newsNew = false;
                var newsItems = await newsTask;
                if (newsItems != null)
                {
                    foreach (var n in newsItems)
                    {
                        if (string.IsNullOrEmpty(n.Title)) continue;
                        if (!seenNews.Contains(n.Title)) { newsNew = true; break; }
                    }
                    if (seenNews.Count == 0 && newsItems.Count == 0) newsNew = false;
                }

                int storeNew = 0;
                var cosItems = await cosmeticsTask;
                if (cosItems != null)
                {
                    foreach (var c in cosItems)
                    {
                        if (string.IsNullOrEmpty(c.Id)) continue;
                        if (!seenStore.Contains(c.Id)) storeNew++;
                    }
                }

                bool verNew = false;
                if (_allVersions != null)
                {
                    foreach (var v in _allVersions)
                    {
                        if (string.IsNullOrEmpty(v.FullVersion)) continue;
                        if (!seenVer.Contains(v.FullVersion)) { verNew = true; break; }
                    }
                }

                int invNew = 0;
                foreach (var id in _ownedCosmeticIds)
                {
                    if (string.IsNullOrEmpty(id)) continue;
                    if (!seenInv.Contains(id)) invNew++;
                }

                int shotsNew = 0;
                List<string> currentShots = new();
                try
                {
                    var mc = ((Services.IMainWindowHost)this).MinecraftFolder;
                    if (!string.IsNullOrEmpty(mc))
                    {
                        var dir = System.IO.Path.Combine(mc, "screenshots");
                        if (System.IO.Directory.Exists(dir))
                        {
                            currentShots = System.IO.Directory.EnumerateFiles(dir)
                                .Where(p => p.EndsWith(".png", StringComparison.OrdinalIgnoreCase)
                                         || p.EndsWith(".jpg", StringComparison.OrdinalIgnoreCase)
                                         || p.EndsWith(".jpeg", StringComparison.OrdinalIgnoreCase))
                                .ToList();
                            foreach (var p in currentShots)
                                if (!seenShots.Contains(p)) shotsNew++;
                        }
                    }
                }
                catch { }

                bool firstRun = (seenNews.Count + seenStore.Count + seenVer.Count + seenInv.Count + seenShots.Count) == 0;

                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    SetDotVisible("NewsNotifDot", newsNew && !firstRun);
                    SetDotVisible("VersionsNotifDot", verNew && !firstRun);
                    SetBadge("StoreNotifDot", "StoreNotifText", firstRun ? 0 : storeNew);
                    SetBadge("CosmeticsNotifDot", "CosmeticsNotifText", firstRun ? 0 : invNew);
                    SetBadge("ScreenshotsNotifDot", "ScreenshotsNotifText", firstRun ? 0 : shotsNew);
                });

                if (firstRun)
                {
                    if (newsItems != null)
                        _currentSettings.SeenNewsTitles = newsItems.Where(n => !string.IsNullOrEmpty(n.Title)).Select(n => n.Title).Distinct().ToList();
                    if (cosItems != null)
                        _currentSettings.SeenCosmeticIds = cosItems.Where(c => !string.IsNullOrEmpty(c.Id)).Select(c => c.Id).Distinct().ToList();
                    if (_allVersions != null)
                        _currentSettings.SeenMcVersions = _allVersions.Where(v => !string.IsNullOrEmpty(v.FullVersion)).Select(v => v.FullVersion).Distinct().ToList();
                    _currentSettings.SeenInventoryCosmeticIds = _ownedCosmeticIds.Where(id => !string.IsNullOrEmpty(id)).Distinct().ToList();
                    _currentSettings.SeenScreenshotPaths = currentShots;
                    try { await _settingsService.SaveSettingsAsync(_currentSettings); } catch { }
                }
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("NewContent", $"refresh failed: {ex.Message}"); }
        }

        private void SetBadge(string borderName, string textName, int count)
        {
            try
            {
                var dot = this.FindControl<Border>(borderName);
                var txt = this.FindControl<TextBlock>(textName);
                if (dot == null) return;
                if (count <= 0) { dot.IsVisible = false; return; }
                if (txt != null) txt.Text = count > 99 ? "99+" : count.ToString();
                dot.IsVisible = true;
            }
            catch { }
        }

        private void SetDotVisible(string name, bool visible)
        {
            try
            {
                var dot = this.FindControl<Border>(name);
                if (dot != null) dot.IsVisible = visible;
            }
            catch { }
        }

        private async Task MarkContentSeenAsync(int pageIndex)
        {
            if (_currentSettings == null) return;
            try
            {
                bool changed = false;
                if (pageIndex == 0)
                {
                    var items = await LeafClient.Services.LeafApiService.GetNewsAsync();
                    if (items != null)
                    {
                        _currentSettings.SeenNewsTitles = items.Where(n => !string.IsNullOrEmpty(n.Title)).Select(n => n.Title).Distinct().ToList();
                        changed = true;
                    }
                    SetDotVisible("NewsNotifDot", false);
                }
                else if (pageIndex == 1)
                {
                    if (_allVersions != null)
                    {
                        _currentSettings.SeenMcVersions = _allVersions.Where(v => !string.IsNullOrEmpty(v.FullVersion)).Select(v => v.FullVersion).Distinct().ToList();
                        changed = true;
                    }
                    SetDotVisible("VersionsNotifDot", false);
                }
                else if (pageIndex == 6)
                {
                    _currentSettings.SeenInventoryCosmeticIds = _ownedCosmeticIds.Where(id => !string.IsNullOrEmpty(id)).Distinct().ToList();
                    changed = true;
                    SetBadge("CosmeticsNotifDot", "CosmeticsNotifText", 0);
                }
                else if (pageIndex == 7)
                {
                    var items = await LeafClient.Services.LeafApiService.GetCosmeticsCatalogAsync();
                    if (items != null)
                    {
                        _currentSettings.SeenCosmeticIds = items.Where(c => !string.IsNullOrEmpty(c.Id)).Select(c => c.Id).Distinct().ToList();
                        changed = true;
                    }
                    SetBadge("StoreNotifDot", "StoreNotifText", 0);
                }
                else if (pageIndex == 8)
                {
                    try
                    {
                        var mc = ((Services.IMainWindowHost)this).MinecraftFolder;
                        if (!string.IsNullOrEmpty(mc))
                        {
                            var dir = System.IO.Path.Combine(mc, "screenshots");
                            if (System.IO.Directory.Exists(dir))
                            {
                                _currentSettings.SeenScreenshotPaths = System.IO.Directory.EnumerateFiles(dir)
                                    .Where(p => p.EndsWith(".png", StringComparison.OrdinalIgnoreCase)
                                             || p.EndsWith(".jpg", StringComparison.OrdinalIgnoreCase)
                                             || p.EndsWith(".jpeg", StringComparison.OrdinalIgnoreCase))
                                    .ToList();
                                changed = true;
                            }
                        }
                    }
                    catch { }
                    SetBadge("ScreenshotsNotifDot", "ScreenshotsNotifText", 0);
                }
                if (changed)
                {
                    try { await _settingsService.SaveSettingsAsync(_currentSettings); } catch { }
                }
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("NewContent", $"mark seen failed: {ex.Message}"); }
        }

        private System.Threading.CancellationTokenSource? _wakeListenerCts;

        private void StartSingleInstanceWakeListener()
        {
            try
            {
                if (!LeafClient.Program.IsPrimaryInstance) return;
                _wakeListenerCts?.Cancel();
                _wakeListenerCts = new System.Threading.CancellationTokenSource();
                var ct = _wakeListenerCts.Token;
                System.Threading.Tasks.Task.Run(async () =>
                {
                    while (!ct.IsCancellationRequested)
                    {
                        try
                        {
                            System.IO.Pipes.NamedPipeServerStream server;
                            if (OperatingSystem.IsWindows())
                            {
                                var sec = new System.IO.Pipes.PipeSecurity();
                                var sid = System.Security.Principal.WindowsIdentity.GetCurrent().User;
                                if (sid != null)
                                {
                                    sec.AddAccessRule(new System.IO.Pipes.PipeAccessRule(
                                        sid,
                                        System.IO.Pipes.PipeAccessRights.ReadWrite,
                                        System.Security.AccessControl.AccessControlType.Allow));
                                }
                                server = System.IO.Pipes.NamedPipeServerStreamAcl.Create(
                                    LeafClient.Program.SingleInstancePipeName,
                                    System.IO.Pipes.PipeDirection.In,
                                    maxNumberOfServerInstances: 1,
                                    System.IO.Pipes.PipeTransmissionMode.Byte,
                                    System.IO.Pipes.PipeOptions.Asynchronous,
                                    inBufferSize: 256,
                                    outBufferSize: 0,
                                    pipeSecurity: sec);
                            }
                            else
                            {
                                server = new System.IO.Pipes.NamedPipeServerStream(
                                    LeafClient.Program.SingleInstancePipeName,
                                    System.IO.Pipes.PipeDirection.In,
                                    maxNumberOfServerInstances: 1,
                                    System.IO.Pipes.PipeTransmissionMode.Byte,
                                    System.IO.Pipes.PipeOptions.Asynchronous);
                            }
                            using (server)
                            {
                                await server.WaitForConnectionAsync(ct).ConfigureAwait(false);
                                if (ct.IsCancellationRequested) return;
                                try
                                {
                                    var buf = new byte[64];
                                    using var readCts = System.Threading.CancellationTokenSource.CreateLinkedTokenSource(ct);
                                    readCts.CancelAfter(TimeSpan.FromSeconds(2));
                                    _ = await server.ReadAsync(buf.AsMemory(0, buf.Length), readCts.Token).ConfigureAwait(false);
                                }
                                catch { }
                            }
                            Dispatcher.UIThread.Post(() =>
                            {
                                try
                                {
                                    if (this.IsVisible) { this.WindowState = WindowState.Normal; this.Activate(); }
                                    else { RestoreFromTray(); }
                                    ForceWindowToForeground();
                                }
                                catch { }
                            });
                            try { await System.Threading.Tasks.Task.Delay(250, ct).ConfigureAwait(false); } catch { return; }
                        }
                        catch (OperationCanceledException) { return; }
                        catch (Exception ex)
                        {
                            LeafLog.Error("WakeListener", $"{ex.Message}");
                            try { await System.Threading.Tasks.Task.Delay(500, ct).ConfigureAwait(false); } catch { return; }
                        }
                    }
                }, ct);
            }
            catch (Exception ex) { LeafLog.Error("WakeListener", $"start failed: {ex.Message}"); }
        }

        private void StartUpdateNotificationTimer()
        {
            try
            {
                _updateNotificationTimer?.Dispose();
                _updateNotificationTimer = new System.Threading.Timer(async _ =>
                {
                    try
                    {
                        if (_currentSettings == null || !_currentSettings.EnableUpdateNotifications) return;
                        var newVer = await Services.UpdateService.CheckForUpdateAsync();
                        if (string.IsNullOrEmpty(newVer)) return;
                        string lastShown = _currentSettings.LastNotifiedUpdateVersion ?? "";
                        if (string.Equals(newVer, lastShown, StringComparison.Ordinal)) return;
                        if (string.Equals(newVer, _lastUpdateNotificationVersionShown, StringComparison.Ordinal)) return;
                        _lastUpdateNotificationVersionShown = newVer;
                        _currentSettings.LastNotifiedUpdateVersion = newVer;
                        try { await _settingsService.SaveSettingsAsync(_currentSettings); } catch { }
                        await Dispatcher.UIThread.InvokeAsync(() =>
                        {
                            ToastService.Show($"Launcher v{newVer} is available - restart to install", ToastType.Info);
                        });
                    }
                    catch (Exception ex) { LeafClient.Services.LeafLog.Error("UpdateNotif", $"check failed: {ex.Message}"); }
                }, null, TimeSpan.FromMinutes(30), TimeSpan.FromMinutes(30));
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("UpdateNotif", $"start failed: {ex.Message}"); }
        }

        private void RefreshPlaytimeStatsCard()
        {
            if (_currentSettings == null) return;

            var playtimeLabel    = this.FindControl<TextBlock>("FooterStatsPlaytime");
            var launchCountLabel = this.FindControl<TextBlock>("FooterStatsLaunches");
            var topVersionLabel  = this.FindControl<TextBlock>("FooterStatsTopVersion");

            if (playtimeLabel != null)
                playtimeLabel.Text = FormatPlaytimeShort(_currentSettings.TotalPlaytimeSeconds);

            if (launchCountLabel != null)
                launchCountLabel.Text = _currentSettings.TotalLaunchCount.ToString();

            if (topVersionLabel != null)
            {
                if (_currentSettings.PlaytimeByVersion != null && _currentSettings.PlaytimeByVersion.Count > 0)
                {
                    var top = _currentSettings.PlaytimeByVersion
                        .OrderByDescending(kv => kv.Value)
                        .First();
                    topVersionLabel.Text = top.Key;
                }
                else
                {
                    topVersionLabel.Text = "-";
                }
            }
        }

        private static string FormatPlaytimeShort(long seconds)
        {
            if (seconds < 60)         return $"{seconds}s";
            if (seconds < 3600)       return $"{seconds / 60}m";
            if (seconds < 86400)      return $"{seconds / 3600}h {(seconds % 3600) / 60}m";
            return $"{seconds / 86400}d {(seconds % 86400) / 3600}h";
        }

        private void ApplyPlaytimeVisibility()
        {
            bool show = !(_currentSettings?.HidePlaytimeDisplay ?? false);
            if (_footerPlaytimeGroup != null) _footerPlaytimeGroup.IsVisible = show;
            if (_footerPlaytimeDivider != null) _footerPlaytimeDivider.IsVisible = show;
            if (_po_PlaytimeGroup != null) _po_PlaytimeGroup.IsVisible = show;
        }

        private static string? NullIfBlank(string? s)
            => string.IsNullOrWhiteSpace(s) ? null : s.Trim();

        private static int? ParseNullableInt(string? s)
        {
            if (string.IsNullOrWhiteSpace(s)) return null;
            return int.TryParse(s.Trim(), out int v) ? v : (int?)null;
        }

