            this.GetObservable(WindowStateProperty).Subscribe(_ => UpdateMaximizeIcon());
            UpdateMaximizeIcon();
            this.Opened += (_, _) => AdaptInitialSizeToScreen();
            this.GetObservable(BoundsProperty).Subscribe(_ => ApplyResponsiveHeader());
