            {
                LeafLog.Error("MainWindow ERROR", $"Failed to initialize IngameHeartbeatBeacon: {ex.Message}");
                _ingameHeartbeat = null;
            }

            this.Opened += async (_, __) =>
            {
                try
                {
                    StartFreezeWatchdog();
                    StartAccountIpcWatcher();
                    try
                    {
                        this.Activate();
                        ForceWindowToForeground();
                        _ = Dispatcher.UIThread.InvokeAsync(async () =>
                        {
                            await Task.Delay(180);
                            try { this.Activate(); ForceWindowToForeground(); } catch { }
                            await Task.Delay(600);
                            try { this.Activate(); ForceWindowToForeground(); } catch { }
                        });
                    }
                    catch { }
                    await PlayCinematicStartupAsync();
                    StartRichPresenceIfEnabled();
                    StartHeartbeatLoop();
                    _ = CheckKillSwitchAsync();
                    _ = Task.Run(() => RunLauncherStartupHealthChecksAsync());
                    _ = CheckApiHealthAndMaybeShowMaintenanceAsync();
                    InitializeNatureTheme();

                    await InitializeDefaultServersAsync();

                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        LoadServers();
                        RefreshQuickPlayBar();
                    });

                    _ = Task.Run(async () =>
                    {
                        try { await LoadFeaturedServersFromApiAsync(); } catch (Exception ex) { LeafClient.Services.LeafLog.Error("LoadFeaturedServersFromApiAsync Error", $"{ex.Message}"); }
                        try { await RefreshAllServerStatusesAsync(); } catch (Exception ex) { LeafClient.Services.LeafLog.Error("RefreshAllServerStatusesAsync Error", $"{ex.Message}"); }
                        try { await WarmupServerIconsAsync(); } catch (Exception ex) { LeafClient.Services.LeafLog.Error("WarmupServerIconsAsync Error", $"{ex.Message}"); }
                    });

                    UpdateLaunchButton("LAUNCH GAME", "SeaGreen");

                    _ = RefreshNewContentDotsAsync();
                    StartUpdateNotificationTimer();
                    StartSingleInstanceWakeListener();
                    UpdateInstancesPill();

                    if (_currentSettings.IsFirstLaunch)
                    {
                        _currentSettings.RenderDistance = 8;
                        _currentSettings.MaxFps = 0;
                        _currentSettings.VSync = false;
                        _currentSettings.SimulationDistance = 5;

                        var minimap = _currentSettings.InstalledMods.FirstOrDefault(m =>
                            m.Name.Contains("Minimap", StringComparison.OrdinalIgnoreCase) ||
                            m.ModId.Contains("minimap", StringComparison.OrdinalIgnoreCase));

                        if (minimap != null) minimap.Enabled = false;

                        ApplySettingsToUi(_currentSettings);
                        await _settingsService.SaveSettingsAsync(_currentSettings);

                        await Task.Delay(500);
                        TutorialService.Instance.SetCrackedAccount(_currentSettings?.AccountType == "offline");
                        TutorialService.Instance.StartTutorial();

                        _currentSettings.IsFirstLaunch = false;
                        await _settingsService.SaveSettingsAsync(_currentSettings);
                    }

                    if (!TutorialService.Instance.IsRunning
                        && string.IsNullOrEmpty(_currentSettings?.RenderBackendChoice))
                    {
                        Avalonia.Threading.Dispatcher.UIThread.Post(() =>
                        {
                            try { ShowRenderBackendPopup(); }
                            catch (Exception ex) { LeafClient.Services.LeafLog.Error("RenderBackend", $"Startup show failed: {ex.Message}"); }
