                    else if (!string.IsNullOrEmpty(_currentSettings?.RenderBackendChoice))
                    {
                        try { await ApplyRenderEngineChoiceAsync(_currentSettings.RenderBackendChoice); }
                        catch (Exception ex) { LeafClient.Services.LeafLog.Error("RenderBackend", $"Migration apply failed: {ex.Message}"); }
                    }

                    await CheckForUpdatesAsync();

                    if (_onlineCountService != null)
                    {
                        var mcUsername = _currentSettings?.SessionUsername
                            ?? DecodeJwtMinecraftUsername(_currentSettings?.LeafApiJwt);
                        LeafClient.Services.LeafLog.Info("OnlineCountService", $"Opened handler: mcUsername='{mcUsername}', hasJwt={!string.IsNullOrEmpty(_currentSettings?.LeafApiJwt)}");
                        if (!string.IsNullOrWhiteSpace(mcUsername))
                        {
                            _onlineCountService.Start(mcUsername!, _currentSettings?.LeafApiJwt);
                        }
                        try { await _onlineCountService.UpdateCount(true); } catch (Exception ex) { LeafClient.Services.LeafLog.Error("UpdateCount Error", $"{ex.Message}"); }
                        try { await UpdateOnlineCountDisplay(); } catch (Exception ex) { LeafClient.Services.LeafLog.Error("UpdateOnlineCountDisplay Error", $"{ex.Message}"); }
                    }

                    try
                    {
                        var activeEntry = _currentSettings?.SavedAccounts.FirstOrDefault(a => a.Id == _currentSettings.ActiveAccountId);
                        if (activeEntry != null) await EnsureFreshJwtForAccountAsync(activeEntry);
                    }
                    catch (Exception ex) { LeafClient.Services.LeafLog.Info("Startup JWT refresh", $"{ex.Message}"); }
                    try { await UpdateLeafsBalanceAsync(); } catch (Exception ex) { LeafClient.Services.LeafLog.Error("UpdateLeafsBalance Error", $"{ex.Message}"); }
                    _ = SyncOwnedCosmeticsFromApiAsync();

                    _ = Task.Run(async () => { try { await PerformModCleanup(); } catch (Exception ex) { LeafClient.Services.LeafLog.Error("PerformModCleanup Error", $"{ex.Message}"); } });

                    _ = Task.Run(async () =>
                    {
                        try
                        {
                            await Task.Delay(1500);
                            await Dispatcher.UIThread.InvokeAsync(() =>
                            {
                                try { _cosmeticsPage?.LoadCosmeticsPage(); }
                                catch (Exception ex) { LeafClient.Services.LeafLog.Info("CosmeticsPreload", $"{ex.Message}"); }
                            });
                        }
                        catch (Exception ex) { LeafClient.Services.LeafLog.Info("CosmeticsPreload outer", $"{ex.Message}"); }
                    });
                }
                catch (Exception ex)
                {
                    LeafLog.Error("MainWindow.Opened Critical Error", $"An unhandled exception occurred during startup tasks: {ex.Message}");
                    FadeOutUpdateOverlay();
                }
            };

            this.Closing += OnWindowClosing;

            _networkMonitorTimer = new DispatcherTimer
            {
                Interval = TimeSpan.FromSeconds(5)
            };
            _networkMonitorTimer.Tick += (_, __) => CheckNetworkConnectivity();
            _networkMonitorTimer.Start();
        }

        private void InitializeNatureTheme()
        {
            var canvas = this.FindControl<Canvas>("FallingLeavesCanvas");
            var overlay = this.FindControl<Grid>("NatureOverlay");

            if (!_currentSettings.EnableNatureTheme)
            {
                if (canvas != null) canvas.IsVisible = false;
                if (overlay != null) overlay.IsVisible = false;
                return;
            }

            if (canvas == null) return;

            canvas.IsVisible = true;
            if (overlay != null) overlay.IsVisible = true;

            if (_leafTimer == null)
            {
                _leafTimer = new DispatcherTimer
                {
                    Interval = TimeSpan.FromMilliseconds(16)
                };
                _leafTimer.Tick += UpdateLeaves;
            }

            if (!_leafTimer.IsEnabled)
            {
                _leafTimer.Start();

                if (_leaves.Count == 0)
                {
                    for (int i = 0; i < 20; i++)
                    {
                        SpawnLeaf(canvas, true);
                    }
                }
            }
        }

        private void UpdateNatureThemeState()
        {
            bool enabled = _natureThemeToggle?.IsChecked ?? true;
            _currentSettings.EnableNatureTheme = enabled;

            if (enabled)
            {
                InitializeNatureTheme();
            }
            else
            {
                _leafTimer?.Stop();

                var canvas = this.FindControl<Canvas>("FallingLeavesCanvas");
                if (canvas != null)
                {
                    canvas.Children.Clear();
                    canvas.IsVisible = false;
                }

                var overlay = this.FindControl<Grid>("NatureOverlay");
                if (overlay != null) overlay.IsVisible = false;

                _leaves.Clear();
            }
        }

        private void SpawnLeaf(Canvas canvas, bool randomY = false)
        {
            double size = _leafRand.Next(12, 24);

            var leafShape = new Avalonia.Controls.Shapes.Path
            {
                Data = Avalonia.Media.Geometry.Parse("M 0,0 C 5,10 10,10 10,0 C 10,-10 5,-10 0,0"),
                Width = size,
                Height = size,
                Stretch = Stretch.Uniform,
                Fill = new SolidColorBrush(GetRandomLeafColor()),
                Opacity = 0.7,
                RenderTransform = new TransformGroup
                {
                    Children = new Transforms
                    {
                        new RotateTransform(0),
                        new TranslateTransform(0, 0)
                    }
                }
            };

            double containerWidth = this.Bounds.Width > 0 ? this.Bounds.Width : 1400;
            double containerHeight = this.Bounds.Height > 0 ? this.Bounds.Height : 750;

            double startX = _leafRand.NextDouble() * containerWidth;
            double startY = randomY ? _leafRand.NextDouble() * containerHeight : -50;

            var leaf = new LeafParticle
            {
                Shape = leafShape,
                X = startX,
                Y = startY,
                SpeedY = 0.5 + (_leafRand.NextDouble() * 1.0),
                SwayAmplitude = 0.5 + (_leafRand.NextDouble() * 1.0),
                SwayFrequency = 0.02 + (_leafRand.NextDouble() * 0.03),
                SwayPhase = _leafRand.NextDouble() * Math.PI * 2,
                Rotation = _leafRand.Next(0, 360),
                RotationSpeed = (_leafRand.NextDouble() - 0.5) * 3
            };

            _leaves.Add(leaf);
            canvas.Children.Add(leafShape);
        }

        private Color GetRandomLeafColor()
        {
            var colors = new[]
            {
        Color.Parse("#66BB6A"),
        Color.Parse("#9CCC65"),
        Color.Parse("#FFCA28"),
        Color.Parse("#8D6E63")
    };
            return colors[_leafRand.Next(colors.Length)];
        }

        private void UpdateLeaves(object? sender, EventArgs e)
        {
            var canvas = this.FindControl<Canvas>("FallingLeavesCanvas");
            if (canvas == null || !canvas.IsVisible) return;

            double windowHeight = this.Bounds.Height;

            for (int i = _leaves.Count - 1; i >= 0; i--)
            {
                var leaf = _leaves[i];

                leaf.Y += leaf.SpeedY;
                leaf.SwayPhase += leaf.SwayFrequency;
                double xOffset = Math.Sin(leaf.SwayPhase) * leaf.SwayAmplitude;
                leaf.Rotation += leaf.RotationSpeed;

                if (leaf.Shape.RenderTransform is TransformGroup group)
                {
                    if (group.Children[0] is RotateTransform rotate)
                        rotate.Angle = leaf.Rotation;

                    if (group.Children[1] is TranslateTransform translate)
                        translate.X = xOffset;
                }

                Canvas.SetLeft(leaf.Shape, leaf.X);
                Canvas.SetTop(leaf.Shape, leaf.Y);

                if (leaf.Y > windowHeight + 50)
                {
                    canvas.Children.Remove(leaf.Shape);
                    _leaves.RemoveAt(i);
                    SpawnLeaf(canvas);
                }
            }

            if (_leaves.Count < 25 && _leafRand.NextDouble() < 0.05)
            {
                SpawnLeaf(canvas);
            }
        }

        private void StartUpdateSpinner()
        {
            if (_updateSpinner == null) return;

            _updateSpinnerCts?.Cancel();
            _updateSpinnerCts = new CancellationTokenSource();
            var token = _updateSpinnerCts.Token;

            Task.Run(async () =>
            {
                var sw = System.Diagnostics.Stopwatch.StartNew();
                const double periodSec = 1.0;
                const int dotCount = 12;

                while (!token.IsCancellationRequested)
                {
                    double phase = (sw.Elapsed.TotalSeconds / periodSec) % 1.0;
                    double leadFloat = phase * dotCount;

                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        if (_updateSpinner == null) return;
                        var children = _updateSpinner.Children;
                        int count = Math.Min(children.Count, dotCount);
                        for (int i = 0; i < count; i++)
                        {
                            if (children[i] is Visual v)
                            {
                                double rawDist = (leadFloat - i + dotCount) % dotCount;
                                double opacity = 0.15 + 0.85 * Math.Exp(-rawDist * 0.55);
                                v.Opacity = opacity;
                            }
                        }
                    });
                    await Task.Delay(16, token);
                }
            }, token);
        }

        private const bool UPDATE_TEST_MODE = false;
        private const string UPDATE_TEST_VERSION = "2.0";

        private async Task CheckForUpdatesAsync()
        {
            ShowUpdateCheckOverlay();
            StartUpdateSpinner();
            LeafLog.Info("Updater", "Checking for updates...");

            if (UPDATE_TEST_MODE)
            {
                LeafClient.Services.LeafLog.Info("Updater", $"TEST MODE - simulating update v{UPDATE_TEST_VERSION}");
                await Task.Delay(2000);
                FadeOutUpdateOverlay();

                await ShowUpdateDownloadOverlay(UPDATE_TEST_VERSION);

                for (int i = 0; i <= 100; i += 2)
                {
                    double pct = i / 100.0;
                    await UpdateProgress(pct, i < 80 ? "Downloading update..." : "Extracting files...");
                    await Task.Delay(50);
                }

                await UpdateProgress(1.0, "Update complete! Restarting...");
                await Task.Delay(1500);

                await Dispatcher.UIThread.InvokeAsync(FadeOutDownloadOverlay);
                LeafLog.Info("Updater", "TEST MODE - would restart here");
                return;
            }

            if (!System.Net.NetworkInformation.NetworkInterface.GetIsNetworkAvailable())
            {
                LeafLog.Info("Updater", "No network. Skipping check.");
                await Task.Delay(1000);
                FadeOutUpdateOverlay();
                return;
            }

            try
            {
                _ = Task.Run(async () =>
                {
                    try { await Task.Delay(TimeSpan.FromSeconds(30)); Services.UpdateService.MarkBootSuccessful(); }
                    catch { }
                });

                Services.UpdateService.CurrentChannel = (_currentSettings?.GameUpdateDelivery == UpdateDelivery.EarlyOptIn && _isLeafPlus)
                    ? Services.UpdateService.UpdateChannel.Early
                    : Services.UpdateService.UpdateChannel.Stable;

                var delayTask = Task.Delay(1500);
                var checkTask = Services.UpdateService.CheckForUpdateDetailedAsync();
                await Task.WhenAll(delayTask, checkTask);
                var result = await checkTask;

                if (result.Outcome == Services.UpdateService.UpdateCheckOutcome.UpdateAvailable && result.Version != null)
                {
                    string newVersion = result.Version;
                    LeafClient.Services.LeafLog.Info("Updater", $"Update v{newVersion} found - mandatory update starting");
                    FadeOutUpdateOverlay();

                    await ShowUpdateDownloadOverlay(newVersion);

                    bool staged = await Services.UpdateService.DownloadAndStageAsync(
                        onProgress: async (pct) =>
                        {
                            await UpdateProgress(pct, pct < 0.8 ? "Downloading update..." : "Extracting files...");
                        }
                    );

                    if (staged)
                    {
                        await UpdateProgress(1.0, "Update complete! Restarting...");
                        await Task.Delay(1200);
                        Services.UpdateService.RestartToApply();
                    }
                    else
                    {
                        await UpdateProgress(0, "Update failed. Please try again later.");
                        await Task.Delay(3000);
                        await Dispatcher.UIThread.InvokeAsync(FadeOutDownloadOverlay);
                    }
                }
                else if (result.Outcome == Services.UpdateService.UpdateCheckOutcome.VersionFileMissing)
                {
                    LeafLog.Info("Updater", "Version file missing - showing blocker popup.");
                    FadeOutUpdateOverlay();
                    await Dispatcher.UIThread.InvokeAsync(ShowUpdateBlockedPopup);
                    StartUpdateBlockedRecoveryPoller();
                }
                else
                {
                    LeafClient.Services.LeafLog.Info("Updater", $"Outcome: {result.Outcome}");
                    FadeOutUpdateOverlay();
                }
            }
            catch (Exception ex)
            {
                LeafLog.Error("Updater ERROR", $"{ex.Message}");
                FadeOutUpdateOverlay();
            }
        }

        private Grid? _updateBlockedOverlay;
        private Border? _updateBlockedCard;
        private System.Threading.CancellationTokenSource? _updateBlockedPollerCts;
        private bool _isUpdateBlockedAnimating;

        private async void ShowUpdateBlockedPopup()
        {
            if (_updateBlockedOverlay != null) return;
            _isUpdateBlockedAnimating = true;

            var overlay = new Grid
            {
                Background = new SolidColorBrush(Color.Parse("#CC000000")),
                IsVisible = false,
                ZIndex = 9999,
            };
            overlay.Tapped += (_, e) => e.Handled = true;

            var card = new Border
            {
                Background = new SolidColorBrush(Color.Parse("#1A1A2E")),
                CornerRadius = new CornerRadius(16),
                BorderBrush = new SolidColorBrush(Color.Parse("#FF6B6B")),
                BorderThickness = new Thickness(1),
                Width = 440,
                Padding = new Thickness(28, 26),
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                RenderTransform = new ScaleTransform { ScaleX = 0.85, ScaleY = 0.85 },
                BoxShadow = BoxShadows.Parse("0 20 60 0 #80000000"),
            };
            card.Tapped += (_, e) => e.Handled = true;

            var stack = new StackPanel { Spacing = 14 };

            var iconBorder = new Border
            {
                Background = new SolidColorBrush(Color.Parse("#22FF6B6B")),
                CornerRadius = new CornerRadius(28),
                Width = 56,
                Height = 56,
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                Child = new TextBlock
                {
                    Text = "\u26A0",
                    FontSize = 28,
                    Foreground = new SolidColorBrush(Color.Parse("#FF6B6B")),
                    HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                    VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                },
            };
            stack.Children.Add(iconBorder);

            stack.Children.Add(new TextBlock
            {
                Text = "Update Required",
                FontSize = 20,
                FontWeight = FontWeight.Bold,
                Foreground = new SolidColorBrush(Colors.White),
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                TextAlignment = TextAlignment.Center,
            });

            stack.Children.Add(new TextBlock
            {
                Text = "We can't reach the version server right now, so Leaf Client cannot verify it's up to date. To continue, please download the latest version manually from our website.",
                FontSize = 13,
                Foreground = new SolidColorBrush(Color.Parse("#C0FFFFFF")),
                TextWrapping = TextWrapping.Wrap,
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                TextAlignment = TextAlignment.Center,
                LineHeight = 19,
                Margin = new Thickness(0, 0, 0, 6),
            });

            var btnBorder = new Border
            {
                Background = new SolidColorBrush(Color.Parse("#4CAF50")),
                CornerRadius = new CornerRadius(10),
                Padding = new Thickness(20, 12),
                Cursor = new Avalonia.Input.Cursor(Avalonia.Input.StandardCursorType.Hand),
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Stretch,
                Child = new TextBlock
                {
                    Text = "Download from leafclient.com",
                    FontSize = 14,
                    FontWeight = FontWeight.SemiBold,
                    Foreground = new SolidColorBrush(Colors.White),
                    HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                },
            };
            btnBorder.Tapped += (_, e) =>
            {
                e.Handled = true;
                try
                {
                    System.Diagnostics.Process.Start(new System.Diagnostics.ProcessStartInfo
                    {
                        FileName = "https://leafclient.com/download",
                        UseShellExecute = true,
                    });
                }
                catch (Exception ex) { LeafClient.Services.LeafLog.Error("UpdateBlocked", $"Open download page failed: {ex.Message}"); }
            };
            stack.Children.Add(btnBorder);

            var statusLabel = new TextBlock
            {
                Text = "Retrying connection in the background...",
                FontSize = 11,
                Foreground = new SolidColorBrush(Color.Parse("#80FFFFFF")),
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                TextAlignment = TextAlignment.Center,
                FontStyle = FontStyle.Italic,
                Margin = new Thickness(0, 4, 0, 0),
            };
            stack.Children.Add(statusLabel);

            card.Child = stack;
            overlay.Children.Add(card);

            var rootGrid = this.FindControl<Grid>("RootGrid") ?? (Content as Grid);
            if (rootGrid == null)
            {
                _isUpdateBlockedAnimating = false;
                return;
            }
            rootGrid.Children.Add(overlay);

            _updateBlockedOverlay = overlay;
            _updateBlockedCard = card;

            overlay.IsVisible = true;

            if (AreAnimationsEnabled())
            {
                var st = (ScaleTransform)card.RenderTransform!;
                card.RenderTransformOrigin = new RelativePoint(0.5, 0.5, RelativeUnit.Relative);
                card.Opacity = 0;
                overlay.Opacity = 0;

                const int dur = 220;
                const int frames = 13;
                const int delay = dur / frames;

                for (int i = 0; i <= frames; i++)
                {
                    double t = (double)i / frames;
                    double eased = 1 - Math.Pow(1 - t, 3);
                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        overlay.Opacity = eased;
                        card.Opacity = eased;
                        st.ScaleX = 0.85 + 0.15 * eased;
                        st.ScaleY = 0.85 + 0.15 * eased;
                    });
                    if (i < frames) await Task.Delay(delay);
                }
            }
            else
            {
                overlay.Opacity = 1;
                card.Opacity = 1;
                var st = (ScaleTransform)card.RenderTransform!;
                st.ScaleX = 1; st.ScaleY = 1;
            }

            _isUpdateBlockedAnimating = false;
        }

        private async void HideUpdateBlockedPopup()
        {
            if (_updateBlockedOverlay == null || _updateBlockedCard == null) return;
            if (_isUpdateBlockedAnimating) return;
            _isUpdateBlockedAnimating = true;

            var overlay = _updateBlockedOverlay;
            var card = _updateBlockedCard;

            if (AreAnimationsEnabled())
            {
                var st = card.RenderTransform as ScaleTransform ?? new ScaleTransform { ScaleX = 1, ScaleY = 1 };
                card.RenderTransform = st;
                const int dur = 180;
                const int frames = 10;
                const int delay = dur / frames;

                for (int i = 0; i <= frames; i++)
                {
                    double t = (double)i / frames;
                    double eased = 1 - Math.Pow(1 - t, 3);
                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        overlay.Opacity = 1 - eased;
                        card.Opacity = 1 - eased;
                        st.ScaleX = 1.0 - 0.1 * eased;
                        st.ScaleY = 1.0 - 0.1 * eased;
                    });
                    if (i < frames) await Task.Delay(delay);
                }
            }

            overlay.IsVisible = false;
            var rootGrid = this.FindControl<Grid>("RootGrid") ?? (Content as Grid);
            if (rootGrid != null) rootGrid.Children.Remove(overlay);
            _updateBlockedOverlay = null;
            _updateBlockedCard = null;
            _isUpdateBlockedAnimating = false;
        }

        private void StartUpdateBlockedRecoveryPoller()
        {
            _updateBlockedPollerCts?.Cancel();
            _updateBlockedPollerCts = new System.Threading.CancellationTokenSource();
            var ct = _updateBlockedPollerCts.Token;

            _ = Task.Run(async () =>
            {
                while (!ct.IsCancellationRequested)
                {
                    try { await Task.Delay(TimeSpan.FromSeconds(30), ct); }
                    catch (OperationCanceledException) { return; }

                    var result = await Services.UpdateService.CheckForUpdateDetailedAsync(ct);
                    if (ct.IsCancellationRequested) return;

                    if (result.Outcome == Services.UpdateService.UpdateCheckOutcome.UpdateAvailable && result.Version != null)
                    {
                        _updateBlockedPollerCts?.Cancel();
                        await Dispatcher.UIThread.InvokeAsync(async () =>
                        {
                            HideUpdateBlockedPopup();
                            await Task.Delay(220);
                            await ShowUpdateDownloadOverlay(result.Version);
                            bool staged = await Services.UpdateService.DownloadAndStageAsync(
                                onProgress: async (pct) =>
                                {
                                    await UpdateProgress(pct, pct < 0.8 ? "Downloading update..." : "Extracting files...");
                                });
                            if (staged)
                            {
                                await UpdateProgress(1.0, "Update complete! Restarting...");
                                await Task.Delay(1200);
                                Services.UpdateService.RestartToApply();
                            }
                            else
                            {
                                await UpdateProgress(0, "Update failed. Please try again later.");
                                await Task.Delay(3000);
                                await Dispatcher.UIThread.InvokeAsync(FadeOutDownloadOverlay);
                            }
                        });
                        return;
                    }

                    if (result.Outcome == Services.UpdateService.UpdateCheckOutcome.UpToDate)
                    {
                        _updateBlockedPollerCts?.Cancel();
                        await Dispatcher.UIThread.InvokeAsync(HideUpdateBlockedPopup);
                        return;
                    }
                }
            }, ct);
        }

        private void ShowUpdateCheckOverlay()
        {
            if (_updateCheckOverlay == null) return;

            var card = this.FindControl<Border>("UpdateCheckCard");

            if (!AreAnimationsEnabled())
            {
                _updateCheckOverlay.Opacity = 1;
                _updateCheckOverlay.IsVisible = true;
                if (card != null)
                    card.RenderTransform = Avalonia.Media.Transformation.TransformOperations.Parse("scale(1.0)");
                return;
            }

            _updateCheckOverlay.Opacity = 0;
            _updateCheckOverlay.IsVisible = true;
            if (card != null)
                card.RenderTransform = Avalonia.Media.Transformation.TransformOperations.Parse("scale(0.94)");

            Dispatcher.UIThread.Post(() =>
            {
                if (_updateCheckOverlay != null)
                    _updateCheckOverlay.Opacity = 1;
                if (card != null)
                    card.RenderTransform = Avalonia.Media.Transformation.TransformOperations.Parse("scale(1.0)");
            }, DispatcherPriority.Render);
        }

