        private async Task PlayCinematicStartupAsync()
        {
            if (_startupOverlay == null || _startupLogo == null || _startupBg == null || _startupLogoText == null) return;

            _startupOverlay.IsVisible = true;
            _startupOverlay.Opacity = 1;
            _startupLogo.Opacity = 0;
            _startupLogoText.Opacity = 0;

            var easing = new CubicEaseOut();

            _startupBg.Transitions = new Transitions
            {
                new DoubleTransition { Property = Image.OpacityProperty, Duration = TimeSpan.FromMilliseconds(1200), Easing = easing },
                new TransformOperationsTransition { Property = Image.RenderTransformProperty, Duration = TimeSpan.FromMilliseconds(3000), Easing = easing }
            };

            var logoTransitions = new Transitions
            {
                new DoubleTransition { Property = Image.OpacityProperty, Duration = TimeSpan.FromMilliseconds(680), Easing = easing },
                new TransformOperationsTransition { Property = Image.RenderTransformProperty, Duration = TimeSpan.FromMilliseconds(1800), Easing = easing }
            };
            _startupLogo.Transitions = logoTransitions;
            _startupLogoText.Transitions = logoTransitions;

            await Dispatcher.UIThread.InvokeAsync(() =>
            {
                _startupBg.Opacity = 1;
                _startupBg.RenderTransform = TransformOperations.Parse("scale(1.0)");

                _startupLogo.Opacity = 1;
                _startupLogo.RenderTransform = TransformOperations.Parse("scale(1.0)");
                _startupLogoText.Opacity = 1;
                _startupLogoText.RenderTransform = TransformOperations.Parse("scale(1.0)");
            });

            await Task.Delay(1800);

            _startupOverlay.Transitions = new Transitions
            {
                new DoubleTransition { Property = Grid.OpacityProperty, Duration = TimeSpan.FromMilliseconds(600), Easing = new QuarticEaseIn() }
            };

            await Dispatcher.UIThread.InvokeAsync(() =>
            {
                _startupOverlay.Opacity = 0;
            });

            await Task.Delay(600);
            _startupOverlay.IsVisible = false;
        }

        private async Task PerformModCleanup()
        {
            if (_modCleanupService == null) return;

            LeafLog.Info("Mod Cleanup", "Starting background cleanup process...");
            var cleanupList = _modCleanupService.GetCleanupList();
            var modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");

            List<ModCleanupEntry> successfullyCleanedMods = new List<ModCleanupEntry>();

            foreach (var entry in cleanupList)
            {
                var tempInstalledMod = new InstalledMod
                {
                    ModId = entry.ModId,
                    FileName = entry.FileName,
                    MinecraftVersion = entry.MinecraftVersion
                };

                string jarPath = GetModFilePath(modsFolder, tempInstalledMod, isDisabled: false);
                string disabledPath = GetModFilePath(modsFolder, tempInstalledMod, isDisabled: true);

                bool deletedAnyFile = false;
                if (File.Exists(jarPath))
                {
                    try
                    {
                        File.Delete(jarPath);
                        LeafClient.Services.LeafLog.Warn("Mod Cleanup", $"Successfully deleted orphaned mod file: {System.IO.Path.GetFileName(jarPath)}");
                        deletedAnyFile = true;
                    }
                    catch (Exception ex)
                    {
                        LeafLog.Error("Mod Cleanup ERROR", $"Failed to delete orphaned mod file '{System.IO.Path.GetFileName(jarPath)}': {ex.Message}");
                    }
                }
                if (File.Exists(disabledPath))
                {
                    try
                    {
                        File.Delete(disabledPath);
                        LeafClient.Services.LeafLog.Warn("Mod Cleanup", $"Successfully deleted orphaned disabled mod file: {System.IO.Path.GetFileName(disabledPath)}");
                        deletedAnyFile = true;
                    }
                    catch (Exception ex)
                    {
                        LeafClient.Services.LeafLog.Error("Mod Cleanup ERROR", $"Failed to delete orphaned disabled mod file '{System.IO.Path.GetFileName(disabledPath)}': {ex.Message}");
                    }
                }

                if (deletedAnyFile)
                {
                    successfullyCleanedMods.Add(entry);
                }
            }

            foreach (var entry in successfullyCleanedMods)
            {
                _modCleanupService.RemoveModFromCleanup(entry);
            }

            if (successfullyCleanedMods.Any())
            {
                LeafClient.Services.LeafLog.Info("Mod Cleanup", $"Completed. Cleaned up {successfullyCleanedMods.Count} mods.");
            }
            else
            {
                LeafLog.Info("Mod Cleanup", "Completed. No mods needed cleanup.");
            }
        }

        private static readonly HttpClient _connectivityClient = new HttpClient { Timeout = TimeSpan.FromSeconds(4) };
        private bool _offlineOverlayVisible = false;
        private bool _connectivityCheckInFlight = false;

        private static readonly string[] _connectivityProbes = new[]
        {
            "https://www.gstatic.com/generate_204",
            "https://cp.cloudflare.com/",
            "https://www.apple.com/library/test/success.html",
            "http://www.msftconnecttest.com/connecttest.txt",
        };

        private async Task<bool> HasRealInternetAsync()
        {
            var tasks = _connectivityProbes.Select(async url =>
            {
                try
                {
                    using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(3));
                    using var req = new HttpRequestMessage(HttpMethod.Get, url);
                    req.Headers.UserAgent.ParseAdd("LeafClient/1.0 (connectivity-probe)");
                    using var res = await _connectivityClient.SendAsync(req, HttpCompletionOption.ResponseHeadersRead, cts.Token).ConfigureAwait(false);
                    int code = (int)res.StatusCode;
                    return code >= 200 && code < 500;
                }
                catch { return false; }
            }).ToList();

            while (tasks.Count > 0)
            {
                var done = await Task.WhenAny(tasks).ConfigureAwait(false);
                if (await done.ConfigureAwait(false)) return true;
                tasks.Remove(done);
            }
            return false;
        }

        private void CheckNetworkConnectivity()
        {
            if (_connectivityCheckInFlight) return;
            _connectivityCheckInFlight = true;
            _ = Task.Run(async () =>
            {
                bool online = false;
                try { online = await HasRealInternetAsync().ConfigureAwait(false); }
                catch { online = false; }
                finally { _connectivityCheckInFlight = false; }

                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    SetOfflineOverlay(!online);
                    ApplyLaunchButtonState();
                });
            });
        }

        private void SetOfflineOverlay(bool show)
        {
            if (_offlineOverlayVisible == show) return;
            _offlineOverlayVisible = show;
            var overlay = this.FindControl<Border>("OfflineOverlay");
            if (overlay == null) return;
            overlay.IsVisible = show;
            var statusText = this.FindControl<TextBlock>("OfflineStatusText");
            var dot = this.FindControl<Ellipse>("OfflineSpinnerDot");
            if (show)
            {
                if (statusText != null) statusText.Text = "Waiting for connection…";
                if (dot != null) dot.Fill = new SolidColorBrush(Color.Parse("#FF5252"));
                var retry = this.FindControl<Button>("OfflineRetryButton");
                if (retry != null)
                {
                    retry.Click -= OfflineRetry_Click;
                    retry.Click += OfflineRetry_Click;
                }
            }
        }

        private void OfflineRetry_Click(object? sender, RoutedEventArgs e)
        {
            var statusText = this.FindControl<TextBlock>("OfflineStatusText");
            var dot = this.FindControl<Ellipse>("OfflineSpinnerDot");
            if (statusText != null) statusText.Text = "Checking connection…";
            if (dot != null) dot.Fill = new SolidColorBrush(Color.Parse("#FFC857"));
            CheckNetworkConnectivity();
        }

        private async Task UpdateOnlineCountDisplay()
        {
            if (_onlineCountService == null)
            {
                LeafLog.Info("OnlineCountService", "Service not available. Cannot update UI.");
                if (_onlineCountTextBlock != null) _onlineCountTextBlock.Text = "You're offline";
                if (_onlineStatusDot != null) _onlineStatusDot.Fill = new SolidColorBrush(Colors.Red);
                return;
            }

            if (_onlineCountTextBlock == null || _onlineStatusDot == null)
            {
                _onlineCountTextBlock = this.FindControl<TextBlock>("OnlineCountTextBlock");
                _onlineStatusDot = this.FindControl<Ellipse>("OnlineStatusDot");

                if (_onlineCountTextBlock == null || _onlineStatusDot == null)
                {
                    LeafLog.Info("OnlineCountService", "Online count TextBlock or Ellipse not found in UI.");
                    return;
                }
            }

            int count = await _onlineCountService.GetOnlineCount();
            string? motd = _onlineCountService.GetMotd();
            string? motdColor = _onlineCountService.GetMotdColor();
            string? motdBgColor = _onlineCountService.GetMotdBgColor();
            string? motdLink = _onlineCountService.GetMotdLink();

            _lastOnlineCount = count;
            _lastMotd = motd;
            _lastMotdLink = motdLink;

            if (count == int.MinValue)
            {
                Dispatcher.UIThread.Post(() =>
                {
                    _onlineCountTextBlock.Text = "N/A";
                    _onlineStatusDot.Fill = new SolidColorBrush(Colors.Gray);
                });
            }
            else if (count >= 0)
            {
                Dispatcher.UIThread.Post(() =>
                {
                    _onlineCountTextBlock.Text = $"{count} Online";
                    _onlineStatusDot.Fill = new SolidColorBrush(count > 0 ? Colors.Green : Colors.Gray);
                });
            }
            else
            {
                Dispatcher.UIThread.Post(() =>
                {
                    _onlineCountTextBlock.Text = "You're offline";
                    _onlineStatusDot.Fill = new SolidColorBrush(Colors.Red);
                });
            }

            if (!string.IsNullOrEmpty(motd))
            {
                Dispatcher.UIThread.Post(() =>
                {
                    _motdTextBlock ??= this.FindControl<TextBlock>("MotdTextBlock");
                    _motdBanner ??= this.FindControl<Border>("MotdBanner");
                    if (_motdTextBlock != null)
                    {
                        _motdTextBlock.Text = motd;
                        IBrush brush = new SolidColorBrush(Colors.White);
                        if (!string.IsNullOrWhiteSpace(motdColor))
                        {
                            try { brush = SolidColorBrush.Parse(NormalizeCssHex(motdColor)); } catch { }
                        }
                        _motdTextBlock.Foreground = brush;
                    }
                    if (_motdBanner != null)
                    {
                        if (!string.IsNullOrWhiteSpace(motdBgColor))
                        {
                            try { _motdBanner.Background = SolidColorBrush.Parse(NormalizeCssHex(motdBgColor)); } catch { }
                        }
                        _motdBanner.Cursor = !string.IsNullOrWhiteSpace(motdLink)
                            ? new Avalonia.Input.Cursor(Avalonia.Input.StandardCursorType.Hand)
                            : Avalonia.Input.Cursor.Default;
                        _motdBanner.IsVisible = true;
                    }
                });
            }
        }

        private string? _lastMotdLink;

        private static string NormalizeCssHex(string hex)
        {
            if (string.IsNullOrWhiteSpace(hex)) return hex;
            string s = hex.Trim();
            if (!s.StartsWith("#")) return s;
            if (s.Length == 9)
            {
                string rgb = s.Substring(1, 6);
                string a = s.Substring(7, 2);
                return "#" + a + rgb;
            }
            return s;
        }

        private void OnMotdBannerPressed(object? sender, Avalonia.Input.PointerPressedEventArgs e)
        {
            var link = _lastMotdLink;
            if (string.IsNullOrWhiteSpace(link)) return;
            if (!Uri.TryCreate(link, UriKind.Absolute, out var uri)) return;
            if (uri.Scheme != Uri.UriSchemeHttp && uri.Scheme != Uri.UriSchemeHttps) return;
            try
            {
                System.Diagnostics.Process.Start(new System.Diagnostics.ProcessStartInfo
                {
                    FileName = uri.ToString(),
                    UseShellExecute = true
                });
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("MOTD", $"Failed to open link: {ex.Message}");
            }
        }

        private async Task ReportSessionPlaytimeAsync()
        {
            var jwt = _currentSettings?.LeafApiJwt;
            if (string.IsNullOrEmpty(jwt)) return;
            if (_sessionStartUtc == null) return;

            int totalMinutes = (int)((DateTime.UtcNow - _sessionStartUtc.Value).TotalMinutes);
            int unreported = totalMinutes - _sessionReportedMinutes;
            if (unreported < 1) return;

            var result = await LeafClient.Services.LeafApiService.ReportPlaytimeAsync(jwt, unreported);
            if (result == null) return;
            _sessionReportedMinutes = totalMinutes;
            if (result.Awarded == 0) return;

            _currentCoinBalance = result.Coins;
            Dispatcher.UIThread.Post(() =>
            {
                _leafsBalanceText ??= this.FindControl<TextBlock>("LeafsBalanceText");
                if (_leafsBalanceText != null)
                    _leafsBalanceText.Text = result.Coins.ToString("N0");
            });

            ToastService.Show($"+{result.Awarded} \U0001F343 Leaf Points earned!", ToastType.Success);
        }

        private async Task ClaimMidGamePlaytimeAsync()
        {
            if (System.Threading.Interlocked.Exchange(ref _midGameClaimInFlight, 1) == 1) return;
            try
            {
                var jwt = _currentSettings?.LeafApiJwt;
                if (string.IsNullOrEmpty(jwt)) return;
                if (_sessionStartUtc == null) return;
                if (_gameProcess == null || _gameProcess.HasExited) return;

                var nowUtc = DateTime.UtcNow;
                int totalMinutes = (int)((nowUtc - _sessionStartUtc.Value).TotalMinutes);
                int unreported = totalMinutes - _sessionReportedMinutes;
                if (unreported < 1) return;

                var result = await LeafClient.Services.LeafApiService.ReportPlaytimeAsync(jwt, unreported);
                if (result == null) return;

                _sessionReportedMinutes = totalMinutes;

                if (result.Awarded > 0)
                {
                    _currentCoinBalance = result.Coins;
                    Dispatcher.UIThread.Post(() =>
                    {
                        _leafsBalanceText ??= this.FindControl<TextBlock>("LeafsBalanceText");
                        if (_leafsBalanceText != null)
                            _leafsBalanceText.Text = result.Coins.ToString("N0");
                    });
                    ToastService.Show($"+{result.Awarded} \U0001F343 Leaf Points earned!", ToastType.Success);
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Playtime", $"Mid-game claim failed: {ex.Message}");
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _midGameClaimInFlight, 0);
            }
        }

        private void StartHeartbeatLoop()
        {
            if (_heartbeatTimer != null) return;
            _heartbeatTimer = new System.Timers.Timer(60_000) { AutoReset = true };
            _heartbeatTimer.Elapsed += async (_, __) =>
            {
                if (System.Threading.Interlocked.Exchange(ref _heartbeatInFlight, 1) == 1) return;
                try
                {
                    var jwt = _currentSettings?.LeafApiJwt;
                    if (string.IsNullOrEmpty(jwt)) return;
                    if (!_loggedIn) return;
                    await LeafClient.Services.LeafApiService.SendHeartbeatAsync(jwt);
                }
                catch { }
                finally
                {
                    System.Threading.Interlocked.Exchange(ref _heartbeatInFlight, 0);
                }
            };
            _heartbeatTimer.Start();
            _ = Task.Run(async () =>
            {
                try
                {
                    var jwt = _currentSettings?.LeafApiJwt;
                    if (!string.IsNullOrEmpty(jwt) && _loggedIn)
                        await LeafClient.Services.LeafApiService.SendHeartbeatAsync(jwt);
                }
                catch { }
            });
        }

        private void StopHeartbeatLoop()
        {
            try { _heartbeatTimer?.Stop(); _heartbeatTimer?.Dispose(); } catch { }
            _heartbeatTimer = null;
        }

        private void StartGameplayPlaytimePolling()
        {
            if (_gameplayPlaytimeTimer != null) return;
            _gameplayPlaytimeTimer = new System.Timers.Timer(5 * 60_000) { AutoReset = true };
            _gameplayPlaytimeTimer.Elapsed += async (_, __) =>
            {
                try { CheckpointLocalPlaytime(); } catch { }
                try { await ClaimMidGamePlaytimeAsync(); } catch { }
            };
            _gameplayPlaytimeTimer.Start();
        }

        private void CheckpointLocalPlaytime()
        {
            if (_currentSettings == null) return;
            if (_lastLocalPlaytimeCheckpointUtc == null) return;
            var nowUtc = DateTime.UtcNow;
            long delta = (long)(nowUtc - _lastLocalPlaytimeCheckpointUtc.Value).TotalSeconds;
            if (delta <= 0) return;
            if (delta > 86400) delta = 86400;
            _lastLocalPlaytimeCheckpointUtc = nowUtc;
            _currentSettings.TotalPlaytimeSeconds += delta;
            var mcVersion = _currentSettings.SelectedSubVersion;
            if (!string.IsNullOrEmpty(mcVersion))
            {
                _currentSettings.PlaytimeByVersion.TryGetValue(mcVersion, out long cur);
                _currentSettings.PlaytimeByVersion[mcVersion] = cur + delta;
            }
            var server = _currentSettings.QuickJoinServerAddress;
            if (!string.IsNullOrEmpty(server))
            {
                _currentSettings.PlaytimeByServer.TryGetValue(server, out long curS);
                _currentSettings.PlaytimeByServer[server] = curS + delta;
            }
            var activeProfile = GetActiveProfile();
            if (activeProfile != null) activeProfile.PlaytimeSeconds += delta;
            try { _ = _settingsService.SaveSettingsAsync(_currentSettings); } catch { }
        }

        private void StopGameplayPlaytimePolling()
        {
            try { _gameplayPlaytimeTimer?.Stop(); _gameplayPlaytimeTimer?.Dispose(); } catch { }
            _gameplayPlaytimeTimer = null;
        }

        private async Task CheckKillSwitchAsync()
        {
            try
            {
                var config = await LeafClient.Services.LeafApiService.GetConfigAsync();
                if (config == null) return;

                if (string.IsNullOrWhiteSpace(config.MinLauncherVersion)) return;

                var current = System.Reflection.Assembly.GetExecutingAssembly().GetName().Version;
                if (current == null) return;

                if (!System.Version.TryParse(config.MinLauncherVersion.Trim(), out var minVersion)) return;

                if (current >= minVersion) return;

                _launcherKilled = true;
                _killReason = string.IsNullOrWhiteSpace(config.KillMessage)
                    ? $"This version of LeafClient ({current}) is no longer supported. Please reinstall the latest launcher (>= {minVersion})."
                    : config.KillMessage;

                LeafClient.Services.LeafLog.Info("KillSwitch", $"Launcher version {current} < required {minVersion}. Disabling launch.");

                Dispatcher.UIThread.Post(() => ShowKillSwitchOverlay());
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("KillSwitch", $"Check failed (allowing launch): {ex.Message}");
            }
        }

        private void ShowKillSwitchOverlay()
        {
            try
            {
                if (this.FindControl<Button>("LaunchGameButton") is { } btn)
                {
                    btn.IsEnabled = false;
                    btn.Content = "REINSTALL REQUIRED";
                }

                var msg = _killReason ?? "This launcher version is no longer supported.";
                ShowLaunchErrorBanner(msg);

                _ = Task.Run(async () =>
                {
                    await Task.Delay(500);
                    Dispatcher.UIThread.Post(() =>
                    {
                        try
                        {
                            var box = new Window
                            {
                                Title = "Launcher Update Required",
                                Width = 520,
                                Height = 280,
                                CanResize = false,
                                WindowStartupLocation = WindowStartupLocation.CenterOwner,
                                SystemDecorations = SystemDecorations.Full,
                            };

                            var stack = new StackPanel
                            {
                                Margin = new Avalonia.Thickness(24),
                                Spacing = 14,
                            };

                            stack.Children.Add(new TextBlock
                            {
                                Text = "This LeafClient launcher is no longer supported.",
                                FontWeight = Avalonia.Media.FontWeight.Bold,
                                FontSize = 17,
                                TextWrapping = Avalonia.Media.TextWrapping.Wrap,
                            });
                            stack.Children.Add(new TextBlock
                            {
                                Text = msg,
                                TextWrapping = Avalonia.Media.TextWrapping.Wrap,
                                Opacity = 0.9,
                            });
                            stack.Children.Add(new TextBlock
                            {
                                Text = "Please download the new launcher and run a clean install. Auto-update can no longer reach this version.",
                                TextWrapping = Avalonia.Media.TextWrapping.Wrap,
                                Opacity = 0.75,
                                FontSize = 12,
                            });

                            var btnRow = new StackPanel
                            {
                                Orientation = Avalonia.Layout.Orientation.Horizontal,
                                Spacing = 12,
                                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Right,
                            };
                            var dl = new Button { Content = "Download Latest", Padding = new Avalonia.Thickness(16, 8) };
                            dl.Click += (_, __) =>
                            {
                                try
                                {
                                    System.Diagnostics.Process.Start(new System.Diagnostics.ProcessStartInfo
                                    {
                                        FileName = LauncherDownloadUrl,
                                        UseShellExecute = true,
                                    });
                                }
                                catch (Exception ex) { LeafClient.Services.LeafLog.Error("KillSwitch", $"Open URL failed: {ex.Message}"); }
                            };
                            var close = new Button { Content = "Close Launcher", Padding = new Avalonia.Thickness(16, 8) };
                            close.Click += (_, __) =>
                            {
                                if (Application.Current?.ApplicationLifetime is IClassicDesktopStyleApplicationLifetime desktop)
                                    desktop.Shutdown();
                            };
                            btnRow.Children.Add(dl);
                            btnRow.Children.Add(close);
                            stack.Children.Add(btnRow);

                            box.Content = stack;
                            box.ShowDialog(this);
                        }
                        catch (Exception ex) { LeafClient.Services.LeafLog.Error("KillSwitch", $"Dialog failed: {ex.Message}"); }
                    });
                });
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("KillSwitch", $"Overlay failed: {ex.Message}");
            }
        }

        private async Task<bool> EnsureFreshJwtForAccountAsync(AccountEntry account)
        {
            if (_currentSettings == null || account == null) return false;

            if (!string.IsNullOrEmpty(account.LeafApiJwt))
            {
                var probe = await LeafApiService.ProbeJwtAsync(account.LeafApiJwt);
                if (probe == LeafApiService.JwtProbeResult.Valid) return true;
                if (probe == LeafApiService.JwtProbeResult.NetworkError) return true;
            }

            if (!string.IsNullOrWhiteSpace(account.LeafApiRefreshToken))
            {
                try
                {
                    var refreshed = await LeafApiService.RefreshAsync(account.LeafApiRefreshToken);
                    if (refreshed != null)
                    {
                        account.LeafApiJwt = refreshed.AccessToken;
                        account.LeafApiRefreshToken = refreshed.RefreshToken;
                        _currentSettings.LeafApiJwt = refreshed.AccessToken;
                        _currentSettings.LeafApiRefreshToken = refreshed.RefreshToken;
                        await _settingsService.SaveSettingsAsync(_currentSettings);
                        _onlineCountService?.UpdateAccessToken(refreshed.AccessToken);
                        WriteSessionJson(refreshed.AccessToken);
                        LeafClient.Services.LeafLog.Info("Accounts", $"Refreshed JWT via refresh-token for {account.Username}");
                        return true;
                    }
                }
                catch (Exception ex) { LeafClient.Services.LeafLog.Error("Accounts", $"Refresh-token failed for {account.Username}: {ex.Message}"); }
            }

            if (account.AccountType == "microsoft" &&
                !string.IsNullOrWhiteSpace(account.Uuid) && !string.IsNullOrWhiteSpace(account.AccessToken))
            {
                try
                {
                    var apiResult = await LeafApiService.MicrosoftLoginAsync(account.Uuid!, account.AccessToken!);
                    if (apiResult != null)
                    {
                        account.LeafApiJwt = apiResult.AccessToken;
                        account.LeafApiRefreshToken = apiResult.RefreshToken;
                        _currentSettings.LeafApiJwt = apiResult.AccessToken;
                        _currentSettings.LeafApiRefreshToken = apiResult.RefreshToken;
                        await _settingsService.SaveSettingsAsync(_currentSettings);
                        _onlineCountService?.UpdateAccessToken(apiResult.AccessToken);
                        WriteSessionJson(apiResult.AccessToken);
                        LeafClient.Services.LeafLog.Info("Accounts", $"Silent MS re-link for {account.Username}");
                        return true;
                    }
                }
                catch (Exception ex) { LeafClient.Services.LeafLog.Error("Accounts", $"MS re-link failed for {account.Username}: {ex.Message}"); }

                if (!string.IsNullOrWhiteSpace(_currentSettings.MicrosoftRefreshToken))
                {
                    try
                    {
                        var refreshedSession = await TryDirectTokenRefreshAsync(_currentSettings.MicrosoftRefreshToken);
                        if (refreshedSession != null && !string.IsNullOrWhiteSpace(refreshedSession.UUID) && !string.IsNullOrWhiteSpace(refreshedSession.AccessToken))
                        {
                            account.Uuid = refreshedSession.UUID;
                            account.AccessToken = refreshedSession.AccessToken;
                            account.Xuid = refreshedSession.Xuid;
                            _currentSettings.SessionUuid = refreshedSession.UUID;
                            _currentSettings.SessionAccessToken = refreshedSession.AccessToken;
                            _currentSettings.SessionXuid = refreshedSession.Xuid;
                            var apiResult2 = await LeafApiService.MicrosoftLoginAsync(refreshedSession.UUID, refreshedSession.AccessToken);
                            if (apiResult2 != null)
                            {
                                account.LeafApiJwt = apiResult2.AccessToken;
                                account.LeafApiRefreshToken = apiResult2.RefreshToken;
                                _currentSettings.LeafApiJwt = apiResult2.AccessToken;
                                _currentSettings.LeafApiRefreshToken = apiResult2.RefreshToken;
                                await _settingsService.SaveSettingsAsync(_currentSettings);
                                _onlineCountService?.UpdateAccessToken(apiResult2.AccessToken);
                                WriteSessionJson(apiResult2.AccessToken);
                                LeafClient.Services.LeafLog.Info("Accounts", $"Full MS refresh + re-link for {account.Username}");
                                return true;
                            }
                        }
                    }
                    catch (Exception ex) { LeafClient.Services.LeafLog.Error("Accounts", $"Full MS refresh failed for {account.Username}: {ex.Message}"); }
                }
            }

            return false;
        }

        private async Task UpdateLeafsBalanceAsync()
        {
            var jwt = _currentSettings?.LeafApiJwt;
            if (string.IsNullOrEmpty(jwt)) return;

            Dispatcher.UIThread.Post(() =>
            {
                _leafsBalanceText ??= this.FindControl<TextBlock>("LeafsBalanceText");
                _leafsCurrencyWidget ??= this.FindControl<Border>("LeafsCurrencyWidget");
                _leafsCurrencyShouldBeVisible = true;
                if (_leafsCurrencyWidget != null)
                    _leafsCurrencyWidget.IsVisible = true;
                ApplyResponsiveHeader();
            });

            var balance = await LeafClient.Services.LeafApiService.GetUserBalanceAsync(jwt);
            if (balance == null) return;

            _currentCoinBalance = balance.Coins;
            _isLeafPlus = balance.IsLeafPlus;
            _leafPlusTier = balance.LeafPlusTier;
            _leafPlusPeriodEnd = balance.LeafPlusPeriodEnd;
            _hadLeafPlusRevoked = balance.HadLeafPlusRevoked;
            _leafPlusRevokeSeenAt = balance.LeafPlusRevokeSeenAt;
            _hadLeafPlusTrial = balance.HadLeafPlusTrial;
            _isTrial = balance.IsTrial;

            Dispatcher.UIThread.Post(() =>
            {
                _leafsBalanceText ??= this.FindControl<TextBlock>("LeafsBalanceText");
                if (_leafsBalanceText != null)
                    _leafsBalanceText.Text = balance.Coins.ToString("N0");
                var apb = this.FindControl<TextBlock>("AccountPanelLeafsBalanceText");
                if (apb != null) apb.Text = balance.Coins.ToString("N0");
                ApplyLeafPlusUiState();
            });
        }

        private void ApplyLeafPlusUiState()
        {
            try
            {
                var pill = this.FindControl<Border>("LeafPlusActivePill");
                _leafPlusPillShouldBeVisible = _isLeafPlus;
                if (pill != null)
                    pill.IsVisible = _isLeafPlus;
                ApplyResponsiveHeader();

                var pillText = this.FindControl<TextBlock>("LeafPlusActivePillText");
                if (pillText != null && _isLeafPlus)
                {
                    pillText.Text = _isTrial ? "TRIAL" : "LEAF+";
                }

                var cardTitle    = this.FindControl<TextBlock>("LeafPlusCardTitle");
                var cardSubtitle = this.FindControl<TextBlock>("LeafPlusCardSubtitle");
                var cardActionTx = this.FindControl<TextBlock>("LeafPlusCardActionText");

                if (_isLeafPlus)
                {
                    string tier = _leafPlusTier switch
                    {
                        "yearly"    => "Yearly",
                        "quarterly" => "Quarterly",
                        "trial"     => "Trial",
                        _           => "Monthly",
                    };
                    string expiry = "active";
                    if (!string.IsNullOrEmpty(_leafPlusPeriodEnd))
                    {
                        if (DateTimeOffset.TryParse(_leafPlusPeriodEnd, out var dt))
                        {
                            string verb = _isTrial ? "ends" : "renews";
                            expiry = $"{verb} {dt.ToLocalTime():MMM d, yyyy}";
                        }
                    }
                    if (cardTitle    != null) cardTitle.Text    = $"Leaf+ {tier}";
                    if (cardSubtitle != null)
                    {
                        cardSubtitle.Text = _isTrial
                            ? $"7-day trial · {expiry}"
                            : $"Subscription {expiry}";
                    }
                    if (cardActionTx != null) cardActionTx.Text = _isTrial ? "DETAILS" : "MANAGE";
                }
                else
                {
                    if (cardTitle    != null) cardTitle.Text    = "Leaf+";
                    if (cardSubtitle != null) cardSubtitle.Text = "Unlock cloud sync, custom name tag, and exclusive perks.";
                    if (cardActionTx != null) cardActionTx.Text = "GET LEAF+";
                }

                if (!_isLeafPlus)
                {
                    var earlyRadio = this.FindControl<RadioButton>("UpdateDeliveryEarlyRadio");
                    if (earlyRadio?.IsChecked == true)
                    {
                        _suppressEarlyOptInGate = true;
                        try
                        {
                            earlyRadio.IsChecked = false;
                            var normalRadio = this.FindControl<RadioButton>("UpdateDeliveryNormalRadio");
                            if (normalRadio != null) normalRadio.IsChecked = true;
                        }
                        finally { _suppressEarlyOptInGate = false; }
                        if (_currentSettings != null)
                        {
                            _currentSettings.GameUpdateDelivery = UpdateDelivery.Normal;
                            MarkSettingsDirty();
                        }
                    }
                }

                MaybeShowRevokedPopup();

                var slotC = this.FindControl<Border>("PartnerBannerSlotC");
                if (slotC != null)
                    slotC.IsVisible = !_isLeafPlus;

                _gameOutputWindow?.SetIsLeafPlus(_isLeafPlus);

                if (_isLeafPlus && !_cloudSyncPullDone)
                    _ = TryCloudSyncPullAsync();

                if (_isLeafPlus && !_cosmeticDropChecked)
                    _ = TryCheckAndClaimCosmeticDropAsync();

                if (!_trialOverlayCheckScheduled)
                {
                    _trialOverlayCheckScheduled = true;
                    _ = MaybeShowTrialOverlayAsync();
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Info("ApplyLeafPlusUiState", $"{ex.Message}");
            }
        }

        private void OnLeafPlusCardActionClick(object? sender, RoutedEventArgs e)
        {
            try
            {
                CloseAccountPanel();
                if (_isLeafPlus && _isTrial)
                {
                    ShowTrialStatusOverlay();
                }
                else if (_isLeafPlus)
                {
                    _ = OpenSubscriptionManagementAsync();
                }
                else
                {
                    ShowLeafPlusBenefitsPopup();
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Info("OnLeafPlusCardActionClick", $"{ex.Message}");
            }
        }

        private async Task OpenSubscriptionManagementAsync()
        {
            try
            {
                var jwt = _currentSettings?.LeafApiJwt;
                (string? Url, bool Manual) portal = (null, false);
                if (!string.IsNullOrEmpty(jwt))
                {
                    portal = await LeafClient.Services.LeafApiService.GetSubscriptionPortalAsync(jwt);
                }

                if (portal.Manual)
                {
                    await ShowManualGrantInfoAsync();
                    return;
                }

                string url = !string.IsNullOrWhiteSpace(portal.Url)
                    ? portal.Url!
                    : "https://leafclient.lemonsqueezy.com/billing";

                LeafClient.Services.LeafLog.Info("Leaf+", $"Opening subscription management: {url}");
                System.Diagnostics.Process.Start(new System.Diagnostics.ProcessStartInfo
                {
                    FileName        = url,
                    UseShellExecute = true,
                });
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Info("OpenSubscriptionManagementAsync", $"{ex.Message}");
            }
        }

        private async Task ShowManualGrantInfoAsync()
        {
            var overlay = this.FindControl<Grid>("ManualGrantInfoOverlay");
            var panel   = this.FindControl<Border>("ManualGrantInfoPanel");
            if (overlay == null || panel == null) return;
            overlay.Opacity = 0;
            overlay.IsVisible = true;
            if (panel.RenderTransform is ScaleTransform st0)
            {
                st0.ScaleX = 0.92; st0.ScaleY = 0.92;
            }
            int steps = 10;
            for (int i = 1; i <= steps; i++)
            {
                float t = i / (float)steps;
                float ease = 1f - (float)Math.Pow(1f - t, 3);
                overlay.Opacity = ease;
                if (panel.RenderTransform is ScaleTransform s)
                {
                    s.ScaleX = 0.92 + 0.08 * ease;
                    s.ScaleY = 0.92 + 0.08 * ease;
                }
                await Task.Delay(18);
            }
            overlay.Opacity = 1;
            if (panel.RenderTransform is ScaleTransform fs) { fs.ScaleX = 1; fs.ScaleY = 1; }
        }

        private void OnManualGrantInfoDismiss(object? sender, RoutedEventArgs e)
        {
            HideManualGrantInfo();
        }

        private void OnManualGrantInfoBackdropTapped(object? sender, TappedEventArgs e)
        {
            if (e.Source == sender)
                HideManualGrantInfo();
        }

        private void HideManualGrantInfo()
        {
            var overlay = this.FindControl<Grid>("ManualGrantInfoOverlay");
            if (overlay != null) overlay.IsVisible = false;
        }

        private void MaybeShowRevokedPopup()
        {
            if (!_hadLeafPlusRevoked) return;
            if (!string.IsNullOrEmpty(_leafPlusRevokeSeenAt)) return;
            if (_revokedPopupShownThisSession) return;
            _revokedPopupShownThisSession = true;
            ShowLeafPlusRevokedPopup();
        }

        private bool _revokedPopupShownThisSession;

        private async void ShowLeafPlusRevokedPopup()
        {
            try
            {
                var overlay = this.FindControl<Grid>("LeafPlusRevokedOverlay");
                var panel   = this.FindControl<Border>("LeafPlusRevokedPanel");
                if (overlay == null || panel == null) return;
                overlay.Opacity = 0;
                overlay.IsVisible = true;
                if (panel.RenderTransform is ScaleTransform st)
                {
                    st.ScaleX = 0.92; st.ScaleY = 0.92;
                }
                int steps = 10;
                for (int i = 1; i <= steps; i++)
                {
                    float t = i / (float)steps;
                    float ease = 1f - (float)Math.Pow(1f - t, 3);
                    overlay.Opacity = ease;
                    if (panel.RenderTransform is ScaleTransform s)
                    {
                        s.ScaleX = 0.92 + 0.08 * ease;
                        s.ScaleY = 0.92 + 0.08 * ease;
                    }
                    await Task.Delay(18);
                }
                overlay.Opacity = 1;
                if (panel.RenderTransform is ScaleTransform fs) { fs.ScaleX = 1; fs.ScaleY = 1; }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Info("ShowLeafPlusRevokedPopup", $"{ex.Message}");
            }
        }

        private async Task CloseLeafPlusRevokedPopupAsync()
        {
            try
            {
                var overlay = this.FindControl<Grid>("LeafPlusRevokedOverlay");
                var panel   = this.FindControl<Border>("LeafPlusRevokedPanel");
                if (overlay == null || panel == null) return;
                int steps = 8;
                for (int i = steps - 1; i >= 0; i--)
                {
                    float t = i / (float)(steps - 1);
                    overlay.Opacity = t;
                    if (panel.RenderTransform is ScaleTransform s)
                    {
                        s.ScaleX = 0.92 + 0.08 * t;
                        s.ScaleY = 0.92 + 0.08 * t;
                    }
                    await Task.Delay(14);
                }
                overlay.IsVisible = false;
            }
            catch { }
        }

