        private LeafClient.Services.ModMigrationService.MigrationResult? _lastMigrationResultCache;

        private void RefreshLastMigrationPanel()
        {
            try
            {
                var panel = this.FindControl<Border>("LastMigrationPanel");
                if (panel == null) return;
                var r = LeafClient.Services.ModMigrationService.ReadLastResult();
                _lastMigrationResultCache = r;
                if (r == null) { panel.IsVisible = false; return; }

                panel.IsVisible = true;
                var header = this.FindControl<TextBlock>("LastMigrationHeader");
                var stats = this.FindControl<TextBlock>("LastMigrationStats");
                var backup = this.FindControl<TextBlock>("LastMigrationBackup");
                var failedBlock = this.FindControl<StackPanel>("LastMigrationFailedBlock");
                var failedList = this.FindControl<ItemsControl>("LastMigrationFailedList");
                var openBtn = this.FindControl<Button>("LastMigrationOpenBackupBtn");

                string when = r.CompletedAtUtc.ToLocalTime().ToString("yyyy-MM-dd HH:mm");
                if (header != null) header.Text = $"{when}  ·  MC {r.FromMcVersion} → {r.ToMcVersion}";
                if (stats != null) stats.Text = $"Updated {r.Updated}  ·  Disabled {r.Disabled}  ·  Failed {r.Failed}";
                if (backup != null) backup.Text = string.IsNullOrEmpty(r.BackupFolder) ? "(no backup folder)" : r.BackupFolder;
                if (openBtn != null) openBtn.IsEnabled = !string.IsNullOrWhiteSpace(r.BackupFolder) && Directory.Exists(r.BackupFolder);

                if (r.FailureMessages.Count > 0)
                {
                    if (failedBlock != null) failedBlock.IsVisible = true;
                    if (failedList != null)
                    {
                        failedList.ItemsSource = r.FailureMessages.Select(s => new TextBlock
                        {
                            Text = "• " + s,
                            Foreground = SolidColorBrush.Parse("#FCA5A5"),
                            FontSize = 11,
                            TextWrapping = TextWrapping.Wrap,
                            Margin = new Thickness(0, 0, 0, 2),
                        }).ToList();
                    }
                }
                else
                {
                    if (failedBlock != null) failedBlock.IsVisible = false;
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("LastMigrationPanel", $"refresh failed: {ex.Message}");
            }
        }

        private void OnLastMigrationOpenBackup(object? sender, RoutedEventArgs e)
        {
            try
            {
                var r = _lastMigrationResultCache ?? LeafClient.Services.ModMigrationService.ReadLastResult();
                if (r == null || string.IsNullOrWhiteSpace(r.BackupFolder) || !Directory.Exists(r.BackupFolder))
                {
                    ToastService.Show("No backup folder available.", ToastType.Info);
                    return;
                }
                LeafClient.Utils.SystemUtil.OpenFolder(r.BackupFolder);
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("LastMigrationPanel", $"open backup failed: {ex.Message}"); }
        }

        private async void OnLastMigrationCopyLog(object? sender, RoutedEventArgs e)
        {
            try
            {
                var r = _lastMigrationResultCache ?? LeafClient.Services.ModMigrationService.ReadLastResult();
                if (r == null) return;
                var sb = new System.Text.StringBuilder();
                sb.AppendLine($"LeafClient mod migration {r.FromMcVersion} -> {r.ToMcVersion}");
                sb.AppendLine($"Completed: {r.CompletedAtUtc:u}");
                sb.AppendLine($"Updated: {r.Updated}  Disabled: {r.Disabled}  Failed: {r.Failed}");
                sb.AppendLine($"Backup folder: {r.BackupFolder}");
                if (r.UpdatedItems.Count > 0) { sb.AppendLine(""); sb.AppendLine("Updated:"); foreach (var s in r.UpdatedItems) sb.AppendLine($"  - {s}"); }
                if (r.DisabledItems.Count > 0) { sb.AppendLine(""); sb.AppendLine("Disabled:"); foreach (var s in r.DisabledItems) sb.AppendLine($"  - {s}"); }
                if (r.FailureMessages.Count > 0) { sb.AppendLine(""); sb.AppendLine("Failed:"); foreach (var s in r.FailureMessages) sb.AppendLine($"  - {s}"); }
                var clip = this.Clipboard;
                if (clip != null)
                {
                    await clip.SetTextAsync(sb.ToString());
                    ToastService.Show("Migration log copied to clipboard.", ToastType.Success);
                }
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("LastMigrationPanel", $"copy log failed: {ex.Message}"); }
        }

