                            Foreground = GetBrush("ErrorBrush"),
                            FontWeight = FontWeight.Bold,
                            FontSize = 16,
                            TextWrapping = TextWrapping.Wrap
                        },
                        new TextBlock
                        {
                            Text = message,
                            Foreground = GetBrush("PrimaryForegroundBrush"),
                            FontSize = 13,
                            TextWrapping = TextWrapping.Wrap
                        },
                        new Button
                        {
                            Content = "OK",
                            HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Right,
                            Padding = new Thickness(15, 8),
                            Background = GetBrush("PrimaryAccentBrush"),
                            Foreground = GetBrush("AccentButtonForegroundBrush"),
                            CornerRadius = new CornerRadius(8)
                        }
                    }
                }
            };
            if ((dialog.Content as StackPanel)?.Children.OfType<Button>().Last() is Button okButton)
            {
                okButton.Click += (s, e) => dialog.Close();
            }
            await dialog.ShowDialog(this);
        }

        private static readonly System.Collections.Generic.HashSet<string> _launcherManagedModIds =
            new(StringComparer.OrdinalIgnoreCase)
            {
                "sodium", "vulkanmod", "lithium", "ferritecore", "immediatelyfast",
                "entityculling", "fabric-api",
                "iris", "dynamiclights", "betterfps",
                "ebe", "moreculling", "krypton", "sodiumextra",
                "betterbeds", "reeses-sodium-options",
                "starlight", "indium", "viafabricplus",
                "nofade", "nodoublesneak", "serverpingfixer", "chestsearchbar",
                "forcecloseloadingscreen", "modernfix", "dynamicfps", "cullleaves",
                "ksyxis", "debugify", "vmp",
            };

        private void LoadUserMods()
        {
            if (_userModsPanel == null || _noUserModsMessage == null) return;

            LeafClient.Services.LeafLog.Info("User Mods", $"Loading {_currentSettings.InstalledMods.Count} mods from settings");

            _userModsPanel.Children.Clear();

            string currentMcVersion = ResolveCurrentMcVersion();
            if (string.IsNullOrEmpty(currentMcVersion))
                currentMcVersion = _currentSettings.SelectedSubVersion ?? "";

            foreach (var m in _currentSettings.InstalledMods)
            {
                if (!m.IsAutoInstalled && _launcherManagedModIds.Contains(m.ModId))
                    m.IsAutoInstalled = true;
            }

            var modsForCurrentVersion = _currentSettings.InstalledMods
                .Where(m => m.MinecraftVersion.Equals(currentMcVersion, StringComparison.OrdinalIgnoreCase))
                .Where(m => !m.IsAutoInstalled)
                .OrderBy(m => m.Name)
                .ToList();

            var modsForOtherVersions = _currentSettings.InstalledMods
                .Where(m => !m.IsAutoInstalled)
                .Where(m => !m.MinecraftVersion.Equals(currentMcVersion, StringComparison.OrdinalIgnoreCase))
                .Where(m => !m.ModId.Equals("leafclient", StringComparison.OrdinalIgnoreCase))
                .OrderBy(m => m.MinecraftVersion)
                .ThenBy(m => m.Name)
                .ToList();

            var importedMods = ScanModsFolderForImported(modsForCurrentVersion);

            if (modsForOtherVersions.Count > 0)
            {
                var banner = BuildOtherVersionsBanner(currentMcVersion, modsForOtherVersions);
                if (banner != null) _userModsPanel.Children.Add(banner);
            }

            if (!modsForCurrentVersion.Any() && importedMods.Count == 0)
            {
                LeafLog.Info("User Mods", $"No user-installed mods for {currentMcVersion}. ({modsForOtherVersions.Count} on other versions)");
                _noUserModsMessage.IsVisible = modsForOtherVersions.Count == 0;
                return;
            }

            if (_noSkinsMessage != null) _noSkinsMessage.IsVisible = false;
            _noUserModsMessage.IsVisible = false;

            foreach (var mod in modsForCurrentVersion)
            {
                if (mod.ModId.Equals("leafclient", StringComparison.OrdinalIgnoreCase))
                {
                    LeafClient.Services.LeafLog.Info("User Mods", $"Skipping display of internal mod: {mod.Name}");
                    continue;
                }

                LeafClient.Services.LeafLog.Info("User Mods", $"Creating card for: {mod.Name} (MC {mod.MinecraftVersion}, Enabled: {mod.Enabled})");
                var modCard = CreateUserModCard(mod);
                _userModsPanel.Children.Add(modCard);
            }

            foreach (var imp in importedMods)
            {
                LeafClient.Services.LeafLog.Info("User Mods", $"Imported (filesystem): {imp.Name}");
                var modCard = CreateUserModCard(imp);
                _userModsPanel.Children.Add(modCard);
            }

            LeafClient.Services.LeafLog.Info("User Mods", $"Loaded {_userModsPanel.Children.Count} user-mod cards for MC {currentMcVersion} (incl. {importedMods.Count} imported)");
        }

        private List<InstalledMod> ScanModsFolderForImported(List<InstalledMod> tracked)
        {
            var result = new List<InstalledMod>();
            try
            {
                string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                if (!Directory.Exists(modsFolder)) return result;

                var trackedFileNames = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                foreach (var t in _currentSettings.InstalledMods)
                {
                    if (!string.IsNullOrEmpty(t.FileName)) trackedFileNames.Add(t.FileName);
                }

                var preserved = GetModpackPreservedModFiles();
                var managed = _launcherManagedModIds;

                var entries = Directory.EnumerateFiles(modsFolder, "*.*", SearchOption.TopDirectoryOnly)
                    .Where(p =>
                    {
                        var ext = System.IO.Path.GetExtension(p);
                        return ext.Equals(".jar", StringComparison.OrdinalIgnoreCase)
                            || p.EndsWith(".jar.disabled", StringComparison.OrdinalIgnoreCase);
                    })
                    .OrderBy(p => System.IO.Path.GetFileName(p), StringComparer.OrdinalIgnoreCase);

                foreach (var path in entries)
                {
                    var fileName = System.IO.Path.GetFileName(path);
                    if (trackedFileNames.Contains(fileName)) continue;
                    if (preserved.Contains(fileName)) continue;

                    var stem = System.IO.Path.GetFileNameWithoutExtension(fileName).ToLowerInvariant();
                    if (stem.EndsWith(".jar")) stem = stem.Substring(0, stem.Length - 4);
                    string? matchedManagedId = managed.FirstOrDefault(id =>
                        stem.Contains(id, StringComparison.OrdinalIgnoreCase));
                    if (matchedManagedId != null)
                    {
                        var profileForCheck = GetActiveProfile();
                        bool isUserOverride = profileForCheck?.DisabledRequiredMods?
                            .GetValueOrDefault(matchedManagedId, false) == true;
                        if (!isUserOverride) continue;
                    }

                    bool enabled = !path.EndsWith(".disabled", StringComparison.OrdinalIgnoreCase);

                    result.Add(new InstalledMod
                    {
                        ModId = "imported:" + fileName,
                        Name = System.IO.Path.GetFileNameWithoutExtension(
                            enabled ? fileName : fileName.Substring(0, fileName.Length - ".disabled".Length)),
                        Description = "Imported from mods folder.",
                        Version = "-",
                        MinecraftVersion = _currentSettings.SelectedSubVersion ?? "",
                        FileName = fileName,
                        DownloadUrl = "",
                        IconUrl = "",
                        Enabled = enabled,
                        InstallDate = File.GetLastWriteTime(path),
                        IsAutoInstalled = false,
                    });
                }
            }
            catch (Exception ex) { LeafLog.Error("User Mods", $"filesystem scan failed: {ex.Message}"); }
            return result;
        }

        private Border? BuildOtherVersionsBanner(string currentMcVersion, List<InstalledMod> otherVersionMods)
        {
            if (otherVersionMods.Count == 0) return null;

            var byVersion = otherVersionMods
                .GroupBy(m => m.MinecraftVersion, StringComparer.OrdinalIgnoreCase)
                .OrderByDescending(g => g.Count())
                .ToList();
            string topVersion = byVersion[0].Key;
            int total = otherVersionMods.Count;

            string headline = byVersion.Count == 1
                ? $"You have {total} mod{(total == 1 ? "" : "s")} installed for Minecraft {topVersion}."
                : $"You have {total} mods across {byVersion.Count} other Minecraft versions ({topVersion} has {byVersion[0].Count()}).";

            var banner = new Border
            {
                Background      = SolidColorBrush.Parse("#0F1B27"),
                BorderBrush     = SolidColorBrush.Parse("#1F3A2A"),
                BorderThickness = new Thickness(1),
                CornerRadius    = new CornerRadius(12),
                Padding         = new Thickness(16, 12),
                Margin          = new Thickness(0, 0, 0, 12),
            };

            var rootStack = new StackPanel { Spacing = 10 };

            var topRow = new Grid { ColumnDefinitions = new ColumnDefinitions("Auto,*,Auto,Auto") };

            var iconBorder = new Border
            {
                Width             = 32,
                Height            = 32,
                CornerRadius      = new CornerRadius(8),
                Background        = SolidColorBrush.Parse("#1B4CAF50"),
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                Margin            = new Thickness(0, 0, 12, 0),
                Child = new Avalonia.Controls.Shapes.Path
                {
                    Data            = Geometry.Parse("M3,7 L21,7 M3,12 L21,12 M3,17 L21,17 M12,3 L12,21"),
                    Stroke          = SolidColorBrush.Parse("#4ADE80"),
                    StrokeThickness = 1.8,
                    StrokeLineCap   = PenLineCap.Round,
                    Width           = 16,
                    Height          = 16,
                    Stretch         = Stretch.Uniform,
                    HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                    VerticalAlignment   = Avalonia.Layout.VerticalAlignment.Center,
                },
            };
            Grid.SetColumn(iconBorder, 0);

            var textStack = new StackPanel
            {
                Spacing           = 2,
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
            };
            textStack.Children.Add(new TextBlock
            {
                Text       = headline,
                Foreground = SolidColorBrush.Parse("#E5E7EB"),
                FontWeight = FontWeight.SemiBold,
                FontSize   = 13,
                TextWrapping = TextWrapping.Wrap,
            });
            textStack.Children.Add(new TextBlock
            {
                Text       = $"You're currently on {currentMcVersion}. Migrate updates each mod via Modrinth; jars get backed up first.",
                Foreground = SolidColorBrush.Parse("#94A3B8"),
                FontSize   = 11,
                TextWrapping = TextWrapping.Wrap,
            });
            Grid.SetColumn(textStack, 1);

            var migrateBtn = new Button
            {
                Content = $"Migrate to {currentMcVersion}",
                Background = SolidColorBrush.Parse("#1B4CAF50"),
                BorderBrush = SolidColorBrush.Parse("#354CAF50"),
                BorderThickness = new Thickness(1),
                Foreground = SolidColorBrush.Parse("#E8FFE8"),
                FontWeight = FontWeight.SemiBold,
                FontSize = 12,
                Padding = new Thickness(14, 8),
                CornerRadius = new CornerRadius(8),
                Cursor = new Cursor(StandardCursorType.Hand),
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                Margin = new Thickness(0, 0, 8, 0),
            };
            migrateBtn.Click += async (_, _) => await TriggerManualMigrationAsync(topVersion, currentMcVersion);
            Grid.SetColumn(migrateBtn, 2);

            var detailsPanel = new StackPanel
            {
                Spacing = 6,
                IsVisible = false,
            };

            var showBtn = new Button
            {
                Content = "Show them here",
                Background = SolidColorBrush.Parse("#10FFFFFF"),
                BorderBrush = SolidColorBrush.Parse("#1EFFFFFF"),
                BorderThickness = new Thickness(1),
                Foreground = SolidColorBrush.Parse("#E2E8F0"),
                FontWeight = FontWeight.SemiBold,
                FontSize = 12,
                Padding = new Thickness(14, 8),
                CornerRadius = new CornerRadius(8),
                Cursor = new Cursor(StandardCursorType.Hand),
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
            };
            showBtn.Click += (_, _) =>
            {
                detailsPanel.IsVisible = !detailsPanel.IsVisible;
                showBtn.Content = detailsPanel.IsVisible ? "Hide list" : "Show them here";
                if (detailsPanel.IsVisible && detailsPanel.Children.Count == 0)
                {
                    foreach (var g in byVersion)
                    {
                        var header = new TextBlock
                        {
                            Text = $"Minecraft {g.Key}  ·  {g.Count()} mod{(g.Count() == 1 ? "" : "s")}",
                            Foreground = SolidColorBrush.Parse("#94A3B8"),
                            FontWeight = FontWeight.SemiBold,
                            FontSize = 11,
                            Margin = new Thickness(2, 8, 0, 2),
                        };
                        detailsPanel.Children.Add(header);
                        foreach (var m in g)
                        {
                            detailsPanel.Children.Add(BuildOtherVersionRow(m, currentMcVersion));
                        }
                    }
                }
            };
            Grid.SetColumn(showBtn, 3);

            topRow.Children.Add(iconBorder);
            topRow.Children.Add(textStack);
            topRow.Children.Add(migrateBtn);
            topRow.Children.Add(showBtn);

            rootStack.Children.Add(topRow);
            rootStack.Children.Add(detailsPanel);
            banner.Child = rootStack;
            return banner;
        }

        private Border BuildOtherVersionRow(InstalledMod mod, string currentMcVersion)
        {
            var row = new Border
            {
                Background = SolidColorBrush.Parse("#0B1018"),
                BorderBrush = SolidColorBrush.Parse("#1C2A38"),
                BorderThickness = new Thickness(1),
                CornerRadius = new CornerRadius(8),
                Padding = new Thickness(10, 8),
            };
            var grid = new Grid { ColumnDefinitions = new ColumnDefinitions("*,Auto,Auto") };

            var info = new StackPanel { Spacing = 2, VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center };
            info.Children.Add(new TextBlock
            {
                Text = string.IsNullOrWhiteSpace(mod.Name) ? mod.FileName : mod.Name,
                Foreground = SolidColorBrush.Parse("#E5E7EB"),
                FontWeight = FontWeight.SemiBold,
                FontSize = 12,
                TextTrimming = TextTrimming.CharacterEllipsis,
            });
            info.Children.Add(new TextBlock
            {
                Text = $"v{mod.Version}  ·  MC {mod.MinecraftVersion}  ·  {mod.FileName}",
                Foreground = SolidColorBrush.Parse("#6B7280"),
                FontSize = 10,
                TextTrimming = TextTrimming.CharacterEllipsis,
            });
            Grid.SetColumn(info, 0);
            grid.Children.Add(info);

            var versionBadge = new Border
            {
                Background = SolidColorBrush.Parse("#1A2535"),
                BorderBrush = SolidColorBrush.Parse("#2D3F58"),
                BorderThickness = new Thickness(1),
                CornerRadius = new CornerRadius(6),
                Padding = new Thickness(8, 3),
                Margin = new Thickness(8, 0, 8, 0),
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                Child = new TextBlock
                {
                    Text = mod.MinecraftVersion,
                    Foreground = SolidColorBrush.Parse("#94A3B8"),
                    FontSize = 10,
                    FontWeight = FontWeight.SemiBold,
                },
            };
            Grid.SetColumn(versionBadge, 1);
            grid.Children.Add(versionBadge);

            row.Child = grid;
            return row;
        }

        private async Task TriggerManualMigrationAsync(string fromVersion, string toVersion)
        {
            try
            {
                var service = new ModMigrationService(_modrinthClient, _minecraftFolder, _currentSettings, _settingsService);
                _gameOutputWindow?.AppendLog($"[ModMigration] Manual migration {fromVersion} -> {toVersion}", "INFO");
                ToastService.Show($"Checking Modrinth for {fromVersion} → {toVersion} migrations...", ToastType.Info);
                var plan = await service.BuildPlanAsync(fromVersion, toVersion, "fabric");
                if (!plan.NeedsAttention)
                {
                    ToastService.Show("No migrations needed for the mods you have.", ToastType.Success);
                    return;
                }
                var dialog = new LeafClient.Views.ModMigrationWindow(service, plan, launchMode: false);
                await dialog.ShowDialog(this);
                if (dialog.AppliedResult != null)
                {
                    _gameOutputWindow?.AppendLog(
                        $"[ModMigration] Manual result: Updated={dialog.AppliedResult.Updated} Disabled={dialog.AppliedResult.Disabled} Failed={dialog.AppliedResult.Failed}",
                        dialog.AppliedResult.Failed > 0 ? "WARN" : "INFO");
                    try { RefreshLastMigrationPanel(); } catch { }
                }
                LoadUserMods();
            }
            catch (Exception ex)
            {
                LeafLog.Error("ModMigration", $"Manual migration failed: {ex.Message}");
                ToastService.Show("Migration check failed. See log.", ToastType.Error);
            }
        }

        private Border CreateUserModCard(InstalledMod mod)
        {
            var card = new Border
            {
                Background      = SolidColorBrush.Parse("#0F1A24"),
                BorderBrush     = SolidColorBrush.Parse("#1C2A38"),
                BorderThickness = new Thickness(1),
                CornerRadius    = new CornerRadius(12),
                Padding         = new Thickness(14, 12),
                Margin          = new Thickness(0, 0, 0, 8),
            };

            var grid = new Grid { ColumnDefinitions = new ColumnDefinitions("Auto,*,Auto") };

            var iconBorder = new Border
            {
                Width             = 38,
                Height            = 38,
                Margin            = new Thickness(0, 0, 14, 0),
                CornerRadius      = new CornerRadius(10),
                ClipToBounds      = true,
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                Background        = new LinearGradientBrush
                {
                    StartPoint = new RelativePoint(0, 0, RelativeUnit.Relative),
                    EndPoint   = new RelativePoint(1, 1, RelativeUnit.Relative),
                    GradientStops =
                    {
                        new GradientStop(Color.Parse("#1A2535"), 0),
                        new GradientStop(Color.Parse("#0D1620"), 1),
                    },
                },
                BorderBrush     = SolidColorBrush.Parse("#243244"),
                BorderThickness = new Thickness(1),
            };

            var modIcon = new Image
            {
                Width               = 28,
                Height              = 28,
                Stretch             = Stretch.Uniform,
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                VerticalAlignment   = Avalonia.Layout.VerticalAlignment.Center,
            };

            if (!string.IsNullOrEmpty(mod.IconUrl))
            {
                _ = LoadModIcon(modIcon, mod.IconUrl);
            }
            else
            {
                modIcon.Source = new Avalonia.Media.Imaging.Bitmap(
                    AssetLoader.Open(new Uri("avares://LeafClient/Assets/mc-default-icon.png")));
            }

            iconBorder.Child = modIcon;
            Grid.SetColumn(iconBorder, 0);
            grid.Children.Add(iconBorder);

            var infoStack = new StackPanel
            {
                Spacing           = 3,
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
            };
            infoStack.Children.Add(new TextBlock
            {
                Text         = mod.Name,
                Foreground   = SolidColorBrush.Parse("#E5E7EB"),
                FontWeight   = FontWeight.SemiBold,
                FontSize     = 13,
                TextTrimming = TextTrimming.CharacterEllipsis,
            });
            infoStack.Children.Add(new TextBlock
            {
                Text       = $"v{mod.Version}  \u2022  MC {mod.MinecraftVersion}",
                Foreground = SolidColorBrush.Parse("#6B7280"),
                FontSize   = 10,
            });
            Grid.SetColumn(infoStack, 1);
            grid.Children.Add(infoStack);

            var actions = new StackPanel
            {
                Orientation       = Avalonia.Layout.Orientation.Horizontal,
                Spacing           = 8,
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
            };

            var pillToggle = MakeContentPillToggle(mod.Enabled, async newState =>
            {
                await ToggleMod(mod, newState);
            });

            var openBtn = MakeContentVectorPillButton(ContentRowOpenIconData, "#0B1018", "#1C2A38", "#9CA3AF");
            openBtn.Tapped += (_, _) =>
            {
                LeafClient.Utils.SystemUtil.OpenFolder(System.IO.Path.Combine(_minecraftFolder, "mods"));
            };

            var delBtn = MakeContentVectorPillButton(ContentRowTrashIconData, "#1A0B0B", "#3B1F1F", "#F87171");
            delBtn.Tapped += async (_, _) => await DeleteUserMod(mod);

            actions.Children.Add(pillToggle);
            actions.Children.Add(openBtn);
            actions.Children.Add(delBtn);
            Grid.SetColumn(actions, 2);
            grid.Children.Add(actions);

            card.Child = grid;
            return card;
        }

        private async Task ToggleMod(InstalledMod mod, bool enabled)
        {
            mod.Enabled = enabled;

            string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
            string currentJarPath = GetModFilePath(modsFolder, mod, isDisabled: false);
            string currentDisabledPath = GetModFilePath(modsFolder, mod, isDisabled: true);

            string targetPath = GetModFilePath(modsFolder, mod, isDisabled: !enabled);

            if (enabled)
            {
                if (File.Exists(currentDisabledPath))
                {
                    try
                    {
                        File.Move(currentDisabledPath, currentJarPath);
                        LeafClient.Services.LeafLog.Info("Mod Manager", $"Enabled mod '{mod.Name}'.");
                    }
                    catch (Exception ex)
                    {
                        LeafLog.Error("Mod Manager", $"Failed to enable mod '{mod.Name}': {ex.Message}");
                        ShowLaunchErrorBanner($"Failed to enable mod '{mod.Name}'. It might be in use.");
                        mod.Enabled = !enabled;
                    }
                }
                else if (!File.Exists(currentJarPath))
                {
                    LeafClient.Services.LeafLog.Info("Mod Manager", $"Mod '{mod.Name}' file missing. Will be re-downloaded on next launch if still enabled.");
                }
            }
            else
            {
                if (File.Exists(currentJarPath))
                {
                    try
                    {
                        File.Move(currentJarPath, currentDisabledPath);
                        LeafClient.Services.LeafLog.Info("Mod Manager", $"Disabled mod '{mod.Name}'.");
                    }
                    catch (Exception ex)
                    {
                        LeafLog.Error("Mod Manager", $"Failed to disable mod '{mod.Name}': {ex.Message}");
                        ShowLaunchErrorBanner($"Failed to disable mod '{mod.Name}'. It might be in use.");
                        mod.Enabled = !enabled;
                    }
                }
            }

            await _settingsService.SaveSettingsAsync(_currentSettings);
            LoadUserMods();
        }

        private async Task DeleteUserMod(InstalledMod mod)
        {
            string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
            string jarPath = GetModFilePath(modsFolder, mod, isDisabled: false);
            string disabledPath = GetModFilePath(modsFolder, mod, isDisabled: true);

            try
            {
                if (mod.ModId != null && mod.ModId.StartsWith("imported:", StringComparison.Ordinal)
                    && !string.IsNullOrEmpty(mod.FileName))
                {
                    var stem = System.IO.Path.GetFileNameWithoutExtension(mod.FileName).ToLowerInvariant();
                    var matchedManagedId = _launcherManagedModIds
                        .FirstOrDefault(id => stem.Contains(id, StringComparison.OrdinalIgnoreCase));
                    if (matchedManagedId != null)
                    {
                        var profile = GetActiveProfile();
                        if (profile?.DisabledRequiredMods?.GetValueOrDefault(matchedManagedId, false) == true)
                        {
                            profile.DisabledRequiredMods[matchedManagedId] = false;
                            LeafClient.Services.LeafLog.Info("Mod Manager", $"Override removed - re-enabled bundled '{matchedManagedId}' for next launch.");
                        }
                    }
                }
                else if (!string.IsNullOrEmpty(mod.FileName))
                {
                    var stem = System.IO.Path.GetFileNameWithoutExtension(mod.FileName).ToLowerInvariant();
                    string bestMatch = null;
                    foreach (var id in _launcherManagedModIds)
                    {
                        var idLow = id.ToLowerInvariant();
                        bool match = stem.Equals(idLow, StringComparison.Ordinal)
                                   || stem.StartsWith(idLow + "-", StringComparison.Ordinal)
                                   || stem.StartsWith(idLow + "_", StringComparison.Ordinal)
                                   || stem.StartsWith(idLow + ".", StringComparison.Ordinal);
                        if (match && (bestMatch == null || idLow.Length > bestMatch.Length))
                            bestMatch = idLow;
                    }
                    if (bestMatch != null)
                    {
                        var profile = GetActiveProfile();
                        if (profile != null)
                        {
                            profile.DisabledRequiredMods ??= new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase);
                            profile.DisabledRequiredMods[bestMatch] = true;
                            LeafClient.Services.LeafLog.Info("Mod Manager", $"User deleted '{bestMatch}' - marked disabled to prevent auto-reinstall.");

                            foreach (var (engineSlug, _, _) in _renderEngines)
                            {
                                if (bestMatch.Equals(engineSlug, StringComparison.OrdinalIgnoreCase)
                                    && string.Equals(_currentSettings?.RenderBackendChoice, engineSlug, StringComparison.OrdinalIgnoreCase))
                                {
                                    string fallback = null;
                                    foreach (var (other, _, _) in _renderEngines)
                                        if (!other.Equals(engineSlug, StringComparison.OrdinalIgnoreCase)) { fallback = other; break; }
                                    if (fallback != null)
                                    {
                                        await ApplyRenderEngineChoiceAsync(fallback);
                                        ToastService.Show($"Render engine switched to {fallback} after delete", ToastType.Info);
                                    }
                                    break;
                                }
                            }
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                LeafLog.Error("Mod Manager", $"override-undo failed: {ex.Message}");
            }

            _currentSettings.InstalledMods.Remove(mod);
            await _settingsService.SaveSettingsAsync(_currentSettings);
            LeafClient.Services.LeafLog.Info("Mod Manager", $"Removed '{mod.Name}' from settings.");

            bool fileDeletedSuccessfully = false;
            if (File.Exists(jarPath))
            {
                try
                {
                    File.Delete(jarPath);
                    LeafClient.Services.LeafLog.Info("Mod Manager", $"Deleted mod file: {System.IO.Path.GetFileName(jarPath)}");
                    fileDeletedSuccessfully = true;
                }
                catch (Exception ex)
                {
                    LeafLog.Error("Mod Manager", $"Failed to delete mod file '{System.IO.Path.GetFileName(jarPath)}': {ex.Message}");
                    _modCleanupService?.AddModToCleanup(mod);
                    ShowLaunchErrorBanner($"Failed to delete mod '{mod.Name}'. It might be in use. It will be retried later.");
                }
            }
            if (File.Exists(disabledPath))
            {
                try
                {
                    File.Delete(disabledPath);
                    LeafClient.Services.LeafLog.Info("Mod Manager", $"Deleted disabled mod file: {System.IO.Path.GetFileName(disabledPath)}");
                    fileDeletedSuccessfully = true;
                }
                catch (Exception ex)
                {
                    LeafLog.Error("Mod Manager", $"Failed to delete disabled mod file '{System.IO.Path.GetFileName(disabledPath)}': {ex.Message}");
                    _modCleanupService?.AddModToCleanup(mod);
                    ShowLaunchErrorBanner($"Failed to delete mod '{mod.Name}'. It might be in use. It will be retried later.");
                }
            }

            if (!fileDeletedSuccessfully && _modCleanupService != null)
            {
                _modCleanupService.RemoveModFromCleanup(new ModCleanupEntry
                {
                    ModId = mod.ModId,
                    FileName = mod.FileName,
                    MinecraftVersion = mod.MinecraftVersion
                });
            }

            if (_currentSettings.SelectedSkinId == mod.ModId)
            {
                _currentSettings.SelectedSkinId = null;
                _currentlySelectedSkinCard = null;
            }

            LoadUserMods();
        }

        private void InitializeModManagementControls()
        {
            _userModsPanel = this.FindControl<StackPanel>("UserModsPanel");
            _noUserModsMessage = this.FindControl<Border>("NoUserModsMessage");

            if (_userModsPanel == null)
            {
                LeafLog.Info("User Mods", "ERROR: UserModsPanel not found!");
                return;
            }

            if (_noUserModsMessage == null)
            {
                LeafLog.Info("User Mods", "ERROR: NoUserModsMessage not found!");
                return;
            }

            LeafLog.Info("User Mods", "Controls initialized successfully");
            LoadUserMods();
        }

