        private void InitializeAAdsSystem()
        {
            _adButton = this.FindControl<Button>("AdButton");
            _adImage = this.FindControl<Image>("AdImage");
            _adLoadingText = this.FindControl<TextBlock>("AdLoadingText");

            _ = LoadAAdsBannerAsync();
        }

        private async Task LoadAAdsBannerAsync()
        {
            if (!RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
            {
                LeafLog.Info("A-Ads", "Non-Windows OS detected. Hiding ad section.");
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (AdSection != null) AdSection.IsVisible = false;
                });
                return;
            }

            try
            {
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (_adLoadingText != null) _adLoadingText.IsVisible = true;
                    if (AdSection != null) AdSection.IsVisible = true;
                });

                string apiUrl = $"{AAdsApiBaseUrl}{AAdsAdUnitId}";
                LeafClient.Services.LeafLog.Info("A-Ads", $"Fetching from: {apiUrl}");

                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(10));
                var json = await _httpClient.GetStringAsync(apiUrl, cts.Token);

                LeafClient.Services.LeafLog.Info("A-Ads", $"Raw Response: {json}");

                var adResponse = JsonSerializer.Deserialize(json, JsonContext.Default.AAdsAdResponse);

                if (adResponse == null)
                {
                    LeafLog.Info("A-Ads", "Response was null.");
                    await HideAdSection();
                    return;
                }

                if (adResponse.status == false)
                {
                    LeafLog.Info("A-Ads", "Ad status is 'false' (likely pending verification or no fill).");
                    await HideAdSection();
                    return;
                }

                if (string.IsNullOrEmpty(adResponse.banner) || string.IsNullOrEmpty(adResponse.link))
                {
                    LeafLog.Info("A-Ads", "Banner image or Link URL is missing.");
                    await HideAdSection();
                    return;
                }

                _currentAdData = adResponse;

                LeafClient.Services.LeafLog.Info("A-Ads", $"Downloading banner image: {_currentAdData.banner}");
                var imageBytes = await _httpClient.GetByteArrayAsync(_currentAdData.banner, cts.Token);
                using var stream = new MemoryStream(imageBytes);
                var bitmap = new Avalonia.Media.Imaging.Bitmap(stream);

                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (_adImage != null) _adImage.Source = bitmap;
                    if (_adLoadingText != null) _adLoadingText.IsVisible = false;
                    if (AdSection != null) AdSection.IsVisible = true;

                    if (_adButton != null)
                    {
                        ToolTip.SetTip(_adButton, _currentAdData.alt ?? "Anonymous Ad");
                    }

                    LeafClient.Services.LeafLog.Info("A-Ads", $"Ad loaded successfully.");
                });
            }
            catch (Exception ex)
            {
                LeafLog.Error("A-Ads", $"Failed to load banner: {ex.Message}");
                await HideAdSection();
            }
        }

        private async Task HideAdSection()
        {
            await Dispatcher.UIThread.InvokeAsync(() =>
            {
                if (AdSection != null) AdSection.IsVisible = false;
            });
        }

        private void OnAdClicked(object? sender, RoutedEventArgs e)
        {
            if (_currentAdData != null && !string.IsNullOrEmpty(_currentAdData.link))
            {
                try
                {
                    Process.Start(new ProcessStartInfo
                    {
                        FileName = _currentAdData.link,
                        UseShellExecute = true
                    });
                    LeafClient.Services.LeafLog.Info("A-Ads", $"User clicked ad. Opening: {_currentAdData.link}");
                }
                catch (Exception ex)
                {
                    LeafLog.Error("A-Ads", $"Failed to open ad link: {ex.Message}");
                }
            }
        }

        private string MaskUsername(string username)
        {
            if (string.IsNullOrWhiteSpace(username) || username.Length <= 2)
                return username;

            int visibleChars = 1;
            int maskedLength = username.Length - (visibleChars * 2);

            if (maskedLength <= 0)
                return username;

            string masked = username[0] + new string('*', maskedLength) + username[username.Length - 1];
            return masked;
        }

        private double _lastAspectRatio = 16.0 / 9.0;

        private void OnResolutionWidthChanged(object? sender, RoutedEventArgs e)
        {
            if (!_currentSettings.LockGameAspectRatio || _isApplyingSettings)
                return;

            if (_gameResolutionWidthTextBox != null && _gameResolutionHeightTextBox != null)
            {
                if (int.TryParse(_gameResolutionWidthTextBox.Text, out int newWidth) && newWidth > 0)
                {
                    if (int.TryParse(_gameResolutionHeightTextBox.Text, out int currentHeight) && currentHeight > 0)
                    {
                        _lastAspectRatio = (double)currentHeight / newWidth;
                    }

                    int newHeight = (int)Math.Round(newWidth * _lastAspectRatio);
                    _gameResolutionHeightTextBox.Text = newHeight.ToString();

                    LeafClient.Services.LeafLog.Info("Aspect Ratio Lock", $"Width changed to {newWidth}, adjusted height to {newHeight} (ratio: {_lastAspectRatio:F4})");
                }
            }
        }

        private void OnResolutionHeightChanged(object? sender, RoutedEventArgs e)
        {
            if (!_currentSettings.LockGameAspectRatio || _isApplyingSettings)
                return;

            if (_gameResolutionWidthTextBox != null && _gameResolutionHeightTextBox != null)
            {
                if (int.TryParse(_gameResolutionHeightTextBox.Text, out int newHeight) && newHeight > 0)
                {
                    if (int.TryParse(_gameResolutionWidthTextBox.Text, out int currentWidth) && currentWidth > 0)
                    {
                        _lastAspectRatio = (double)newHeight / currentWidth;
                    }

                    int newWidth = (int)Math.Round(newHeight / _lastAspectRatio);
                    _gameResolutionWidthTextBox.Text = newWidth.ToString();

                    LeafClient.Services.LeafLog.Info("Aspect Ratio Lock", $"Height changed to {newHeight}, adjusted width to {newWidth} (ratio: {_lastAspectRatio:F4})");
                }
            }
        }

        private async void ClearLogsButton_Click(object? sender, RoutedEventArgs e)
        {
            var confirmed = await ShowConfirmationDialog("Clear Logs", "Are you sure you want to delete all launcher log files? This action cannot be undone.");
            if (!confirmed) return;

            try
            {
                if (System.IO.Directory.Exists(_logFolderPath))
                {
                    foreach (var file in System.IO.Directory.GetFiles(_logFolderPath, "launcher_log_*.txt"))
                    {
                        try
                        {
                            System.IO.File.Delete(file);
                        }
                        catch (Exception ex)
                        {
                            LeafLog.Error("Clear Logs", $"Failed to delete log file {System.IO.Path.GetFileName(file)}: {ex.Message}");
                        }
                    }
                    LeafLog.Info("Clear Logs", "All launcher log files cleared.");
                    await ShowAccountActionSuccessDialog("All launcher log files have been cleared.");
                }
                else
                {
                    LeafLog.Info("Clear Logs", "Log folder does not exist.");
                    await ShowAccountActionErrorDialog("Log folder does not exist.");
                }
            }
            catch (Exception ex)
            {
                LeafLog.Error("Clear Logs ERROR", $"{ex.Message}");
                await ShowAccountActionErrorDialog($"Failed to clear logs: {ex.Message}");
            }
            finally
            {
                await CalculateDiskUsageAsync();
            }
        }

        private async void ClearCacheButton_Click(object? sender, RoutedEventArgs e)
        {
            var confirmed = await ShowConfirmationDialog("Clear Cache", "Are you sure you want to delete all launcher cache files? This includes downloaded assets and temporary files. This may temporarily increase game launch times.");
            if (!confirmed) return;

            try
            {
                string minecraftCachePath = System.IO.Path.Combine(_minecraftFolder, "assets", "objects");
                string cmlLibCachePath = System.IO.Path.Combine(_minecraftFolder, "libraries");

                if (System.IO.Directory.Exists(minecraftCachePath))
                {
                    System.IO.Directory.Delete(minecraftCachePath, true);
                    LeafClient.Services.LeafLog.Info("Clear Cache", $"Deleted Minecraft assets cache: {minecraftCachePath}");
                }
                if (System.IO.Directory.Exists(cmlLibCachePath))
                {
                    System.IO.Directory.Delete(cmlLibCachePath, true);
                    LeafClient.Services.LeafLog.Info("Clear Cache", $"Deleted CMLib libraries cache: {cmlLibCachePath}");
                }

                System.IO.Directory.CreateDirectory(System.IO.Path.Combine(_minecraftFolder, "assets", "objects"));
                System.IO.Directory.CreateDirectory(System.IO.Path.Combine(_minecraftFolder, "libraries"));

                await ShowAccountActionSuccessDialog("Launcher cache has been cleared.");
                LeafLog.Info("Clear Cache", "Launcher cache cleared successfully.");
            }
            catch (Exception ex)
            {
                LeafLog.Error("Clear Cache ERROR", $"{ex.Message}");
                await ShowAccountActionErrorDialog($"Failed to clear cache: {ex.Message}");
            }
            finally
            {
                await CalculateDiskUsageAsync();
            }
        }

        private (DateTime At, double Logs, double Profiles, double Assets, double Cache, double Other)? _diskUsageCache;
        private static readonly TimeSpan DiskUsageCacheTtl = TimeSpan.FromSeconds(30);
        private int _diskUsageScanInFlight;

        private async Task CalculateDiskUsageAsync()
        {
            if (_logsUsageBar == null || _profilesUsageBar == null || _assetsUsageBar == null || _cacheUsageBar == null ||
                _otherUsageBar == null || _logsUsageText == null || _profilesUsageText == null || _assetsUsageText == null ||
                _cacheUsageText == null || _otherUsageText == null || _totalUsageText == null) return;

            if (_diskUsageCache.HasValue && DateTime.UtcNow - _diskUsageCache.Value.At < DiskUsageCacheTtl)
            {
                ApplyDiskUsage(_diskUsageCache.Value.Logs, _diskUsageCache.Value.Profiles,
                    _diskUsageCache.Value.Assets, _diskUsageCache.Value.Cache, _diskUsageCache.Value.Other);
                return;
            }

            if (System.Threading.Interlocked.Exchange(ref _diskUsageScanInFlight, 1) == 1) return;

            ShowDiskUsageShimmer(true);

            try
            {
                var logsTask     = Task.Run(() => GetDirectorySizeFast(_logFolderPath));
                var profilesTask = Task.Run(() => GetDirectorySizeFast(System.IO.Path.Combine(_minecraftFolder, "versions")));
                var assetsTask   = Task.Run(() => GetDirectorySizeFast(System.IO.Path.Combine(_minecraftFolder, "assets")));
                var librariesTask = Task.Run(() => GetDirectorySizeFast(System.IO.Path.Combine(_minecraftFolder, "libraries")));
                var otherTask    = Task.Run(() => GetMinecraftOtherSizeFast());

                await Task.WhenAll(logsTask, profilesTask, assetsTask, librariesTask, otherTask);

                _diskUsageCache = (DateTime.UtcNow, logsTask.Result, profilesTask.Result, assetsTask.Result,
                                   librariesTask.Result, otherTask.Result);

                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    ShowDiskUsageShimmer(false);
                    ApplyDiskUsage(logsTask.Result, profilesTask.Result, assetsTask.Result,
                                   librariesTask.Result, otherTask.Result);
                });
            }
            catch (Exception ex)
            {
                LeafLog.Error("Disk Usage", $"Scan failed: {ex.Message}");
                await Dispatcher.UIThread.InvokeAsync(() => ShowDiskUsageShimmer(false));
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _diskUsageScanInFlight, 0);
            }
        }

        private (double Logs, double Profiles, double Assets, double Cache, double Other)? _lastDiskUsageValues;
        private EventHandler? _diskUsageLayoutHandler;

        private void ApplyDiskUsage(double logs, double profiles, double assets, double cache, double other)
        {
            if (_logsUsageText == null) return;
            double total = logs + profiles + assets + cache + other;
            _logsUsageText!.Text     = $"Logs - {FormatBytes(logs)}";
            _profilesUsageText!.Text = $"Profiles - {FormatBytes(profiles)}";
            _assetsUsageText!.Text   = $"Assets - {FormatBytes(assets)}";
            _cacheUsageText!.Text    = $"Cache - {FormatBytes(cache)}";
            _otherUsageText!.Text    = $"Other - {FormatBytes(other)}";
            _totalUsageText!.Text    = FormatBytes(total);

            _lastDiskUsageValues = (logs, profiles, assets, cache, other);

            if (!ApplyDiskUsageBars(logs, profiles, assets, cache, other, total))
            {
                var host = this.FindControl<Grid>("DiskUsageBarHost");
                if (host != null)
                {
                    if (_diskUsageLayoutHandler != null)
                        host.LayoutUpdated -= _diskUsageLayoutHandler;

                    _diskUsageLayoutHandler = (_, __) =>
                    {
                        if (_lastDiskUsageValues == null) return;
                        var v = _lastDiskUsageValues.Value;
                        double t = v.Logs + v.Profiles + v.Assets + v.Cache + v.Other;
                        if (ApplyDiskUsageBars(v.Logs, v.Profiles, v.Assets, v.Cache, v.Other, t))
                        {
                            host.LayoutUpdated -= _diskUsageLayoutHandler!;
                            _diskUsageLayoutHandler = null;
                        }
                    };
                    host.LayoutUpdated += _diskUsageLayoutHandler;
                }
            }
        }

        private bool ApplyDiskUsageBars(double logs, double profiles, double assets, double cache, double other, double total)
        {
            if (_logsUsageBar == null) return false;
            var host = this.FindControl<Grid>("DiskUsageBarHost");
            double parentWidth = host?.Bounds.Width ?? 0;
            if (parentWidth <= 0 || total <= 0)
            {
                _logsUsageBar.Width     = 0;
                _profilesUsageBar!.Width = 0;
                _assetsUsageBar!.Width   = 0;
                _cacheUsageBar!.Width    = 0;
                _otherUsageBar!.Width    = 0;
                return parentWidth > 0;
            }
            _logsUsageBar.Width      = (logs / total) * parentWidth;
            _profilesUsageBar!.Width = (profiles / total) * parentWidth;
            _assetsUsageBar!.Width   = (assets / total) * parentWidth;
            _cacheUsageBar!.Width    = (cache / total) * parentWidth;
            _otherUsageBar!.Width    = (other / total) * parentWidth;
            return true;
        }

        private System.Timers.Timer? _diskShimmerTimer;
        private void ShowDiskUsageShimmer(bool show)
        {
            if (_logsUsageText == null) return;
            if (show)
            {
                _logsUsageText!.Text     = "Logs - …";
                _profilesUsageText!.Text = "Profiles - …";
                _assetsUsageText!.Text   = "Assets - …";
                _cacheUsageText!.Text    = "Cache - …";
                _otherUsageText!.Text    = "Other - …";
                _totalUsageText!.Text    = "…";

                double parentWidth = this.FindControl<Grid>("DiskUsageBarHost")?.Bounds.Width ?? 0;
                if (parentWidth > 0)
                {
                    double seg = parentWidth / 5.0;
                    _logsUsageBar!.Width     = seg;
                    _profilesUsageBar!.Width = seg;
                    _assetsUsageBar!.Width   = seg;
                    _cacheUsageBar!.Width    = seg;
                    _otherUsageBar!.Width    = parentWidth - seg * 4;
                }

                _diskShimmerTimer?.Stop();
                _diskShimmerTimer = new System.Timers.Timer(60) { AutoReset = true };
                double phase = 0;
                _diskShimmerTimer.Elapsed += (_, __) =>
                {
                    phase += 0.18;
                    double op = 0.35 + 0.35 * (Math.Sin(phase) * 0.5 + 0.5);
                    Dispatcher.UIThread.Post(() =>
                    {
                        if (_logsUsageBar     != null) _logsUsageBar.Opacity     = op;
                        if (_profilesUsageBar != null) _profilesUsageBar.Opacity = op;
                        if (_assetsUsageBar   != null) _assetsUsageBar.Opacity   = op;
                        if (_cacheUsageBar    != null) _cacheUsageBar.Opacity    = op;
                        if (_otherUsageBar    != null) _otherUsageBar.Opacity    = op;
                    });
                };
                _diskShimmerTimer.Start();
            }
            else
            {
                _diskShimmerTimer?.Stop();
                _diskShimmerTimer = null;
                if (_logsUsageBar     != null) _logsUsageBar.Opacity     = 1;
                if (_profilesUsageBar != null) _profilesUsageBar.Opacity = 1;
                if (_assetsUsageBar   != null) _assetsUsageBar.Opacity   = 1;
                if (_cacheUsageBar    != null) _cacheUsageBar.Opacity    = 1;
                if (_otherUsageBar    != null) _otherUsageBar.Opacity    = 1;
            }
        }

        private static double GetDirectorySizeFast(string path)
        {
            if (!System.IO.Directory.Exists(path)) return 0;
            try
            {
                var di = new System.IO.DirectoryInfo(path);
                return SumFiles(di);
            }
            catch (Exception ex)
            {
                LeafLog.Error("Disk Usage", $"Error calculating size for {path}: {ex.Message}");
                return 0;
            }
        }

        private static double SumFiles(System.IO.DirectoryInfo dir)
        {
            double total = 0;
            try
            {
                foreach (var fi in dir.EnumerateFiles("*", new System.IO.EnumerationOptions
                {
                    RecurseSubdirectories = true,
                    IgnoreInaccessible = true,
                    AttributesToSkip = System.IO.FileAttributes.ReparsePoint,
                }))
                {
                    try { total += fi.Length; }
                    catch { }
                }
            }
            catch { }
            return total;
        }

        private double GetMinecraftOtherSizeFast()
        {
            try
            {
                if (!System.IO.Directory.Exists(_minecraftFolder)) return 0;
                var skip = new HashSet<string>(StringComparer.OrdinalIgnoreCase) { "logs", "versions", "assets", "libraries" };
                if (System.IO.Path.GetFileName(_logFolderPath) is { Length: > 0 } logsFolderName)
                    skip.Add(logsFolderName);

                double total = 0;
                var root = new System.IO.DirectoryInfo(_minecraftFolder);
                foreach (var fi in root.EnumerateFiles())
                {
                    try { total += fi.Length; } catch { }
                }
                foreach (var sub in root.EnumerateDirectories())
                {
                    if (skip.Contains(sub.Name)) continue;
                    total += SumFiles(sub);
                }
                return total;
            }
            catch (Exception ex)
            {
                LeafLog.Error("Disk Usage", $"Other-size scan failed: {ex.Message}");
                return 0;
            }
        }

        private string FormatBytes(double bytes)
        {
            string[] Suffix = { "B", "KB", "MB", "GB", "TB" };
            int i;
            double dblSByte = bytes;
            for (i = 0; i < Suffix.Length && bytes >= 1024; i++, bytes /= 1024)
            {
                dblSByte = bytes / 1024;
            }
            return $"{dblSByte:0.##} {Suffix[i]}";
        }

        private async void SelectGameResolutionPreset(object? sender, RoutedEventArgs e)
        {
            if (_resolutionPresetOverlay == null || _resolutionPresetPanel == null) return;

            if (_resolutionPresetOverlay.IsVisible) return;

            _resolutionPresetOverlay.IsVisible = true;

            var tt = _resolutionPresetPanel.RenderTransform as TranslateTransform ?? new TranslateTransform();
            _resolutionPresetPanel.RenderTransform = tt;

            if (!AreAnimationsEnabled())
            {
                tt.Y = 0;
                _resolutionPresetPanel.Opacity = 1;
                return;
            }

            const int durationMs = 500;
            const int steps = 30;
            int delayMs = durationMs / steps;

            tt.Y = -700;
            _resolutionPresetPanel.Opacity = 0;

            for (int i = 0; i <= steps; i++)
            {
                double t = (double)i / steps;
                double eased = 1 - Math.Pow(1 - t, 3);
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    tt.Y = -700 + (700 * eased);
                    _resolutionPresetPanel.Opacity = eased;
                });
                if (i < steps) await Task.Delay(delayMs);
            }
        }

        private void CloseResolutionPreset(object? sender, RoutedEventArgs e)
        {
            if (_resolutionPresetOverlay == null || _resolutionPresetPanel == null) return;

            var tt = _resolutionPresetPanel.RenderTransform as TranslateTransform ?? new TranslateTransform();
            _resolutionPresetPanel.RenderTransform = tt;

            if (!AreAnimationsEnabled())
            {
                tt.Y = -700;
                _resolutionPresetPanel.Opacity = 0;
                _resolutionPresetOverlay.IsVisible = false;
                return;
            }

            _ = Task.Run(async () =>
            {
                const int durationMs = 500;
                const int steps = 30;
                int delayMs = durationMs / steps;

                for (int i = 0; i <= steps; i++)
                {
                    double t = (double)i / steps;
                    double eased = 1 - Math.Pow(1 - t, 3);
                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        tt.Y = 0 - (700 * eased);
                        _resolutionPresetPanel.Opacity = 1 - eased;
                    });
                    if (i < steps) await Task.Delay(delayMs);
                }
                await Dispatcher.UIThread.InvokeAsync(() => _resolutionPresetOverlay.IsVisible = false);
            });
        }

        private void OnPresetClicked(object? sender, RoutedEventArgs e)
        {
            if (sender is Button btn && btn.Tag is string tag)
            {
                var parts = tag.Split('x');
                if (parts.Length == 2 &&
                    int.TryParse(parts[0], out int w) &&
                    int.TryParse(parts[1], out int h))
                {
                    if (_gameResolutionWidthTextBox != null) _gameResolutionWidthTextBox.Text = w.ToString();
                    if (_gameResolutionHeightTextBox != null) _gameResolutionHeightTextBox.Text = h.ToString();
                    MarkSettingsDirty();
                }
            }
            CloseResolutionPreset(null, new RoutedEventArgs());
        }

        private void VisualiseGameResolution(object? sender, RoutedEventArgs e)
        {
            if (!int.TryParse(_gameResolutionWidthTextBox?.Text, out int width) || width <= 0 ||
                !int.TryParse(_gameResolutionHeightTextBox?.Text, out int height) || height <= 0)
            {
                _ = ShowAccountActionErrorDialog("Invalid resolution. Enter positive integers for width and height.");
                return;
            }

            double scaling = this.RenderScaling;
            double logicalWidth = width / scaling;
            double logicalHeight = height / scaling;

            var previewWindow = new Window
            {
                Title = "Resolution Preview",
                SystemDecorations = SystemDecorations.None,
                Width = logicalWidth,
                Height = logicalHeight,
                WindowStartupLocation = WindowStartupLocation.CenterScreen,
                CanResize = false,
                Topmost = true,
                Background = new SolidColorBrush(Color.Parse("#CC101010")),
                TransparencyLevelHint = new[] { WindowTransparencyLevel.Transparent },
                ExtendClientAreaToDecorationsHint = true,
                ExtendClientAreaChromeHints = Avalonia.Platform.ExtendClientAreaChromeHints.NoChrome
            };

            var container = new Border
            {
                BorderBrush = GetBrush("PrimaryAccentBrush", Brushes.Lime),
                BorderThickness = new Thickness(4),
                Child = new StackPanel
                {
                    VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                    HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                    Spacing = 5,
                    Children =
            {
                new TextBlock
                {
                    Text = $"{width} × {height}",
                    Foreground = Brushes.White,
                    FontWeight = FontWeight.ExtraBold,
                    FontSize = 32,
                    HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center
                },
                new TextBlock
                {
                    Text = $"Physical Pixels (Scale: {scaling:0.##}x)",
                    Foreground = Brushes.LightGray,
                    FontSize = 14,
                    HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center
                },
                new TextBlock
                {
                    Text = "Click anywhere to close",
                    Foreground = Brushes.Gray,
                    FontSize = 12,
                    HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                    Margin = new Thickness(0, 10, 0, 0)
                }
            }
                }
            };

            previewWindow.Content = container;

            previewWindow.PointerPressed += (_, __) => previewWindow.Close();

            previewWindow.Deactivated += (_, __) => previewWindow.Close();

            previewWindow.Show();
        }

        private void CloseResolutionVisualOverlay(object? sender, RoutedEventArgs e)
        {
            if (_resolutionVisualOverlay == null || _resolutionVisualPanel == null) return;

            var tt = _resolutionVisualPanel.RenderTransform as TranslateTransform ?? new TranslateTransform();
            _resolutionVisualPanel.RenderTransform = tt;

            if (!AreAnimationsEnabled())
            {
                tt.Y = -700;
                _resolutionVisualPanel.Opacity = 0;
                _resolutionVisualOverlay.IsVisible = false;
                return;
            }

            _ = Task.Run(async () =>
            {
                const int durationMs = 500;
                const int steps = 30;
                int delayMs = durationMs / steps;

                for (int i = 0; i <= steps; i++)
                {
                    double t = (double)i / steps;
                    double eased = 1 - Math.Pow(1 - t, 3);
                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        tt.Y = 0 - (700 * eased);
                        _resolutionVisualPanel.Opacity = 1 - eased;
                    });
                    if (i < steps) await Task.Delay(delayMs);
                }
                await Dispatcher.UIThread.InvokeAsync(() => _resolutionVisualOverlay.IsVisible = false);
            });
        }

        private async void ShowLaunchFailureBanner(string message)
        {
            if (_launchFailureBanner == null || _launchFailureBannerText == null) return;

            if (_launchFailureBannerShownForCurrentLaunch) return;

            _launchFailureBannerText.Text = message;
            _launchFailureBanner.IsVisible = true;
            _launchFailureBannerShownForCurrentLaunch = true;

            _launchFailureBannerCts?.Cancel();
            _launchFailureBannerCts = new CancellationTokenSource();
            var ct = _launchFailureBannerCts.Token;

            TranslateTransform? transform = _launchFailureBanner.RenderTransform as TranslateTransform;
            if (transform == null)
            {
                transform = new TranslateTransform();
                _launchFailureBanner.RenderTransform = transform;
            }

            if (!AreAnimationsEnabled())
            {
                transform.Y = 0;
                _launchFailureBanner.Opacity = 1;
                return;
            }

            transform.Y = -100;
            _launchFailureBanner.Opacity = 0;

            const int durationMs = 500;
            const int steps = 30;
            const int delayMs = durationMs / steps;

            try
            {
                for (int i = 0; i <= steps; i++)
                {
                    if (ct.IsCancellationRequested) break;

                    double progress = (double)i / steps;
                    double eased = 1 - Math.Pow(1 - progress, 3);

                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        if (_launchFailureBanner == null || ct.IsCancellationRequested) return;
                        transform.Y = -100 + (100 * eased);
                        _launchFailureBanner.Opacity = eased;
                    });

                    if (i < steps)
                        await Task.Delay(delayMs, ct);
                }

                _ = Task.Run(async () =>
                {
                    try
                    {
                        await Task.Delay(5000, ct);
                        if (!ct.IsCancellationRequested)
                        {
                            await Dispatcher.UIThread.InvokeAsync(() => HideLaunchFailureBanner());
                        }
                    }
                    catch (OperationCanceledException) {  }
                }, ct);
            }
            catch (OperationCanceledException)
            {
            }
        }

        private async void HideLaunchFailureBanner()
        {
            if (_launchFailureBanner == null) return;

            _launchFailureBannerCts?.Cancel();
            _launchFailureBannerShownForCurrentLaunch = false;

            TranslateTransform? transform = _launchFailureBanner.RenderTransform as TranslateTransform;
            if (transform == null)
            {
                _launchFailureBanner.IsVisible = false;
                return;
            }

            if (!AreAnimationsEnabled())
            {
                transform.Y = -100;
                _launchFailureBanner.Opacity = 0;
                _launchFailureBanner.IsVisible = false;
                return;
            }

            double startY = transform.Y;
            double startOpacity = _launchFailureBanner.Opacity;

            if (startOpacity < 0.01)
            {
                _launchFailureBanner.IsVisible = false;
                return;
            }

            var hideCts = new CancellationTokenSource();
            var ct = hideCts.Token;

            const int durationMs = 380;
            const int steps = 24;
            const int delayMs = durationMs / steps;

            try
            {
                for (int i = 0; i <= steps; i++)
                {
                    if (ct.IsCancellationRequested) break;

                    double progress = (double)i / steps;
                    double eased = progress * progress;

                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        if (_launchFailureBanner == null || ct.IsCancellationRequested) return;
                        transform.Y      = startY + (-100.0 - startY) * eased;
                        _launchFailureBanner.Opacity = startOpacity * (1.0 - eased);
                    });

                    if (i < steps)
                        await Task.Delay(delayMs, ct);
                }
            }
            catch (OperationCanceledException) { }

            await Dispatcher.UIThread.InvokeAsync(() =>
            {
                if (_launchFailureBanner != null)
                {
                    transform.Y = -100;
                    _launchFailureBanner.Opacity  = 0;
                    _launchFailureBanner.IsVisible = false;
                }
            });
        }

