        private async void OnModsLoadMore(object? sender, RoutedEventArgs e)
        {
            await SearchMods(_currentModQuery, true);
        }

        private string BuildModrinthUrl(string query, int offset, int limit)
        {
            return BuildModrinthSearchUrl(query, _selectedMcVersion ?? "", offset, limit);
        }

        private string BuildModrinthSearchUrl(string query, string version, int offset, int limit)
        {
            var facets = new List<string>();
            facets.Add($"[\"project_type:{_modBrowseProjectType}\"]");
            bool isShader = _modBrowseProjectType == "shader";
            bool isResourcePack = _modBrowseProjectType == "resourcepack";
            bool needsLoader = !isShader && !isResourcePack;
            if (needsLoader && _selectedLoader != "all")
            {
                facets.Add($"[\"categories:{_selectedLoader}\"]");
            }
            if (!string.IsNullOrEmpty(_selectedCategory))
            {
                facets.Add($"[\"categories:{_selectedCategory}\"]");
            }
            if (!isShader && !string.IsNullOrEmpty(version))
            {
                facets.Add($"[\"versions:{version}\"]");
            }
            var facetsJson = "[" + string.Join(",", facets) + "]";
            var sb = new System.Text.StringBuilder("https://api.modrinth.com/v2/search?");
            sb.Append($"limit={limit}");
            sb.Append($"&offset={offset}");
            sb.Append($"&index={Uri.EscapeDataString(_selectedSort)}");
            sb.Append($"&facets={Uri.EscapeDataString(facetsJson)}");
            if (!string.IsNullOrWhiteSpace(query))
            {
                sb.Append($"&query={Uri.EscapeDataString(query)}");
            }
            return sb.ToString();
        }

        private async Task SearchMods(string query, bool append)
        {
            if (_modsResultsGrid == null || _modsEmptyPanel == null || _modsSkeletonPanel == null || _modsLoadMoreBtn == null) return;

            try { _searchModsCts?.Cancel(); } catch { }
            _searchModsCts?.Dispose();
            _searchModsCts = new CancellationTokenSource();
            var ct = _searchModsCts.Token;
            long epoch = System.Threading.Interlocked.Increment(ref _searchModsEpoch);

            const int pageSize = 30;
            if (!append)
            {
                _modOffset = 0;
                _modsResultsGrid.ItemsSource = null;
                _modsResultsGrid.Items.Clear();
                _modsResultsGrid.IsVisible = false;
                _modsEmptyPanel.IsVisible = false;
                _modsLoadMoreBtn.IsVisible = false;
                _modsSkeletonPanel.IsVisible = true;
                if (_modsResultCount != null) _modsResultCount.Text = "Searching Modrinth…";
            }
            else
            {
                _modsLoadMoreBtn.Content = "Loading…";
                _modsLoadMoreBtn.IsEnabled = false;
            }

            try
            {
                var apiUrl = BuildModrinthUrl(query, _modOffset, pageSize);
                var response = await _modrinthClient.GetStringAsync(apiUrl, ct);
                ct.ThrowIfCancellationRequested();
                var searchResponse = JsonSerializer.Deserialize(response, JsonContext.Default.ModrinthSearchResponse);

                string? usedFallbackVersion = null;

                if (searchResponse?.hits == null || (searchResponse.hits.Count == 0 && !append))
                {
                    if (!string.IsNullOrEmpty(_selectedMcVersion))
                    {
                        var fallback = ModrinthVersionFallback.GetFallbackVersion(_selectedMcVersion);
                        if (fallback != null)
                        {
                            var fallbackUrl = BuildModrinthSearchUrl(query, fallback, _modOffset, pageSize);
                            var fallbackJson = await _modrinthClient.GetStringAsync(fallbackUrl, ct);
                            ct.ThrowIfCancellationRequested();
                            var fallbackResponse = JsonSerializer.Deserialize(fallbackJson, JsonContext.Default.ModrinthSearchResponse);
                            if (fallbackResponse?.hits != null && fallbackResponse.hits.Count > 0)
                            {
                                usedFallbackVersion = fallback;
                                searchResponse = fallbackResponse;
                            }
                        }
                    }
                }

                bool aborted = false;
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (System.Threading.Interlocked.Read(ref _searchModsEpoch) != epoch) { aborted = true; return; }
                    _modsSkeletonPanel.IsVisible = false;

                    if (!append)
                    {
                        _modsResultsGrid.Items.Clear();
                    }

                    if (searchResponse?.hits == null || (searchResponse.hits.Count == 0 && !append))
                    {
                        if (_modsBrowserVersionNotice != null) _modsBrowserVersionNotice.IsVisible = false;
                        _modsEmptyPanel.IsVisible = true;
                        _modsResultsGrid.IsVisible = false;
                        _modsLoadMoreBtn.IsVisible = false;
                        if (_modsResultCount != null) _modsResultCount.Text = "No results found";
                        aborted = true;
                        return;
                    }

                    if (usedFallbackVersion != null)
                    {
                        if (_modsBrowserVersionNotice != null) _modsBrowserVersionNotice.IsVisible = true;
                        if (_modsBrowserVersionNoticeText != null)
                            _modsBrowserVersionNoticeText.Text =
                                $"No mods found for {_selectedMcVersion} yet - showing compatible {usedFallbackVersion} mods instead";
                    }
                    else
                    {
                        if (_modsBrowserVersionNotice != null) _modsBrowserVersionNotice.IsVisible = false;
                    }

                    _modTotalHits = searchResponse.total_hits;
                    _modsResultsGrid.IsVisible = true;
                    _modsEmptyPanel.IsVisible = false;
                });

                if (aborted) return;
                if (searchResponse?.hits == null) return;

                int addedThisRun = 0;
                const int batchSize = 4;
                for (int i = 0; i < searchResponse.hits.Count; i += batchSize)
                {
                    if (ct.IsCancellationRequested) return;
                    if (System.Threading.Interlocked.Read(ref _searchModsEpoch) != epoch) return;

                    int start = i;
                    int end = Math.Min(i + batchSize, searchResponse.hits.Count);
                    int added = await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        if (System.Threading.Interlocked.Read(ref _searchModsEpoch) != epoch) return 0;
                        int count = 0;
                        for (int j = start; j < end; j++)
                        {
                            try
                            {
                                var card = CreateModCard(searchResponse.hits[j]);
                                _modsResultsGrid.Items.Add(card);
                                count++;
                            }
                            catch (Exception ex)
                            {
                                LeafClient.Services.LeafLog.Error("Mod Browser", $"CreateModCard failed: {ex.Message}");
                            }
                        }
                        return count;
                    }, Avalonia.Threading.DispatcherPriority.Background);
                    addedThisRun += added;
                    await Task.Delay(1, ct);
                }

                if (System.Threading.Interlocked.Read(ref _searchModsEpoch) != epoch) return;

                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (System.Threading.Interlocked.Read(ref _searchModsEpoch) != epoch) return;
                    _modOffset += addedThisRun;
                    if (_modsResultCount != null)
                    {
                        var scope = string.IsNullOrEmpty(query) ? "mods" : $"results for \"{query}\"";
                        _modsResultCount.Text = $"Showing {_modOffset} of {FormatCount(_modTotalHits)} {scope}";
                    }
                    _modsLoadMoreBtn.Content = "Load more";
                    _modsLoadMoreBtn.IsEnabled = true;
                    _modsLoadMoreBtn.IsVisible = _modOffset < _modTotalHits;
                });
            }
            catch (OperationCanceledException)
            {
            }
            catch (System.Net.Http.HttpRequestException) when (ct.IsCancellationRequested)
            {
            }
            catch (Exception ex)
            {
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (System.Threading.Interlocked.Read(ref _searchModsEpoch) != epoch) return;
                    _modsSkeletonPanel.IsVisible = false;
                    _modsLoadMoreBtn.Content = "Load more";
                    _modsLoadMoreBtn.IsEnabled = true;
                    if (!append)
                    {
                        _modsEmptyPanel.IsVisible = true;
                        _modsResultsGrid.IsVisible = false;
                        _modsLoadMoreBtn.IsVisible = false;
                        if (_modsBrowserVersionNotice != null) _modsBrowserVersionNotice.IsVisible = false;
                        if (_modsResultCount != null) _modsResultCount.Text = "Unable to load mods";
                    }
                    LeafClient.Services.LeafLog.Error("Mod Browser", $"Error searching mods: {ex.Message}");
                });
            }
        }

        private Border CreateModCard(ModrinthProject mod)
        {
            var card = new Border
            {
                Height = 300,
                CornerRadius = new CornerRadius(14),
                BorderBrush = new SolidColorBrush(Color.Parse("#1A2332")),
                BorderThickness = new Thickness(1),
                Margin = new Thickness(6),
                Cursor = new Cursor(StandardCursorType.Hand),
                ClipToBounds = true,
            };
            card.Classes.Add("ModCard");

            var bgGradient = new LinearGradientBrush
            {
                StartPoint = new RelativePoint(0, 0, RelativeUnit.Relative),
                EndPoint = new RelativePoint(0, 1, RelativeUnit.Relative),
            };
            bgGradient.GradientStops.Add(new GradientStop(Color.Parse("#101826"), 0));
            bgGradient.GradientStops.Add(new GradientStop(Color.Parse("#0A1018"), 1));
            card.Background = bgGradient;

            var rootGrid = new Grid();
            rootGrid.RowDefinitions.Add(new RowDefinition { Height = new GridLength(128) });
            rootGrid.RowDefinitions.Add(new RowDefinition { Height = GridLength.Auto });
            rootGrid.RowDefinitions.Add(new RowDefinition { Height = GridLength.Star });
            rootGrid.RowDefinitions.Add(new RowDefinition { Height = GridLength.Auto });

            var bannerGradient = new LinearGradientBrush
            {
                StartPoint = new RelativePoint(0, 0, RelativeUnit.Relative),
                EndPoint = new RelativePoint(1, 1, RelativeUnit.Relative),
            };
            bannerGradient.GradientStops.Add(new GradientStop(Color.Parse("#1E1338"), 0));
            bannerGradient.GradientStops.Add(new GradientStop(Color.Parse("#120A24"), 1));
            var banner = new Border
            {
                Background = bannerGradient,
                ClipToBounds = true,
            };
            Grid.SetRow(banner, 0);
            rootGrid.Children.Add(banner);

            var iconHolder = new Border
            {
                Width = 76,
                Height = 76,
                CornerRadius = new CornerRadius(14),
                Background = new SolidColorBrush(Color.Parse("#0D1520")),
                BorderBrush = new SolidColorBrush(Color.Parse("#052E16")),
                BorderThickness = new Thickness(1),
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                Padding = new Thickness(8),
                BoxShadow = BoxShadows.Parse("0 12 30 0 #80000000"),
            };
            var modIcon = new Image
            {
                Stretch = Avalonia.Media.Stretch.Uniform,
            };
            if (!string.IsNullOrEmpty(mod.icon_url))
            {
                var iconCt = _searchModsCts?.Token ?? default;
                long iconEpoch = System.Threading.Interlocked.Read(ref _searchModsEpoch);
                _ = LoadModIcon(modIcon, mod.icon_url, iconCt, iconEpoch);
            }
            else
                modIcon.Source = new Avalonia.Media.Imaging.Bitmap(
                    AssetLoader.Open(new Uri("avares://LeafClient/Assets/mc-default-icon.png")));
            iconHolder.Child = modIcon;
            Grid.SetRow(iconHolder, 0);
            rootGrid.Children.Add(iconHolder);

            if (mod.loaders != null && mod.loaders.Count > 0)
            {
                var primaryLoader = mod.loaders.FirstOrDefault(l =>
                    l.Equals("fabric", StringComparison.OrdinalIgnoreCase) ||
                    l.Equals("forge", StringComparison.OrdinalIgnoreCase) ||
                    l.Equals("quilt", StringComparison.OrdinalIgnoreCase) ||
                    l.Equals("neoforge", StringComparison.OrdinalIgnoreCase)) ?? mod.loaders[0];
                var loaderBadge = new Border
                {
                    Background = new SolidColorBrush(Color.Parse("#CC0D1520")),
                    BorderBrush = new SolidColorBrush(Color.Parse("#16A34A")),
                    BorderThickness = new Thickness(1),
                    CornerRadius = new CornerRadius(7),
                    Padding = new Thickness(8, 3),
                    Margin = new Thickness(10),
                    HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Right,
                    VerticalAlignment = Avalonia.Layout.VerticalAlignment.Top,
                };
                loaderBadge.Child = new TextBlock
                {
                    Text = CapitalizeFirst(primaryLoader),
                    FontSize = 10,
                    FontWeight = FontWeight.Bold,
                    Foreground = new SolidColorBrush(Color.Parse("#86EFAC")),
                };
                Grid.SetRow(loaderBadge, 0);
                rootGrid.Children.Add(loaderBadge);
            }

            try
            {
                string ptypeLowerCard = (mod.project_type ?? "").ToLowerInvariant();
                bool isModTypeCard = ptypeLowerCard == "" || ptypeLowerCard == "mod";
                bool isInstalledCard = isModTypeCard
                    ? IsModAlreadyInstalled(mod, _currentSettings.SelectedSubVersion)
                    : IsContentInstalled(mod);
                if (isInstalledCard)
                {
                    var installedBadge = new Border
                    {
                        Background = new SolidColorBrush(Color.Parse("#CC064E3B")),
                        BorderBrush = new SolidColorBrush(Color.Parse("#10B981")),
                        BorderThickness = new Thickness(1),
                        CornerRadius = new CornerRadius(7),
                        Padding = new Thickness(8, 3),
                        Margin = new Thickness(10),
                        HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Left,
                        VerticalAlignment = Avalonia.Layout.VerticalAlignment.Top,
                    };
                    installedBadge.Child = new TextBlock
                    {
                        Text = "INSTALLED",
                        FontSize = 10,
                        FontWeight = FontWeight.Bold,
                        Foreground = new SolidColorBrush(Color.Parse("#6EE7B7")),
                    };
                    Grid.SetRow(installedBadge, 0);
                    rootGrid.Children.Add(installedBadge);
                }
            }
            catch { }

            var titleStack = new StackPanel
            {
                Spacing = 2,
                Margin = new Thickness(16, 14, 16, 0),
            };
            titleStack.Children.Add(new TextBlock
            {
                Text = mod.title ?? "Untitled mod",
                Foreground = new SolidColorBrush(Color.Parse("#F8FAFC")),
                FontWeight = FontWeight.Bold,
                FontSize = 14,
                TextTrimming = Avalonia.Media.TextTrimming.CharacterEllipsis,
            });
            titleStack.Children.Add(new TextBlock
            {
                Text = $"by {mod.author ?? "unknown"}",
                Foreground = new SolidColorBrush(Color.Parse("#64748B")),
                FontSize = 11,
                TextTrimming = Avalonia.Media.TextTrimming.CharacterEllipsis,
            });
            Grid.SetRow(titleStack, 1);
            rootGrid.Children.Add(titleStack);

            var descText = new TextBlock
            {
                Text = string.IsNullOrWhiteSpace(mod.description) ? "No description available." : mod.description,
                Foreground = new SolidColorBrush(Color.Parse("#94A3B8")),
                FontSize = 11,
                LineHeight = 16,
                TextWrapping = Avalonia.Media.TextWrapping.Wrap,
                TextTrimming = Avalonia.Media.TextTrimming.CharacterEllipsis,
                MaxLines = 3,
                Margin = new Thickness(16, 8, 16, 12),
            };
            Grid.SetRow(descText, 2);
            rootGrid.Children.Add(descText);

            var statsRow = new Border
            {
                Background = new SolidColorBrush(Color.Parse("#080D14")),
                BorderBrush = new SolidColorBrush(Color.Parse("#1A2332")),
                BorderThickness = new Thickness(0, 1, 0, 0),
                Padding = new Thickness(16, 10),
            };
            var statsGrid = new Grid();
            statsGrid.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Star });
            statsGrid.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Star });
            var dl = new StackPanel { Orientation = Avalonia.Layout.Orientation.Horizontal, Spacing = 4 };
            dl.Children.Add(new TextBlock { Text = "⬇", FontSize = 11, Foreground = new SolidColorBrush(Color.Parse("#34D399")), VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center });
            dl.Children.Add(new TextBlock { Text = FormatCount(mod.downloads), FontSize = 11, FontWeight = FontWeight.SemiBold, Foreground = new SolidColorBrush(Color.Parse("#CBD5E1")), VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center });
            Grid.SetColumn(dl, 0);
            statsGrid.Children.Add(dl);
            var fl = new StackPanel { Orientation = Avalonia.Layout.Orientation.Horizontal, Spacing = 4, HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Right };
            fl.Children.Add(new TextBlock { Text = "♥", FontSize = 11, Foreground = new SolidColorBrush(Color.Parse("#86EFAC")), VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center });
            fl.Children.Add(new TextBlock { Text = FormatCount(mod.follows), FontSize = 11, FontWeight = FontWeight.SemiBold, Foreground = new SolidColorBrush(Color.Parse("#CBD5E1")), VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center });
            Grid.SetColumn(fl, 1);
            statsGrid.Children.Add(fl);
            statsRow.Child = statsGrid;
            Grid.SetRow(statsRow, 3);
            rootGrid.Children.Add(statsRow);

            card.Child = rootGrid;
            card.PointerPressed += (s, e) => ShowModDetails(mod, modIcon.Source);
            return card;
        }

        private static string CapitalizeFirst(string value)
        {
            if (string.IsNullOrEmpty(value)) return value;
            return char.ToUpperInvariant(value[0]) + value.Substring(1).ToLowerInvariant();
        }

        private void ShowModDetails(ModrinthProject mod, IImage? iconSource)
        {
            _selectedMod = mod;

            if (_modDetailsSidebar != null) _modDetailsSidebar.IsVisible = true;
            if (_modDetailsTitle != null) _modDetailsTitle.Text = mod.title;
            if (_modDetailsDescription != null)
                _modDetailsDescription.Text = string.IsNullOrWhiteSpace(mod.description) ? "No description available." : mod.description;

            if (_modDetailsStats != null)
            {
                var author = string.IsNullOrWhiteSpace(mod.author) ? "unknown" : mod.author;
                _modDetailsStats.Text = $"by {author}   •   ⬇ {FormatCount(mod.downloads)}   •   ♥ {FormatCount(mod.follows)}";
            }

            if (_modDetailsIcon != null)
            {
                if (iconSource != null) _modDetailsIcon.Source = iconSource;
                else if (!string.IsNullOrEmpty(mod.icon_url)) _ = LoadModIcon(_modDetailsIcon, mod.icon_url);
            }

            if (_modDetailsDownloadButton != null)
            {
                bool isBundled = !string.IsNullOrEmpty(mod.project_id) && BundledModIds.Contains(mod.project_id);
                string ptypeLower = (mod.project_type ?? "").ToLowerInvariant();
                bool isModType = ptypeLower == "" || ptypeLower == "mod";
                bool supportsFabric = !isModType || mod.loaders == null || mod.loaders.Count == 0 ||
                    mod.loaders.Any(l => l.Equals("fabric", StringComparison.OrdinalIgnoreCase));
                bool isInstalled = !isBundled && supportsFabric && (
                    isModType
                        ? IsModAlreadyInstalled(mod, _currentSettings.SelectedSubVersion)
                        : IsContentInstalled(mod));

                if (isBundled)
                {
                    _modDetailsDownloadButton.IsEnabled = false;
                    _modDetailsDownloadButton.Content = "Already included with LeafClient";
                    _modDetailsDownloadButton.Background = new SolidColorBrush(Color.Parse("#1A2332"));
                }
                else if (!supportsFabric)
                {
                    _modDetailsDownloadButton.IsEnabled = false;
                    _modDetailsDownloadButton.Content = "Fabric only - not supported";
                    _modDetailsDownloadButton.Background = new SolidColorBrush(Color.Parse("#1A2332"));
                }
                else if (isInstalled)
                {
                    _modDetailsDownloadButton.IsEnabled = false;
                    _modDetailsDownloadButton.Content = "Installed";
                    _modDetailsDownloadButton.Background = new SolidColorBrush(Color.Parse("#16532A"));
                }
                else
                {
                    _modDetailsDownloadButton.IsEnabled = true;
                    _modDetailsDownloadButton.Content = "Download";
                    _modDetailsDownloadButton.Background = new SolidColorBrush(Color.Parse("#22C55E"));
                }
            }
        }

        private string FormatCount(long count)
        {
            if (count >= 1000000) return (count / 1000000.0).ToString("0.0") + "M";
            if (count >= 1000) return (count / 1000.0).ToString("0.0") + "K";
            return count.ToString();
        }

        private void OnModDetailsViewOnModrinthClicked(object? sender, RoutedEventArgs e)
        {
            if (_selectedMod == null) return;
            try
            {
                string slug = !string.IsNullOrWhiteSpace(_selectedMod.slug) ? _selectedMod.slug! : _selectedMod.project_id ?? "";
                if (string.IsNullOrWhiteSpace(slug)) return;
                string ptype = (_selectedMod.project_type ?? "mod").ToLowerInvariant();
                string urlSegment = ptype switch
                {
                    "modpack" => "modpack",
                    "resourcepack" => "resourcepack",
                    "shader" => "shader",
                    "plugin" => "plugin",
                    "datapack" => "datapack",
                    _ => "mod",
                };
                string url = $"https://modrinth.com/{urlSegment}/{slug}";
                Process.Start(new ProcessStartInfo { FileName = url, UseShellExecute = true });
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Modrinth", $"Open URL failed: {ex.Message}");
                ToastService.Show("Could not open Modrinth page.", ToastType.Error);
            }
        }

        private async void OnModDetailsDownloadClicked(object? sender, RoutedEventArgs e)
        {
            if (_selectedMod == null) return;
            var btn = _modDetailsDownloadButton;
            if (btn != null)
            {
                btn.IsEnabled = false;
                btn.Content = "Installing...";
                btn.Background = new SolidColorBrush(Color.Parse("#16A34A"));
            }
            try
            {
                await InstallMod(_selectedMod);
                if (btn != null)
                {
                    btn.Content = "Installed";
                    btn.Background = new SolidColorBrush(Color.Parse("#16532A"));
                    btn.IsEnabled = false;
                }
            }
            catch
            {
                if (btn != null)
                {
                    btn.Content = "Download";
                    btn.Background = new SolidColorBrush(Color.Parse("#22C55E"));
                    btn.IsEnabled = true;
                }
                throw;
            }
        }

        private async Task LoadModIcon(Image image, string iconUrl)
        {
            await LoadModIcon(image, iconUrl, default, 0);
        }

        private async Task LoadModIcon(Image image, string iconUrl, CancellationToken ct, long expectedEpoch)
        {
            try
            {
                var imageBytes = await _modrinthClient.GetByteArrayAsync(iconUrl, ct);
                ct.ThrowIfCancellationRequested();
                if (expectedEpoch != 0 && System.Threading.Interlocked.Read(ref _searchModsEpoch) != expectedEpoch)
                    return;
                using var stream = new MemoryStream(imageBytes);
                image.Source = new Avalonia.Media.Imaging.Bitmap(stream);
            }
            catch (OperationCanceledException)
            {
            }
            catch (System.Net.Http.HttpRequestException) when (ct.IsCancellationRequested)
            {
            }
            catch
            {
                if (expectedEpoch != 0 && System.Threading.Interlocked.Read(ref _searchModsEpoch) != expectedEpoch)
                    return;
                try
                {
                    image.Source = new Avalonia.Media.Imaging.Bitmap(
                        AssetLoader.Open(new Uri("avares://LeafClient/Assets/mc-default-icon.png")));
                }
                catch { }
            }
        }

        private string FormatCount(int count)
        {
            if (count >= 1000000)
                return (count / 1000000.0).ToString("0.0") + "M";
            if (count >= 1000)
                return (count / 1000.0).ToString("0.0") + "K";
            return count.ToString();
        }

        private bool IsModAlreadyInstalled(ModrinthProject mod, string mcVersion)
        {
            try
            {
                if (_currentSettings.InstalledMods.Any(m =>
                        m.ModId == mod.project_id &&
                        m.MinecraftVersion == mcVersion))
                    return true;

                string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                if (!System.IO.Directory.Exists(modsFolder)) return false;

                string slug = (mod.slug ?? mod.title ?? "").ToLowerInvariant();
                if (string.IsNullOrWhiteSpace(slug)) return false;
                string slugStem = new string(slug.Where(c => char.IsLetterOrDigit(c) || c == '-' || c == '_').ToArray());
                if (string.IsNullOrWhiteSpace(slugStem)) return false;

                foreach (var f in System.IO.Directory.EnumerateFiles(modsFolder, "*.jar"))
                {
                    var name = System.IO.Path.GetFileName(f).ToLowerInvariant();
                    if (name.Contains(slugStem)) return true;
                }
            }
            catch { }
            return false;
        }

        private async Task InstallMod(ModrinthProject mod)
        {
            var ptype = (mod.project_type ?? "").ToLowerInvariant();
            if ((ptype == "" || ptype == "mod" || ptype == "modpack") && AnyGameRunning)
            {
                ToastService.Show("Quit all running Minecraft instances before installing mods.", ToastType.Info);
                return;
            }
            if (ptype == "shader")
            {
                await InstallShader(mod);
                return;
            }
            if (ptype == "modpack")
            {
                await InstallModpack(mod);
                return;
            }
            if (ptype == "resourcepack")
            {
                await InstallResourcePack(mod);
                return;
            }

            var mcVersion = _currentSettings.SelectedSubVersion;
            if (IsModAlreadyInstalled(mod, mcVersion))
            {
                ToastService.Show($"'{mod.title}' is already installed\nFind it in Installed Mods.", ToastType.Info);
                if (!_currentSettings.InstalledMods.Any(m => m.ModId == mod.project_id && m.MinecraftVersion == mcVersion))
                {
                    _currentSettings.InstalledMods.Add(new InstalledMod
                    {
                        ModId = mod.project_id,
                        Name = mod.title,
                        Description = mod.description ?? "",
                        Version = "existing",
                        MinecraftVersion = mcVersion,
                        FileName = "",
                        DownloadUrl = "",
                        Enabled = true,
                        InstallDate = DateTime.Now,
                        IconUrl = mod.icon_url ?? ""
                    });
                    try { await _settingsService.SaveSettingsAsync(_currentSettings); } catch { }
                    await Dispatcher.UIThread.InvokeAsync(() => { LoadUserMods(); });
                }
                return;
            }

            try
            {
                var versions = await LeafClient.Services.ModrinthApi.GetAllProjectVersionsDetailedAsync(mod.project_id);

                try
                {
                    var currentVersion = ResolveCurrentMcVersion();
                    if (string.IsNullOrWhiteSpace(currentVersion))
                    {
                        ToastService.Show("Installation failed\nNo Minecraft version selected. Pick a version on the Home page first.", ToastType.Error);
                        return;
                    }

                    var compatibleVersion = versions.FirstOrDefault(v =>
                        v.GameVersions.Contains(currentVersion) &&
                        v.loaders.Contains("fabric"));

                    if (compatibleVersion == null)
                    {
                        ToastService.Show($"Installation failed\nNo compatible version for Minecraft {currentVersion} + Fabric.", ToastType.Error);
                        return;
                    }

                    var modFile = compatibleVersion.files.FirstOrDefault(f =>
                        f.filename.EndsWith(".jar", StringComparison.OrdinalIgnoreCase));

                    if (modFile == null)
                    {
                        ToastService.Show("Installation failed\nNo valid .jar file found.", ToastType.Error);
                        return;
                    }

                    var installedMod = new InstalledMod
                    {
                        ModId = mod.project_id,
                        Name = mod.title,
                        Description = mod.description ?? "No description available",
                        Version = compatibleVersion.version_number,
                        MinecraftVersion = currentVersion,
                        FileName = modFile.filename,
                        DownloadUrl = modFile.url,
                        Enabled = true,
                        InstallDate = DateTime.Now,
                        IconUrl = mod.icon_url ?? ""
                    };

                    await DownloadAndInstallMod(modFile.url, modFile.filename, mod.title, installedMod);

                    if (!_currentSettings.InstalledMods.Any(m => m.ModId == installedMod.ModId && m.MinecraftVersion == installedMod.MinecraftVersion))
                    {
                        _currentSettings.InstalledMods.Add(installedMod);
                        LeafClient.Services.LeafLog.Info("User Mods", $"Added '{mod.title}' to settings, now {_currentSettings.InstalledMods.Count} mods total");
                        await _settingsService.SaveSettingsAsync(_currentSettings);
                        LeafClient.Services.LeafLog.Info("User Mods", $"Settings saved successfully");
                    }
                    else
                    {
                        LeafClient.Services.LeafLog.Info("User Mods", $"Mod '{mod.title}' for MC {installedMod.MinecraftVersion} already exists in settings. Updating existing entry.");
                        var existingMod = _currentSettings.InstalledMods.First(m => m.ModId == installedMod.ModId && m.MinecraftVersion == installedMod.MinecraftVersion);
                        existingMod.Name = installedMod.Name;
                        existingMod.Description = installedMod.Description;
                        existingMod.Version = installedMod.Version;
                        existingMod.FileName = installedMod.FileName;
                        existingMod.DownloadUrl = installedMod.DownloadUrl;
                        existingMod.Enabled = true;
                        existingMod.InstallDate = DateTime.Now;
                        existingMod.IconUrl = installedMod.IconUrl;
                        await _settingsService.SaveSettingsAsync(_currentSettings);
                        LeafClient.Services.LeafLog.Info("User Mods", $"Settings updated for '{mod.title}'.");
                    }

                    await Dispatcher.UIThread.InvokeAsync(() => { LoadUserMods(); });

                    ToastService.Show($"'{mod.title}' installed\nFind it in Installed Mods.", ToastType.Success);

                }
                catch (NotSupportedException ex)
                {
                    LeafClient.Services.LeafLog.Error("JSON ERROR in InstallMod", $"{ex.Message}");
                    LeafClient.Services.LeafLog.Error("JSON ERROR", $"Stack trace: {ex.StackTrace}");
                    throw;
                }

            }
            catch (JsonException jsonEx)
            {
                ToastService.Show($"Install failed\nJSON error: {jsonEx.Message}", ToastType.Error);
            }
            catch (Exception ex)
            {
                ToastService.Show($"Install failed\n{ex.Message}", ToastType.Error);
            }
        }

        private string ModpacksTrackingPath
            => System.IO.Path.Combine(_minecraftFolder, "leafclient", "modpacks-installed.json");

        private string ShadersTrackingPath
            => System.IO.Path.Combine(_minecraftFolder, "leafclient", "shaders-installed.json");

        private string ResourcePacksTrackingPath
            => System.IO.Path.Combine(_minecraftFolder, "leafclient", "resourcepacks-installed.json");

        private List<InstalledContentEntry> LoadInstalledContent(string path)
        {
            try
            {
                if (!File.Exists(path)) return new();
                var json = File.ReadAllText(path);
                return JsonSerializer.Deserialize(json, JsonContext.Default.ListInstalledContentEntry) ?? new();
            }
            catch { return new(); }
        }

        private void RecordInstalledContent(string path, ModrinthProject project, string fileName)
        {
            try
            {
                Directory.CreateDirectory(System.IO.Path.GetDirectoryName(path)!);
                var list = LoadInstalledContent(path);
                list.RemoveAll(e => e.ProjectId == project.project_id);
                list.Insert(0, new InstalledContentEntry
                {
                    ProjectId   = project.project_id ?? "",
                    Slug        = project.slug ?? "",
                    Title       = project.title ?? "",
                    IconUrl     = project.icon_url ?? "",
                    FileName    = fileName ?? "",
                    InstalledAt = DateTime.UtcNow,
                });
                File.WriteAllText(path,
                    JsonSerializer.Serialize(list, JsonContext.Default.ListInstalledContentEntry));
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("Tracker", $"write failed: {ex.Message}"); }
        }

        private void PruneMissingTrackedContent(string trackerPath, string contentDir)
        {
            try
            {
                if (!File.Exists(trackerPath)) return;
                var list = LoadInstalledContent(trackerPath);
                if (list.Count == 0) return;
                bool changed = false;
                if (!Directory.Exists(contentDir))
                {
                    if (list.Count > 0) { list.Clear(); changed = true; }
                }
                else
                {
                    var present = new HashSet<string>(
                        Directory.EnumerateFileSystemEntries(contentDir).Select(p => System.IO.Path.GetFileName(p)),
                        StringComparer.OrdinalIgnoreCase);
                    int before = list.Count;
                    list.RemoveAll(e => !string.IsNullOrEmpty(e.FileName) && !present.Contains(e.FileName));
                    if (list.Count != before) changed = true;
                }
                if (changed)
                {
                    File.WriteAllText(trackerPath,
                        JsonSerializer.Serialize(list, JsonContext.Default.ListInstalledContentEntry));
                }
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("Tracker", $"prune failed: {ex.Message}"); }
        }

        private void RecordInstalledModpack(ModrinthProject project, string? targetMcVersion, int fileCount, int overrideCount, List<string>? modFiles = null)
        {
            try
            {
                Directory.CreateDirectory(System.IO.Path.GetDirectoryName(ModpacksTrackingPath)!);
                var list = LoadInstalledModpacks();
                list.RemoveAll(e => e.ProjectId == project.project_id);
                list.Insert(0, new InstalledModpackEntry
                {
                    ProjectId = project.project_id,
                    Slug = project.slug,
                    Title = project.title,
                    IconUrl = project.icon_url ?? "",
                    McVersion = targetMcVersion ?? "",
                    FileCount = fileCount,
                    OverrideCount = overrideCount,
                    InstalledAt = DateTime.UtcNow,
                    ModFiles = modFiles ?? new List<string>(),
                });
                File.WriteAllText(ModpacksTrackingPath,
                    JsonSerializer.Serialize(list, JsonContext.Default.ListInstalledModpackEntry));
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("Modpacks", $"track failed: {ex.Message}"); }
        }

        private HashSet<string> GetModpackPreservedModFiles()
        {
            var set = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            try
            {
                foreach (var e in LoadInstalledModpacks())
                {
                    if (e.ModFiles == null) continue;
                    foreach (var rel in e.ModFiles)
                    {
                        if (string.IsNullOrEmpty(rel)) continue;
                        var norm = rel.Replace('\\', '/');
                        if (norm.StartsWith("mods/", StringComparison.OrdinalIgnoreCase))
                            set.Add(norm.Substring("mods/".Length));
                        else if (norm.IndexOf('/') < 0)
                            set.Add(norm);
                    }
                }
            }
            catch { }
            return set;
        }

        private List<InstalledModpackEntry> LoadInstalledModpacks()
        {
            try
            {
                if (!File.Exists(ModpacksTrackingPath)) return new();
                var json = File.ReadAllText(ModpacksTrackingPath);
                return JsonSerializer.Deserialize(json, JsonContext.Default.ListInstalledModpackEntry) ?? new();
            }
            catch { return new(); }
        }

        private void RefreshInstalledShaders()
        {
            var list = this.FindControl<StackPanel>("InstalledShadersList");
            var empty = this.FindControl<TextBlock>("InstalledShadersEmpty");
            if (list == null) return;
            list.Children.Clear();
            string dir = System.IO.Path.Combine(_minecraftFolder, "shaderpacks");
            try { Directory.CreateDirectory(dir); } catch { }
            string[] files;
            try
            {
                files = Directory.EnumerateFileSystemEntries(dir)
                    .Where(p => System.IO.Path.GetExtension(p).Equals(".zip", StringComparison.OrdinalIgnoreCase)
                             || Directory.Exists(p))
                    .OrderByDescending(p => new FileInfo(p).LastWriteTimeUtc)
                    .ToArray();
            }
            catch { files = Array.Empty<string>(); }
            if (empty != null) empty.IsVisible = files.Length == 0;
            foreach (var path in files)
            {
                list.Children.Add(BuildInstalledFileRow(path, () => RefreshInstalledShaders(), "shaderpacks"));
            }
        }

        private void RefreshInstalledModpacks()
        {
            var list = this.FindControl<StackPanel>("InstalledModpacksList");
            var empty = this.FindControl<TextBlock>("InstalledModpacksEmpty");
            if (list == null) return;
            list.Children.Clear();
            var entries = LoadInstalledModpacks();
            if (empty != null) empty.IsVisible = entries.Count == 0;
            foreach (var e in entries)
            {
                list.Children.Add(BuildInstalledModpackRow(e));
            }
        }

