        private static Border MakeContentPillToggle(bool initial, Action<bool> onChanged)
        {
            bool state = initial;

            var thumb = new Border
            {
                Width  = 16,
                Height = 16,
                CornerRadius = new CornerRadius(8),
                Background   = SolidColorBrush.Parse("#E5E7EB"),
                HorizontalAlignment = state ? Avalonia.Layout.HorizontalAlignment.Right : Avalonia.Layout.HorizontalAlignment.Left,
                Margin = new Thickness(3, 0, 3, 0),
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
            };

            var track = new Border
            {
                Width  = 44,
                Height = 22,
                CornerRadius    = new CornerRadius(11),
                Background      = SolidColorBrush.Parse(state ? "#1F7A3A" : "#1F2937"),
                BorderBrush     = SolidColorBrush.Parse(state ? "#2D8E4D" : "#374151"),
                BorderThickness = new Thickness(1),
                Cursor          = new Cursor(StandardCursorType.Hand),
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                Child = thumb,
            };

            track.Tapped += (_, _) =>
            {
                state = !state;
                thumb.HorizontalAlignment = state ? Avalonia.Layout.HorizontalAlignment.Right : Avalonia.Layout.HorizontalAlignment.Left;
                track.Background  = SolidColorBrush.Parse(state ? "#1F7A3A" : "#1F2937");
                track.BorderBrush = SolidColorBrush.Parse(state ? "#2D8E4D" : "#374151");
                onChanged(state);
            };

            return track;
        }

        private Border BuildInstalledFileRow(string fullPath, Action onChanged, string folderLabel)
        {
            string name = System.IO.Path.GetFileName(fullPath);
            string sizeStr;
            try
            {
                long size = Directory.Exists(fullPath)
                    ? Directory.EnumerateFiles(fullPath, "*", SearchOption.AllDirectories).Sum(f => new FileInfo(f).Length)
                    : new FileInfo(fullPath).Length;
                sizeStr = size > 1024 * 1024
                    ? $"{size / 1024.0 / 1024.0:0.0} MB"
                    : $"{size / 1024.0:0} KB";
            }
            catch { sizeStr = ""; }

            var row = new Border
            {
                Background      = SolidColorBrush.Parse("#0F1A24"),
                BorderBrush     = SolidColorBrush.Parse("#1C2A38"),
                BorderThickness = new Thickness(1),
                CornerRadius    = new CornerRadius(12),
                Padding         = new Thickness(14, 12),
            };
            var grid = new Grid { ColumnDefinitions = new ColumnDefinitions("*,Auto") };

            var info = new StackPanel { Spacing = 3, VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center };
            info.Children.Add(new TextBlock
            {
                Text         = name,
                Foreground   = SolidColorBrush.Parse("#E5E7EB"),
                FontWeight   = FontWeight.SemiBold,
                FontSize     = 13,
                TextTrimming = TextTrimming.CharacterEllipsis,
            });
            info.Children.Add(new TextBlock
            {
                Text       = $"{sizeStr}  \u2022  in /{folderLabel}",
                Foreground = SolidColorBrush.Parse("#6B7280"),
                FontSize   = 10,
            });
            Grid.SetColumn(info, 0);
            grid.Children.Add(info);

            var actions = new StackPanel
            {
                Orientation       = Avalonia.Layout.Orientation.Horizontal,
                Spacing           = 6,
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
            };

            var openBtn = MakeContentVectorPillButton(ContentRowOpenIconData, "#0B1018", "#1C2A38", "#9CA3AF");
            openBtn.Tapped += (_, _) =>
            {
                LeafClient.Utils.SystemUtil.OpenFolder(System.IO.Path.GetDirectoryName(fullPath) ?? fullPath);
            };

            var delBtn = MakeContentVectorPillButton(ContentRowTrashIconData, "#1A0B0B", "#3B1F1F", "#F87171");
            delBtn.Tapped += (_, _) =>
            {
                try
                {
                    if (Directory.Exists(fullPath)) Directory.Delete(fullPath, true);
                    else File.Delete(fullPath);
                }
                catch (Exception ex) { ToastService.Show($"Delete failed: {ex.Message}", ToastType.Error); }
                onChanged();
            };

            actions.Children.Add(openBtn);
            actions.Children.Add(delBtn);
            Grid.SetColumn(actions, 1);
            grid.Children.Add(actions);

            row.Child = grid;
            return row;
        }

        private Border BuildInstalledModpackRow(InstalledModpackEntry e)
        {
            var row = new Border
            {
                Background      = SolidColorBrush.Parse("#0F1A24"),
                BorderBrush     = SolidColorBrush.Parse("#1C2A38"),
                BorderThickness = new Thickness(1),
                CornerRadius    = new CornerRadius(12),
                Padding         = new Thickness(14, 12),
            };
            var grid = new Grid { ColumnDefinitions = new ColumnDefinitions("*,Auto") };

            var info = new StackPanel { Spacing = 3, VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center };
            info.Children.Add(new TextBlock
            {
                Text         = e.Title,
                Foreground   = SolidColorBrush.Parse("#E5E7EB"),
                FontWeight   = FontWeight.SemiBold,
                FontSize     = 13,
                TextTrimming = TextTrimming.CharacterEllipsis,
            });
            info.Children.Add(new TextBlock
            {
                Text       = $"{e.FileCount} mods, {e.OverrideCount} overrides  \u2022  MC {e.McVersion}  \u2022  {e.InstalledAt:yyyy-MM-dd}",
                Foreground = SolidColorBrush.Parse("#6B7280"),
                FontSize   = 10,
            });
            Grid.SetColumn(info, 0);
            grid.Children.Add(info);

            var actions = new StackPanel
            {
                Orientation       = Avalonia.Layout.Orientation.Horizontal,
                Spacing           = 6,
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
            };

            var openBtn = MakeContentVectorPillButton(ContentRowOpenIconData, "#0B1018", "#1C2A38", "#9CA3AF");
            openBtn.Tapped += (_, _) =>
            {
                LeafClient.Utils.SystemUtil.OpenFolder(System.IO.Path.Combine(_minecraftFolder, "mods"));
            };

            var delBtn = MakeContentVectorPillButton(ContentRowTrashIconData, "#1A0B0B", "#3B1F1F", "#F87171");
            delBtn.Tapped += (_, _) =>
            {
                try
                {
                    var entries = LoadInstalledModpacks();
                    var target = entries.FirstOrDefault(x => x.ProjectId == e.ProjectId);
                    if (target?.ModFiles != null)
                    {
                        foreach (var rel in target.ModFiles)
                        {
                            try
                            {
                                string p = System.IO.Path.Combine(_minecraftFolder, rel.Replace('/', System.IO.Path.DirectorySeparatorChar));
                                if (File.Exists(p)) File.Delete(p);
                            }
                            catch { }
                        }
                    }
                    entries.RemoveAll(x => x.ProjectId == e.ProjectId);
                    File.WriteAllText(ModpacksTrackingPath,
                        JsonSerializer.Serialize(entries, JsonContext.Default.ListInstalledModpackEntry));
                }
                catch { }
                RefreshInstalledModpacks();
            };

            actions.Children.Add(openBtn);
            actions.Children.Add(delBtn);
            Grid.SetColumn(actions, 1);
            grid.Children.Add(actions);

            row.Child = grid;
            return row;
        }

        private bool IsContentInstalled(ModrinthProject mod)
        {
            try
            {
                string ptype = (mod.project_type ?? "").ToLowerInvariant();
                if (ptype == "modpack")
                {
                    return LoadInstalledModpacks().Any(e => e.ProjectId == mod.project_id);
                }
                if (ptype == "shader")
                {
                    string dir = System.IO.Path.Combine(_minecraftFolder, "shaderpacks");
                    PruneMissingTrackedContent(ShadersTrackingPath, dir);
                    if (LoadInstalledContent(ShadersTrackingPath).Any(e => e.ProjectId == mod.project_id))
                        return true;
                    if (!Directory.Exists(dir)) return false;
                    return Directory.EnumerateFileSystemEntries(dir)
                        .Any(p => System.IO.Path.GetFileNameWithoutExtension(p)
                                  .Contains(mod.slug ?? "", StringComparison.OrdinalIgnoreCase));
                }
                if (ptype == "resourcepack")
                {
                    string dir = System.IO.Path.Combine(_minecraftFolder, "resourcepacks");
                    PruneMissingTrackedContent(ResourcePacksTrackingPath, dir);
                    if (LoadInstalledContent(ResourcePacksTrackingPath).Any(e => e.ProjectId == mod.project_id))
                        return true;
                    if (!Directory.Exists(dir)) return false;
                    return Directory.EnumerateFileSystemEntries(dir)
                        .Any(p => System.IO.Path.GetFileNameWithoutExtension(p)
                                  .Contains(mod.slug ?? "", StringComparison.OrdinalIgnoreCase));
                }
            }
            catch { }
            return false;
        }

        private async Task InstallResourcePack(ModrinthProject project)
        {
            try
            {
                var versions = await LeafClient.Services.ModrinthApi.GetAllProjectVersionsDetailedAsync(project.project_id);
                string currentMc = ResolveCurrentMcVersion() ?? "";
                ModrinthVersionDetailed? latest = null;
                if (!string.IsNullOrEmpty(currentMc))
                    latest = versions.FirstOrDefault(v => v.GameVersions != null && v.GameVersions.Contains(currentMc, StringComparer.OrdinalIgnoreCase));
                latest ??= versions.FirstOrDefault();
                if (latest == null)
                {
                    ToastService.Show("No resource pack versions found.", ToastType.Error);
                    return;
                }
                var file = latest.files.FirstOrDefault(f =>
                    f.filename.EndsWith(".zip", StringComparison.OrdinalIgnoreCase));
                if (file == null)
                {
                    ToastService.Show("No resource pack .zip found.", ToastType.Error);
                    return;
                }

                string rpDir = System.IO.Path.Combine(_minecraftFolder, "resourcepacks");
                Directory.CreateDirectory(rpDir);
                string destPath = System.IO.Path.Combine(rpDir, file.filename);

                ToastService.Show($"Downloading resource pack '{project.title}'...", ToastType.Info);
                await DownloadAndVerifyModrinthFileAsync(file, destPath, project.title);
                RecordInstalledContent(ResourcePacksTrackingPath, project, file.filename);
                ToastService.Show($"Resource pack '{project.title}' installed\nEnable it in-game via Options → Resource Packs.", ToastType.Success);
                if (_activeModsTab == "rp" && _resourcePacksPage != null) _resourcePacksPage.LoadResourcePacksPage();
            }
            catch (Exception ex)
            {
                ToastService.Show($"Resource pack install failed\n{ex.Message}", ToastType.Error);
                LeafClient.Services.LeafLog.Info("InstallResourcePack", $"{ex}");
            }
        }

        private async Task InstallShader(ModrinthProject project)
        {
            try
            {
                var versions = await LeafClient.Services.ModrinthApi.GetAllProjectVersionsDetailedAsync(project.project_id);
                string currentMc = ResolveCurrentMcVersion() ?? "";
                ModrinthVersionDetailed? latest = null;
                if (!string.IsNullOrEmpty(currentMc))
                    latest = versions.FirstOrDefault(v => v.GameVersions != null && v.GameVersions.Contains(currentMc, StringComparer.OrdinalIgnoreCase));
                latest ??= versions.FirstOrDefault();
                if (latest == null)
                {
                    ToastService.Show("No shader versions found.", ToastType.Error);
                    return;
                }
                var file = latest.files.FirstOrDefault(f =>
                    f.filename.EndsWith(".zip", StringComparison.OrdinalIgnoreCase));
                if (file == null)
                {
                    ToastService.Show("No shader .zip found.", ToastType.Error);
                    return;
                }

                string shaderpacksDir = System.IO.Path.Combine(_minecraftFolder, "shaderpacks");
                Directory.CreateDirectory(shaderpacksDir);
                string destPath = System.IO.Path.Combine(shaderpacksDir, file.filename);

                ToastService.Show($"Downloading shader '{project.title}'...", ToastType.Info);
                await DownloadAndVerifyModrinthFileAsync(file, destPath, project.title);
                RecordInstalledContent(ShadersTrackingPath, project, file.filename);

                string mcVer = _currentSettings.SelectedSubVersion ?? "";
                string modsDir = System.IO.Path.Combine(_minecraftFolder, "mods");
                bool hasIris = Directory.Exists(modsDir) && Directory.EnumerateFiles(modsDir, "*.jar")
                    .Any(p => System.IO.Path.GetFileName(p).IndexOf("iris", StringComparison.OrdinalIgnoreCase) >= 0);
                if (!hasIris && !string.IsNullOrEmpty(mcVer))
                {
                    ToastService.Show("Installing Iris + Sodium so the shader can run...", ToastType.Info);
                    try
                    {
                        await InstallSodiumIfNeededAsync(mcVer);
                        await InstallIrisShadersIfNeededAsync(mcVer);
                        ToastService.Show($"Shader '{project.title}' installed\nIris+Sodium added. Launch, then Video → Shader Packs.", ToastType.Success);
                    }
                    catch (Exception irisEx)
                    {
                        LeafClient.Services.LeafLog.Error("InstallShader", $"Iris auto-install failed: {irisEx.Message}");
                        ToastService.Show($"Shader '{project.title}' installed\nNote: install Iris+Sodium manually to use it.", ToastType.Success);
                    }
                }
                else
                {
                    ToastService.Show($"Shader '{project.title}' installed\nLaunch, then Video → Shader Packs.", ToastType.Success);
                }
                if (_activeModsTab == "shaders") RefreshInstalledShaders();
            }
            catch (Exception ex)
            {
                ToastService.Show($"Shader install failed\n{ex.Message}", ToastType.Error);
                LeafClient.Services.LeafLog.Info("InstallShader", $"{ex}");
            }
        }

        public async Task<bool> InstallLocalMrpackAsync(string mrpackPath, string title)
        {
            try
            {
                if (!File.Exists(mrpackPath))
                {
                    ToastService.Show($"Modpack file not found:\n{mrpackPath}", ToastType.Error);
                    return false;
                }

                var pseudo = new ModrinthProject(
                    project_id: $"local-{Guid.NewGuid():N}",
                    project_type: "modpack",
                    slug: title.ToLowerInvariant().Replace(' ', '-'),
                    title: title,
                    description: "Imported from local file",
                    icon_url: "",
                    downloads: 0,
                    follows: 0,
                    author: "",
                    versions: new List<string>(),
                    date_created: "",
                    date_modified: "",
                    license: "",
                    client_side: "",
                    server_side: "",
                    categories: new List<string>(),
                    loaders: new List<string>()
                );

                ToastService.Show($"Installing modpack '{title}'...", ToastType.Info);
                return await InstallModpackFromMrpackPath(pseudo, mrpackPath, deleteAfter: false);
            }
            catch (Exception ex)
            {
                ToastService.Show($"Modpack install failed\n{ex.Message}", ToastType.Error);
                LeafClient.Services.LeafLog.Info("InstallLocalMrpack", $"{ex}");
                return false;
            }
        }

        private async Task InstallModpack(ModrinthProject project)
        {
            try
            {
                var versions = await LeafClient.Services.ModrinthApi.GetAllProjectVersionsDetailedAsync(project.project_id);
                string currentMc = ResolveCurrentMcVersion() ?? "";
                ModrinthVersionDetailed? latest = null;
                if (!string.IsNullOrEmpty(currentMc))
                    latest = versions.FirstOrDefault(v => v.GameVersions != null && v.GameVersions.Contains(currentMc, StringComparer.OrdinalIgnoreCase));
                latest ??= versions.FirstOrDefault();
                if (latest == null)
                {
                    ToastService.Show($"No modpack versions found for Minecraft {currentMc}.", ToastType.Error);
                    return;
                }
                var file = latest.files.FirstOrDefault(f =>
                    f.filename.EndsWith(".mrpack", StringComparison.OrdinalIgnoreCase));
                if (file == null)
                {
                    ToastService.Show("No .mrpack file in latest modpack version.", ToastType.Error);
                    return;
                }

                string tempPath = System.IO.Path.Combine(System.IO.Path.GetTempPath(),
                    $"leafclient-mrpack-{Guid.NewGuid():N}.mrpack");
                ToastService.Show($"Downloading modpack '{project.title}'...", ToastType.Info);
                await DownloadAndVerifyModrinthFileAsync(file, tempPath, project.title);
                await InstallModpackFromMrpackPath(project, tempPath, deleteAfter: true);
