        private static Avalonia.Controls.Control BuildPaymentProvidersRow()
        {
            var wrap = new WrapPanel
            {
                Orientation = Avalonia.Layout.Orientation.Horizontal,
                Margin = new Thickness(0, 4, 0, 0),
            };
            foreach (var (slug, fill, pathData) in BrandIconPaths)
            {
                var chip = new Border
                {
                    Background = new SolidColorBrush(Color.Parse("#FFFFFF")),
                    CornerRadius = new CornerRadius(4),
                    Padding = new Thickness(6, 4),
                    Margin = new Thickness(0, 0, 6, 6),
                    Width = 44,
                    Height = 28,
                    BorderBrush = new SolidColorBrush(Color.Parse("#1A2332")),
                    BorderThickness = new Thickness(1),
                    Child = new Avalonia.Controls.Shapes.Path
                    {
                        Data = Geometry.Parse(pathData),
                        Fill = new SolidColorBrush(Color.Parse(fill)),
                        Stretch = Stretch.Uniform,
                        HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                        VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                    },
                };
                wrap.Children.Add(chip);
            }
            return wrap;
        }

        private async void ClosePurchasePopup()
        {
            if (_purchasePopupOverlay == null || !_purchasePopupOverlay.IsVisible) return;
            if (_isPurchasePopupAnimating) return;
            _isPurchasePopupAnimating = true;

            if (AreAnimationsEnabled() && _purchasePopupPanel != null)
            {
                var st = _purchasePopupPanel.RenderTransform as ScaleTransform ?? new ScaleTransform();
                _purchasePopupPanel.RenderTransform = st;

                const int dur = 150;
                const int frames = 10;
                const int delay = dur / frames;

                for (int i = 0; i <= frames; i++)
                {
                    double t = (double)i / frames;
                    double eased = t * t;

                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        if (_purchasePopupOverlay != null) _purchasePopupOverlay.Opacity = 1 - eased;
                        if (_purchasePopupPanel != null) _purchasePopupPanel.Opacity = 1 - eased;
                        st.ScaleX = 1 - 0.1 * eased;
                        st.ScaleY = 1 - 0.1 * eased;
                    });

                    if (i < frames) await Task.Delay(delay);
                }
            }

            _purchasePopupOverlay.IsVisible = false;
            var rootGrid = this.FindControl<Grid>("RootGrid") ?? (Content as Grid);
            if (rootGrid != null && _purchasePopupOverlay != null)
                rootGrid.Children.Remove(_purchasePopupOverlay);
            _purchasePopupOverlay = null;
            _purchasePopupPanel = null;
            _isPurchasePopupAnimating = false;
        }

        private async Task HandleCoinPurchaseFromPopup(string itemId, string itemName, string preview, string rarity, int coinPrice)
        {
            var token = await EnsureLeafJwtAsync();
            if (string.IsNullOrEmpty(token)) return;

            var (success, newCoins, error) = await LeafApiService.PurchaseCosmeticWithCoinsAsync(token, itemId);

            if (success)
            {
                ClosePurchasePopup();
                _ownedCosmeticIds.Add(itemId);
                SaveOwnedJson();
                _cosmeticsPage?.RefreshOwnedList(_ownedCosmeticIds);
                _currentCoinBalance = newCoins;
                Dispatcher.UIThread.Post(() =>
                {
                    _leafsBalanceText ??= this.FindControl<TextBlock>("LeafsBalanceText");
                    if (_leafsBalanceText != null)
                        _leafsBalanceText.Text = newCoins.ToString("N0");
                });
                ShowPurchaseCelebration(itemId, itemName, preview, rarity);
                _storePage?.RefreshAfterPurchase(itemId);
            }
            else
            {
                ClosePurchasePopup();
                ToastService.Show(error ?? "Purchase failed.", ToastType.Error);
            }
        }

        private bool _isMonthlyPassAnimating;

        public async void ShowMonthlyPassPopup()
        {
            var overlay = this.FindControl<Grid>("MonthlyPassOverlay");
            var panel   = this.FindControl<Border>("MonthlyPassPanel");
            var backdrop= this.FindControl<Border>("MonthlyPassBackdrop");
            if (overlay == null || panel == null) return;
            if (_isMonthlyPassAnimating || overlay.IsVisible) return;

            _isMonthlyPassAnimating = true;

            if (this.FindControl<Border>("LeafPlusTier_Monthly") is { } monthlyPill)
            {
                OnLeafPlusTierTapped(monthlyPill, null!);
            }

            overlay.IsVisible = true;
            if (backdrop != null) backdrop.Opacity = 0;
            panel.Opacity = 0;

            var st = panel.RenderTransform as ScaleTransform ?? new ScaleTransform(0.85, 0.85);
            panel.RenderTransform       = st;
            panel.RenderTransformOrigin = new RelativePoint(0.5, 0.5, RelativeUnit.Relative);
            st.ScaleX = 0.85;
            st.ScaleY = 0.85;

            if (!AreAnimationsEnabled())
            {
                if (backdrop != null) backdrop.Opacity = 1;
                panel.Opacity = 1;
                st.ScaleX = 1; st.ScaleY = 1;
                _isMonthlyPassAnimating = false;
                return;
            }

            const int steps = 18;
            const int durationMs = 260;
            for (int i = 0; i <= steps; i++)
            {
                double t    = (double)i / steps;
                double ease = 1 - Math.Pow(1 - t, 3);
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (backdrop != null) backdrop.Opacity = ease;
                    panel.Opacity = ease;
                    st.ScaleX = 0.85 + 0.15 * ease;
                    st.ScaleY = 0.85 + 0.15 * ease;
                });
                if (i < steps) await Task.Delay(durationMs / steps);
            }

            _isMonthlyPassAnimating = false;
        }

        private async void CloseMonthlyPassPopup()
        {
            var overlay = this.FindControl<Grid>("MonthlyPassOverlay");
            var panel   = this.FindControl<Border>("MonthlyPassPanel");
            var backdrop= this.FindControl<Border>("MonthlyPassBackdrop");
            if (overlay == null || panel == null) return;
            if (!overlay.IsVisible || _isMonthlyPassAnimating) return;

            _isMonthlyPassAnimating = true;

            var st = panel.RenderTransform as ScaleTransform ?? new ScaleTransform(1, 1);
            panel.RenderTransform = st;

            if (!AreAnimationsEnabled())
            {
                overlay.IsVisible = false;
                _isMonthlyPassAnimating = false;
                return;
            }

            const int steps = 14;
            const int durationMs = 200;
            for (int i = 0; i <= steps; i++)
            {
                double t    = (double)i / steps;
                double ease = Math.Pow(t, 2);
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (backdrop != null) backdrop.Opacity = 1 - ease;
                    panel.Opacity = 1 - ease;
                    st.ScaleX = 1.0 - 0.15 * ease;
                    st.ScaleY = 1.0 - 0.15 * ease;
                });
                if (i < steps) await Task.Delay(durationMs / steps);
            }

            overlay.IsVisible = false;
            _isMonthlyPassAnimating = false;
        }

        private void OnMonthlyPassClose(object? sender, TappedEventArgs e) => CloseMonthlyPassPopup();
        private void OnMonthlyPassBackdropTapped(object? sender, TappedEventArgs e) => CloseMonthlyPassPopup();

        private string _selectedLeafPlusTier = "monthly";

        private void OnLeafPlusTierTapped(object? sender, TappedEventArgs e)
        {
            if (sender is not Border pill || pill.Tag is not string tier) return;
            _selectedLeafPlusTier = tier;

            var monthly   = this.FindControl<Border>("LeafPlusTier_Monthly");
            var quarterly = this.FindControl<Border>("LeafPlusTier_Quarterly");
            var yearly    = this.FindControl<Border>("LeafPlusTier_Yearly");

            void Paint(Border? b, bool selected)
            {
                if (b == null) return;
                if (selected)
                {
                    b.Background = SolidColorBrush.Parse("#052E16");
                    b.BorderBrush = SolidColorBrush.Parse("#16A34A");
                    b.BorderThickness = new Thickness(1.5);
                }
                else
                {
                    b.Background = SolidColorBrush.Parse("#0F1A24");
                    b.BorderBrush = SolidColorBrush.Parse("#1C2A38");
                    b.BorderThickness = new Thickness(1);
                }
            }

            Paint(monthly,   tier == "monthly");
            Paint(quarterly, tier == "quarterly");
            Paint(yearly,    tier == "yearly");

            var bMonthly   = this.FindControl<Border>("LeafPlusTierMonthly");
            var bQuarterly = this.FindControl<Border>("LeafPlusTierQuarterly");
            var bYearly    = this.FindControl<Border>("LeafPlusTierYearly");
            void PaintBenefit(Border? b, bool selected, bool isYearly)
            {
                if (b == null) return;
                if (selected)
                {
                    b.BorderBrush = SolidColorBrush.Parse("#34D399");
                    b.BorderThickness = new Thickness(2);
                }
                else if (isYearly)
                {
                    var br = new LinearGradientBrush
                    {
                        StartPoint = new RelativePoint(0, 0, RelativeUnit.Relative),
                        EndPoint   = new RelativePoint(1, 1, RelativeUnit.Relative),
                    };
                    br.GradientStops.Add(new GradientStop(Color.Parse("#22C55E"), 0));
                    br.GradientStops.Add(new GradientStop(Color.Parse("#16A34A"), 1));
                    b.BorderBrush = br;
                    b.BorderThickness = new Thickness(1.5);
                }
                else
                {
                    b.BorderBrush = SolidColorBrush.Parse("#2A2055");
                    b.BorderThickness = new Thickness(1.5);
                }
            }
            PaintBenefit(bMonthly,   tier == "monthly",   isYearly: false);
            PaintBenefit(bQuarterly, tier == "quarterly", isYearly: false);
            PaintBenefit(bYearly,    tier == "yearly",    isYearly: true);
        }

        private bool _isLeafPlusBenefitsAnimating;

        private async void ShowLeafPlusBenefitsPopup()
        {
            var overlay  = this.FindControl<Grid>("LeafPlusBenefitsOverlay");
            var panel    = this.FindControl<Border>("LeafPlusBenefitsPanel");
            var backdrop = this.FindControl<Border>("LeafPlusBenefitsBackdrop");
            if (overlay == null || panel == null) return;
            if (_isLeafPlusBenefitsAnimating || overlay.IsVisible) return;

            _isLeafPlusBenefitsAnimating = true;

            var titleTb        = this.FindControl<TextBlock>("LeafPlusBenefitsTitle");
            var subtitleTb     = this.FindControl<TextBlock>("LeafPlusBenefitsSubtitle");
            var choosePlanTb   = this.FindControl<TextBlock>("LeafPlusBenefitsChoosePlanLabel");
            var tierGrid       = this.FindControl<Grid>("LeafPlusBenefitsTierGrid");
            var continueText   = this.FindControl<TextBlock>("LeafPlusBenefitsContinueText");

            if (_isLeafPlus && !_isTrial)
            {
                string tier = _leafPlusTier switch
                {
                    "yearly"    => "Yearly",
                    "quarterly" => "Quarterly",
                    _           => "Monthly",
                };
                string sub = $"{tier} subscription active";
                if (!string.IsNullOrEmpty(_leafPlusPeriodEnd) &&
                    DateTimeOffset.TryParse(_leafPlusPeriodEnd, out var dt))
                {
                    sub = $"{tier} · renews {dt.ToLocalTime():MMM d, yyyy}";
                }

                if (titleTb      != null) titleTb.Text      = "You're subscribed to Leaf+";
                if (subtitleTb   != null) subtitleTb.Text   = sub;
                if (choosePlanTb != null) choosePlanTb.IsVisible = false;
                if (tierGrid     != null) tierGrid.IsVisible     = false;
                if (continueText != null) continueText.Text = "CLOSE";
            }
            else
            {
                if (_isTrial)
                {
                    if (titleTb      != null) titleTb.Text      = "Upgrade your Leaf+";
                    if (subtitleTb   != null) subtitleTb.Text   = "Keep these features after your trial ends";
                }
                else
                {
                    if (titleTb      != null) titleTb.Text      = "Leaf+";
                    if (subtitleTb   != null) subtitleTb.Text   = "Unlock the full Leaf experience";
                }
                if (choosePlanTb != null) choosePlanTb.IsVisible = true;
                if (tierGrid     != null) tierGrid.IsVisible     = true;
                if (continueText != null) continueText.Text = "CONTINUE";

                if (string.IsNullOrEmpty(_selectedLeafPlusTier)) _selectedLeafPlusTier = "yearly";
                var seedBorder = _selectedLeafPlusTier switch
                {
                    "monthly"   => this.FindControl<Border>("LeafPlusTierMonthly"),
                    "quarterly" => this.FindControl<Border>("LeafPlusTierQuarterly"),
                    _           => this.FindControl<Border>("LeafPlusTierYearly"),
                };
                if (seedBorder != null)
                    OnLeafPlusTierTapped(seedBorder, new TappedEventArgs(Avalonia.Input.Gestures.TappedEvent, null));
            }

            overlay.IsVisible = true;
            if (backdrop != null) backdrop.Opacity = 0;
            panel.Opacity = 0;

            var st = panel.RenderTransform as ScaleTransform ?? new ScaleTransform(0.85, 0.85);
            panel.RenderTransform       = st;
            panel.RenderTransformOrigin = new RelativePoint(0.5, 0.5, RelativeUnit.Relative);
            st.ScaleX = 0.85; st.ScaleY = 0.85;

            if (!AreAnimationsEnabled())
            {
                if (backdrop != null) backdrop.Opacity = 1;
                panel.Opacity = 1;
                st.ScaleX = 1; st.ScaleY = 1;
                _isLeafPlusBenefitsAnimating = false;
                return;
            }

            const int steps = 18;
            const int durationMs = 240;
            for (int i = 0; i <= steps; i++)
            {
                double t = (double)i / steps;
                double ease = 1 - Math.Pow(1 - t, 3);
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (backdrop != null) backdrop.Opacity = ease;
                    panel.Opacity = ease;
                    st.ScaleX = 0.85 + 0.15 * ease;
                    st.ScaleY = 0.85 + 0.15 * ease;
                });
                if (i < steps) await Task.Delay(durationMs / steps);
            }

            _isLeafPlusBenefitsAnimating = false;
        }

        private async void CloseLeafPlusBenefitsPopup()
        {
            var overlay  = this.FindControl<Grid>("LeafPlusBenefitsOverlay");
            var panel    = this.FindControl<Border>("LeafPlusBenefitsPanel");
            var backdrop = this.FindControl<Border>("LeafPlusBenefitsBackdrop");
            if (overlay == null || panel == null || !overlay.IsVisible) return;
            if (_isLeafPlusBenefitsAnimating) return;

            _isLeafPlusBenefitsAnimating = true;

            var st = panel.RenderTransform as ScaleTransform ?? new ScaleTransform(1, 1);

            if (!AreAnimationsEnabled())
            {
                overlay.IsVisible = false;
                _isLeafPlusBenefitsAnimating = false;
                return;
            }

            const int steps = 14;
            const int durationMs = 180;
            for (int i = 0; i <= steps; i++)
            {
                double t = (double)i / steps;
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (backdrop != null) backdrop.Opacity = 1 - t;
                    panel.Opacity = 1 - t;
                    st.ScaleX = 1 - 0.1 * t;
                    st.ScaleY = 1 - 0.1 * t;
                });
                if (i < steps) await Task.Delay(durationMs / steps);
            }
            overlay.IsVisible = false;
            _isLeafPlusBenefitsAnimating = false;
        }

