        private static IEnumerable<string> EnumerateManagedJarsForSlug(string modsFolder, string slug)
        {
            if (string.IsNullOrEmpty(modsFolder) || !System.IO.Directory.Exists(modsFolder)) yield break;
            if (!_slugJarPrefixes.TryGetValue(slug, out var prefixes)) yield break;
            var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (var prefix in prefixes)
            {
                foreach (var f in System.IO.Directory.EnumerateFiles(modsFolder, prefix + "*.jar"))
                {
                    if (seen.Add(f)) yield return f;
                }
            }
        }

        private static bool IsBlockedByEngine(string slug, string engine)
        {
            if (string.IsNullOrEmpty(slug) || string.IsNullOrEmpty(engine)) return false;
            if (!_renderEngineIncompatSlugs.TryGetValue(engine, out var blocked)) return false;
            foreach (var b in blocked)
                if (b.Equals(slug, StringComparison.OrdinalIgnoreCase)) return true;
            return false;
        }

        private static bool ShouldInstallCoreMod(string slug, string preset, string engine, IReadOnlyDictionary<string, bool> overrides)
        {
            if (IsBlockedByEngine(slug, engine)) return false;
            if (overrides != null && overrides.TryGetValue(slug, out var ovr)) return ovr;
            if (!_presetDefaults.TryGetValue(preset ?? "none", out var defaults)) return false;
            return defaults.Contains(slug);
        }

