        private string GetActiveRenderEngine()
        {
            var profile = GetActiveProfile();
            if (profile != null && !string.IsNullOrEmpty(profile.RenderEngine))
            {
                var e = profile.RenderEngine.ToLowerInvariant();
                if (e == "sodium" || e == "vulkanmod" || e == "none") return e;
            }
            string c = _currentSettings?.RenderBackendChoice ?? "";
            if (!string.IsNullOrEmpty(c))
            {
                foreach (var (slug, _, _) in _renderEngines)
                    if (slug.Equals(c, StringComparison.OrdinalIgnoreCase)) return slug;
            }
            if (_currentSettings?.IsVulkanModEnabled == true) return "vulkanmod";
            return "sodium";
        }

        private bool IsSlugBlockedByActiveEngine(string slug)
        {
            if (string.IsNullOrEmpty(slug)) return false;
            var engine = GetActiveRenderEngine();
            if (!_renderEngineIncompatSlugs.TryGetValue(engine, out var blocked)) return false;
            foreach (var b in blocked)
                if (b.Equals(slug, StringComparison.OrdinalIgnoreCase)) return true;
            return false;
        }

        private string FindIncompatEngineForSlug(string slug)
        {
            if (string.IsNullOrEmpty(slug)) return null;
            foreach (var kv in _renderEngineIncompatSlugs)
            {
                foreach (var b in kv.Value)
                    if (b.Equals(slug, StringComparison.OrdinalIgnoreCase)) return kv.Key;
            }
            return null;
        }

