        private async void ShowPreInstalledModsPopup()
        {
            var profile = GetActiveProfile();
            string profileName = profile?.Name ?? "Default";
            string basePreset = (profile?.ModPreset ?? "none").ToLowerInvariant();
            bool hasDisabledCoreMods = profile?.DisabledRequiredMods != null
                && profile.DisabledRequiredMods.Any(kv => kv.Value);
            string preset = hasDisabledCoreMods ? "custom" : basePreset;
            string presetTooltip = hasDisabledCoreMods
                ? $"Based on '{basePreset}' - modified by you (one or more core mods disabled)"
                : null;

            var overlay = new Grid
            {
                Background = new SolidColorBrush(Color.Parse("#CC000000")),
                IsHitTestVisible = true,
                ZIndex = 9999,
            };
            overlay.PointerPressed += (s, e) => { if (ReferenceEquals(e.Source, overlay)) ClosePreInstalledModsPopup(overlay); };

            var panel = new Border
            {
                Background = new SolidColorBrush(Color.Parse("#0D1520")),
                BorderBrush = new SolidColorBrush(Color.Parse("#1A2332")),
                BorderThickness = new Thickness(1),
                CornerRadius = new CornerRadius(12),
                Width = 420,
                MaxHeight = 640,
                Opacity = 0,
                BoxShadow = BoxShadows.Parse("0 20 60 0 #B0000000"),
            };

            var content = new StackPanel { Spacing = 4, Margin = new Thickness(20) };
            content.Children.Add(new TextBlock
            {
                Text = "Pre-installed mods",
                FontSize = 16,
                FontWeight = FontWeight.Bold,
                Foreground = GetBrush("PrimaryForegroundBrush"),
            });
            var presetLine = new TextBlock
            {
                Text = $"Profile: {profileName}  ·  Preset: {preset}",
                FontSize = 11,
                Foreground = new SolidColorBrush(Color.Parse("#94A3B8")),
                Margin = new Thickness(0, 0, 0, 12),
            };
            if (presetTooltip != null) ToolTip.SetTip(presetLine, presetTooltip);
            content.Children.Add(presetLine);

            var scrollViewer = new ScrollViewer
            {
                VerticalScrollBarVisibility = Avalonia.Controls.Primitives.ScrollBarVisibility.Auto,
                MaxHeight = 460
            };

            var modsList = new StackPanel { Spacing = 8 };

            void AddSectionHeader(string label)
            {
                modsList.Children.Add(new TextBlock
                {
                    Text = label,
                    FontSize = 10,
                    FontWeight = FontWeight.Bold,
                    Foreground = new SolidColorBrush(Color.Parse("#34D399")),
                    Margin = new Thickness(2, 6, 0, 2),
                });
            }

            var rowsForUpdateCheck = new List<(string slug, TextBlock pip)>();
            void AddRow((string slug, string name, string desc) m)
            {
                bool isDisabled = profile != null && profile.DisabledRequiredMods.GetValueOrDefault(m.slug, false);
                string blockedByEngine = IsSlugBlockedByActiveEngine(m.slug) ? GetActiveRenderEngine() : null;
                if (blockedByEngine != null) isDisabled = true;

                var modItem = new Border
                {
                    Background = new SolidColorBrush(Color.Parse("#0C1620")),
                    CornerRadius = new CornerRadius(8),
                    Padding = new Thickness(12),
                    Opacity = blockedByEngine != null ? 0.55 : 1.0,
                };
                var modGrid = new Grid { ColumnDefinitions = new ColumnDefinitions("*,Auto,Auto") };
                var textStack = new StackPanel { Spacing = 2, VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center };
                textStack.Children.Add(new TextBlock
                {
                    Text = m.name,
                    FontWeight = FontWeight.Bold,
                    FontSize = 12,
                    Foreground = GetBrush("PrimaryForegroundBrush")
                });
                textStack.Children.Add(new TextBlock
                {
                    Text = m.desc,
                    FontSize = 10,
                    Foreground = GetBrush("SecondaryForegroundBrush")
                });
                if (blockedByEngine != null)
                {
                    string label = blockedByEngine.Equals("vulkanmod", StringComparison.OrdinalIgnoreCase) ? "VulkanMod" : "Sodium";
                    textStack.Children.Add(new TextBlock
                    {
                        Text = $"Incompatible with {label}",
                        FontSize = 10,
                        FontWeight = FontWeight.SemiBold,
                        Foreground = new SolidColorBrush(Color.Parse("#FCA5A5")),
                        Margin = new Thickness(0, 2, 0, 0),
                    });
                }
                Grid.SetColumn(textStack, 0);
                modGrid.Children.Add(textStack);

                var pip = new TextBlock
                {
                    Text = "UPDATE",
                    FontSize = 9,
                    FontWeight = FontWeight.Bold,
                    Foreground = new SolidColorBrush(Color.Parse("#FBBF24")),
                    Background = new SolidColorBrush(Color.Parse("#3F2A07")),
                    Padding = new Thickness(6, 2),
                    VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                    Margin = new Thickness(0, 0, 8, 0),
                    IsVisible = false,
                };
                Grid.SetColumn(pip, 1);
                modGrid.Children.Add(pip);
                if (blockedByEngine == null) rowsForUpdateCheck.Add((m.slug, pip));

                var toggle = new ToggleSwitch
                {
                    IsChecked = !isDisabled,
                    IsEnabled = blockedByEngine == null,
                    VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                    Margin = new Thickness(8, 0, 0, 0)
                };
                Grid.SetColumn(toggle, 2);
                modGrid.Children.Add(toggle);
                if (blockedByEngine == null)
                {
                    toggle.Checked += (_, __) => OnModToggled(m.slug, m.name, true);
                    toggle.Unchecked += (_, __) => OnModToggled(m.slug, m.name, false);
                }

                modItem.Child = modGrid;
                modsList.Children.Add(modItem);
            }

            AddSectionHeader("RENDER ENGINE");
            modsList.Children.Add(new TextBlock
            {
                Text = "Pick one - they conflict with each other.",
                FontSize = 10,
                Foreground = new SolidColorBrush(Color.Parse("#94A3B8")),
                Margin = new Thickness(2, 0, 0, 6),
            });
            string activeEngine = GetActiveRenderEngine();
            var enginesGrid = new Grid { ColumnDefinitions = new ColumnDefinitions("*,8,*") };
            int engineCol = 0;
            foreach (var eng in _renderEngines)
            {
                var card = BuildRenderEngineInlineCard(eng.slug, eng.name, eng.desc, string.Equals(activeEngine, eng.slug, StringComparison.OrdinalIgnoreCase), overlay);
                Grid.SetColumn(card, engineCol);
                enginesGrid.Children.Add(card);
                engineCol += 2;
            }
            modsList.Children.Add(enginesGrid);

            AddSectionHeader("OPTIMIZATION MODS");
            foreach (var m in _preInstalledCoreMods) AddRow(m);

            if (_preInstalledPresetExtras.TryGetValue(preset, out var extras) && extras.Length > 0)
            {
                AddSectionHeader($"PRESET EXTRAS - {preset.ToUpperInvariant()}");
                foreach (var m in extras) AddRow(m);
            }

            scrollViewer.Content = modsList;
            content.Children.Add(scrollViewer);

            var footer = new Grid { ColumnDefinitions = new ColumnDefinitions("Auto,*,Auto,Auto"), Margin = new Thickness(0, 12, 0, 0) };
            var resetButton = new Button
            {
                Content = "Reset",
                Padding = new Thickness(14, 8),
                Background = new SolidColorBrush(Color.Parse("#1A2332")),
                Foreground = new SolidColorBrush(Color.Parse("#CBD5E1")),
                CornerRadius = new CornerRadius(8),
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Left,
            };
            resetButton.Click += async (_, __) =>
            {
                if (profile == null) return;
                profile.DisabledRequiredMods.Clear();
                try { await _settingsService.SaveSettingsAsync(_currentSettings); }
                catch (Exception ex) { LeafClient.Services.LeafLog.Error("PreInstalledMods", $"Reset save failed: {ex.Message}"); }
                MarkSettingsDirty();
                ToastService.Show($"Mods reset to defaults for '{profileName}'", ToastType.Success);
                ClosePreInstalledModsPopup(overlay);
                ShowPreInstalledModsPopup();
            };
            Grid.SetColumn(resetButton, 0);
            footer.Children.Add(resetButton);

            var switchEngineButton = new Button
            {
                Content = "Switch render engine",
                Padding = new Thickness(14, 8),
                Background = new SolidColorBrush(Color.Parse("#1A1330")),
                Foreground = new SolidColorBrush(Color.Parse("#86EFAC")),
                BorderBrush = new SolidColorBrush(Color.Parse("#14532D")),
                BorderThickness = new Thickness(1),
                CornerRadius = new CornerRadius(8),
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Right,
                Margin = new Thickness(0, 0, 8, 0),
            };
            switchEngineButton.Click += (_, __) =>
            {
                ClosePreInstalledModsPopup(overlay);
                try { ShowRenderBackendPopup(); }
                catch (Exception ex) { LeafClient.Services.LeafLog.Error("PreInstalledMods", $"Re-open render popup failed: {ex.Message}"); }
            };
            Grid.SetColumn(switchEngineButton, 2);
            footer.Children.Add(switchEngineButton);

            var closeButton = new Button
            {
                Content = "Close",
                Padding = new Thickness(20, 8),
                Background = GetBrush("PrimaryAccentBrush"),
                Foreground = GetBrush("AccentButtonForegroundBrush"),
                CornerRadius = new CornerRadius(8),
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Right,
            };
            closeButton.Click += (_, __) => ClosePreInstalledModsPopup(overlay);
            Grid.SetColumn(closeButton, 3);
            footer.Children.Add(closeButton);
            content.Children.Add(footer);

            panel.Child = content;
            panel.RenderTransform = new ScaleTransform(0.85, 0.85);
            panel.RenderTransformOrigin = new RelativePoint(0.5, 0.5, RelativeUnit.Relative);

            var dockPanel = new DockPanel { LastChildFill = false, VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center, HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center };
            DockPanel.SetDock(panel, Dock.Top);
            dockPanel.Children.Add(panel);
            overlay.Children.Add(dockPanel);

            var rootGrid = this.FindControl<Grid>("RootGrid") ?? (Content as Grid);
            if (rootGrid != null)
            {
                if (Grid.GetRowSpan(overlay) <= 1) Grid.SetRowSpan(overlay, 99);
                if (Grid.GetColumnSpan(overlay) <= 1) Grid.SetColumnSpan(overlay, 99);
                rootGrid.Children.Add(overlay);

                const int steps = 18;
                const int durationMs = 240;
                for (int i = 0; i <= steps; i++)
                {
                    double t = (double)i / steps;
                    double ease = 1 - Math.Pow(1 - t, 3);
                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        panel.Opacity = ease;
                        var st = panel.RenderTransform as ScaleTransform;
                        if (st != null) { st.ScaleX = 0.85 + 0.15 * ease; st.ScaleY = 0.85 + 0.15 * ease; }
                    });
                    if (i < steps) await Task.Delay(durationMs / steps);
                }
                await Dispatcher.UIThread.InvokeAsync(() => overlay.Opacity = 1.0);
            }

            _ = CheckPreInstalledModsForUpdatesAsync(rowsForUpdateCheck);
        }

        private async Task CheckPreInstalledModsForUpdatesAsync(List<(string slug, TextBlock pip)> rows)
        {
            try
            {
                string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                if (!Directory.Exists(modsFolder)) return;

                foreach (var (slug, pip) in rows)
                {
                    try
                    {
                        var localFile = Directory.EnumerateFiles(modsFolder, "*.jar")
                            .Select(p => new FileInfo(p))
                            .FirstOrDefault(fi => fi.Name.IndexOf(slug, StringComparison.OrdinalIgnoreCase) >= 0);
                        if (localFile == null) continue;

                        var url = $"https://api.modrinth.com/v2/project/{slug}";
                        using var resp = await _modrinthClient.GetAsync(url);
                        if (!resp.IsSuccessStatusCode) continue;
                        var json = await resp.Content.ReadAsStringAsync();
                        using var doc = JsonDocument.Parse(json);
                        if (!doc.RootElement.TryGetProperty("updated", out var updEl)) continue;
                        if (!DateTime.TryParse(updEl.GetString(), null,
                            System.Globalization.DateTimeStyles.AssumeUniversal | System.Globalization.DateTimeStyles.AdjustToUniversal,
                            out var modrinthUpdated)) continue;

                        var localUtc = localFile.LastWriteTimeUtc;
                        if (modrinthUpdated > localUtc.AddHours(24))
                        {
                            await Dispatcher.UIThread.InvokeAsync(() => pip.IsVisible = true);
                        }
                    }
                    catch (Exception inner) { LeafClient.Services.LeafLog.Info("PreInstalled update-check", $"{slug}: {inner.Message}"); }
                }
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Info("PreInstalled update-check", $"{ex.Message}"); }
        }

        private async void ClosePreInstalledModsPopup(Grid overlay)
        {
            await AnimateInWindowPopupOutAsync(overlay);
        }

        private async Task FadeShowOverlayAsync(Control? overlay, Visual? card)
        {
            if (overlay == null) return;
            overlay.IsVisible = true;

            if (!AreAnimationsEnabled() || card == null)
            {
                overlay.Opacity = 1;
                if (card != null) card.Opacity = 1;
                return;
            }

            card.Opacity = 0;
            if (card.RenderTransform is not ScaleTransform st)
            {
                st = new ScaleTransform(0.92, 0.92);
                card.RenderTransform = st;
            }
            st.ScaleX = 0.92;
            st.ScaleY = 0.92;
            overlay.Opacity = 0;

            const int steps = 16;
            const int durationMs = 220;
            for (int i = 0; i <= steps; i++)
            {
                double t = (double)i / steps;
                double ease = 1 - Math.Pow(1 - t, 3);
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    overlay.Opacity = ease;
                    card.Opacity = ease;
                    st.ScaleX = 0.92 + 0.08 * ease;
                    st.ScaleY = 0.92 + 0.08 * ease;
                });
                if (i < steps) await Task.Delay(durationMs / steps);
            }
        }

        private async Task FadeHideOverlayAsync(Control? overlay, Visual? card)
        {
            if (overlay == null) return;
            if (!overlay.IsVisible) return;

            if (!AreAnimationsEnabled() || card == null)
            {
                overlay.IsVisible = false;
                return;
            }

            var st = card.RenderTransform as ScaleTransform;
            if (st == null)
            {
                st = new ScaleTransform(1, 1);
                card.RenderTransform = st;
            }

            const int steps = 14;
            const int durationMs = 180;
            for (int i = 0; i <= steps; i++)
            {
                double t = (double)i / steps;
                double ease = t * t;
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    overlay.Opacity = 1 - ease;
                    card.Opacity = 1 - ease;
                    st.ScaleX = 1 - 0.08 * ease;
                    st.ScaleY = 1 - 0.08 * ease;
                });
                if (i < steps) await Task.Delay(durationMs / steps);
            }
            overlay.IsVisible = false;
            overlay.Opacity = 1;
            card.Opacity = 1;
            st.ScaleX = 1;
            st.ScaleY = 1;
        }

        private async Task AnimateInWindowPopupOutAsync(Grid overlay)
        {
            if (overlay == null) return;
            var rootGrid = this.FindControl<Grid>("RootGrid") ?? (Content as Grid);

            Border? panel = null;
            foreach (var child in overlay.GetVisualDescendants())
            {
                if (child is Border b && b.Child is StackPanel)
                {
                    panel = b;
                    break;
                }
            }

            if (!AreAnimationsEnabled() || panel == null)
            {
                if (rootGrid != null && rootGrid.Children.Contains(overlay))
                    rootGrid.Children.Remove(overlay);
                return;
            }

            var st = panel.RenderTransform as ScaleTransform;
            const int steps = 14;
            const int durationMs = 180;
            for (int i = 0; i <= steps; i++)
            {
                double t = (double)i / steps;
                double ease = t * t;
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    overlay.Opacity = 1.0 - ease;
                    panel.Opacity = 1.0 - ease;
                    if (st != null)
                    {
                        st.ScaleX = 1.0 - 0.15 * ease;
                        st.ScaleY = 1.0 - 0.15 * ease;
                    }
                });
                if (i < steps) await Task.Delay(durationMs / steps);
            }
            if (rootGrid != null && rootGrid.Children.Contains(overlay))
                rootGrid.Children.Remove(overlay);
        }

