        private Grid? _renderBackendOverlay;
        private string _renderBackendSelected = "";
        private bool _renderBackendApplying;

        private async void ShowRenderBackendPopup()
        {
            if (_renderBackendOverlay != null) return;

            var gpu = await Task.Run(() => LeafClient.Services.GpuDetectionService.Detect());
            string recommended = LeafClient.Services.GpuDetectionService.Recommend(gpu);
            _renderBackendSelected = "";

            string gpuLabel = string.IsNullOrEmpty(gpu.Name) || gpu.Name == "Unknown GPU"
                ? "your system"
                : gpu.Name;

            var overlay = new Grid
            {
                Background = new SolidColorBrush(Color.Parse("#CC000000")),
                IsHitTestVisible = true,
                ZIndex = 9999,
            };
            _renderBackendOverlay = overlay;

            var panel = new Border
            {
                Background = new SolidColorBrush(Color.Parse("#0D1520")),
                BorderBrush = new SolidColorBrush(Color.Parse("#1A2332")),
                BorderThickness = new Thickness(1),
                CornerRadius = new CornerRadius(14),
                Width = 640,
                Opacity = 0,
                BoxShadow = BoxShadows.Parse("0 20 60 0 #B0000000"),
            };

            var content = new StackPanel { Spacing = 12, Margin = new Thickness(28) };

            content.Children.Add(new TextBlock
            {
                Text = "Pick your renderer",
                FontSize = 18,
                FontWeight = FontWeight.Bold,
                Foreground = GetBrush("PrimaryForegroundBrush"),
            });

            content.Children.Add(new TextBlock
            {
                Text = "Leaf Client ships with two render engines. Click the one that fits your hardware - you can change this later in Settings.",
                FontSize = 12,
                Foreground = GetBrush("SecondaryForegroundBrush"),
                TextWrapping = TextWrapping.Wrap,
            });

            string recoText = recommended == "vulkanmod"
                ? $"Recommended for {gpuLabel}: VulkanMod"
                : $"Recommended for {gpuLabel}: Sodium";

            content.Children.Add(new Border
            {
                CornerRadius = new CornerRadius(8),
                Padding = new Thickness(12, 8),
                Background = new SolidColorBrush(Color.Parse("#1A1330")),
                BorderBrush = new SolidColorBrush(Color.Parse("#14532D")),
                BorderThickness = new Thickness(1),
                Margin = new Thickness(0, 4, 0, 8),
                Child = new TextBlock
                {
                    Text = recoText,
                    FontSize = 12,
                    FontWeight = FontWeight.SemiBold,
                    Foreground = new SolidColorBrush(Color.Parse("#86EFAC")),
                    TextWrapping = TextWrapping.Wrap,
                }
            });

            var cardsRow = new Grid
            {
                ColumnDefinitions = new ColumnDefinitions("*,14,*"),
            };
            var sodiumCard = BuildRenderBackendCard(
                slug: "sodium",
                title: "Sodium",
                logoAsset: "avares://LeafClient/Assets/sodium-logo.png",
                tagline: "Maximum compatibility",
                isRecommended: recommended == "sodium",
                pros: new[]
                {
                    "Supports shader packs (Iris)",
                    "Rock-solid stability",
                    "Works on every GPU",
                    "Mature, battle-tested"
                },
                cons: new[]
                {
                    "Lower FPS ceiling",
                    "Higher CPU usage when modded"
                });
            var vulkanCard = BuildRenderBackendCard(
                slug: "vulkanmod",
                title: "VulkanMod",
                logoAsset: "avares://LeafClient/Assets/vulkanmod-logo.png",
                tagline: "Maximum FPS",
                isRecommended: recommended == "vulkanmod",
                pros: new[]
                {
                    "Highest FPS on modern GPUs",
                    "Lower CPU usage",
                    "Native Vulkan pipeline"
                },
                cons: new[]
                {
                    "No shader pack support",
                    "Glitches on old/weak GPUs",
                    "Less compatible with render mods"
                });

            Grid.SetColumn(sodiumCard, 0);
            Grid.SetColumn(vulkanCard, 2);
            cardsRow.Children.Add(sodiumCard);
            cardsRow.Children.Add(vulkanCard);
            content.Children.Add(cardsRow);

            panel.Child = content;
            panel.RenderTransform = new ScaleTransform(0.85, 0.85);
            panel.RenderTransformOrigin = new RelativePoint(0.5, 0.5, RelativeUnit.Relative);

            var dockPanel = new DockPanel
            {
                LastChildFill = false,
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center
            };
            DockPanel.SetDock(panel, Dock.Top);
            dockPanel.Children.Add(panel);
            overlay.Children.Add(dockPanel);

            var rootGrid = this.FindControl<Grid>("RootGrid") ?? (Content as Grid);
            if (rootGrid != null)
            {
                if (Grid.GetRowSpan(overlay) <= 1) Grid.SetRowSpan(overlay, 99);
                if (Grid.GetColumnSpan(overlay) <= 1) Grid.SetColumnSpan(overlay, 99);
                rootGrid.Children.Add(overlay);

                if (!AreAnimationsEnabled())
                {
                    overlay.Opacity = 1.0;
                    panel.Opacity = 1;
                    var st = panel.RenderTransform as ScaleTransform;
                    if (st != null) { st.ScaleX = 1; st.ScaleY = 1; }
                    return;
                }

                const int steps = 18;
                const int durationMs = 240;
                for (int i = 0; i <= steps; i++)
                {
                    double t = (double)i / steps;
                    double ease = 1 - Math.Pow(1 - t, 3);
                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        panel.Opacity = ease;
                        var st = panel.RenderTransform as ScaleTransform;
                        if (st != null) { st.ScaleX = 0.85 + 0.15 * ease; st.ScaleY = 0.85 + 0.15 * ease; }
                    });
                    if (i < steps) await Task.Delay(durationMs / steps);
                }
            }
        }

        private Border BuildRenderBackendCard(string slug, string title, string logoAsset, string tagline, bool isRecommended, string[] pros, string[] cons)
        {
            var border = new Border
            {
                CornerRadius = new CornerRadius(14),
                Padding = new Thickness(16),
                Background = new SolidColorBrush(Color.Parse(isRecommended ? "#1F1740" : "#11091F")),
                BorderBrush = new SolidColorBrush(Color.Parse(isRecommended ? "#22C55E" : "#231A3A")),
                BorderThickness = new Thickness(isRecommended ? 2 : 1),
                Cursor = new Avalonia.Input.Cursor(Avalonia.Input.StandardCursorType.Hand),
                Tag = slug,
            };
            if (isRecommended)
            {
                border.BoxShadow = BoxShadows.Parse("0 0 16 0 #15803D5E");
            }

            var stack = new StackPanel { Spacing = 10 };

            var header = new StackPanel
            {
                Orientation = Avalonia.Layout.Orientation.Horizontal,
                Spacing = 12,
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Left,
            };

            try
            {
                var logoBorder = new Border
                {
                    Width = 52,
                    Height = 52,
                    CornerRadius = new CornerRadius(10),
                    ClipToBounds = true,
                    Child = new Avalonia.Controls.Image
                    {
                        Width = 52,
                        Height = 52,
                        Source = new Avalonia.Media.Imaging.Bitmap(Avalonia.Platform.AssetLoader.Open(new Uri(logoAsset))),
                        Stretch = Avalonia.Media.Stretch.UniformToFill,
                    }
                };
                header.Children.Add(logoBorder);
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("RenderBackend", $"Failed to load logo {logoAsset}: {ex.Message}");
            }

            var titleStack = new StackPanel { Spacing = 2, VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center };
            titleStack.Children.Add(new TextBlock
            {
                Text = title,
                FontSize = 16,
                FontWeight = FontWeight.Bold,
                Foreground = GetBrush("PrimaryForegroundBrush"),
            });
            titleStack.Children.Add(new TextBlock
            {
                Text = tagline,
                FontSize = 11,
                Foreground = new SolidColorBrush(Color.Parse("#9CA3AF")),
            });
            header.Children.Add(titleStack);
            stack.Children.Add(header);

            var prosCons = new StackPanel { Spacing = 4, Margin = new Thickness(0, 4, 0, 0) };
            foreach (var p in pros)
            {
                prosCons.Children.Add(new TextBlock
                {
                    Text = "+ " + p,
                    FontSize = 11,
                    Foreground = new SolidColorBrush(Color.Parse("#86EFAC")),
                    TextWrapping = TextWrapping.Wrap,
                });
            }
            foreach (var c in cons)
            {
                prosCons.Children.Add(new TextBlock
                {
                    Text = "− " + c,
                    FontSize = 11,
                    Foreground = new SolidColorBrush(Color.Parse("#FCA5A5")),
                    TextWrapping = TextWrapping.Wrap,
                });
            }
            stack.Children.Add(prosCons);

            border.Child = stack;
            border.PointerPressed += async (_, __) => await OnRenderBackendCardClickedAsync(slug);
            return border;
        }

        private async Task OnRenderBackendCardClickedAsync(string slug)
        {
            if (_renderBackendApplying) return;
            _renderBackendApplying = true;
            _renderBackendSelected = slug;
            if (_renderBackendOverlay != null)
            {
                foreach (var child in _renderBackendOverlay.GetVisualDescendants())
                {
                    if (child is Border b && b.Tag is string s && (s == "sodium" || s == "vulkanmod"))
                    {
                        bool sel = s == slug;
                        b.Background = new SolidColorBrush(Color.Parse(sel ? "#1F1740" : "#11091F"));
                        b.BorderBrush = new SolidColorBrush(Color.Parse(sel ? "#22C55E" : "#231A3A"));
                        b.BorderThickness = new Thickness(sel ? 2 : 1);
                        b.BoxShadow = sel ? BoxShadows.Parse("0 0 16 0 #15803D5E") : default;
                    }
                }
            }
            await OnRenderBackendContinueAsync();
            _renderBackendApplying = false;
        }

        private async Task OnRenderBackendContinueAsync()
        {
            try
            {
                if (string.IsNullOrEmpty(_renderBackendSelected)) return;
                if (_currentSettings == null) return;
                await ApplyRenderEngineChoiceAsync(_renderBackendSelected);
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("RenderBackend", $"Continue failed: {ex.Message}");
            }
            finally
            {
                if (_renderBackendOverlay != null)
                {
                    var ov = _renderBackendOverlay;
                    _renderBackendOverlay = null;
                    await AnimateInWindowPopupOutAsync(ov);
                }
            }
        }

        private async Task ApplyRenderEngineChoiceAsync(string slug)
        {
            if (_currentSettings == null) return;
            if (string.IsNullOrEmpty(slug)) return;
            slug = slug.ToLowerInvariant();
            bool valid = false;
            foreach (var (s, _, _) in _renderEngines) if (s == slug) { valid = true; break; }
            if (!valid) return;

            _currentSettings.RenderBackendChoice = slug;
            _currentSettings.IsVulkanModEnabled = (slug == "vulkanmod");
            if (_vulkanModToggle != null) _vulkanModToggle.IsChecked = (slug == "vulkanmod");

            var profile = _currentSettings.Profiles?.FirstOrDefault(p => p.Id == _currentSettings.ActiveProfileId)
                          ?? _currentSettings.Profiles?.FirstOrDefault();
            if (profile != null)
            {
                string? prevEngine = profile.RenderEngine;
                profile.RenderEngine = slug;
                LeafClient.Services.LeafLog.Info("RenderEngine", $"Active profile '{profile.Name ?? profile.Id}' RenderEngine: '{prevEngine ?? "<unset>"}' -> '{slug}'");

                profile.DisabledRequiredMods ??= new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase);

                var allIncompatBySomeEngine = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                foreach (var kv in _renderEngineIncompatSlugs)
                    foreach (var s in kv.Value) allIncompatBySomeEngine.Add(s);
                foreach (var s in allIncompatBySomeEngine)
                    profile.DisabledRequiredMods[s] = false;

                if (_renderEngineIncompatSlugs.TryGetValue(slug, out var blocked))
                    foreach (var s in blocked)
                        profile.DisabledRequiredMods[s] = true;
            }

            try
            {
                string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                if (Directory.Exists(modsFolder))
                {
                    var prefixes = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                    if (_renderEngineIncompatSlugs.TryGetValue(slug, out var blocked))
                        foreach (var b in blocked) prefixes.Add(b);
                    foreach (var (engineSlug, _, _) in _renderEngines)
                        if (engineSlug != slug) prefixes.Add(engineSlug);

                    foreach (var prefix in prefixes)
                    {
                        foreach (var pattern in new[] { $"{prefix}-*.jar", $"{prefix}-fabric-*.jar", $"fabric-{prefix}-*.jar", $"*{prefix}*.jar" })
                        {
                            foreach (var f in Directory.GetFiles(modsFolder, pattern))
                            {
                                try { File.Delete(f); LeafClient.Services.LeafLog.Info("RenderEngine", $"Removed incompat jar: {System.IO.Path.GetFileName(f)}"); } catch { }
                            }
                        }
                    }
                }
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("RenderEngine", $"Jar cleanup failed: {ex.Message}"); }

            await _settingsService.SaveSettingsAsync(_currentSettings);
        }

        private Border BuildRenderEngineInlineCard(string slug, string title, string desc, bool isActive, Grid parentOverlay)
        {
            var border = new Border
            {
                CornerRadius = new CornerRadius(10),
                Padding = new Thickness(12),
                Background = new SolidColorBrush(Color.Parse(isActive ? "#1F1740" : "#0C1620")),
                BorderBrush = new SolidColorBrush(Color.Parse(isActive ? "#22C55E" : "#231A3A")),
                BorderThickness = new Thickness(isActive ? 2 : 1),
                Cursor = new Avalonia.Input.Cursor(Avalonia.Input.StandardCursorType.Hand),
                Tag = slug,
            };
            var stack = new StackPanel { Spacing = 4 };
            var header = new StackPanel { Orientation = Avalonia.Layout.Orientation.Horizontal, Spacing = 8 };
            header.Children.Add(new TextBlock
            {
                Text = title,
                FontWeight = FontWeight.Bold,
                FontSize = 13,
                Foreground = GetBrush("PrimaryForegroundBrush"),
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
            });
            if (isActive)
            {
                header.Children.Add(new Border
                {
                    Background = new SolidColorBrush(Color.Parse("#22C55E")),
                    CornerRadius = new CornerRadius(6),
                    Padding = new Thickness(6, 1),
                    VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                    Child = new TextBlock
                    {
                        Text = "ACTIVE",
                        FontSize = 9,
                        FontWeight = FontWeight.Bold,
                        Foreground = new SolidColorBrush(Colors.White),
                    }
                });
            }
            stack.Children.Add(header);
            stack.Children.Add(new TextBlock
            {
                Text = desc,
                FontSize = 10,
                Foreground = GetBrush("SecondaryForegroundBrush"),
                TextWrapping = TextWrapping.Wrap,
            });
            border.Child = stack;
            border.PointerPressed += async (_, __) =>
            {
                if (isActive) return;
                try
                {
                    await ApplyRenderEngineChoiceAsync(slug);
                    MarkSettingsDirty();
                    ToastService.Show($"Render engine switched to {title}", ToastType.Success);
                    ClosePreInstalledModsPopup(parentOverlay);
                    ShowPreInstalledModsPopup();
                }
                catch (Exception ex) { LeafClient.Services.LeafLog.Error("RenderEngine", $"Inline switch failed: {ex.Message}"); }
            };
            return border;
        }

        private async void OnModToggled(string slug, string name, bool enabled)
        {
            var profile = GetActiveProfile();
            if (profile == null) return;

            if (enabled && IsSlugBlockedByActiveEngine(slug))
            {
                string engine = GetActiveRenderEngine();
                string label = engine.Equals("vulkanmod", StringComparison.OrdinalIgnoreCase) ? "VulkanMod" : "Sodium";
                ToastService.Show($"{name} is incompatible with {label}. Switch render engine first.", ToastType.Info);
                return;
            }

            profile.DisabledRequiredMods[slug] = !enabled;
            try { await _settingsService.SaveSettingsAsync(_currentSettings); }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("PreInstalledMods", $"Save failed: {ex.Message}"); }
            MarkSettingsDirty();

            if (enabled)
            {
                ToastService.Show($"{name} will be installed on next launch", ToastType.Success);
            }
            else
            {
                ToastService.Show($"{name} will be removed on next launch", ToastType.Info);
                string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                if (Directory.Exists(modsFolder))
                {
                    try
                    {
                        var modFiles = Directory.GetFiles(modsFolder, $"*{slug}*", SearchOption.TopDirectoryOnly);
                        foreach (var file in modFiles)
                        {
                            File.Delete(file);
                        }
                    }
                    catch (Exception ex)
                    {
                        LeafClient.Services.LeafLog.Error("PreInstalledMods", $"Failed to delete mod file for {slug}: {ex.Message}");
                    }
                }
            }
        }

        private async void OnReapplyDefaultsClicked(object? sender, RoutedEventArgs e)
        {
            try
            {
                await FirstLaunchDefaultsService.Instance.ApplyDefaultsIfNeededAsync(_minecraftFolder);
                _ = Dispatcher.UIThread.InvokeAsync(() => ShowFirstLaunchDefaultsPopup());
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("FirstLaunchDefaults", $"Error reapplying defaults: {ex.Message}");
                ToastService.Show("Failed to apply settings", ToastType.Error);
            }
        }

        private bool _cosmeticDropChecked;
        private bool _isCosmeticDropAnimating;
        private System.Threading.CancellationTokenSource? _confettiCts;

        private static string CurrentDropMonthUtc()
        {
            var n = DateTime.UtcNow;
            return $"{n.Year:0000}-{n.Month:00}";
        }

        private static string RarityColorHex(string? rarity) => rarity switch
        {
            "legendary" => "#F59E0B",
            "epic"      => "#34D399",
            "rare"      => "#3B82F6",
            _           => "#9CA3AF",
        };

        private static string RarityBorderHex(string? rarity) => rarity switch
        {
            "legendary" => "#7C5413",
            "epic"      => "#166534",
            "rare"      => "#1E3A8A",
            _           => "#374151",
        };

        private async Task TryCheckAndClaimCosmeticDropAsync()
        {
            if (_cosmeticDropChecked) return;
            _cosmeticDropChecked = true;
            if (!_isLeafPlus) return;
            var jwt = _currentSettings?.LeafApiJwt;
            if (string.IsNullOrEmpty(jwt) || _currentSettings == null) return;

            var month = CurrentDropMonthUtc();
            var activeEntry = _currentSettings.SavedAccounts.FirstOrDefault(a => a.Id == _currentSettings.ActiveAccountId);
            if (activeEntry?.LastSeenCosmeticDropMonth == month) return;

            try
            {
                var info = await Services.LeafApiService.GetCurrentDropInfoAsync();
                if (info == null || !info.HasActiveDrop) return;

                var (result, error) = await Services.LeafApiService.ClaimCurrentDropAsync(jwt!);
                if (result == null)
                {
                    LeafClient.Services.LeafLog.Error("CosmeticDrop", $"claim failed: {error}");
                    return;
                }

                if (activeEntry != null) activeEntry.LastSeenCosmeticDropMonth = month;
                _currentSettings.LastSeenCosmeticDropMonth = month;
                MarkSettingsDirty();
                if (result.NewCoinBalance.HasValue)
                {
                    ((Services.IMainWindowHost)this).UpdateCoinBalance(result.NewCoinBalance.Value);
                }

                _ = SyncOwnedCosmeticsFromApiAsync();

                await Dispatcher.UIThread.InvokeAsync(() => ShowCosmeticDropPopup(result));
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("CosmeticDrop", $"error: {ex.Message}");
            }
        }

        private async void ShowCosmeticDropPopup(LeafApiDropClaimResult result)
        {
            var overlay  = this.FindControl<Grid>("CosmeticDropOverlay");
            var panel    = this.FindControl<Border>("CosmeticDropPanel");
            var backdrop = this.FindControl<Border>("CosmeticDropBackdrop");
            var canvas   = this.FindControl<Canvas>("CosmeticDropConfettiCanvas");
            var titleTb  = this.FindControl<TextBlock>("CosmeticDropTitle");
            var subTb    = this.FindControl<TextBlock>("CosmeticDropSubtitle");
            var sectionTb= this.FindControl<TextBlock>("CosmeticDropSectionLabel");
            var lpPanel  = this.FindControl<Border>("CosmeticDropLpPanel");
            var lpHead   = this.FindControl<TextBlock>("CosmeticDropLpHeadline");
            var lpSub    = this.FindControl<TextBlock>("CosmeticDropLpSubline");
            var cards    = this.FindControl<WrapPanel>("CosmeticDropCardsPanel");
            if (overlay == null || panel == null || cards == null) return;
            if (_isCosmeticDropAnimating || overlay.IsVisible) return;
            _isCosmeticDropAnimating = true;

            string monthDisplay;
            try
            {
                var parts = result.Month.Split('-');
                if (parts.Length == 2 && int.TryParse(parts[0], out var y) && int.TryParse(parts[1], out var m))
                    monthDisplay = new DateTime(y, m, 1).ToString("MMMM yyyy", System.Globalization.CultureInfo.InvariantCulture);
                else
                    monthDisplay = result.Month;
            }
            catch { monthDisplay = result.Month; }

            bool grantedAny = result.Granted != null && result.Granted.Count > 0;
            bool ownedAny = result.AlreadyOwned != null && result.AlreadyOwned.Count > 0;

            if (titleTb != null) titleTb.Text = grantedAny ? "🎉 New cosmetics dropped!" : "Already in your collection";
            if (subTb   != null) subTb.Text   = $"Leaf+ Monthly Drop · {monthDisplay}";

            if (lpPanel != null && lpHead != null && lpSub != null)
            {
                if (result.LpCompensation > 0)
                {
                    lpPanel.IsVisible = true;
                    lpHead.Text = $"+{result.LpCompensation:N0} 🍃 Leaf Points";
                    lpSub.Text  = grantedAny
                        ? "You already owned some of this month's drops, so here's a Leaf Points refund equal to what you paid."
                        : "You already had everything in this month's drop, so here's a Leaf Points refund equal to what you paid.";
                }
                else
                {
                    lpPanel.IsVisible = false;
                }
            }

            if (sectionTb != null)
            {
                sectionTb.Text = grantedAny
                    ? (ownedAny ? "GRANTED · YOU ALREADY HAD" : "GRANTED")
                    : "THIS MONTH'S DROPS";
            }

            cards.Children.Clear();
            byte[]? dropSkinBytes = null;
            try { dropSkinBytes = await FetchSkinBytesAsync(); } catch { }
            if (result.Granted != null) foreach (var c in result.Granted) cards.Children.Add(BuildDropCard(c, owned: false, dropSkinBytes));
            if (result.AlreadyOwned != null) foreach (var c in result.AlreadyOwned) cards.Children.Add(BuildDropCard(c, owned: true, dropSkinBytes));

            overlay.IsVisible = true;
            if (backdrop != null) backdrop.Opacity = 0;
            panel.Opacity = 0;
            var st = panel.RenderTransform as ScaleTransform ?? new ScaleTransform(0.85, 0.85);
            panel.RenderTransform = st;
            panel.RenderTransformOrigin = new RelativePoint(0.5, 0.5, RelativeUnit.Relative);
            st.ScaleX = 0.85; st.ScaleY = 0.85;

            _confettiCts?.Cancel();
            _confettiCts = new System.Threading.CancellationTokenSource();
            if (canvas != null) _ = AnimateConfettiAsync(canvas, _confettiCts.Token);

            if (!AreAnimationsEnabled())
            {
                if (backdrop != null) backdrop.Opacity = 1;
                panel.Opacity = 1;
                st.ScaleX = 1; st.ScaleY = 1;
                _isCosmeticDropAnimating = false;
                return;
            }

            const int steps = 22;
            const int durationMs = 320;
            for (int i = 0; i <= steps; i++)
            {
                double t = (double)i / steps;
                double ease = 1 - Math.Pow(1 - t, 3);
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (backdrop != null) backdrop.Opacity = ease;
                    panel.Opacity = ease;
                    st.ScaleX = 0.85 + 0.15 * ease;
                    st.ScaleY = 0.85 + 0.15 * ease;
                });
                if (i < steps) await Task.Delay(durationMs / steps);
            }
            _isCosmeticDropAnimating = false;
        }

        private Border BuildDropCard(LeafApiDropCosmetic cos, bool owned, byte[]? userSkinBytes = null)
        {
            var card = new Border
            {
                Width = 168, Height = 196,
                Margin = new Thickness(0, 0, 10, 10),
                CornerRadius = new CornerRadius(14),
                Background = SolidColorBrush.Parse(owned ? "#0F1722" : "#1A1042"),
                BorderBrush = SolidColorBrush.Parse(owned ? "#1F2937" : RarityBorderHex(cos.Rarity)),
                BorderThickness = new Thickness(1),
                ClipToBounds = true,
                Opacity = owned ? 0.65 : 1.0,
            };
            var grid = new Grid { RowDefinitions = new RowDefinitions("*,Auto") };

            var preview = new Border
            {
                Background = SolidColorBrush.Parse(owned ? "#0A0F18" : "#0D0A28"),
            };
            var img = new Image
            {
                Width = 156, Height = 156,
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                Stretch = Avalonia.Media.Stretch.Uniform,
            };
            byte[]? rendered = null;
            try { rendered = TryRenderDropCardCharacterPreview(cos, userSkinBytes); } catch { }
            try
            {
                if (rendered != null)
                {
                    using var ms = new System.IO.MemoryStream(rendered);
                    img.Source = new Avalonia.Media.Imaging.Bitmap(ms);
                    img.Width = 160; img.Height = 160;
                }
                else
                {
                    var bytes = LeafClient.Services.CosmeticHelpers.TryLoadCosmeticAsset(cos.Id);
                    if (bytes != null)
                    {
                        using var ms = new System.IO.MemoryStream(bytes);
                        img.Source = new Avalonia.Media.Imaging.Bitmap(ms);
                        img.Width = 88; img.Height = 88;
                    }
                }
            }
            catch { }
            preview.Child = img;
            Grid.SetRow(preview, 0);
            grid.Children.Add(preview);

            var rarityPill = new Border
            {
                CornerRadius = new CornerRadius(6),
                Padding = new Thickness(6, 2),
                Margin = new Thickness(8, 8, 0, 0),
                HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Left,
                VerticalAlignment = Avalonia.Layout.VerticalAlignment.Top,
                Background = SolidColorBrush.Parse(RarityColorHex(cos.Rarity)),
                Child = new TextBlock
                {
                    Text = (cos.Rarity ?? "common").ToUpperInvariant(),
                    Foreground = Brushes.White,
                    FontSize = 9,
                    FontWeight = FontWeight.ExtraBold,
                    LetterSpacing = 0.8,
                },
            };
            Grid.SetRow(rarityPill, 0);
            grid.Children.Add(rarityPill);

            if (owned)
            {
                var ownedPill = new Border
                {
                    CornerRadius = new CornerRadius(6),
                    Padding = new Thickness(6, 2),
                    Margin = new Thickness(0, 8, 8, 0),
                    HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Right,
                    VerticalAlignment = Avalonia.Layout.VerticalAlignment.Top,
                    Background = SolidColorBrush.Parse("#1F2937"),
                    Child = new TextBlock
                    {
                        Text = "OWNED",
                        Foreground = SolidColorBrush.Parse("#9CA3AF"),
                        FontSize = 9,
                        FontWeight = FontWeight.ExtraBold,
                        LetterSpacing = 0.8,
                    },
                };
                Grid.SetRow(ownedPill, 0);
                grid.Children.Add(ownedPill);
            }

            var footer = new StackPanel
            {
                Spacing = 2,
                Margin = new Thickness(12, 8, 12, 12),
                Background = SolidColorBrush.Parse(owned ? "#0D1422" : "#160A33"),
            };
            footer.Children.Add(new TextBlock
            {
                Text = cos.Name ?? cos.Id,
                Foreground = Brushes.White,
                FontWeight = FontWeight.Bold,
                FontSize = 12,
                TextTrimming = Avalonia.Media.TextTrimming.CharacterEllipsis,
            });
            footer.Children.Add(new TextBlock
            {
                Text = (cos.Category ?? "").ToUpperInvariant(),
                Foreground = SolidColorBrush.Parse(owned ? "#4B5563" : "#86EFAC"),
                FontSize = 9,
                FontWeight = FontWeight.SemiBold,
                LetterSpacing = 0.5,
            });
            Grid.SetRow(footer, 1);
            grid.Children.Add(footer);

            card.Child = grid;
            return card;
        }

        private static byte[]? TryRenderDropCardCharacterPreview(LeafApiDropCosmetic cos, byte[]? userSkinBytes)
        {
            if (userSkinBytes == null || userSkinBytes.Length == 0) return null;
            string cat = (cos.Category ?? "").ToLowerInvariant();
            SixLabors.ImageSharp.Image<SixLabors.ImageSharp.PixelFormats.Rgba32>? skin = null;
            SixLabors.ImageSharp.Image<SixLabors.ImageSharp.PixelFormats.Rgba32>? cape = null;
            SixLabors.ImageSharp.Image<SixLabors.ImageSharp.PixelFormats.Rgba32>? hat = null;
            SixLabors.ImageSharp.Image<SixLabors.ImageSharp.PixelFormats.Rgba32>? wings = null;
            string? auraType = null;
            bool isHorns = false;
            try
            {
                skin = SixLabors.ImageSharp.Image.Load<SixLabors.ImageSharp.PixelFormats.Rgba32>(userSkinBytes);
                if (cat == "wings")
                {
                    var b = LeafClient.Services.CosmeticHelpers.TryLoadCosmeticAsset(cos.Id);
                    if (b == null) return null;
                    wings = SixLabors.ImageSharp.Image.Load<SixLabors.ImageSharp.PixelFormats.Rgba32>(b);
                }
                else if (cat == "hat")
                {
                    var b = LeafClient.Services.CosmeticHelpers.TryLoadCosmeticAsset(cos.Id);
                    if (b == null) return null;
                    hat = SixLabors.ImageSharp.Image.Load<SixLabors.ImageSharp.PixelFormats.Rgba32>(b);
                    isHorns = (cos.Id ?? "").Contains("horns");
                }
                else if (cat == "cape")
                {
                    var b = LeafClient.Services.CosmeticHelpers.TryLoadCosmeticAsset(cos.Id);
                    if (b == null) return null;
                    cape = SixLabors.ImageSharp.Image.Load<SixLabors.ImageSharp.PixelFormats.Rgba32>(b);
                }
                else if (cat == "aura")
                {
                    auraType = LeafClient.Services.CosmeticHelpers.AuraIdToType(cos.Id ?? "");
                    if (string.IsNullOrEmpty(auraType)) return null;
                }
                else
                {
                    return null;
                }

                const int sz = 320;
                float yaw = (cat == "hat" || cat == "hats" || cat == "face" || cat == "aura" || cat == "auras") ? 180f : 25f;
                byte[]? bgra = LeafClient.Controls.SkinRendererControl.RenderFrame(
                    skin, cape, hat, wings,
                    sz, sz,
                    rotationY: yaw, rotationX: -10f,
                    zoom: 1.05f,
                    capeSwingX: 0f,
                    wingFlapPhase: 0.75f,
                    isHorns: isHorns,
                    auraType: auraType,
                    auraPhase: 0.5f,
                    previewLit: false);
                if (bgra == null) return null;

                using var pngImg = SixLabors.ImageSharp.Image.LoadPixelData<SixLabors.ImageSharp.PixelFormats.Bgra32>(bgra, sz, sz);
                using var ms = new System.IO.MemoryStream();
                SixLabors.ImageSharp.ImageExtensions.SaveAsPng(pngImg, ms);
                return ms.ToArray();
            }
            catch
            {
                return null;
            }
            finally
            {
                skin?.Dispose();
                cape?.Dispose();
                hat?.Dispose();
                wings?.Dispose();
            }
        }

        private async Task AnimateConfettiAsync(Canvas canvas, System.Threading.CancellationToken ct)
        {
            try
            {
                await Dispatcher.UIThread.InvokeAsync(() => canvas.Children.Clear());
                if (!AreAnimationsEnabled()) return;

                var rng = new Random();
                string[] colors = { "#34D399", "#F59E0B", "#3B82F6", "#22C55E", "#EF4444", "#FFFFFF" };
                int total = 36;
                double width = canvas.Bounds.Width > 0 ? canvas.Bounds.Width : 1280;

                var pieces = new List<(Border b, double vx, double vy, double rotSpeed, double startX, double startY)>();
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    for (int i = 0; i < total; i++)
                    {
                        var sz = 6 + rng.NextDouble() * 6;
                        var b = new Border
                        {
                            Width = sz,
                            Height = sz * 0.45,
                            CornerRadius = new CornerRadius(1.5),
                            Background = SolidColorBrush.Parse(colors[rng.Next(colors.Length)]),
                            RenderTransform = new RotateTransform(rng.NextDouble() * 360),
                        };
                        var startX = rng.NextDouble() * width;
                        var startY = -20 - rng.NextDouble() * 80;
                        Canvas.SetLeft(b, startX);
                        Canvas.SetTop(b, startY);
                        canvas.Children.Add(b);
                        var vx = (rng.NextDouble() - 0.5) * 60;
                        var vy = 80 + rng.NextDouble() * 100;
                        var rotSpeed = (rng.NextDouble() - 0.5) * 360;
                        pieces.Add((b, vx, vy, rotSpeed, startX, startY));
                    }
                });

                var sw = System.Diagnostics.Stopwatch.StartNew();
                double lifetimeMs = 4500;
                while (!ct.IsCancellationRequested && sw.ElapsedMilliseconds < lifetimeMs)
                {
                    double t = sw.Elapsed.TotalSeconds;
                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        foreach (var p in pieces)
                        {
                            double x = p.startX + p.vx * t + Math.Sin(t * 2 + p.startX) * 12;
                            double y = p.startY + p.vy * t + 0.5 * 80 * t * t;
                            Canvas.SetLeft(p.b, x);
                            Canvas.SetTop(p.b, y);
                            if (p.b.RenderTransform is RotateTransform rt)
                                rt.Angle += p.rotSpeed * 0.016;
                            double fade = 1 - Math.Min(1, t / (lifetimeMs / 1000));
                            p.b.Opacity = fade;
                        }
                    });
                    await Task.Delay(16, ct);
                }
                await Dispatcher.UIThread.InvokeAsync(() => canvas.Children.Clear());
            }
            catch (TaskCanceledException) { }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("CosmeticDrop", $"confetti error: {ex.Message}"); }
        }

        private async void OnCosmeticDropOk(object? sender, RoutedEventArgs e)
        {
            var overlay  = this.FindControl<Grid>("CosmeticDropOverlay");
            var panel    = this.FindControl<Border>("CosmeticDropPanel");
            var backdrop = this.FindControl<Border>("CosmeticDropBackdrop");
            if (overlay == null || panel == null) return;
            if (_isCosmeticDropAnimating) return;
            _isCosmeticDropAnimating = true;

            _confettiCts?.Cancel();

            var st = panel.RenderTransform as ScaleTransform ?? new ScaleTransform(1, 1);
            if (!AreAnimationsEnabled())
            {
                overlay.IsVisible = false;
                _isCosmeticDropAnimating = false;
                return;
            }

            const int steps = 14;
            const int durationMs = 180;
            for (int i = 0; i <= steps; i++)
            {
                double t = (double)i / steps;
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (backdrop != null) backdrop.Opacity = 1 - t;
                    panel.Opacity = 1 - t;
                    st.ScaleX = 1 - 0.1 * t;
                    st.ScaleY = 1 - 0.1 * t;
                });
                if (i < steps) await Task.Delay(durationMs / steps);
            }
            overlay.IsVisible = false;
            _isCosmeticDropAnimating = false;
        }

