        private async Task WarmupServerIconsAsync()
        {
            var serversNeedingIcons = _currentSettings.CustomServers
                .Where(s => string.IsNullOrEmpty(s.IconBase64))
                .ToList();

            using var throttler = new SemaphoreSlim(4);
            var tasks = serversNeedingIcons.Select(async s =>
            {
                await throttler.WaitAsync();
                try
                {
                    var status = await _serverChecker.GetServerStatusAsync(s.Address, s.Port);
                    if (!string.IsNullOrEmpty(status.IconData))
                    {
                        s.IconBase64 = status.IconData;
                    }
                }
                catch {  }
                finally
                {
                    throttler.Release();
                }
            });

            await Task.WhenAll(tasks);
            await _settingsService.SaveSettingsAsync(_currentSettings);
            await Dispatcher.UIThread.InvokeAsync(() =>
            {
                LoadServers();
                RefreshQuickPlayBar();
            });
        }

        private async Task RefreshSingleServerAsync(ServerInfo server)
        {
            try
            {
                var status = await _serverChecker.GetServerStatusAsync(server.Address, server.Port);

                server.IsOnline = status.IsOnline;
                server.CurrentPlayers = status.CurrentPlayers;
                server.MaxPlayers = status.MaxPlayers;
                server.Motd = status.Motd;

                if (!string.IsNullOrEmpty(status.IconData))
                {
                    server.IconBase64 = status.IconData;
                    await _settingsService.SaveSettingsAsync(_currentSettings);
                }

                await Dispatcher.UIThread.InvokeAsync(() => { UpdateServerCardUI(server); });
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Server Status Refresh Error", $"{server.Name}: {ex.Message}");
                server.IsOnline = false;
                server.Motd = "Refresh Failed (No Response)";
                server.CurrentPlayers = 0;
                server.MaxPlayers = 0;
                await Dispatcher.UIThread.InvokeAsync(() => { UpdateServerCardUI(server); });
            }
        }

        private async Task RefreshAllServerStatusesAsync()
        {
            var allServers = _currentSettings.CustomServers.Concat(_featuredServers).ToList();
            var tasks = allServers.Select(async server =>
            {
                bool isFeatured = server.Id?.StartsWith("featured_") == true;
                string serverId = server.Id ?? "";
                string address = server.Address;
                int port = server.Port;
                try
                {
                    var status = await _serverChecker.GetServerStatusAsync(address, port);

                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        ServerInfo? target = isFeatured
                            ? _featuredServers.FirstOrDefault(s => s.Id == serverId)
                            : _currentSettings.CustomServers.FirstOrDefault(s => s.Id == serverId) ?? server;
                        if (target == null) return;

                        target.IsOnline = status.IsOnline;
                        target.CurrentPlayers = status.CurrentPlayers;
                        target.MaxPlayers = status.MaxPlayers;
                        target.Motd = status.Motd;
                        target.StatusText = status.IsOnline ? "Online" : "Offline";
                        target.StatusColor = status.IsOnline ? Brushes.Green : Brushes.Red;
                        if (!string.IsNullOrEmpty(status.IconData))
                            target.IconBase64 = status.IconData;

                        if (isFeatured)
                        {
                            UpdateFeaturedServerCardUI(target);
                            try { RefreshQuickPlayBar(); } catch { }
                        }
                        else if (_serversPage?.IsVisible == true)
                        {
                            UpdateServerCardUI(target);
                        }
                    });
                }
                catch (Exception ex)
                {
                    LeafClient.Services.LeafLog.Error("Server Status", $"Error checking {server.Name}: {ex.Message}");

                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        ServerInfo? target = isFeatured
                            ? _featuredServers.FirstOrDefault(s => s.Id == serverId)
                            : _currentSettings.CustomServers.FirstOrDefault(s => s.Id == serverId) ?? server;
                        if (target == null) return;

                        target.IsOnline = false;
                        target.StatusText = "Offline";
                        target.StatusColor = Brushes.Red;
                        target.Motd = "Connection Failed";
                        target.CurrentPlayers = 0;
                        target.MaxPlayers = 0;

                        if (isFeatured)
                        {
                            UpdateFeaturedServerCardUI(target);
                            try { RefreshQuickPlayBar(); } catch { }
                        }
                        else if (_serversPage?.IsVisible == true)
                        {
                            UpdateServerCardUI(target);
                        }
                    });
                }
            });

            await Task.WhenAll(tasks);

            await _settingsService.SaveSettingsAsync(_currentSettings);

            await Dispatcher.UIThread.InvokeAsync(() => RefreshQuickPlayBar());

            await UpdateServerButtonStates();
        }

