        private async void ShowSettingsSaveBanner()
        {
            if (_settingsSaveBanner == null) return;

            _settingsSaveBanner.IsVisible = true;

            TranslateTransform? transform = _settingsSaveBanner.RenderTransform as TranslateTransform;
            if (transform == null)
            {
                transform = new TranslateTransform();
                _settingsSaveBanner.RenderTransform = transform;
            }

            if (!AreAnimationsEnabled())
            {
                transform.Y = 0;
                _settingsSaveBanner.Opacity = 1;
                return;
            }

            transform.Y = 80;
            _settingsSaveBanner.Opacity = 0;

            const int durationMs = 300;
            const int steps = 20;
            const int delayMs = durationMs / steps;

            for (int i = 0; i <= steps; i++)
            {
                double progress = (double)i / steps;
                double eased = 1 - Math.Pow(1 - progress, 3);

                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (_settingsSaveBanner == null) return;
                    transform.Y = 80 - (80 * eased);
                    _settingsSaveBanner.Opacity = eased;
                });

                if (i < steps)
                    await Task.Delay(delayMs);
            }
        }

        private async void HideSettingsSaveBanner()
        {
            if (_settingsSaveBanner == null) return;
            TranslateTransform? transform = _settingsSaveBanner.RenderTransform as TranslateTransform;
            if (transform == null) return;

            _settingsDirty = false;

            if (!AreAnimationsEnabled())
            {
                transform.Y = 80;
                _settingsSaveBanner.Opacity = 0;
                _settingsSaveBanner.IsVisible = false;
                return;
            }

            const int durationMs = 300;
            const int steps = 20;
            const int delayMs = durationMs / steps;

            for (int i = 0; i <= steps; i++)
            {
                double progress = (double)i / steps;
                double eased = 1 - Math.Pow(1 - progress, 3);

                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (_settingsSaveBanner == null) return;
                    transform.Y = 0 + (80 * eased);
                    _settingsSaveBanner.Opacity = 1 - eased;
                });

                if (i < steps)
                    await Task.Delay(delayMs);
            }

            _settingsSaveBanner.IsVisible = false;
        }

        private void MarkSettingsDirty()
        {
            if (_isApplyingSettings) return;
            if (!_settingsDirty)
            {
                _settingsDirty = true;
                ShowSettingsSaveBanner();
            }
            _ = TryCloudSyncPushAsync();
        }

        private bool _cloudSyncPullDone;

        private async Task TryCloudSyncPullAsync()
        {
            if (_cloudSyncPullDone) return;
            if (!_isLeafPlus) return;
            var jwt = _currentSettings?.LeafApiJwt;
            if (string.IsNullOrEmpty(jwt) || _currentSettings == null) return;
            try
            {
                var remote = await Services.CloudSyncService.PullAsync(jwt);
                if (remote == null) return;
                _cloudSyncPullDone = true;
                if (!Services.CloudSyncService.ShouldApplyRemote(_currentSettings.LastCloudSyncAt, remote.LastSyncedAt))
                    return;

                if (remote.LauncherSettings.HasValue && remote.LauncherSettings.Value.ValueKind != JsonValueKind.Null)
                {
                    try
                    {
                        var json = remote.LauncherSettings.Value.GetRawText();
                        var incoming = System.Text.Json.JsonSerializer.Deserialize(json, JsonContext.Default.LauncherSettings);
                        if (incoming != null)
                        {
                            incoming.SessionAccessToken = _currentSettings.SessionAccessToken;
                            incoming.MicrosoftRefreshToken = _currentSettings.MicrosoftRefreshToken;
                            incoming.LeafApiJwt = _currentSettings.LeafApiJwt;
                            incoming.LeafApiRefreshToken = _currentSettings.LeafApiRefreshToken;
                            incoming.SavedAccounts = _currentSettings.SavedAccounts;
                            incoming.ActiveAccountId = _currentSettings.ActiveAccountId;
                            incoming.SessionUsername = _currentSettings.SessionUsername;
                            incoming.SessionUuid = _currentSettings.SessionUuid;
                            incoming.SessionXuid = _currentSettings.SessionXuid;
                            incoming.IsLoggedIn = _currentSettings.IsLoggedIn;
                            incoming.AccountType = _currentSettings.AccountType;
                            incoming.LastCloudSyncAt = remote.LastSyncedAt;
                            _currentSettings = incoming;
                            await _settingsService.SaveSettingsAsync(_currentSettings);
                            await Avalonia.Threading.Dispatcher.UIThread.InvokeAsync(() => ApplySettingsToUi(_currentSettings));
                        }
                    }
                    catch (Exception ex) { LeafClient.Services.LeafLog.Error("CloudSync", $"Apply launcher_settings failed: {ex.Message}"); }
                }

                Services.CloudSyncService.ApplyRemoteAuxiliary(remote);
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("CloudSync", $"Pull failed: {ex.Message}"); }
        }

        private async Task TryCloudSyncPushAsync(bool force = false)
        {
            if (!_isLeafPlus) return;
            var jwt = _currentSettings?.LeafApiJwt;
            if (string.IsNullOrEmpty(jwt) || _currentSettings == null) return;
            try
            {
                var result = await Services.CloudSyncService.PushAsync(jwt, _currentSettings, force);
                if (result?.Ok == true && _settingsService != null)
                {
                    try { await _settingsService.SaveSettingsAsync(_currentSettings); } catch { }
                }
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("CloudSync", $"Push failed: {ex.Message}"); }
        }

        protected override void OnClosing(WindowClosingEventArgs e)
        {
            LeafClient.Services.LeafLog.Info("MainWindow", $"OnClosing called - IsSwapToLogin: {(Application.Current as App)?.IsSwapToLogin}");
            base.OnClosing(e);
        }

        private bool _isShuttingDown = false;
        private async void OnWindowClosing(object? sender, WindowClosingEventArgs e)
        {
            bool isAppSwappingToLogin = (Application.Current as App)?.IsSwapToLogin ?? false;

            if (_isShuttingDown)
            {
                e.Cancel = false;
                return;
            }

            if (isAppSwappingToLogin)
            {
                LeafClient.Services.LeafLog.Info("MainWindow", $"OnWindowClosing: Detected app is swapping windows. Cancelling close for this window.");
                e.Cancel = false;

                if (Application.Current is App app)
                {
                    app.IsSwapToLogin = false;
                }
                return;
            }

            if (_currentSettings.MinimizeToTray && !_isExitingApp)
            {
                LeafLog.Info("MainWindow", "OnWindowClosing: Minimize to tray enabled. Hiding window.");
                e.Cancel = true;
                MinimizeToTray();
                return;
            }

            _gameOutputWindow?.Close();
            _isShuttingDown = true;
            e.Cancel = true;

            this.Hide();
            LeafLog.Info("MainWindow", "Window hidden. Starting graceful application shutdown...");

            if (_onlineCountService != null)
            {
                try
                {
                    LeafLog.Info("MainWindow", "Attempting to decrement online count before shutdown...");
                    var cts = new CancellationTokenSource(TimeSpan.FromSeconds(3));
                    await _onlineCountService.UpdateCount(false, cts.Token);
                }
                catch (Exception ex)
                {
                    LeafLog.Error("MainWindow ERROR", $"Failed to decrement online count during shutdown: {ex.Message}");
                }
            }

            StopHeartbeatLoop();
            StopGameplayPlaytimePolling();
            StopRichPresence();

            try
            {
                if (_sessionStartUtc.HasValue && _currentSettings != null)
                {
                    long sessionSeconds = (long)(DateTime.UtcNow - _sessionStartUtc.Value).TotalSeconds;
                    if (sessionSeconds < 0) sessionSeconds = 0;
                    if (sessionSeconds > 86400) sessionSeconds = 86400;

                    long checkpointBaseSeconds = _lastLocalPlaytimeCheckpointUtc.HasValue
                        ? (long)(DateTime.UtcNow - _lastLocalPlaytimeCheckpointUtc.Value).TotalSeconds
                        : sessionSeconds;
                    if (checkpointBaseSeconds < 0) checkpointBaseSeconds = 0;
                    if (checkpointBaseSeconds > 86400) checkpointBaseSeconds = 86400;

                    _currentSettings.CurrentSessionSeconds = sessionSeconds;
                    _currentSettings.TotalPlaytimeSeconds += checkpointBaseSeconds;
                    _currentSettings.LastExitTime = DateTime.Now;

                    var mcVersion = _currentSettings.SelectedSubVersion;
                    if (!string.IsNullOrEmpty(mcVersion))
                    {
                        _currentSettings.PlaytimeByVersion.TryGetValue(mcVersion, out long cur);
                        _currentSettings.PlaytimeByVersion[mcVersion] = cur + checkpointBaseSeconds;
                    }

                    var server = _currentSettings.QuickJoinServerAddress;
                    if (!string.IsNullOrEmpty(server))
                    {
                        _currentSettings.PlaytimeByServer.TryGetValue(server, out long curS);
                        _currentSettings.PlaytimeByServer[server] = curS + checkpointBaseSeconds;
                    }

                    var activeProfile = GetActiveProfile();
                    if (activeProfile != null)
                    {
                        activeProfile.PlaytimeSeconds += checkpointBaseSeconds;
                    }

                    _sessionStartUtc = null;
                    _lastLocalPlaytimeCheckpointUtc = null;
                    _sessionReportedMinutes = 0;
                    try { _settingsService.SaveSettingsAsync(_currentSettings).GetAwaiter().GetResult(); } catch { }
                    LeafClient.Services.LeafLog.Info("Playtime", $"Shutdown flush: +{checkpointBaseSeconds}s since last checkpoint, total: {_currentSettings.TotalPlaytimeSeconds}s");
                }
            }
            catch (Exception flushEx)
            {
                LeafLog.Error("Playtime", $"Shutdown flush failed: {flushEx.Message}");
            }

            KillMinecraftProcess();

            if (_trayIcon != null)
            {
                _trayIcon.IsVisible = false;
                _trayIcon.Dispose();
            }

            if (_logStreamWriter != null)
            {
                try
                {
                    LeafLog.Info("MainWindow", "Closing log writer...");
                    Console.SetOut(_originalConsoleOut ?? new StreamWriter(Console.OpenStandardOutput()) { AutoFlush = true });
                    Console.SetError(_originalConsoleError ?? new StreamWriter(Console.OpenStandardError()) { AutoFlush = true });
                    _logStreamWriter.Close();
                    _logStreamWriter.Dispose();
                    _logStreamWriter = null;
                }
                catch (Exception ex)
                {
                    _originalConsoleOut?.WriteLine($"[MainWindow ERROR] Failed to close log writer: {ex.Message}");
                }
            }

            if (Application.Current?.ApplicationLifetime is IClassicDesktopStyleApplicationLifetime desktop)
            {
                LeafLog.Info("MainWindow", "Graceful shutdown complete. Terminating process.");
                desktop.Shutdown();
            }
        }

        private async Task<T> RunExclusiveInstall<T>(Func<Task<T>> installAction)
        {
            await _installGate.WaitAsync();
            try
            {
                return await installAction();
            }
            finally
            {
                _installGate.Release();
            }
        }

        private sealed class TrayActionCommand : System.Windows.Input.ICommand
        {
            private readonly Action _action;
            public TrayActionCommand(Action action) { _action = action; }
            public event EventHandler? CanExecuteChanged { add { } remove { } }
            public bool CanExecute(object? parameter) => true;
            public void Execute(object? parameter)
            {
                try { Dispatcher.UIThread.Post(() => { try { _action(); } catch (Exception ex) { LeafLog.Error("TrayCommand", $"{ex.Message}"); } }); }
                catch (Exception ex) { LeafLog.Error("TrayCommand", $"post failed: {ex.Message}"); }
            }
        }

        private void InitializeTrayIcon()
        {
            try
            {
                _trayIcon = new TrayIcon();

                var iconStream = AssetLoader.Open(new Uri("avares://LeafClient/Assets/logo_icon_tray.png"));
                _trayIcon.Icon = new WindowIcon(iconStream);
                _trayIcon.ToolTipText = "Leaf Client";
                _trayIcon.IsVisible = false;

                var trayMenu = new NativeMenu();

                trayMenu.Add(new NativeMenuItem("Open Launcher") { Command = new TrayActionCommand(() => RestoreFromTray()) });
                trayMenu.Add(new NativeMenuItemSeparator());
                trayMenu.Add(new NativeMenuItem("Home")     { Command = new TrayActionCommand(TrayMenuItem_Home) });
                trayMenu.Add(new NativeMenuItem("Versions") { Command = new TrayActionCommand(TrayMenuItem_Versions) });
                trayMenu.Add(new NativeMenuItem("Servers")  { Command = new TrayActionCommand(TrayMenuItem_Servers) });
                trayMenu.Add(new NativeMenuItem("Mods")     { Command = new TrayActionCommand(TrayMenuItem_Mods) });
                trayMenu.Add(new NativeMenuItem("Settings") { Command = new TrayActionCommand(TrayMenuItem_Settings) });
                trayMenu.Add(new NativeMenuItem("Skins")    { Command = new TrayActionCommand(TrayMenuItem_Skins) });
                trayMenu.Add(new NativeMenuItemSeparator());
                trayMenu.Add(new NativeMenuItem("Log out")          { Command = new TrayActionCommand(TrayMenuItem_Logout) });
                trayMenu.Add(new NativeMenuItem("Quit Leaf Client") { Command = new TrayActionCommand(TrayMenuItem_Exit) });

                _trayIcon.Menu = trayMenu;

                _trayIcon.Clicked += (s, e) => RestoreFromTray();

                var trayIconsCollection = new Avalonia.Controls.TrayIcons();
                trayIconsCollection.Add(_trayIcon);

                TrayIcon.SetIcons(Application.Current, trayIconsCollection);
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("TrayIcon", $"Failed to initialize: {ex.Message}");
            }
        }

