        private void RestoreFromTray()
        {
            if (_isShuttingDown) return;

            Dispatcher.UIThread.Post(() =>
            {
                if (_isShuttingDown) return;

                try
                {
                    this.Show();
                    this.WindowState = WindowState.Normal;
                    this.Activate();
                    DisposeTrayIcon();
                    ForceWindowToForeground();
                }
                catch (InvalidOperationException)
                {
                }
            });
        }

        [DllImport("user32.dll")] private static extern bool ShowWindow(IntPtr hWnd, int nCmdShow);
        [DllImport("user32.dll")] private static extern bool SetForegroundWindow(IntPtr hWnd);
        [DllImport("user32.dll")] private static extern IntPtr GetForegroundWindow();
        [DllImport("user32.dll")] private static extern uint GetWindowThreadProcessId(IntPtr hWnd, out uint lpdwProcessId);
        [DllImport("kernel32.dll")] private static extern uint GetCurrentThreadId();
        [DllImport("user32.dll")] private static extern bool AttachThreadInput(uint idAttach, uint idAttachTo, bool fAttach);
        private const int SW_RESTORE = 9;
        private const int SW_SHOW = 5;

        private void ForceWindowToForeground()
        {
            if (!OperatingSystem.IsWindows()) return;
            try
            {
                var handle = TryGetPlatformHandle()?.Handle ?? IntPtr.Zero;
                if (handle == IntPtr.Zero) return;
                ShowWindow(handle, this.WindowState == WindowState.Minimized ? SW_RESTORE : SW_SHOW);
                IntPtr fg = GetForegroundWindow();
                uint fgTid = fg != IntPtr.Zero ? GetWindowThreadProcessId(fg, out _) : 0;
                uint myTid = GetCurrentThreadId();
                bool attached = false;
                if (fgTid != 0 && fgTid != myTid)
                {
                    try { attached = AttachThreadInput(fgTid, myTid, true); } catch { }
                }
                try { SetForegroundWindow(handle); } catch { }
                if (attached)
                {
                    try { AttachThreadInput(fgTid, myTid, false); } catch { }
                }
            }
            catch (Exception ex) { LeafLog.Error("ForceForeground", $"{ex.Message}"); }
        }

        private void DisposeTrayIcon()
        {
            try
            {
                if (_trayIcon != null)
                {
                    _trayIcon.IsVisible = false;
                    if (Application.Current != null)
                    {
                        TrayIcon.SetIcons(Application.Current, new Avalonia.Controls.TrayIcons());
                    }
                    _trayIcon.Dispose();
                    _trayIcon = null;
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("TrayIcon", $"Dispose failed: {ex.Message}");
            }
        }

        private void MinimizeToTray()
        {
            try
            {
                if (_trayIcon == null) InitializeTrayIcon();

                bool trayReady = false;
                if (_trayIcon != null)
                {
                    try { _trayIcon.IsVisible = true; trayReady = true; }
                    catch (Exception ex) { LeafLog.Error("MinimizeToTray", $"tray IsVisible failed: {ex.Message}"); }
                }

                if (trayReady)
                {
                    this.Hide();
                }
                else
                {
                    LeafLog.Error("MinimizeToTray", "Tray icon unavailable - falling back to WindowState.Minimized so the launcher stays reachable from the taskbar.");
                    this.WindowState = WindowState.Minimized;
                }

                if (_currentSettings != null && _currentSettings.ClosingNotificationsPreference != NotificationPreference.Never)
                {
                    try { NotificationWindow.Show("Leaf Client", "Running in background", "Restore", () => RestoreFromTray()); } catch { }
                }
            }
            catch (Exception ex)
            {
                LeafLog.Error("MinimizeToTray", $"failed: {ex.Message} - falling back to minimize.");
                try { this.WindowState = WindowState.Minimized; } catch { }
            }
        }

        private void KillMinecraftProcess()
        {
            List<Process> snapshot;
            lock (_runningInstancesLock)
            {
                snapshot = _runningGameProcesses.Where(p => p != null && !p.HasExited).ToList();
            }
            if (snapshot.Count == 0 && (_gameProcess == null || _gameProcess.HasExited)) return;

            _userTerminatedGame = true;
            foreach (var procToKill in snapshot)
            {
                Task.Run(() =>
                {
                    try
                    {
                        procToKill.Kill(entireProcessTree: true);
                        procToKill.WaitForExit(5000);
                        LeafClient.Services.LeafLog.Info("Launcher", $"Minecraft instance pid={procToKill.Id} terminated.");
                    }
                    catch (Exception ex)
                    {
                        LeafClient.Services.LeafLog.Error("Launcher", $"Error terminating instance pid={procToKill.Id}: {ex.Message}");
                    }
                });
            }
        }

        private int RunningInstanceCount
        {
            get
            {
                lock (_runningInstancesLock)
                {
                    _runningGameProcesses.RemoveAll(p => p == null || p.HasExited);
                    return _runningGameProcesses.Count;
                }
            }
        }

        private bool AnyGameRunning => RunningInstanceCount > 0;

        private void RegisterRunningInstance(Process p)
        {
            lock (_runningInstancesLock)
            {
                _runningGameProcesses.RemoveAll(x => x == null || x.HasExited);
                _runningGameProcesses.Add(p);
            }
            try
            {
                p.EnableRaisingEvents = true;
                p.Exited += (s, e) =>
                {
                    lock (_runningInstancesLock)
                    {
                        _runningGameProcesses.RemoveAll(x => x == null || x.HasExited);
                    }
                    try { Dispatcher.UIThread.Post(() => { UpdateInstancesPill(); ApplyLaunchButtonState(); }); } catch { }
                };
            }
            catch (Exception ex) { LeafLog.Error("Instances", $"hook exit failed: {ex.Message}"); }
            try { Dispatcher.UIThread.Post(() => { UpdateInstancesPill(); ApplyLaunchButtonState(); }); } catch { }
        }

        private const int MaxConcurrentInstances = 3;
        private string? _runningInstancesVersion;
        private readonly SemaphoreSlim _launchPrepSemaphore = new(1, 1);

        private long GetAvailablePhysicalRamMb()
        {
            try
            {
                if (OperatingSystem.IsWindows())
                {
                    var s = new MEMORYSTATUSEX { dwLength = (uint)System.Runtime.InteropServices.Marshal.SizeOf<MEMORYSTATUSEX>() };
                    if (GlobalMemoryStatusEx(ref s))
                        return (long)(s.ullAvailPhys / (1024UL * 1024UL));
                }
            }
            catch { }
            return -1;
        }

        private bool CanLaunchAnotherInstance(string versionToLaunch, out string reason)
        {
            reason = "";
            int count = RunningInstanceCount;
            if (count == 0) { _runningInstancesVersion = versionToLaunch; return true; }

            if (count >= MaxConcurrentInstances)
            {
                reason = $"Maximum of {MaxConcurrentInstances} Minecraft instances allowed. Quit one before launching another.";
                return false;
            }

            if (!string.IsNullOrEmpty(_runningInstancesVersion)
                && !string.Equals(_runningInstancesVersion, versionToLaunch, StringComparison.OrdinalIgnoreCase))
            {
                reason = $"Cannot launch {versionToLaunch} while {_runningInstancesVersion} is running. Quit the running instance or pick the same version.";
                return false;
            }

            try
            {
                int xmxMb = GetEffectiveMaxRamMb();
                long avail = GetAvailablePhysicalRamMb();
                if (avail > 0 && xmxMb > 0 && xmxMb > (avail - 1024))
                {
                    reason = $"Not enough free RAM for another instance ({xmxMb} MB requested, {avail} MB available). Lower your RAM allocation or quit a running instance.";
                    return false;
                }
            }
            catch { }

            try
            {
                if (string.Equals(_currentSettings?.AccountType, "microsoft", StringComparison.OrdinalIgnoreCase))
                {
                    ToastService.Show("Launching a second instance with the same Microsoft account. Mojang may reject the second session.", ToastType.Info);
                }
            }
            catch { }

            return true;
        }

        private void UpdateInstancesPill()
        {
            try
            {
                _instancesPill ??= this.FindControl<Border>("InstancesPill");
                _instancesPillText ??= this.FindControl<TextBlock>("InstancesPillText");
                _instancesPillDot ??= this.FindControl<Avalonia.Controls.Shapes.Ellipse>("InstancesPillDot");
                if (_instancesPillText == null) return;

                int count = RunningInstanceCount;
                _instancesPillText.Text = count == 1 ? "1 Instance" : $"{count} Instances";

                if (_instancesPillDot != null)
                {
                    _instancesPillDot.Fill = new SolidColorBrush(count > 0
                        ? Color.FromRgb(0x4A, 0xDE, 0x80)
                        : Color.FromRgb(0x60, 0x6A, 0x78));
                }
            }
            catch (Exception ex) { LeafLog.Error("InstancesPill", $"{ex.Message}"); }
        }

        private async Task PrepareModsFolderAsync(string mcVersion)
        {
            string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
            try { Directory.CreateDirectory(modsFolder); } catch { }

            try
            {
                if (!_currentSettings.ModFolderMigrationCompleted)
                {
                    int backfilled = await LeafClient.Services.ModFolderManagement.ModFolderTracker
                        .BackfillManagedHashesAsync(modsFolder, _currentSettings.InstalledMods);
                    _currentSettings.ModFolderMigrationCompleted = true;
                    if (backfilled > 0)
                    {
                        _gameOutputWindow?.AppendLog(
                            $"[LaunchDiag] Mod folder migration: backfilled SHA256 for {backfilled} managed mod(s).",
                            "INFO");
                    }
                    try { await _settingsService.SaveSettingsAsync(_currentSettings); } catch { }
                }

                var preserved = GetModpackPreservedModFiles();
                var tracked = await LeafClient.Services.ModFolderManagement.ModFolderTracker
                    .ScanFolderAsync(modsFolder, _currentSettings.InstalledMods);

                int managedCurrent = 0, archived = 0, userMods = 0, modpackPreserved = 0;
                foreach (var jar in tracked)
                {
                    if (preserved.Contains(jar.FileName))
                    {
                        modpackPreserved++;
                        continue;
                    }

                    if (jar.Ownership == LeafClient.Services.ModFolderManagement.JarOwnership.User)
                    {
                        userMods++;
                        continue;
                    }

                    if (jar.Ownership == LeafClient.Services.ModFolderManagement.JarOwnership.Managed
                        && jar.ManagedEntry != null)
                    {
                        var modMc = jar.ManagedEntry.MinecraftVersion;
                        if (string.IsNullOrEmpty(modMc) || string.Equals(modMc, mcVersion, StringComparison.OrdinalIgnoreCase))
                        {
                            managedCurrent++;
                            continue;
                        }

                        try
                        {
                            var dest = System.IO.Path.Combine(
                                LeafClient.Services.ModFolderManagement.ModFolderTracker.GetArchivePath(modsFolder, modMc),
                                jar.FileName);
                            Directory.CreateDirectory(System.IO.Path.GetDirectoryName(dest)!);
                            if (File.Exists(dest)) File.Delete(dest);
                            File.Move(jar.FullPath, dest);
                            archived++;
                        }
                        catch (Exception ex)
                        {
                            LeafLog.Error("LaunchDiag", $"Archive failed for {jar.FileName}: {ex.Message}");
                        }
                    }
                }

                _gameOutputWindow?.AppendLog(
                    $"[LaunchDiag] Mod folder prepared for MC {mcVersion}: managed={managedCurrent} archived={archived} user-protected={userMods} modpack-preserved={modpackPreserved}",
                    "INFO");

                if (archived > 0)
                {
                    _gameOutputWindow?.AppendLog(
                        $"[LaunchDiag] {archived} mod(s) for other MC versions moved to mods/.leaf-archived/ (not deleted).",
                        "INFO");
                }

                int allowlistArchived = await ArchiveStaleManagedJarsAsync(modsFolder, mcVersion, preserved);
                if (allowlistArchived > 0)
                {
                    _gameOutputWindow?.AppendLog(
                        $"[LaunchDiag] {allowlistArchived} pre-installed mod jar(s) for other MC versions archived (allowlist sweep).",
                        "INFO");
                }
            }
            catch (Exception ex)
            {
                LeafLog.Error("LaunchDiag", $"PrepareModsFolderAsync failed: {ex.Message}");
                _gameOutputWindow?.AppendLog(
                    $"[LaunchDiag] Mod folder preparation error: {ex.GetType().Name}: {ex.Message}",
                    "ERROR");
            }
        }

        private async Task<int> ArchiveStaleManagedJarsAsync(string modsFolder, string mcVersion, HashSet<string> preserved)
        {
            int archived = 0;
            try
            {
                var scanned = await LeafClient.Services.ModFolderManagement.ModScanner.ScanFolderAsync(modsFolder, fastMode: true);
                foreach (var meta in scanned)
                {
                    if (!meta.IsParsed || string.IsNullOrEmpty(meta.ModId)) continue;
                    if (preserved.Contains(meta.FileName)) continue;
                    if (!LeafClient.Services.ModFolderManagement.BundledModsAllowlist.IsLauncherManaged(meta.ModId)) continue;

                    string? declaredMcRange = meta.Depends
                        ?.FirstOrDefault(d => string.Equals(d.TargetId, "minecraft", StringComparison.OrdinalIgnoreCase))?.VersionRange;

                    if (string.IsNullOrEmpty(declaredMcRange)) continue;
                    if (LeafClient.Services.ModFolderManagement.VersionRange.Matches(declaredMcRange, mcVersion)) continue;

                    string archiveBucket = ExtractFirstSemverFromRange(declaredMcRange) ?? "unknown";
                    try
                    {
                        var dest = System.IO.Path.Combine(
                            LeafClient.Services.ModFolderManagement.ModFolderTracker.GetArchivePath(modsFolder, archiveBucket),
                            meta.FileName);
                        Directory.CreateDirectory(System.IO.Path.GetDirectoryName(dest)!);
                        if (File.Exists(dest)) File.Delete(dest);
                        File.Move(meta.FilePath, dest);
                        archived++;
                    }
                    catch (Exception ex)
                    {
                        LeafLog.Error("LaunchDiag", $"Allowlist-archive failed for {meta.FileName}: {ex.Message}");
                    }
                }
            }
            catch (Exception ex)
            {
                LeafLog.Error("LaunchDiag", $"ArchiveStaleManagedJarsAsync failed: {ex.Message}");
            }
            return archived;
        }

        private static string? ExtractFirstSemverFromRange(string range)
        {
            if (string.IsNullOrEmpty(range)) return null;
            var match = System.Text.RegularExpressions.Regex.Match(range, @"\d+(\.\d+){1,2}");
            return match.Success ? match.Value : null;
        }

        private void ClearModsFolder()
        {
            string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");

            if (!Directory.Exists(modsFolder))
            {
                try { Directory.CreateDirectory(modsFolder); } catch { }
                LeafLog.Info("Launcher", "Mods folder did not exist, created fresh.");
                _gameOutputWindow?.AppendLog("[LaunchDiag] Mods folder did not exist, created fresh.", "INFO");
                return;
            }

            var preserved = GetModpackPreservedModFiles();
            LeafClient.Services.LeafLog.Info("Launcher", $"Clearing mods folder for a fresh launch (preserving {preserved.Count} modpack file(s))...");
            _gameOutputWindow?.AppendLog($"[LaunchDiag] Clearing mods folder for a fresh launch (preserving {preserved.Count} modpack file(s))...", "INFO");

            const int maxAttempts = 3;
            Exception? lastEx = null;
            for (int attempt = 1; attempt <= maxAttempts; attempt++)
            {
                try
                {
                    int deleted = 0, kept = 0;
                    foreach (var path in Directory.GetFiles(modsFolder, "*.*", SearchOption.AllDirectories))
                    {
                        var rel = System.IO.Path.GetRelativePath(modsFolder, path).Replace('\\', '/');
                        if (preserved.Contains(rel) || preserved.Contains(System.IO.Path.GetFileName(path)))
                        {
                            kept++;
                            continue;
                        }
                        try { File.Delete(path); deleted++; } catch { }
                    }
                    foreach (var dir in Directory.GetDirectories(modsFolder, "*", SearchOption.AllDirectories).OrderByDescending(d => d.Length))
                    {
                        try { if (!Directory.EnumerateFileSystemEntries(dir).Any()) Directory.Delete(dir); } catch { }
                    }
                    LeafClient.Services.LeafLog.Info("Launcher", $"Mods folder cleared (attempt {attempt}): deleted={deleted} kept={kept}.");
                    _gameOutputWindow?.AppendLog($"[LaunchDiag] Mods folder cleared (attempt {attempt}): deleted={deleted} kept={kept} (modpack-preserved).", "INFO");
                    return;
                }
                catch (Exception ex)
                {
                    lastEx = ex;
                    LeafLog.Error("Launcher ERROR", $"Failed to clear mods folder (attempt {attempt}/{maxAttempts}): {ex.Message}");
                    _gameOutputWindow?.AppendLog(
                        $"[LaunchDiag] Failed to clear mods folder (attempt {attempt}/{maxAttempts}): {ex.GetType().Name}: {ex.Message}",
                        "ERROR");
                    try { System.Threading.Thread.Sleep(200); } catch { }
                }
            }

            try
            {
                if (!Directory.Exists(modsFolder)) Directory.CreateDirectory(modsFolder);

                var remaining = Directory.GetFiles(modsFolder, "*.*", SearchOption.AllDirectories);
                foreach (var f in remaining)
                {
                    var rel = System.IO.Path.GetRelativePath(modsFolder, f).Replace('\\', '/');
                    if (preserved.Contains(rel) || preserved.Contains(System.IO.Path.GetFileName(f))) continue;
                    try { File.Delete(f); } catch { }
                }

                var stillThere = Directory.GetFiles(modsFolder, "*.jar", SearchOption.AllDirectories)
                    .Concat(Directory.GetFiles(modsFolder, "*.jar.disabled", SearchOption.AllDirectories))
                    .ToArray();

                var stillLeaf = stillThere
                    .Where(p => System.IO.Path.GetFileName(p).Contains("leaf", StringComparison.OrdinalIgnoreCase))
                    .ToArray();

                if (stillLeaf.Length > 0)
                {
                    _gameOutputWindow?.AppendLog(
                        $"[LaunchDiag] WARNING: {stillLeaf.Length} leafclient-like jar(s) SURVIVED the clear attempt!",
                        "ERROR");
                    foreach (var p in stillLeaf)
                    {
                        try
                        {
                            var fi = new FileInfo(p);
                            _gameOutputWindow?.AppendLog(
                                $"[LaunchDiag]   SURVIVED: {p} (size={fi.Length} bytes, mtime={fi.LastWriteTime:yyyy-MM-dd HH:mm:ss})",
                                "ERROR");
                        }
                        catch
                        {
                            _gameOutputWindow?.AppendLog($"[LaunchDiag]   SURVIVED: {p}", "ERROR");
                        }
                    }
                    ShowLaunchErrorBanner("A leafclient jar survived the mods folder clear. A stale mod may load.");
                }
                else if (stillThere.Length > 0)
                {
                    _gameOutputWindow?.AppendLog(
                        $"[LaunchDiag] WARNING: {stillThere.Length} non-leaf jar(s) survived the mods folder clear.",
                        "WARN");
                }
            }
            catch (Exception scanEx)
            {
                _gameOutputWindow?.AppendLog(
                    $"[LaunchDiag] Post-clear scan failed: {scanEx.GetType().Name}: {scanEx.Message}",
                    "ERROR");
            }

            if (lastEx != null)
            {
                LeafLog.Error("Launcher ERROR", $"Failed to clear mods folder after {maxAttempts} attempts: {lastEx.Message}");
                ShowLaunchErrorBanner("Failed to clear the mods folder after retries. It might be in use.");
            }
        }

        private static string ComputeShortSha256(string filePath)
        {
            try
            {
                using var stream = File.OpenRead(filePath);
                using var sha = SHA256.Create();
                byte[] hash = sha.ComputeHash(stream);
                var sb = new StringBuilder(hash.Length * 2);
                foreach (var b in hash) sb.Append(b.ToString("x2"));
                return sb.ToString(0, Math.Min(16, sb.Length));
            }
            catch (Exception ex)
            {
                return $"hash-err:{ex.GetType().Name}";
            }
        }

        private void LogJarFileInfo(string label, string path)
        {
            try
            {
                if (!File.Exists(path))
                {
                    _gameOutputWindow?.AppendLog($"[LaunchDiag] {label}: MISSING -> {path}", "INFO");
                    return;
                }
                var fi = new FileInfo(path);
                string hash = ComputeShortSha256(path);
                _gameOutputWindow?.AppendLog(
                    $"[LaunchDiag] {label}: {path} | size={fi.Length / 1024}KB | mtime={fi.LastWriteTime:yyyy-MM-dd HH:mm:ss} | sha16={hash}",
                    "INFO");
            }
            catch (Exception ex)
            {
                _gameOutputWindow?.AppendLog($"[LaunchDiag] {label}: EXCEPTION inspecting {path}: {ex.GetType().Name}: {ex.Message}", "ERROR");
            }
        }

        private void ScanForStaleLeafJars(string directory, string scanLabel, string? expectedJarPath)
        {
            try
            {
                if (string.IsNullOrEmpty(directory) || !Directory.Exists(directory))
                {
                    _gameOutputWindow?.AppendLog($"[LaunchDiag] {scanLabel}: directory does not exist -> {directory}", "INFO");
                    return;
                }

                string? normalizedExpected = null;
                try
                {
                    if (!string.IsNullOrEmpty(expectedJarPath))
                        normalizedExpected = System.IO.Path.GetFullPath(expectedJarPath);
                }
                catch { }

                var candidates = new List<string>();
                try
                {
                    candidates.AddRange(Directory.GetFiles(directory, "*leaf*.jar", SearchOption.AllDirectories));
                }
                catch { }
                try
                {
                    candidates.AddRange(Directory.GetFiles(directory, "leafclient*.jar", SearchOption.AllDirectories));
                }
                catch { }
                var unique = candidates
                    .Select(p => { try { return System.IO.Path.GetFullPath(p); } catch { return p; } })
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();

                if (unique.Count == 0)
                {
                    _gameOutputWindow?.AppendLog($"[LaunchDiag] {scanLabel}: no leafclient jars found under {directory}", "INFO");
                    return;
                }

                _gameOutputWindow?.AppendLog($"[LaunchDiag] {scanLabel}: found {unique.Count} leafclient-like jar(s) under {directory}", "INFO");
                foreach (var p in unique)
                {
                    bool isExpected = normalizedExpected != null &&
                                      p.Equals(normalizedExpected, StringComparison.OrdinalIgnoreCase);
                    string tag = isExpected ? "expected" : "STALE?";
                    try
                    {
                        var fi = new FileInfo(p);
                        string hash = ComputeShortSha256(p);
                        string level = isExpected ? "INFO" : "WARN";
                        _gameOutputWindow?.AppendLog(
                            $"[LaunchDiag]   [{tag}] {p} | size={fi.Length / 1024}KB | mtime={fi.LastWriteTime:yyyy-MM-dd HH:mm:ss} | sha16={hash}",
                            level);
                    }
                    catch (Exception ex)
                    {
                        _gameOutputWindow?.AppendLog(
                            $"[LaunchDiag]   [{tag}] {p} (inspect failed: {ex.GetType().Name}: {ex.Message})",
                            "ERROR");
                    }
                }
            }
            catch (Exception ex)
            {
                _gameOutputWindow?.AppendLog($"[LaunchDiag] {scanLabel}: scan failed: {ex.GetType().Name}: {ex.Message}", "ERROR");
            }
        }

        private void LogLaunchPreBuildDiagnostics(string leafModPath, string mcVersion)
        {
            try
            {
                _gameOutputWindow?.AppendLog("[LaunchDiag] ===== PRE-BUILD JAR DIAGNOSTIC =====", "INFO");
                _gameOutputWindow?.AppendLog($"[LaunchDiag] leafModPath target = {leafModPath}", "INFO");
                LogJarFileInfo("leafModPath (before build)", leafModPath);

                string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                string leafRuntimeRoot = System.IO.Path.Combine(_minecraftFolder, "leaf-runtime");
                string leafOfflineRoot = System.IO.Path.Combine(
                    Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),
                    ".leafclient", "offline");

                ScanForStaleLeafJars(modsFolder, "pre-build scan: .minecraft/mods", null);
                ScanForStaleLeafJars(leafRuntimeRoot, "pre-build scan: .minecraft/leaf-runtime", null);
                ScanForStaleLeafJars(leafOfflineRoot, "pre-build scan: .leafclient/offline", leafModPath);

                _gameOutputWindow?.AppendLog("[LaunchDiag] ===== END PRE-BUILD JAR DIAGNOSTIC =====", "INFO");
            }
            catch (Exception ex)
            {
                _gameOutputWindow?.AppendLog($"[LaunchDiag] pre-build diagnostics failed: {ex.GetType().Name}: {ex.Message}", "ERROR");
            }
        }

        private void LogLaunchPreLaunchDiagnostics(string leafModPath)
        {
            try
            {
                _gameOutputWindow?.AppendLog("[LaunchDiag] ===== PRE-LAUNCH FINAL CHECK =====", "INFO");
                string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                ScanForStaleLeafJars(modsFolder, "pre-launch scan: .minecraft/mods (should be clean)", null);
                LogJarFileInfo("leafModPath (final)", leafModPath);
                _gameOutputWindow?.AppendLog($"[LaunchDiag] -Dfabric.addMods target = {leafModPath}", "INFO");
                _gameOutputWindow?.AppendLog("[LaunchDiag] ===== END PRE-LAUNCH FINAL CHECK =====", "INFO");
            }
            catch (Exception ex)
            {
                _gameOutputWindow?.AppendLog($"[LaunchDiag] pre-launch diagnostics failed: {ex.GetType().Name}: {ex.Message}", "ERROR");
            }
        }

        private async Task LoadSessionAsync()
        {
            try
            {
                _currentSettings = await _settingsService.LoadSettingsAsync();
                try { WriteSavedAccountsForMod(); } catch { }
                LeafClient.Services.LocalizationService.Instance.SetLocale(_currentSettings?.Language ?? "en");
                WipeCosmeticFilesIfStale();
                LoadOwnedJson();
                MigrateActiveAccountEntry();
                CleanupCrossAccountPresetPollution();
                OneShotResetPerAccountSkins();
                SyncSkinStateFromActiveAccount();
                ValidateEquippedCosmetics();

                if (_currentSettings.IsLoggedIn && _currentSettings.AccountType == "microsoft")
                {
                    if (!string.IsNullOrWhiteSpace(_currentSettings.SessionAccessToken) &&
                        !string.IsNullOrWhiteSpace(_currentSettings.SessionUsername) &&
                        !string.IsNullOrWhiteSpace(_currentSettings.SessionUuid))
                    {
                        LeafLog.Info("Launch", "Validating cached Minecraft token...");
                        bool tokenValid = await ValidateMinecraftTokenAsync(_currentSettings.SessionAccessToken);
                        if (tokenValid)
                        {
                            _session = new MSession
                            {
                                Username = _currentSettings.SessionUsername,
                                UUID = _currentSettings.SessionUuid,
                                AccessToken = _currentSettings.SessionAccessToken,
                                Xuid = _currentSettings.SessionXuid
                            };
                            LeafLog.Info("Launch", "Cached token is still valid - skipping OAuth.");
                            return;
                        }
                        LeafLog.Info("Launch", "Cached token expired. Attempting MSAL silent refresh...");
                    }

                    try
                    {
                        var app = await MsalClientHelper.BuildApplicationWithCache(LeafClient.Services.AuthConfig.MicrosoftClientId, LeafClient.Services.AuthConfig.BuildMsalCacheSettings());
                        var msalAccounts = (await app.GetAccountsAsync()).ToList();
                        LeafClient.Services.LeafLog.Info("Launch", $"MSAL cache contains {msalAccounts.Count} account(s).");

                        if (msalAccounts.Count > 0)
                        {
                            var loginHandler = JELoginHandlerBuilder.BuildDefault();
                            var authenticator = loginHandler.CreateAuthenticatorWithDefaultAccount();
                            authenticator.AddMsalOAuth(app, msal => msal.Silent());
                            authenticator.AddXboxAuthForJE(xbox => xbox.Basic());
                            authenticator.AddForceJEAuthenticator();

                            var refreshedSession = await authenticator.ExecuteForLauncherAsync();
                            if (refreshedSession != null && refreshedSession.CheckIsValid())
                            {
                                _session = refreshedSession;
                                _currentSettings.SessionUsername = _session.Username;
                                _currentSettings.SessionUuid = _session.UUID;
                                _currentSettings.SessionAccessToken = _session.AccessToken;
                                _currentSettings.SessionXuid = _session.Xuid;
                                await _settingsService.SaveSettingsAsync(_currentSettings);
                                LeafLog.Info("Launch", "MSAL silent refresh succeeded.");
                                return;
                            }
                            LeafLog.Info("Launch", "MSAL silent refresh returned invalid session.");
                        }
                        else
                        {
                            LeafLog.Info("Launch", "MSAL has no cached accounts - silent refresh skipped.");
                        }
                    }
                    catch (Exception ex)
                    {
                        LeafClient.Services.LeafLog.Error("Launch", $"MSAL silent refresh failed: {ex.GetType().Name}: {ex.Message}");
                    }

                    if (!string.IsNullOrWhiteSpace(_currentSettings.MicrosoftRefreshToken))
                    {
                        LeafLog.Info("Launch", "Trying direct HTTP refresh token exchange...");
                        var directSession = await TryDirectTokenRefreshAsync(_currentSettings.MicrosoftRefreshToken);
                        if (directSession != null)
                        {
                            _session = directSession;
                            LeafLog.Info("Launch", "Direct token refresh succeeded.");
                            return;
                        }
                        LeafLog.Error("Launch", "Direct token refresh failed - refresh token may be expired.");
                    }
                    else
                    {
                        LeafLog.Info("Launch", "No stored refresh token available (user logged in before this fix was deployed).");
                    }

                    _session = null;
                    LeafLog.Info("Launch", "All silent authentication methods exhausted.");
                    return;
                }

                if (_currentSettings.IsLoggedIn && _currentSettings.AccountType == "offline" &&
                    !string.IsNullOrWhiteSpace(_currentSettings.OfflineUsername))
                {
                    _session = MSession.CreateOfflineSession(_currentSettings.OfflineUsername);
                    return;
                }

                _session = null;
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Launch", $"Failed to load session: {ex.GetType().Name}: {ex.Message}");
                _session = null;
            }
        }

        private async Task<bool> TryInteractiveReAuthAsync()
        {
            try
            {
                LeafLog.Info("Launch", "Session expired - prompting interactive re-authentication...");
                var tcs = new TaskCompletionSource<bool>();

                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    var loginWindow = new LoginWindow();
                    loginWindow.LoginCompleted += (success) => tcs.TrySetResult(success);
                    loginWindow.Closed += (_, __) => tcs.TrySetResult(loginWindow.LoginSuccessful);
                    loginWindow.Show();
                });

                bool success = await tcs.Task;
                LeafClient.Services.LeafLog.Info("Launch", $"Interactive re-auth result: {success}");
                return success;
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Launch", $"Interactive re-auth failed: {ex.GetType().Name}: {ex.Message}");
                return false;
            }
        }

        private static async Task<bool> ValidateMinecraftTokenAsync(string accessToken)
        {
            try
            {
                using var http = new System.Net.Http.HttpClient { Timeout = TimeSpan.FromSeconds(8) };
                http.DefaultRequestHeaders.Authorization =
                    new System.Net.Http.Headers.AuthenticationHeaderValue("Bearer", accessToken);
                var resp = await http.GetAsync("https://api.minecraftservices.com/minecraft/profile");
                if (resp.IsSuccessStatusCode) return true;

                var code = (int)resp.StatusCode;
                if (code == 401 || code == 403)
                {
                    LeafClient.Services.LeafLog.Info("Launch", $"Token validation: {code} - token genuinely expired/revoked.");
                    return false;
                }

                LeafClient.Services.LeafLog.Info("Launch", $"Token validation: {code} (transient) - keeping cached token.");
                return true;
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Launch", $"Token validation network error ({ex.GetType().Name}) - keeping cached token.");
                return true;
            }
        }

        private Task<MSession?> TryDirectTokenRefreshAsync(string refreshToken)
            => DirectRefreshService.TryRefreshAsync(refreshToken, _currentSettings, _settingsService);

        private async Task UploadSkinToMojangAsync(string filePath, string accessToken, string variant = "classic")
        {
            string url = "https://api.minecraftservices.com/minecraft/profile/skins";

            if (!System.IO.File.Exists(filePath)) return;

            try
            {
                using (var client = new HttpClient())
                {
                    client.DefaultRequestHeaders.Authorization = new System.Net.Http.Headers.AuthenticationHeaderValue("Bearer", accessToken);

                    using (var form = new MultipartFormDataContent())
                    {
                        form.Add(new StringContent(variant), "variant");

                        byte[] fileBytes = await System.IO.File.ReadAllBytesAsync(filePath);
                        var imageContent = new ByteArrayContent(fileBytes);
                        imageContent.Headers.ContentType = System.Net.Http.Headers.MediaTypeHeaderValue.Parse("image/png");

                        form.Add(imageContent, "file", "skin.png");

                        var response = await client.PostAsync(url, form);

                        if (response.IsSuccessStatusCode)
                        {
                            LeafLog.Info("Skin Upload", "Success! Skin updated.");

                            await RefreshAccountPanelPoseAsync();
                            if (_currentSettings.IsLoggedIn)
                            {
                                await UpdateSkinPreviewsAsync(_currentSettings.SessionUsername, _currentSettings.SessionUuid);
                            }
                        }
                        else
                        {
                            LeafClient.Services.LeafLog.Error("Skin Upload", $"Failed: {response.StatusCode}");
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Skin Upload", $"Error: {ex.Message}");
            }
        }

        private void ShowProgress(bool show, string text = "")
        {
            if (_launchProgressPanel != null)
                _launchProgressPanel.IsVisible = show;

            if (show && _launchProgressText != null)
                _launchProgressText.Text = text;

            if (_launchAnimOverlay?.IsVisible == true && _launchAnimSubText != null)
            {
                _launchAnimSubText.Text = show && !string.IsNullOrEmpty(text) ? text : "Preparing your game...";
            }

            if (show)
            {
                _currentOperationText = text.ToUpper();
                if (text.Contains("Fabric")) _currentOperationColor = "DeepSkyBlue";
                else if (text.Contains("Sodium") || text.Contains("Lithium")) _currentOperationColor = "SeaGreen";
                else _currentOperationColor = "DeepSkyBlue";

                _isInstalling = true;
                UpdateLaunchButton(_currentOperationText, _currentOperationColor);
            }
            else
            {
                _isInstalling = false;
                ApplyLaunchButtonState();
            }
        }

        private bool IsOptiFineForFabricSupported(string version)
        {
            var supportedVersions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
{
    "1.21.10", "1.21.9", "1.21.8", "1.21.7", "1.21.6", "1.21.5", "1.21.4", "1.21.3", "1.21.1",
    "1.20.6", "1.20.5", "1.20.4", "1.20.1", "1.19.2", "1.18.2", "1.17.1", "1.16.5"
};

            bool isSupported = supportedVersions.Contains(version);

            if (!isSupported && _optiFineToggle != null && _optiFineToggle.IsChecked == true)
            {
                _optiFineToggle.IsChecked = false;
                LeafClient.Services.LeafLog.Info("OptiFine", $"Version {version} not supported. Disabled toggle.");
            }

            return isSupported;
        }

        private async Task<string?> GetOptiFineMrpackUrlForVersion(string mcVersion)
        {
            LeafClient.Services.LeafLog.Info("OptiFineForFabric", $"Looking for .mrpack for MC {mcVersion}...");
            try
            {
                using var client = new HttpClient();
                string baseApiUrl = "https://api.modrinth.com/v2/project/BHtwz1lb/version";

                string exactVersionUrl = $"{baseApiUrl}?game_versions=[\"{mcVersion}\"]&loaders=[\"fabric\"]";
                var json = await client.GetStringAsync(exactVersionUrl);
                var versions = JsonSerializer.Deserialize(json, JsonContext.Default.ListModrinthVersion);

                if (versions != null && versions.Any())
                {
                    var latestVersion = versions.First();
                    var mrpackFile = latestVersion.files?.FirstOrDefault(f => !string.IsNullOrEmpty(f?.filename) && f.filename.EndsWith(".mrpack", StringComparison.OrdinalIgnoreCase));
                    if (mrpackFile?.url != null)
                    {
                        return mrpackFile.url;
                    }
                }

                string[] mcVersionParts = mcVersion.Split('.');
                if (mcVersionParts.Length >= 2)
                {
                    string majorMinorVersion = $"{mcVersionParts[0]}.{mcVersionParts[1]}";
                    string majorMinorUrl = $"{baseApiUrl}?game_versions=[\"{majorMinorVersion}\"]&loaders=[\"fabric\"]";
                    json = await client.GetStringAsync(majorMinorUrl);
                    versions = JsonSerializer.Deserialize(json, JsonContext.Default.ListModrinthVersion);

                    if (versions != null && versions.Any())
                    {
                        var latestVersion = versions.First();
                        var mrpackFile = latestVersion.files?.FirstOrDefault(f => !string.IsNullOrEmpty(f?.filename) && f.filename.EndsWith(".mrpack", StringComparison.OrdinalIgnoreCase));
                        if (mrpackFile?.url != null)
                        {
                            return mrpackFile.url;
                        }
                    }
                }

                LeafLog.Info("OptiFineForFabric", "No direct API filter match. Falling back to manual search of all versions.");
                json = await client.GetStringAsync(baseApiUrl);
                var allVersions = JsonSerializer.Deserialize(json, JsonContext.Default.ListModrinthVersion);

                if (allVersions != null && allVersions.Any())
                {
                    if (Version.TryParse(mcVersion, out Version? targetSemver))
                    {
                        Models.ModrinthVersion? bestFallbackMatch = null;
                        Version bestFallbackSemver = new Version(0, 0);

                        foreach (var v in allVersions)
                        {
                            if (!v.loaders?.Any(l => l.Equals("fabric", StringComparison.OrdinalIgnoreCase)) ?? true) continue;

                            foreach (string gameVerStr in v.GameVersions ?? new List<string>())
                            {
                                if (Version.TryParse(gameVerStr, out Version? candidateSemver))
                                {
                                    if (candidateSemver <= targetSemver && candidateSemver > bestFallbackSemver)
                                    {
                                        bestFallbackSemver = candidateSemver;
                                        bestFallbackMatch = v;
                                    }
                                }
                            }
                        }

                        if (bestFallbackMatch != null)
                        {
                            var mrpackFile = bestFallbackMatch.files?.FirstOrDefault(f => !string.IsNullOrEmpty(f?.filename) && f.filename.EndsWith(".mrpack", StringComparison.OrdinalIgnoreCase));
                            if (mrpackFile?.url != null)
                            {
                                LeafClient.Services.LeafLog.Info("OptiFineForFabric", $"Found fallback match via manual search: '{bestFallbackMatch.name}'");
                                return mrpackFile.url;
                            }
                        }
                    }
                }

                LeafLog.Error("OptiFineForFabric ERROR", $"All attempts failed. No compatible .mrpack found for Minecraft {mcVersion}.");
                return null;
            }
            catch (Exception ex)
            {
                LeafLog.Error("OptiFineForFabric ERROR", $"An exception occurred while fetching/parsing Modrinth data: {ex.Message}");
                return null;
            }
        }

        private static readonly HttpClient _launcherInstallHttp = new HttpClient { Timeout = TimeSpan.FromMinutes(10) };

        private void InitializeLauncher()
        {
            var path = new MinecraftPath(_minecraftFolder);
            System.IO.Directory.CreateDirectory(System.IO.Path.Combine(_minecraftFolder, "versions"));
            var parameters = CmlLib.Core.MinecraftLauncherParameters.CreateDefault(path, _launcherInstallHttp);
            _launcher = new MinecraftLauncher(parameters);
        }

        private static string ExtractCanonicalJarPrefix(string fileNameOrPath)
        {
            try
            {
                var name = System.IO.Path.GetFileNameWithoutExtension(fileNameOrPath ?? "");
                if (string.IsNullOrEmpty(name)) return "";
                int n = name.Length;
                for (int i = n - 1; i > 0; i--)
                {
                    if (name[i] == '-' && i + 1 < n && char.IsDigit(name[i + 1]))
                        return name.Substring(0, i);
                }
                return name;
            }
            catch { return ""; }
        }

        private void PruneOldJarsForPrefix(string modsFolder, string filePrefix, string keepFileName)
        {
            try
            {
                if (string.IsNullOrEmpty(filePrefix)) return;
                if (string.IsNullOrEmpty(modsFolder) || !System.IO.Directory.Exists(modsFolder)) return;
                string keep = (keepFileName ?? "").ToLowerInvariant();
                string prefix = filePrefix.ToLowerInvariant();
                foreach (var path in System.IO.Directory.EnumerateFiles(modsFolder, "*.jar"))
                {
                    var nameLow = System.IO.Path.GetFileName(path).ToLowerInvariant();
                    if (nameLow == keep) continue;
                    if (!nameLow.StartsWith(prefix + "-", StringComparison.Ordinal)
                        && nameLow != prefix + ".jar")
                        continue;
                    try
                    {
                        System.IO.File.Delete(path);
                        LeafClient.Services.LeafLog.Info("ModInstall", $"Pruned older '{prefix}' jar: {System.IO.Path.GetFileName(path)}");
                    }
                    catch (Exception ex) { LeafClient.Services.LeafLog.Info("ModInstall", $"Could not prune {path}: {ex.Message}"); }
                }
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("ModInstall", $"Prune helper failed: {ex.Message}"); }
        }

        private async Task DownloadAndVerifyModrinthFileAsync(LeafClient.Models.ModrinthFile file, string destinationPath, string displayName)
        {
            if (file.Hashes == null || !file.Hashes.TryGetValue("sha512", out var expectedHashHex) || string.IsNullOrWhiteSpace(expectedHashHex))
                throw new System.Security.SecurityException($"[{displayName}] Modrinth API response missing sha512 hash; refusing to install unverified jar.");

            if (System.IO.File.Exists(destinationPath))
            {
                try
                {
                    byte[] existingHashBytes;
                    using (var sha512 = System.Security.Cryptography.SHA512.Create())
                    using (var fs = System.IO.File.OpenRead(destinationPath))
                        existingHashBytes = await sha512.ComputeHashAsync(fs);
                    var existingHashHex = BitConverter.ToString(existingHashBytes).Replace("-", string.Empty).ToLowerInvariant();
                    if (existingHashHex.Equals(expectedHashHex.Trim(), StringComparison.OrdinalIgnoreCase))
                    {
                        LeafClient.Services.LeafLog.Info(displayName, $"Already present and SHA-verified, skipping download: {System.IO.Path.GetFileName(destinationPath)}");
                        return;
                    }
                }
                catch (Exception ex) { LeafClient.Services.LeafLog.Info(displayName, $"Pre-download SHA check failed, will re-download: {ex.Message}"); }
            }

            try
            {
                string modsFolder = System.IO.Path.GetDirectoryName(destinationPath);
                string canonicalName = System.IO.Path.GetFileName(destinationPath);
                string prefix = ExtractCanonicalJarPrefix(canonicalName);
                if (!string.IsNullOrEmpty(prefix))
                    PruneOldJarsForPrefix(modsFolder, prefix, canonicalName);
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("ModInstall", $"Pre-install prune failed: {ex.Message}"); }

            await DownloadFileWithProgressAsync(file.url, destinationPath, displayName);

            byte[] actualHashBytes;
            using (var sha512 = System.Security.Cryptography.SHA512.Create())
            using (var fs = System.IO.File.OpenRead(destinationPath))
                actualHashBytes = await sha512.ComputeHashAsync(fs);

            var actualHashHex = BitConverter.ToString(actualHashBytes).Replace("-", string.Empty).ToLowerInvariant();
            if (!actualHashHex.Equals(expectedHashHex.Trim(), StringComparison.OrdinalIgnoreCase))
            {
                try { System.IO.File.Delete(destinationPath); } catch { }
                throw new System.Security.SecurityException($"[{displayName}] sha512 mismatch - expected {expectedHashHex}, got {actualHashHex}. File deleted.");
            }

            try
            {
                using var zip = System.IO.Compression.ZipFile.OpenRead(destinationPath);
                if (zip.Entries.Count == 0) throw new System.IO.InvalidDataException("Empty zip archive.");
            }
            catch (Exception ex)
            {
                try { System.IO.File.Delete(destinationPath); } catch { }
                throw new System.Security.SecurityException($"[{displayName}] sha512 OK but file is not a valid jar (zip): {ex.Message}. File deleted.");
            }
        }

        private async Task DownloadFileWithProgressAsync(string url, string destinationPath, string fileName)
        {
            var ct = _activeLaunchToken;
            using var client = new HttpClient();
            client.DefaultRequestHeaders.Add("User-Agent", "LeafClient-Launcher");
            client.Timeout = TimeSpan.FromMinutes(10);

            using var response = await client.GetAsync(url, HttpCompletionOption.ResponseHeadersRead, ct);
            response.EnsureSuccessStatusCode();

            var totalBytes = response.Content.Headers.ContentLength ?? -1L;
            var canReportProgress = totalBytes != -1;

            using var contentStream = await response.Content.ReadAsStreamAsync(ct);

            FileStream? fileStream = null;
            int[] backoffMs = { 250, 500, 1000, 2000, 3000 };
            for (int attempt = 0; attempt <= backoffMs.Length; attempt++)
            {
                try
                {
                    fileStream = new FileStream(destinationPath, FileMode.Create, FileAccess.Write, FileShare.None, 8192, true);
                    break;
                }
                catch (IOException) when (attempt < backoffMs.Length)
                {
                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        if (_launchProgressText != null)
                            _launchProgressText.Text = $"{fileName}: file in use, retrying...";
                    });
                    await Task.Delay(backoffMs[attempt]);
                }
            }
            if (fileStream == null)
                throw new IOException($"Could not write {fileName} to disk - close any running Minecraft instance and try again.");
            using var _fsHolder = fileStream;

            var totalRead = 0L;
            var buffer = new byte[8192];
            var isMoreToRead = true;

            await Dispatcher.UIThread.InvokeAsync(() =>
            {
                if (_launchProgressPanel != null) _launchProgressPanel.IsVisible = true;
                if (_launchProgressBar != null)
                {
                    _launchProgressBar.IsIndeterminate = !canReportProgress;
                    _launchProgressBar.Minimum = 0;
                    _launchProgressBar.Maximum = 100;
                    _launchProgressBar.Value = 0;
                }
                if (_launchProgressText != null)
                    _launchProgressText.Text = $"Downloading {fileName}...";
            });

            do
            {
                ct.ThrowIfCancellationRequested();
                var read = await contentStream.ReadAsync(buffer.AsMemory(0, buffer.Length), ct);
                if (read == 0)
                {
                    isMoreToRead = false;
                }
                else
                {
                    await fileStream.WriteAsync(buffer.AsMemory(0, read), ct);
                    totalRead += read;

                    if (canReportProgress)
                    {
                        var percent = (double)totalRead / totalBytes * 100;
                        await Dispatcher.UIThread.InvokeAsync(() =>
                        {
                            if (_launchProgressBar != null) _launchProgressBar.Value = percent;
                            if (_launchProgressText != null) _launchProgressText.Text = $"Downloading {fileName} ({percent:F0}%)";
                        });
                    }
                }
            }
            while (isMoreToRead);
        }

        private static ModrinthVersion? PickStableModrinthVersion(List<ModrinthVersion>? versions)
        {
            if (versions == null || versions.Count == 0) return null;
            var release = versions.FirstOrDefault(v => string.Equals(v.VersionType, "release", StringComparison.OrdinalIgnoreCase));
            if (release != null) return release;
            var beta = versions.FirstOrDefault(v => string.Equals(v.VersionType, "beta", StringComparison.OrdinalIgnoreCase));
            if (beta != null) return beta;
            bool anyTagged = versions.Any(v => !string.IsNullOrEmpty(v.VersionType));
            if (anyTagged) return null;
            return versions[0];
        }

        private async Task<bool> InstallSodiumIfNeededAsync(string mcVersion)
        {
            string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
            System.IO.Directory.CreateDirectory(modsFolder);

            try
            {
                ShowProgress(true, $"Fetching Sodium for {mcVersion}...");

                var versions = await LeafClient.Services.ModrinthApi.GetProjectVersionsAsync("AANobbMI", mcVersion, "fabric");
                var latest = PickStableModrinthVersion(versions);

                if (latest?.files == null || latest.files.Count == 0) throw new Exception("No Sodium files found");

                var file = latest.files.FirstOrDefault(f => f.filename?.EndsWith(".jar", StringComparison.OrdinalIgnoreCase) == true) ?? latest.files.First();

                string fileName = $"sodium-fabric-{mcVersion}.jar";
                string sodiumPath = System.IO.Path.Combine(modsFolder, fileName);

                await DownloadAndVerifyModrinthFileAsync(file, sodiumPath, "Sodium");

                var fi = new System.IO.FileInfo(sodiumPath);
                if (!fi.Exists || fi.Length < 1024)
                {
                    LeafLog.Info("Sodium", $"Post-install check failed: file missing or too small ({(fi.Exists ? fi.Length.ToString() : "missing")}).");
                    ShowLaunchErrorBanner("Sodium download produced no valid jar. Retry to fix.");
                    return false;
                }

                LeafClient.Services.LeafLog.Info("Sodium", $"Installed: {sodiumPath}");
                await RegisterAutoInstalledMod("sodium", "Sodium", latest.versionNumber, mcVersion, fileName, file.url);

                return true;
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Sodium", $"Install failed: {ex.Message}");
                ShowLaunchErrorBanner($"Failed to install Sodium: {ex.Message}");
                return false;
            }
            finally { ShowProgress(false); }
        }

