        private static bool IsModKnownBrokenForMc(string modKey, string mcVersion)
        {
            if (string.IsNullOrEmpty(modKey) || string.IsNullOrEmpty(mcVersion)) return false;
            string? projectId = modKey.ToLowerInvariant() switch
            {
                "moreculling" => "51shyZVL",
                "cullleaves"  => "GNxdLCoP",
                _ => null
            };
            if (projectId == null) return false;
            return _modIncompatibleVersions.TryGetValue(projectId, out var bad)
                && bad.Contains(mcVersion);
        }

        private void RemoveStaleManagedJars(string modsFolder, string filePrefix, string? keepFileName, string displayName)
        {
            try
            {
                foreach (var path in System.IO.Directory.EnumerateFiles(modsFolder, $"{filePrefix}-*.jar"))
                {
                    var name = System.IO.Path.GetFileName(path);
                    if (keepFileName != null && string.Equals(name, keepFileName, StringComparison.OrdinalIgnoreCase))
                        continue;
                    try { System.IO.File.Delete(path); LeafClient.Services.LeafLog.Info(displayName, $"Removed stale: {name}"); } catch { }
                }
            }
            catch { }
        }

        private async Task<bool> InstallModrinthModGenericAsync(string projectId, string displayName, string filePrefix, string mcVersion)
        {
            string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
            System.IO.Directory.CreateDirectory(modsFolder);

            if (_modIncompatibleVersions.TryGetValue(projectId, out var incompatible) && incompatible.Contains(mcVersion))
            {
                LeafClient.Services.LeafLog.Info(displayName, $"Known incompatibility with MC {mcVersion}, skipping.");
                RemoveStaleManagedJars(modsFolder, filePrefix, keepFileName: null, displayName);
                return true;
            }
            try
            {
                ShowProgress(true, $"Fetching {displayName} for {mcVersion}...");

                var versionsToTry = new List<string> { mcVersion };
                var fallback = Services.ModrinthVersionFallback.GetFallbackVersion(mcVersion);
                if (fallback != null && fallback != mcVersion) versionsToTry.Add(fallback);

                Models.ModrinthVersion? matched = null;
                foreach (var tryVersion in versionsToTry)
                {
                    var versions = await LeafClient.Services.ModrinthApi.GetProjectVersionsAsync(projectId, tryVersion, "fabric");
                    if (versions.Count == 0) continue;

                    matched = versions.FirstOrDefault(v =>
                        v.GameVersions != null && v.GameVersions.Contains(tryVersion, StringComparer.OrdinalIgnoreCase));
                    if (matched != null)
                    {
                        if (tryVersion != mcVersion)
                            LeafClient.Services.LeafLog.Info(displayName, $"No compatible version for {mcVersion}, using {tryVersion} fallback.");
                        break;
                    }
                }

                if (matched == null)
                {
                    LeafClient.Services.LeafLog.Info(displayName, $"No compatible version found for {mcVersion}, skipping.");
                    RemoveStaleManagedJars(modsFolder, filePrefix, keepFileName: null, displayName);
                    return true;
                }

                var file = matched.files?.FirstOrDefault(f => f.filename?.EndsWith(".jar", StringComparison.OrdinalIgnoreCase) == true)
                           ?? matched.files?.FirstOrDefault();
                if (file?.url == null) { LeafClient.Services.LeafLog.Info(displayName, $"No download URL found, skipping."); return false; }
                string destFileName = $"{filePrefix}-{mcVersion}.jar";
                string destPath = System.IO.Path.Combine(modsFolder, destFileName);
                await DownloadAndVerifyModrinthFileAsync(file, destPath, displayName);

                var fi = new System.IO.FileInfo(destPath);
                if (!fi.Exists || fi.Length < 1024)
                {
                    LeafClient.Services.LeafLog.Error(displayName, $"Post-install check failed: file missing or too small.");
                    return false;
                }

                RemoveStaleManagedJars(modsFolder, filePrefix, keepFileName: destFileName, displayName);
                LeafClient.Services.LeafLog.Info(displayName, $"Installed: {destPath}");
                return true;
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error(displayName, $"Install failed: {ex.Message}");
                return false;
            }
            finally { ShowProgress(false); }
        }

