        private bool IsNvidiaGpu()
        {
            try
            {
                if (System.OperatingSystem.IsWindows())
                {
                    var psi = new System.Diagnostics.ProcessStartInfo
                    {
                        FileName = "powershell",
                        Arguments = "-NoProfile -Command \"Get-CimInstance Win32_VideoController | Select-Object -ExpandProperty Name\"",
                        RedirectStandardOutput = true,
                        UseShellExecute = false,
                        CreateNoWindow = true
                    };
                    using var process = System.Diagnostics.Process.Start(psi);
                    if (process != null)
                    {
                        var output = process.StandardOutput.ReadToEnd();
                        process.WaitForExit();
                        if (output.Contains("NVIDIA", StringComparison.OrdinalIgnoreCase))
                            return true;
                    }
                }
                else if (System.OperatingSystem.IsMacOS())
                {
                    var psi = new System.Diagnostics.ProcessStartInfo
                    {
                        FileName = "/usr/sbin/system_profiler",
                        Arguments = "SPDisplaysDataType",
                        RedirectStandardOutput = true,
                        UseShellExecute = false,
                        CreateNoWindow = true
                    };
                    using var process = System.Diagnostics.Process.Start(psi);
                    if (process != null)
                    {
                        var output = process.StandardOutput.ReadToEnd();
                        process.WaitForExit();
                        return output.Contains("NVIDIA", StringComparison.OrdinalIgnoreCase);
                    }
                }
                else if (System.OperatingSystem.IsLinux())
                {
                    if (System.IO.File.Exists("/proc/driver/nvidia/version"))
                        return true;

                    if (System.IO.Directory.Exists("/proc/driver/nvidia"))
                        return true;

                    try
                    {
                        var glxOutput = "";
                        var glxPsi = new System.Diagnostics.ProcessStartInfo
                        {
                            FileName = "bash",
                            Arguments = "-c \"glxinfo 2>/dev/null | grep -i nvidia || lspci 2>/dev/null | grep -i nvidia\"",
                            RedirectStandardOutput = true,
                            UseShellExecute = false,
                            CreateNoWindow = true
                        };
                        using var glxProc = System.Diagnostics.Process.Start(glxPsi);
                        if (glxProc != null)
                        {
                            glxOutput = glxProc.StandardOutput.ReadToEnd();
                            glxProc.WaitForExit();
                            if (glxOutput.Contains("NVIDIA", StringComparison.OrdinalIgnoreCase))
                                return true;
                        }
                    }
                    catch { }

                    var psi = new System.Diagnostics.ProcessStartInfo
                    {
                        FileName = "lspci",
                        RedirectStandardOutput = true,
                        UseShellExecute = false,
                        CreateNoWindow = true
                    };
                    using var process = System.Diagnostics.Process.Start(psi);
                    if (process != null)
                    {
                        var output = process.StandardOutput.ReadToEnd();
                        process.WaitForExit();
                        return output.Contains("NVIDIA", StringComparison.OrdinalIgnoreCase);
                    }
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("IsNvidiaGpu", $"Error detecting GPU: {ex.Message}");
            }

            return false;
        }

        private void ForceHighPerformanceGpu(System.Diagnostics.Process process)
        {
            try
            {
                if (System.OperatingSystem.IsWindows())
                {
                    string javaExePath = process.StartInfo.FileName;
                    if (string.IsNullOrEmpty(javaExePath)) return;

                    if (!System.IO.Path.IsPathRooted(javaExePath))
                    {
                        try { javaExePath = System.IO.Path.GetFullPath(javaExePath); }
                        catch { return; }
                    }

                    var escaped = javaExePath.Replace("\"", "\\\"");
                    var psi = new System.Diagnostics.ProcessStartInfo
                    {
                        FileName = "reg",
                        Arguments = $"add \"HKCU\\Software\\Microsoft\\DirectX\\UserGpuPreferences\" /v \"{escaped}\" /t REG_SZ /d \"GpuPreference=2\" /f",
                        RedirectStandardOutput = true,
                        RedirectStandardError = true,
                        UseShellExecute = false,
                        CreateNoWindow = true
                    };
                    using var regProc = System.Diagnostics.Process.Start(psi);
                    regProc?.WaitForExit(5000);

                    LeafClient.Services.LeafLog.Info("GPU", $"Set Windows GPU preference to High Performance for: {javaExePath}");
                    _gameOutputWindow?.AppendLog("[GPU] Forced High Performance GPU for Java process", "INFO");

                    process.StartInfo.Environment["__GL_THREADED_OPTIMIZATIONS"] = "0";
                    LeafLog.Info("GPU", "Disabled NVIDIA threaded optimizations to prevent Sodium performance workaround");
                    _gameOutputWindow?.AppendLog("[GPU] Disabled NVIDIA threaded optimizations (prevents Sodium GL_DEBUG_OUTPUT_SYNCHRONOUS)", "INFO");
                }
                else if (System.OperatingSystem.IsLinux())
                {
                    var (hasNvidia, hasAmdDiscrete) = DetectLinuxDiscreteGpu();
                    if (hasNvidia)
                    {
                        process.StartInfo.Environment["__NV_PRIME_RENDER_OFFLOAD"] = "1";
                        process.StartInfo.Environment["__GLX_VENDOR_LIBRARY_NAME"] = "nvidia";
                        process.StartInfo.Environment["__VK_LAYER_NV_optimus"] = "NVIDIA_only";
                        process.StartInfo.Environment["DRI_PRIME"] = "1";
                        LeafLog.Info("GPU", "NVIDIA discrete detected - applied PRIME render offload");
                        _gameOutputWindow?.AppendLog("[GPU] NVIDIA discrete detected - forced PRIME render offload", "INFO");
                    }
                    else if (hasAmdDiscrete)
                    {
                        process.StartInfo.Environment["DRI_PRIME"] = "1";
                        LeafLog.Info("GPU", "AMD discrete detected - applied DRI_PRIME=1");
                        _gameOutputWindow?.AppendLog("[GPU] AMD discrete detected - forced DRI_PRIME=1", "INFO");
                    }
                    else
                    {
                        LeafLog.Info("GPU", "No discrete GPU detected - skipping PRIME env vars (single-iGPU system)");
                        _gameOutputWindow?.AppendLog("[GPU] Single-iGPU system - PRIME env vars skipped", "INFO");
                    }
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("GPU", $"Failed to force GPU preference: {ex.Message}");
            }
        }

        private static (bool hasNvidia, bool hasAmdDiscrete) DetectLinuxDiscreteGpu()
        {
            try
            {
                var psi = new System.Diagnostics.ProcessStartInfo
                {
                    FileName = "lspci",
                    Arguments = "-nn",
                    RedirectStandardOutput = true,
                    RedirectStandardError = true,
                    UseShellExecute = false,
                    CreateNoWindow = true
                };
                using var p = System.Diagnostics.Process.Start(psi);
                if (p == null) return (false, false);
                if (!p.WaitForExit(2000))
                {
                    try { p.Kill(); } catch { }
                    return (false, false);
                }
                var output = p.StandardOutput.ReadToEnd() ?? string.Empty;

                bool hasNvidia = false;
                bool hasAmdDiscrete = false;
                bool hasAmdIgpu = false;
                bool hasAmdGpuLine = false;

                foreach (var line in output.Split('\n'))
                {
                    if (line.IndexOf("VGA", StringComparison.OrdinalIgnoreCase) < 0
                        && line.IndexOf("3D controller", StringComparison.OrdinalIgnoreCase) < 0
                        && line.IndexOf("Display controller", StringComparison.OrdinalIgnoreCase) < 0)
                        continue;

                    if (line.IndexOf("[10de:", StringComparison.OrdinalIgnoreCase) >= 0
                        || line.IndexOf("NVIDIA", StringComparison.OrdinalIgnoreCase) >= 0)
                    {
                        hasNvidia = true;
                        continue;
                    }

                    if (line.IndexOf("[1002:", StringComparison.OrdinalIgnoreCase) >= 0
                        || line.IndexOf("Advanced Micro Devices", StringComparison.OrdinalIgnoreCase) >= 0
                        || line.IndexOf("AMD/ATI", StringComparison.OrdinalIgnoreCase) >= 0
                        || line.IndexOf("Radeon", StringComparison.OrdinalIgnoreCase) >= 0)
                    {
                        hasAmdGpuLine = true;
                        if (line.IndexOf("Raphael", StringComparison.OrdinalIgnoreCase) >= 0
                            || line.IndexOf("Phoenix", StringComparison.OrdinalIgnoreCase) >= 0
                            || line.IndexOf("Rembrandt", StringComparison.OrdinalIgnoreCase) >= 0
                            || line.IndexOf("Cezanne", StringComparison.OrdinalIgnoreCase) >= 0
                            || line.IndexOf("Renoir", StringComparison.OrdinalIgnoreCase) >= 0
                            || line.IndexOf("Picasso", StringComparison.OrdinalIgnoreCase) >= 0
                            || line.IndexOf("Raven", StringComparison.OrdinalIgnoreCase) >= 0
                            || line.IndexOf("Lucienne", StringComparison.OrdinalIgnoreCase) >= 0
                            || line.IndexOf("Strix", StringComparison.OrdinalIgnoreCase) >= 0
                            || line.IndexOf("Granite Ridge", StringComparison.OrdinalIgnoreCase) >= 0
                            || line.IndexOf("Krackan", StringComparison.OrdinalIgnoreCase) >= 0)
                        {
                            hasAmdIgpu = true;
                        }
                    }
                }

                if (hasAmdGpuLine && !hasAmdIgpu) hasAmdDiscrete = true;
                return (hasNvidia, hasAmdDiscrete);
            }
            catch
            {
                return (false, false);
            }
        }

        private static string? FindSystemGlfwLibrary()
        {
            try
            {
                string[] candidates =
                {
                    "/usr/lib/x86_64-linux-gnu/libglfw.so",
                    "/usr/lib/x86_64-linux-gnu/libglfw.so.3",
                    "/usr/lib64/libglfw.so",
                    "/usr/lib64/libglfw.so.3",
                    "/usr/lib/libglfw.so",
                    "/usr/lib/libglfw.so.3",
                    "/usr/local/lib/libglfw.so",
                    "/usr/local/lib/libglfw.so.3"
                };
                foreach (var path in candidates)
                {
                    if (System.IO.File.Exists(path)) return path;
                }
            }
            catch { }
            return null;
        }

        private void ForceVulkanModNvidiaDevice()
        {
            if (!(_vulkanModToggle?.IsChecked == true || _currentSettings.IsVulkanModEnabled)) return;

            try
            {
                string configPath = System.IO.Path.Combine(_minecraftFolder, "config", "vulkanmod_settings.json");
                if (!File.Exists(configPath)) return;

                string json = File.ReadAllText(configPath);
                using var doc = System.Text.Json.JsonDocument.Parse(json);
                var root = doc.RootElement;

                if (root.TryGetProperty("device", out var deviceProp) && deviceProp.GetInt32() != 0)
                {
                    json = System.Text.RegularExpressions.Regex.Replace(json, @"""device""\s*:\s*-?\d+", "\"device\": 0");
                    File.WriteAllText(configPath, json);
                    LeafLog.Info("VulkanMod", "Forced device to 0 (NVIDIA discrete GPU)");
                    _gameOutputWindow?.AppendLog("[VulkanMod] Forced GPU device to NVIDIA (device 0)", "INFO");
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("VulkanMod", $"Failed to set device: {ex.Message}");
            }
        }

        private static long _lastWmiProbeMs;
        private static bool _lastWmiProbeOk = true;
        private static bool _wmiPromptShownThisSession;

        private static string HealthTelemetryPath => System.IO.Path.Combine(
            Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData), "LeafClient", "health_telemetry.json");

        private static string FreezeLogPath => System.IO.Path.Combine(
            Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData), "LeafClient", "freeze_log.txt");

        private static long _lastUiTickMs;
        private static DispatcherTimer? _watchdogUiTimer;
        private static System.Threading.Thread? _watchdogBgThread;
        private static System.Threading.CancellationTokenSource? _watchdogCts;
        private static volatile string _watchdogLastOp = "(none)";
        private static volatile bool _watchdogFreezeActive;
        private static long _watchdogFreezeStartMs;
        private static volatile string _watchdogLastUiStackSample = "(no-sample-yet)";
        private static long _watchdogLastUiStackSampleMs;
        private static uint _watchdogUiNativeThreadId;

        internal static void SetWatchdogOp(string op)
        {
            _watchdogLastOp = op ?? "(null)";
        }

        private void StartFreezeWatchdog()
        {
            if (_watchdogUiTimer != null) return;
            _lastUiTickMs = Environment.TickCount64;
            try
            {
                if (OperatingSystem.IsWindows())
                    _watchdogUiNativeThreadId = GetCurrentThreadIdNative();
            }
            catch { }
            _watchdogUiTimer = new DispatcherTimer { Interval = TimeSpan.FromMilliseconds(500) };
            _watchdogUiTimer.Tick += (_, __) =>
            {
                long now = Environment.TickCount64;
                System.Threading.Interlocked.Exchange(ref _lastUiTickMs, now);
                if (now - System.Threading.Interlocked.Read(ref _watchdogLastUiStackSampleMs) >= 750)
                {
                    try { _watchdogLastUiStackSample = Environment.StackTrace; } catch { }
                    System.Threading.Interlocked.Exchange(ref _watchdogLastUiStackSampleMs, now);
                }
            };
            _watchdogUiTimer.Start();

            _watchdogCts = new System.Threading.CancellationTokenSource();
            var token = _watchdogCts.Token;
            _watchdogBgThread = new System.Threading.Thread(() =>
            {
                AppendFreezeLog($"[Watchdog] started pid={Environment.ProcessId} ticks/ms reference={Environment.TickCount64}");
                while (!token.IsCancellationRequested)
                {
                    try
                    {
                        System.Threading.Thread.Sleep(1000);
                        long now = Environment.TickCount64;
                        long last = System.Threading.Interlocked.Read(ref _lastUiTickMs);
                        long gap = now - last;
                        if (gap >= 3000)
                        {
                            try
                            {
                                Avalonia.Threading.Dispatcher.UIThread.Post(() =>
                                {
                                    System.Threading.Interlocked.Exchange(ref _lastUiTickMs, Environment.TickCount64);
                                }, Avalonia.Threading.DispatcherPriority.Background);
                            }
                            catch { }
                            System.Threading.Thread.Sleep(750);
                            now = Environment.TickCount64;
                            last = System.Threading.Interlocked.Read(ref _lastUiTickMs);
                            gap = now - last;
                        }
                        if (gap >= 3000 && !_watchdogFreezeActive)
                        {
                            _watchdogFreezeActive = true;
                            _watchdogFreezeStartMs = last;
                            DumpFreezeSnapshot("FREEZE_START", gap);
                        }
                        else if (gap >= 3000 && _watchdogFreezeActive && gap % 10000 < 1500)
                        {
                            DumpFreezeSnapshot("FREEZE_ONGOING", gap);
                        }
                        else if (gap < 1500 && _watchdogFreezeActive)
                        {
                            _watchdogFreezeActive = false;
                            long total = Environment.TickCount64 - _watchdogFreezeStartMs;
                            AppendFreezeLog($"[Watchdog] FREEZE_END duration_ms={total} last_op={_watchdogLastOp}");
                        }
                    }
                    catch (Exception ex)
                    {
                        try { AppendFreezeLog($"[Watchdog] loop error: {ex.GetType().Name}: {ex.Message}"); } catch { }
                    }
                }
            }) { IsBackground = true, Name = "LeafClient-FreezeWatchdog", Priority = System.Threading.ThreadPriority.AboveNormal };
            _watchdogBgThread.Start();
        }

        private static void DumpFreezeSnapshot(string tag, long gapMs)
        {
            try
            {
                var sb = new System.Text.StringBuilder();
                sb.Append("[Watchdog] ").Append(tag).Append(" gap_ms=").Append(gapMs)
                  .Append(" last_op=").Append(_watchdogLastOp);
                try
                {
                    var p = System.Diagnostics.Process.GetCurrentProcess();
                    sb.Append(" ws_mb=").Append(p.WorkingSet64 / (1024 * 1024));
                    sb.Append(" priv_mb=").Append(p.PrivateMemorySize64 / (1024 * 1024));
                    sb.Append(" handles=").Append(p.HandleCount);
                    sb.Append(" threads=").Append(p.Threads.Count);
                    int waiting = 0, running = 0, other = 0;
                    foreach (System.Diagnostics.ProcessThread t in p.Threads)
                    {
                        try
                        {
                            switch (t.ThreadState)
                            {
                                case System.Diagnostics.ThreadState.Wait: waiting++; break;
                                case System.Diagnostics.ThreadState.Running: running++; break;
                                default: other++; break;
                            }
                        }
                        catch { other++; }
                    }
                    sb.Append(" t_run=").Append(running).Append(" t_wait=").Append(waiting).Append(" t_other=").Append(other);
                    sb.Append(" gc0=").Append(GC.CollectionCount(0));
                    sb.Append(" gc1=").Append(GC.CollectionCount(1));
                    sb.Append(" gc2=").Append(GC.CollectionCount(2));
                    sb.Append(" totalmem_mb=").Append(GC.GetTotalMemory(false) / (1024 * 1024));
                    var topWaits = new Dictionary<string, int>(StringComparer.Ordinal);
                    foreach (System.Diagnostics.ProcessThread t in p.Threads)
                    {
                        try
                        {
                            if (t.ThreadState == System.Diagnostics.ThreadState.Wait)
                            {
                                var wr = t.WaitReason.ToString();
                                topWaits[wr] = (topWaits.TryGetValue(wr, out var c) ? c : 0) + 1;
                            }
                        }
                        catch { }
                    }
                    if (topWaits.Count > 0)
                    {
                        sb.Append(" waits=");
                        bool first = true;
                        foreach (var kv in topWaits)
                        {
                            if (!first) sb.Append(',');
                            sb.Append(kv.Key).Append(':').Append(kv.Value);
                            first = false;
                        }
                    }
                }
                catch (Exception innerEx)
                {
                    sb.Append(" snapshot_error=").Append(innerEx.GetType().Name);
                }

                if (tag == "FREEZE_START")
                {
                    sb.Append(" last_op_started=").Append(_watchdogLastOpStartedTickMs > 0
                        ? (Environment.TickCount64 - _watchdogLastOpStartedTickMs) + "ms ago"
                        : "n/a");
                    sb.Append(" pending_dispatcher=").Append(GetPendingDispatcherOp());
                    sb.Append(" file_io_count=").Append(_watchdogFileIoInFlight);
                    sb.Append(" net_io_count=").Append(_watchdogNetIoInFlight);
                }

                AppendFreezeLog(sb.ToString());

                if (tag == "FREEZE_START")
                {
                    try
                    {
                        long age = Environment.TickCount64 - System.Threading.Interlocked.Read(ref _watchdogLastUiStackSampleMs);
                        AppendFreezeLog("[Watchdog] last_ui_stack_sample_age_ms=" + age);
                        AppendFreezeLog("[Watchdog] last_ui_stack=" + _watchdogLastUiStackSample);
                    }
                    catch { }
                    if (OperatingSystem.IsWindows() && _watchdogUiNativeThreadId != 0)
                    {
                        try { AppendFreezeLog("[Watchdog] ui_native_pc=" + CaptureUiThreadInstructionPointer()); } catch { }
                    }
                }
            }
            catch { }
        }

        private static long _watchdogLastOpStartedTickMs;
        private static int _watchdogFileIoInFlight;
        private static int _watchdogNetIoInFlight;

        private static string GetPendingDispatcherOp()
        {
            try
            {
                var d = Avalonia.Threading.Dispatcher.UIThread;
                return d.CheckAccess() ? "ui-thread-self" : "off-ui";
            }
            catch (Exception ex) { return "err:" + ex.GetType().Name; }
        }

        [System.Runtime.InteropServices.DllImport("kernel32.dll", EntryPoint = "GetCurrentThreadId")]
        private static extern uint GetCurrentThreadIdNative();

        [System.Runtime.InteropServices.DllImport("kernel32.dll", SetLastError = true)]
        private static extern IntPtr OpenThread(uint dwDesiredAccess, bool bInheritHandle, uint dwThreadId);

        [System.Runtime.InteropServices.DllImport("kernel32.dll", SetLastError = true)]
        private static extern uint SuspendThread(IntPtr hThread);

        [System.Runtime.InteropServices.DllImport("kernel32.dll", SetLastError = true)]
        private static extern int ResumeThread(IntPtr hThread);

        [System.Runtime.InteropServices.DllImport("kernel32.dll", SetLastError = true)]
        private static extern bool GetThreadContext(IntPtr hThread, IntPtr lpContext);

        [System.Runtime.InteropServices.DllImport("kernel32.dll", SetLastError = true)]
        private static extern bool CloseHandle(IntPtr hObject);

        private const uint WATCHDOG_THREAD_GET_CONTEXT = 0x0008;
        private const uint WATCHDOG_THREAD_SUSPEND_RESUME = 0x0002;
        private const uint WATCHDOG_THREAD_QUERY_INFORMATION = 0x0040;
        private const uint WATCHDOG_CONTEXT_AMD64_CONTROL = 0x00100001;

        private static string CaptureUiThreadInstructionPointer()
        {
            uint tid = _watchdogUiNativeThreadId;
            if (tid == 0) return "(no-tid)";
            IntPtr h = OpenThread(WATCHDOG_THREAD_GET_CONTEXT | WATCHDOG_THREAD_SUSPEND_RESUME | WATCHDOG_THREAD_QUERY_INFORMATION, false, tid);
            if (h == IntPtr.Zero) return "openthread_err=" + System.Runtime.InteropServices.Marshal.GetLastWin32Error();
            try
            {
                if (SuspendThread(h) == 0xFFFFFFFF)
                    return "suspend_err=" + System.Runtime.InteropServices.Marshal.GetLastWin32Error();
                IntPtr buf = System.Runtime.InteropServices.Marshal.AllocHGlobal(1232);
                try
                {
                    for (int i = 0; i < 1232; i += 8)
                        System.Runtime.InteropServices.Marshal.WriteInt64(buf, i, 0);
                    System.Runtime.InteropServices.Marshal.WriteInt32(buf, 0x30, unchecked((int)WATCHDOG_CONTEXT_AMD64_CONTROL));
                    if (!GetThreadContext(h, buf))
                        return "getcontext_err=" + System.Runtime.InteropServices.Marshal.GetLastWin32Error();
                    long rip = System.Runtime.InteropServices.Marshal.ReadInt64(buf, 0xF8);
                    string moduleHit = "(no-module)";
                    try
                    {
                        var p = System.Diagnostics.Process.GetCurrentProcess();
                        foreach (System.Diagnostics.ProcessModule m in p.Modules)
                        {
                            long basePtr = m.BaseAddress.ToInt64();
                            long size = m.ModuleMemorySize;
                            if (rip >= basePtr && rip < basePtr + size)
                            {
                                moduleHit = m.ModuleName + "+0x" + (rip - basePtr).ToString("X");
                                break;
                            }
                        }
                    }
                    catch { }
                    return "0x" + rip.ToString("X16") + " " + moduleHit;
                }
                finally
                {
                    System.Runtime.InteropServices.Marshal.FreeHGlobal(buf);
                    try { ResumeThread(h); } catch { }
                }
            }
            finally
            {
                try { CloseHandle(h); } catch { }
            }
        }

        private static void AppendFreezeLog(string line)
        {
            try
            {
                System.IO.Directory.CreateDirectory(System.IO.Path.GetDirectoryName(FreezeLogPath)!);
                System.IO.File.AppendAllText(FreezeLogPath,
                    DateTime.UtcNow.ToString("yyyy-MM-dd HH:mm:ss.fff", System.Globalization.CultureInfo.InvariantCulture)
                    + "Z " + line + Environment.NewLine);
            }
            catch { }
            try { Console.WriteLine(line); } catch { }
        }

        private async Task RunLauncherStartupHealthChecksAsync()
        {
            if (!RuntimeInformation.IsOSPlatform(OSPlatform.Windows)) return;
            await Task.Delay(2500);
            try
            {
                LogHealthEvent("startup_probe_begin");
                bool wmiOk = await ProbeWmiHealthAsync();
                LogHealthEvent(wmiOk ? "startup_probe_ok" : "startup_probe_failed");

                if (!wmiOk)
                {
                    await Task.Delay(2000);
                    bool repaired = await TryRepairPerfCountersWithUserConsentAsync();
                    if (repaired)
                    {
                        await Task.Delay(2000);
                        System.Threading.Interlocked.Exchange(ref _lastWmiProbeMs, 0);
                        bool nowOk = await ProbeWmiHealthAsync();
                        LogHealthEvent(nowOk ? "startup_repair_success" : "startup_repair_still_failing");
                    }
                    else
                    {
                        LogHealthEvent("startup_repair_skipped_or_denied");
                    }
                }
            }
            catch (Exception ex)
            {
                LogHealthEvent($"startup_probe_exception: {ex.GetType().Name}: {ex.Message}");
            }
        }

        private void LogHealthEvent(string eventName)
        {
            try
            {
                int counter = IncrementHealthCounter(eventName);
                LeafClient.Services.LeafLog.Info("HealthTelemetry", $"{eventName} (count={counter})");
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("HealthTelemetry", $"log failed for '{eventName}': {ex.Message}");
            }
        }

        private static bool IsRepairPromptSuppressed()
        {
            try
            {
                if (!System.IO.File.Exists(HealthTelemetryPath)) return false;
                var json = System.IO.File.ReadAllText(HealthTelemetryPath);
                if (string.IsNullOrWhiteSpace(json)) return false;
                using var doc = System.Text.Json.JsonDocument.Parse(json);
                if (doc.RootElement.TryGetProperty("repair_prompt_suppressed", out var fEl) && fEl.ValueKind == System.Text.Json.JsonValueKind.True)
                    return true;
                if (doc.RootElement.TryGetProperty("repair_prompt_suppress_until_unix", out var sEl) && sEl.TryGetInt64(out var sUnix))
                {
                    if (sUnix == long.MaxValue) return true;
                    if (DateTimeOffset.UtcNow.ToUnixTimeSeconds() < sUnix) return true;
                }
            }
            catch { }
            return false;
        }

        private static void RecordSkipAndMaybeSuppress()
        {
            try
            {
                IncrementHealthCounter("repair_prompt_skip_total");
                SetHealthFlag("repair_prompt_suppressed", true);
                LeafLog.Info("HealthTelemetry", "suppress_permanent set after No-thanks click");
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("HealthTelemetry", $"RecordSkipAndMaybeSuppress failed: {ex.Message}");
            }
        }

        private static void SetHealthFlag(string key, bool value)
        {
            try
            {
                System.IO.Directory.CreateDirectory(System.IO.Path.GetDirectoryName(HealthTelemetryPath)!);
                var data = new Dictionary<string, object>(StringComparer.Ordinal);
                if (System.IO.File.Exists(HealthTelemetryPath))
                {
                    try
                    {
                        var json = System.IO.File.ReadAllText(HealthTelemetryPath);
                        if (!string.IsNullOrWhiteSpace(json))
                        {
                            using var doc = System.Text.Json.JsonDocument.Parse(json);
                            foreach (var prop in doc.RootElement.EnumerateObject())
                            {
                                if (prop.Value.ValueKind == System.Text.Json.JsonValueKind.Number && prop.Value.TryGetInt64(out var n))
                                    data[prop.Name] = n;
                                else if (prop.Value.ValueKind == System.Text.Json.JsonValueKind.True)
                                    data[prop.Name] = true;
                                else if (prop.Value.ValueKind == System.Text.Json.JsonValueKind.False)
                                    data[prop.Name] = false;
                            }
                        }
                    }
                    catch { }
                }
                data[key] = value;
                var sb = new System.Text.StringBuilder();
                sb.Append('{');
                bool first = true;
                foreach (var kv in data)
                {
                    if (!first) sb.Append(',');
                    sb.Append('"').Append(kv.Key.Replace("\"", "\\\"")).Append("\":");
                    if (kv.Value is bool b) sb.Append(b ? "true" : "false");
                    else sb.Append(kv.Value);
                    first = false;
                }
                sb.Append('}');
                System.IO.File.WriteAllText(HealthTelemetryPath, sb.ToString());
            }
            catch { }
        }

