                    Avalonia.Controls.Grid.SetColumnSpan(backdrop, colSpan);
                    Avalonia.Controls.Grid.SetRowSpan(card, rowSpan);
                    Avalonia.Controls.Grid.SetColumnSpan(card, colSpan);
                    backdrop.ZIndex = 9000;
                    card.ZIndex = 9001;
                    rootGrid.Children.Add(backdrop);
                    rootGrid.Children.Add(card);

                    Dispatcher.UIThread.Post(() =>
                    {
                        backdrop.Opacity = 1;
                        card.Opacity = 1;
                        card.RenderTransform = new Avalonia.Media.ScaleTransform(1.0, 1.0);
                    }, Avalonia.Threading.DispatcherPriority.Background);
                }
                catch (Exception ex)
                {
                    LeafLog.Error("PerfCounterRepair", $"Prompt failed: {ex.Message}");
                    tcs.TrySetResult(false);
                }
            });
            return tcs.Task;
        }

        private async Task<bool> InstallOptiFineForFabricIfNeededAsync(string mcVersion, string profileName, bool isFabric)
        {
            if (!isFabric || !_currentSettings.IsOptiFineEnabled)
            {
                if (!isFabric) LeafLog.Info("OptiFine", "Not Fabric profile.");
                else ManageOptiFineForFabricMods(mcVersion, enable: false);
                return true;
            }

            string? mrpackUrl = await GetOptiFineMrpackUrlForVersion(mcVersion);
            if (string.IsNullOrEmpty(mrpackUrl))
            {
                ShowLaunchErrorBanner($"OptiFine pack not found for {mcVersion}.");
                ManageOptiFineForFabricMods(mcVersion, enable: false);
                return false;
            }

            string mrpackPath = System.IO.Path.Combine(System.IO.Path.GetTempPath(), $"OptiFineForFabric_{mcVersion}.mrpack");

            try
            {
                await DownloadFileWithProgressAsync(mrpackUrl, mrpackPath, "OptiFine Pack");
            }
            catch (Exception ex)
            {
                ShowLaunchErrorBanner($"Failed to download OptiFine pack: {ex.Message}");
                return false;
            }

            bool success = false;
            try
            {
                success = await ProcessModrinthPackInstallation(mrpackPath, System.IO.Path.Combine(_minecraftFolder, "mods"), mcVersion);
                ManageOptiFineForFabricMods(mcVersion, enable: success);
            }
            catch (Exception ex)
            {
                ShowLaunchErrorBanner($"Error installing OptiFine pack: {ex.Message}");
                ManageOptiFineForFabricMods(mcVersion, enable: false);
            }
            finally
            {
                if (File.Exists(mrpackPath)) File.Delete(mrpackPath);
            }

            return success;
        }

        private async Task DownloadAndInstallMod(string downloadUrl, string fileName, string modName, InstalledMod installedMod)
        {
            var modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
            Directory.CreateDirectory(modsFolder);
            var filePath = System.IO.Path.Combine(modsFolder, fileName);

            ShowProgress(true, $"Downloading {modName}...");

            try
            {
                await DownloadFileWithProgressAsync(downloadUrl, filePath, modName);
                installedMod.FileName = fileName;
                LeafClient.Services.LeafLog.Info("Mod Install", $"Successfully installed {modName}");
            }
            catch (Exception ex)
            {
                LeafLog.Error("Mod Install ERROR", $"Failed to download {modName}: {ex.Message}");
                ShowLaunchErrorBanner($"Failed to download {modName}. Check your internet connection.");
                throw;
            }
            finally
            {
                ShowProgress(false);
            }
        }

        private async Task<bool> DownloadFileAsync(string url, string destinationPath)
        {
            try
            {
                await DownloadFileWithProgressAsync(url, destinationPath, System.IO.Path.GetFileName(destinationPath));
                return true;
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("DownloadFile", $"Download error: {ex.Message}");
                return false;
            }
        }

        private async Task RegisterAutoInstalledMod(string modId, string modName, string version, string mcVersion, string fileName, string url)
        {
            var existing = _currentSettings.InstalledMods.FirstOrDefault(m =>
                m.ModId == modId &&
                m.MinecraftVersion == mcVersion);

            if (existing == null)
            {
                _currentSettings.InstalledMods.Add(new InstalledMod
                {
                    ModId = modId,
                    Name = modName,
                    Description = $"Auto-installed {modName}",
                    Version = version,
                    MinecraftVersion = mcVersion,
                    FileName = fileName,
                    DownloadUrl = url,
                    Enabled = true,
                    InstallDate = DateTime.Now,
                    IconUrl = "",
                    IsAutoInstalled = true,
                });
                LeafClient.Services.LeafLog.Info("Mod Tracker", $"Registered {modName} for MC {mcVersion} in settings (auto-installed).");
            }
            else
            {
                existing.FileName = fileName;
                existing.DownloadUrl = url;
                existing.Version = version;
                existing.Enabled = true;
                existing.IsAutoInstalled = true;
            }

            await _settingsService.SaveSettingsAsync(_currentSettings);
        }

        private static readonly HashSet<string> _managedFilePrefixes = new(StringComparer.OrdinalIgnoreCase)
        {
            "sodium-fabric", "sodium-extra", "sodiumextra", "lithium", "ferritecore",
            "immediatelyfast", "entityculling", "modernfix", "ebe", "dynamicfps", "dynamic-fps",
            "cloth-config", "moreculling", "krypton", "cullleaves", "debugify",
            "nofade", "betterbeds", "reeses-sodium-options", "starlight", "indium", "ksyxis",
            "vmp", "forcecloseloadingscreen", "nodoublesneak", "serverpingerfixer",
            "viafabricplus", "chestsearchbar", "fabric-api", "iris", "dynamiclights",
            "betterfps", "vulkanmod", "alphadium", "nvidium", "noisium",
        };

        private static readonly System.Text.RegularExpressions.Regex _managedJarPattern =
            new(@"^(?<prefix>.+)-(?<mcv>\d+\.\d+(?:\.\d+)?)\.jar$",
                System.Text.RegularExpressions.RegexOptions.IgnoreCase | System.Text.RegularExpressions.RegexOptions.Compiled);

        private static string RenderMArgument(CmlLib.Core.ProcessBuilder.MArgument? arg)
        {
            if (arg == null) return "<null>";
            try
            {
                var values = arg.Values;
                if (values != null && values.Count > 0)
                    return string.Join(" ", values);
            }
            catch { }
            return arg.GetType().Name;
        }

        private static string RenderMArgumentRedacted(CmlLib.Core.ProcessBuilder.MArgument? arg)
        {
            string rendered = RenderMArgument(arg);
            foreach (string k in new[] { "-Dleaf.api_jwt=", "-Dleaf.api_jwt_file=" })
            {
                int idx = rendered.IndexOf(k, StringComparison.Ordinal);
                if (idx >= 0)
                {
                    return rendered.Substring(0, idx + k.Length) + "[REDACTED]";
                }
            }
            return rendered;
        }

        private static string? WriteSessionJwtFile(string jwt)
        {
            try
            {
                if (string.IsNullOrEmpty(jwt)) return null;
                string sessionDir = System.IO.Path.Combine(System.IO.Path.GetTempPath(), "leafclient-session");
                System.IO.Directory.CreateDirectory(sessionDir);
                string filePath = System.IO.Path.Combine(sessionDir, $"jwt-{Guid.NewGuid():N}.tok");
                System.IO.File.WriteAllText(filePath, jwt, new System.Text.UTF8Encoding(false));
                try
                {
                    if (!OperatingSystem.IsWindows())
                    {
                        System.IO.File.SetUnixFileMode(filePath, UnixFileMode.UserRead | UnixFileMode.UserWrite);
                    }
                }
                catch { }
                return filePath;
            }
            catch (Exception ex)
            {
                try { LeafClient.Services.LeafLog.Error("Session", $"Failed to write session JWT file: {ex.GetType().Name}"); } catch { }
                return null;
            }
        }

        private static void CleanupStaleSessionFiles()
        {
            try
            {
                string sessionDir = System.IO.Path.Combine(System.IO.Path.GetTempPath(), "leafclient-session");
                if (!System.IO.Directory.Exists(sessionDir)) return;
                DateTime cutoff = DateTime.UtcNow.AddHours(-1);
                foreach (string f in System.IO.Directory.GetFiles(sessionDir, "jwt-*.tok"))
                {
                    try
                    {
                        if (System.IO.File.GetLastWriteTimeUtc(f) < cutoff) System.IO.File.Delete(f);
                    }
                    catch { }
                }
            }
            catch { }
        }

        public enum RenderBackend { Sodium, VulkanMod, None }

        private RenderBackend GetActiveRenderBackend()
        {
            try
            {
                var activeProfile = _currentSettings?.Profiles?.FirstOrDefault(p => p.Id == _currentSettings.ActiveProfileId)
                                 ?? _currentSettings?.Profiles?.FirstOrDefault();
                string raw = activeProfile?.RenderEngine;
                if (string.IsNullOrEmpty(raw))
                    raw = _currentSettings?.RenderBackendChoice;
                if (string.IsNullOrEmpty(raw)) return RenderBackend.Sodium;
                switch (raw.Trim().ToLowerInvariant())
                {
                    case "vulkanmod": return RenderBackend.VulkanMod;
                    case "none":      return RenderBackend.None;
                    case "sodium":    return RenderBackend.Sodium;
                    default:          return RenderBackend.Sodium;
                }
            }
            catch
            {
                return RenderBackend.Sodium;
            }
        }

        private bool IsVulkanModActive() => GetActiveRenderBackend() == RenderBackend.VulkanMod;

        private string? _lastFabricApiInstallError;

        private void PruneStaleManagedModJarsForVersion(string mcVersion)
        {
            try
            {
                string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                if (!System.IO.Directory.Exists(modsFolder)) return;

                var knownMcVersions = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                try
                {
                    foreach (var v in _allVersions)
                    {
                        if (!string.IsNullOrEmpty(v?.FullVersion)) knownMcVersions.Add(v.FullVersion);
                    }
                }
                catch { }
                if (!string.IsNullOrEmpty(mcVersion)) knownMcVersions.Add(mcVersion);

                int removed = 0;
                foreach (var path in System.IO.Directory.EnumerateFiles(modsFolder, "*.jar"))
                {
                    var name = System.IO.Path.GetFileName(path);
                    var m = _managedJarPattern.Match(name);
                    if (!m.Success) continue;
                    var prefix = m.Groups["prefix"].Value;
                    var mcv = m.Groups["mcv"].Value;
                    if (string.Equals(mcv, mcVersion, StringComparison.OrdinalIgnoreCase)) continue;
                    if (!_managedFilePrefixes.Contains(prefix)) continue;
                    if (knownMcVersions.Count > 0 && !knownMcVersions.Contains(mcv))
                    {
                        continue;
                    }
                    try
                    {
                        System.IO.File.Delete(path);
                        LeafClient.Services.LeafLog.Info("ModPruner", $"Removed stale managed jar for MC {mcv}: {name}");
                        removed++;
                    }
                    catch (Exception ex)
                    {
                        LeafClient.Services.LeafLog.Error("ModPruner", $"Failed to delete {name}: {ex.Message}");
                    }
                }
                if (removed > 0) LeafClient.Services.LeafLog.Info("ModPruner", $"Removed {removed} stale managed jar(s) for MC {mcVersion}.");
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("ModPruner", $"Sweep failed: {ex.Message}");
            }
        }

        private void PruneStrayFabricLoaderJars()
        {
            try
            {
                string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                if (!System.IO.Directory.Exists(modsFolder)) return;

                var matches = new List<string>();
                foreach (var pattern in new[] { "fabric-loader-*.jar", "fabricloader-*.jar", "fabric_loader-*.jar" })
                    matches.AddRange(System.IO.Directory.EnumerateFiles(modsFolder, pattern));

                int removed = 0;
                foreach (var path in matches.Distinct(StringComparer.OrdinalIgnoreCase))
                {
                    try
                    {
                        System.IO.File.Delete(path);
                        LeafClient.Services.LeafLog.Info("ModPruner", $"Removed stray fabric-loader jar: {System.IO.Path.GetFileName(path)}");
                        removed++;
                    }
                    catch (Exception ex) { LeafClient.Services.LeafLog.Info("ModPruner", $"Could not delete {path}: {ex.Message}"); }
                }
                if (removed > 0) LeafClient.Services.LeafLog.Info("ModPruner", $"Removed {removed} stray fabric-loader jar(s) from mods/ folder.");
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("ModPruner", $"PruneStrayFabricLoaderJars failed: {ex.Message}"); }
        }

        private async Task ApplyModPresetForLaunchAsync(string mcVersion, string fabricProfile)
        {
            var activeProfile = _currentSettings.Profiles?.FirstOrDefault(p => p.Id == _currentSettings.ActiveProfileId)
                             ?? _currentSettings.Profiles?.FirstOrDefault();
            if (activeProfile == null)
            {
                LeafLog.Info("Mod Reconcile", "No active profile found.");
                return;
            }

            PruneStaleManagedModJarsForVersion(mcVersion);
            PruneStrayFabricLoaderJars();

            string preset = (activeProfile.ModPreset ?? "none").ToLowerInvariant();
            string engine = !string.IsNullOrEmpty(activeProfile.RenderEngine) ? activeProfile.RenderEngine.ToLowerInvariant() : "sodium";
            var overrides = activeProfile.CoreModOverrides ?? new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase);
            string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
            System.IO.Directory.CreateDirectory(modsFolder);

            bool desiredVulkan = (engine == "vulkanmod");
            if (_currentSettings.IsVulkanModEnabled != desiredVulkan)
            {
                LeafClient.Services.LeafLog.Info("Mod Reconcile", $"Syncing legacy IsVulkanModEnabled {_currentSettings.IsVulkanModEnabled} -> {desiredVulkan} from active profile RenderEngine='{engine}'.");
                _currentSettings.IsVulkanModEnabled = desiredVulkan;
                _currentSettings.RenderBackendChoice = engine;
                try { if (_vulkanModToggle != null) _vulkanModToggle.IsChecked = desiredVulkan; } catch { }
            }

            LeafClient.Services.LeafLog.Info("Mod Reconcile", $"preset='{preset}' engine='{engine}' overrides={overrides.Count}");

            var activeEngineSlugs = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            if (engine == "sodium")
            {
                activeEngineSlugs.Add("sodium");
                if (ShouldInstallCoreMod("indium", preset, engine, overrides)) activeEngineSlugs.Add("indium");
                if (ShouldInstallCoreMod("sodiumextra", preset, engine, overrides)) activeEngineSlugs.Add("sodiumextra");
                if (ShouldInstallCoreMod("reeses-sodium-options", preset, engine, overrides)) activeEngineSlugs.Add("reeses-sodium-options");
            }
            else if (engine == "vulkanmod")
            {
                activeEngineSlugs.Add("vulkanmod");
            }
            foreach (var slug in _engineAxisSlugs)
            {
                if (activeEngineSlugs.Contains(slug)) continue;
                foreach (var f in EnumerateManagedJarsForSlug(modsFolder, slug))
                {
                    try { System.IO.File.Delete(f); LeafClient.Services.LeafLog.Info("Engine", $"Removed {System.IO.Path.GetFileName(f)} (engine axis cleanup)"); } catch { }
                }
            }
            bool engineReady = (engine == "none");
            try
            {
                if (engine == "sodium")
                {
                    await InstallSodiumIfNeededAsync(mcVersion);
                    if (ShouldInstallCoreMod("indium", preset, engine, overrides)) await InstallIndiumIfNeededAsync(mcVersion);
                    if (ShouldInstallCoreMod("sodiumextra", preset, engine, overrides)) await InstallSodiumExtraIfNeededAsync(mcVersion);
                    if (ShouldInstallCoreMod("reeses-sodium-options", preset, engine, overrides)) await InstallReesesSodiumOptionsIfNeededAsync(mcVersion);
                    engineReady = EnumerateManagedJarsForSlug(modsFolder, "sodium").Any();
                }
                else if (engine == "vulkanmod")
                {
                    await InstallVulkanModIfNeededAsync(mcVersion);
                    engineReady = EnumerateManagedJarsForSlug(modsFolder, "vulkanmod").Any();
                }
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("Engine", $"Install failed: {ex.Message}"); }

            if (!engineReady && engine != "none")
            {
                LeafClient.Services.LeafLog.Warn("Engine", $"{engine} jar not present on disk after install attempt. Engine-dependent mods will be skipped.");
                ShowLaunchErrorBanner($"{(engine == "sodium" ? "Sodium" : "VulkanMod")} failed to install. Iris/Indium will be skipped - retry to fix.");
            }

            foreach (var (slug, _, _) in _toggleableCoreMods)
            {
                _activeLaunchToken.ThrowIfCancellationRequested();
                bool want = ShouldInstallCoreMod(slug, preset, engine, overrides);
                if (!want)
                {
                    foreach (var f in EnumerateManagedJarsForSlug(modsFolder, slug))
                    {
                        try { System.IO.File.Delete(f); LeafClient.Services.LeafLog.Info("Reconcile", $"Removed {System.IO.Path.GetFileName(f)} (slug {slug} not in target set)"); } catch { }
                    }
                    continue;
                }
                try
                {
                    switch (slug)
                    {
                        case "lithium":         await InstallLithiumIfNeededAsync(mcVersion); break;
                        case "ferritecore":     await InstallFerriteCorIfNeededAsync(mcVersion); break;
                        case "krypton":         await InstallKryptonIfNeededAsync(mcVersion); break;
                        case "immediatelyfast": await InstallImmediatelyFastIfNeededAsync(mcVersion); break;
                        case "entityculling":   await InstallEntityCullingIfNeededAsync(mcVersion); break;
                        case "moreculling":     await InstallMoreCullingIfNeededAsync(mcVersion); break;
                        case "ebe":             await InstallEnhancedBlockEntitiesIfNeededAsync(mcVersion); break;
                        case "starlight":       await InstallStarlightIfNeededAsync(mcVersion); break;
                        case "viafabricplus":   await InstallModrinthSlugIfNeededAsync(mcVersion, "viafabricplus", "ViaFabricPlus", "viafabricplus"); break;
                        case "iris":
                            if (engineReady && engine == "sodium") await InstallIrisShadersIfNeededAsync(mcVersion);
                            else { foreach (var f in EnumerateManagedJarsForSlug(modsFolder, "iris")) { try { System.IO.File.Delete(f); } catch { } } }
                            break;
                        case "dynamiclights":   await InstallDynamicLightsIfNeededAsync(mcVersion); break;
                        case "betterfps":       await InstallBetterFpsIfNeededAsync(mcVersion); break;
                        case "modernfix":       await InstallModrinthSlugIfNeededAsync(mcVersion, "modernfix", "ModernFix", "modernfix"); break;
                        case "dynamicfps":      await InstallModrinthSlugIfNeededAsync(mcVersion, "dynamicfps", "Dynamic FPS", "dynamicfps"); break;
                        case "noisium":         await InstallModrinthSlugIfNeededAsync(mcVersion, "noisium", "Noisium", "noisium"); break;
                        case "debugify":        await InstallModrinthSlugIfNeededAsync(mcVersion, "debugify", "Debugify", "debugify"); break;
                    }
                }
                catch (Exception ex) { LeafClient.Services.LeafLog.Error("Reconcile", $"Install {slug} failed: {ex.Message}"); }
            }

            _lastFabricApiInstallError = null;
            try { await InstallFabricApiIfNeededAsync(mcVersion, fabricProfile); }
            catch (Exception ex)
            {
                _lastFabricApiInstallError = $"{ex.GetType().Name}: {ex.Message}";
                LeafClient.Services.LeafLog.Error("Reconcile", $"Fabric API install failed: {ex.Message}");
            }

            try { await AutoInstallMissingDependenciesAsync(mcVersion, modsFolder); }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("AutoDeps", $"Failed: {ex.Message}"); }

            try
            {
                bool irisPresent = EnumerateManagedJarsForSlug(modsFolder, "iris").Any();
                bool sodiumPresent = EnumerateManagedJarsForSlug(modsFolder, "sodium").Any();
                if (irisPresent && !sodiumPresent)
                {
                    foreach (var f in EnumerateManagedJarsForSlug(modsFolder, "iris"))
                    {
                        try { System.IO.File.Delete(f); LeafClient.Services.LeafLog.Warn("SanitySweep", $"Removed orphan {System.IO.Path.GetFileName(f)} (no Sodium present)"); } catch { }
                    }
                    ShowLaunchErrorBanner("Iris removed - Sodium is missing. Retry launch to reinstall both.");
                }
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("SanitySweep", $"Failed: {ex.Message}"); }

            LeafClient.Services.LeafLog.Info("Mod Reconcile", $"Done for preset='{preset}' engine='{engine}' in MC {mcVersion}");
            return;

        }

        private async Task AutoInstallMissingDependenciesAsync(string mcVersion, string modsFolder)
        {
            var synthetic = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                "minecraft", "java", "fabricloader", "fabric-loader",
            };
            var fabricApiSubs = LeafClient.Services.ModFolderManagement.BundledModsAllowlist.FabricApiSubModules;

            for (int pass = 0; pass < 2; pass++)
            {
                var scanned = await LeafClient.Services.ModFolderManagement.ModScanner.ScanFolderAsync(modsFolder, fastMode: true).ConfigureAwait(false);
                var installedIds = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                bool fabricApiPresent = false;
                foreach (var m in scanned)
                {
                    if (!string.IsNullOrEmpty(m.ModId)) installedIds.Add(m.ModId);
                    if (m.ModId.Equals("fabric-api", StringComparison.OrdinalIgnoreCase) ||
                        m.ModId.Equals("fabric", StringComparison.OrdinalIgnoreCase))
                        fabricApiPresent = true;
                    foreach (var jij in m.JarInJar)
                        if (!string.IsNullOrEmpty(jij.ModId)) installedIds.Add(jij.ModId);
                }
                if (fabricApiPresent)
                {
                    foreach (var sub in fabricApiSubs) installedIds.Add(sub);
                }

                foreach (var kv in _depModrinthSlugAliases)
                {
                    if (installedIds.Contains(kv.Value)) installedIds.Add(kv.Key);
                }

                var toInstall = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                foreach (var m in scanned)
                {
                    if (!m.IsParsed) continue;
                    foreach (var dep in m.Depends)
                    {
                        string id = dep.TargetId;
                        if (string.IsNullOrEmpty(id)) continue;
                        if (synthetic.Contains(id)) continue;
                        if (installedIds.Contains(id)) continue;
                        if (fabricApiSubs.Contains(id) && fabricApiPresent) continue;

                        string slug = _depModrinthSlugAliases.TryGetValue(id, out var aliased) ? aliased : id;
                        toInstall.Add(slug);
                        LeafClient.Services.LeafLog.Info("AutoDeps", $"{m.DisplayName} requires '{id}' → will try Modrinth slug '{slug}'");
                    }
                }
                if (toInstall.Count == 0)
                {
                    if (pass == 0) LeafLog.Info("AutoDeps", "No missing deps after pass 1.");
                    break;
                }
                foreach (var slug in toInstall)
                {
                    try
                    {
                        await InstallModrinthSlugIfNeededAsync(mcVersion, slug, slug, slug);
                    }
                    catch (Exception ex)
                    {
                        LeafClient.Services.LeafLog.Error("AutoDeps", $"Install '{slug}' failed: {ex.Message}");
                    }
                }
            }
        }

        private async Task<bool> ProcessModrinthPackInstallation(string mrpackPath, string modsFolder, string mcVersion)
        {
            LeafClient.Services.LeafLog.Info("Modpack", $"Starting to process .mrpack installation from {mrpackPath} for MC {mcVersion}...");

            string tempExtractionFolder = System.IO.Path.Combine(System.IO.Path.GetTempPath(), "ModrinthPackExtract_" + Guid.NewGuid());
            System.IO.Directory.CreateDirectory(tempExtractionFolder);
            LeafClient.Services.LeafLog.Info("Modpack", $"Created temporary extraction folder: {tempExtractionFolder}");

            try
            {
                try
                {
                    ShowProgress(true, $"Extracting modpack files for {mcVersion}...");
                    System.IO.Compression.ZipFile.ExtractToDirectory(mrpackPath, tempExtractionFolder);
                    LeafClient.Services.LeafLog.Info("Modpack", $"Successfully extracted .mrpack to {tempExtractionFolder}");
                }
                catch (Exception ex)
                {
                    LeafLog.Error("Modpack ERROR", $"Error extracting .mrpack '{mrpackPath}': {ex.GetType().Name} - {ex.Message}");
                    return false;
                }

                string overridesDir = System.IO.Path.Combine(tempExtractionFolder, "overrides");
                if (System.IO.Directory.Exists(overridesDir))
                {
                    LeafLog.Info("Modpack", "Found 'overrides' directory, attempting to copy to .minecraft folder...");
                    CopyDirectory(overridesDir, _minecraftFolder);
                    LeafLog.Info("Modpack", "Finished copying 'overrides'.");
                }

                string clientOverrides = System.IO.Path.Combine(tempExtractionFolder, "client-overrides");
                if (System.IO.Directory.Exists(clientOverrides))
                {
                    LeafLog.Info("Modpack", "Found 'client-overrides' directory, attempting to copy to .minecraft folder...");
                    CopyDirectory(clientOverrides, _minecraftFolder);
                    LeafLog.Info("Modpack", "Finished copying 'client-overrides'.");
                }

                string serverOverrides = System.IO.Path.Combine(tempExtractionFolder, "server-overrides");
                if (System.IO.Directory.Exists(serverOverrides))
                {
                    LeafLog.Info("Modpack", "Found 'server-overrides' directory, attempting to copy to .minecraft folder...");
                    CopyDirectory(serverOverrides, _minecraftFolder);
                    LeafLog.Info("Modpack", "Finished copying 'server-overrides'.");
                }

                string indexPath = System.IO.Path.Combine(tempExtractionFolder, "modrinth.index.json");
                if (!System.IO.File.Exists(indexPath))
                {
                    LeafLog.Error("Modpack ERROR", $"modrinth.index.json not found at {indexPath}. Cannot install mods.");
                    return false;
                }

                string indexJson = await System.IO.File.ReadAllTextAsync(indexPath);
                var options = new JsonSerializerOptions { PropertyNameCaseInsensitive = true };
                var pack = JsonSerializer.Deserialize(indexJson, JsonContext.Default.ModrinthPack);

                if (pack == null || pack.Files == null || pack.Files.Count == 0)
                {
                    LeafLog.Error("Modpack ERROR", "ModrinthPack deserialized to null or contains no files.");
                    return false;
                }

                using (var httpClient = new HttpClient())
                {
                    foreach (var file in pack.Files)
                    {
                        if (file == null)
                        {
                            LeafLog.Info("Modpack", "Skipping null file entry in modrinth.index.json.");
                            continue;
                        }

                        if (string.IsNullOrEmpty(file.Path) || file.Path.Contains("..") || System.IO.Path.IsPathRooted(file.Path))
                        {
                            LeafLog.Error("Modpack ERROR", $"Unsafe or invalid file path '{file.Path}', skipping download.");
                            continue;
                        }

                        if (!file.Path.StartsWith("mods/", StringComparison.OrdinalIgnoreCase) || !file.Path.EndsWith(".jar", StringComparison.OrdinalIgnoreCase))
                        {
                            LeafClient.Services.LeafLog.Info("Modpack", $"Skipping non-mod file or non-jar file from modrinth.index.json: {file.Path}");
                            continue;
                        }

                        if (file.Downloads == null || file.Downloads.Count == 0)
                        {
                            LeafLog.Error("Modpack ERROR", $"No download URLs found for file: {file.Path}, skipping.");
                            continue;
                        }

                        string fileName = System.IO.Path.GetFileName(file.Path);
                        string destPath = System.IO.Path.Combine(modsFolder, fileName);
                        string downloadUrl = file.Downloads[0];

                        LeafClient.Services.LeafLog.Info("Modpack", $"Downloading mod: {fileName} from {downloadUrl}");
                        ShowProgress(true, $"Downloading {fileName}...");

                        try
                        {
                            byte[] modData = await httpClient.GetByteArrayAsync(downloadUrl);

                            if (file.Hashes != null && file.Hashes.TryGetValue("sha512", out var expectedHash))
                            {
                                using var sha512 = System.Security.Cryptography.SHA512.Create();
                                var actualHashBytes = sha512.ComputeHash(modData);
                                var actualHashString = BitConverter.ToString(actualHashBytes).Replace("-", "").ToLowerInvariant();

                                if (!actualHashString.Equals(expectedHash, StringComparison.OrdinalIgnoreCase))
                                {
                                    LeafLog.Error("Modpack ERROR", $"Hash mismatch for {fileName}! Expected: {expectedHash}, Got: {actualHashString}. Skipping file.");
                                    continue;
                                }
                                LeafClient.Services.LeafLog.Info("Modpack", $"Hash validated for {fileName}.");
                            }

                            await System.IO.File.WriteAllBytesAsync(destPath, modData);
                            LeafClient.Services.LeafLog.Info("Modpack", $"Successfully installed mod: {fileName} to {destPath}");

                            var installedMod = new InstalledMod
                            {
                                ModId = System.IO.Path.GetFileNameWithoutExtension(fileName),
                                Name = fileName,
                                Description = "Installed from Modrinth pack",
                                Version = "N/A",
                                MinecraftVersion = mcVersion,
                                FileName = fileName,
                                DownloadUrl = downloadUrl,
                                Enabled = true,
                                InstallDate = DateTime.Now,
                                IconUrl = ""
                            };

                            var existingMod = _currentSettings.InstalledMods.FirstOrDefault(m => m.ModId == installedMod.ModId && m.MinecraftVersion == installedMod.MinecraftVersion);
                            if (existingMod == null)
                            {
                                _currentSettings.InstalledMods.Add(installedMod);
                                LeafClient.Services.LeafLog.Info("Modpack", $"Added '{installedMod.Name}' to settings.");
                            }
                            else
                            {
                                existingMod.Name = installedMod.Name;
                                existingMod.Description = installedMod.Description;
                                existingMod.Version = installedMod.Version;
                                existingMod.FileName = installedMod.FileName;
                                existingMod.DownloadUrl = installedMod.DownloadUrl;
                                existingMod.Enabled = true;
                                existingMod.InstallDate = DateTime.Now;
                                existingMod.IconUrl = installedMod.IconUrl;
                                LeafClient.Services.LeafLog.Info("Modpack", $"Updated '{installedMod.Name}' in settings.");
                            }
                        }
                        catch (Exception ex)
                        {
                            LeafLog.Error("Modpack ERROR", $"Error downloading or writing mod {fileName}: {ex.GetType().Name} - {ex.Message}");
                        }
                    }
                }

                await _settingsService.SaveSettingsAsync(_currentSettings);
                LeafLog.Info("Modpack", "Settings saved after pack installation.");

                LeafClient.Services.LeafLog.Info("Modpack", $"Modpack installation for {mcVersion} completed successfully.");
                return true;
            }
            catch (Exception ex)
            {
                LeafLog.Error("Modpack ERROR", $"Unexpected error during modpack processing: {ex.GetType().Name} - {ex.Message}");
                return false;
            }
            finally
            {
                ShowProgress(false);
                try
                {
                    if (System.IO.Directory.Exists(tempExtractionFolder))
                    {
                        System.IO.Directory.Delete(tempExtractionFolder, true);
                        LeafClient.Services.LeafLog.Info("Modpack", $"Cleaned up temporary extraction folder: {tempExtractionFolder}");
                    }
                }
                catch (Exception ex)
                {
                    LeafLog.Error("Modpack ERROR", $"Cleanup failed for {tempExtractionFolder}: {ex.Message}");
                }
            }
        }

        private void CopyDirectory(string sourceDir, string destDir)
        {
            foreach (var dir in System.IO.Directory.GetDirectories(sourceDir, "*", SearchOption.AllDirectories))
            {
                string targetDir = dir.Replace(sourceDir, destDir);
                System.IO.Directory.CreateDirectory(targetDir);
            }

            foreach (var file in System.IO.Directory.GetFiles(sourceDir, "*", SearchOption.AllDirectories))
            {
                string targetFile = file.Replace(sourceDir, destDir);
                try
                {
                    System.IO.File.Copy(file, targetFile, overwrite: true);
                    LeafClient.Services.LeafLog.Info("Modpack", $"Successfully copied override file: {targetFile}");
                }
                catch (Exception ex)
                {
                    LeafLog.Error("Modpack ERROR", $"Failed to copy override file {file} to {targetFile}: {ex.Message}");
                }
            }
        }

        private async void LaunchFromVersionsSidebar(object? sender, RoutedEventArgs e)
        {
            AnimateSelectionIndicator(0);
            _currentSelectedIndex = 0;
            SwitchToPage(0);

            await Task.Delay(300);

            var launchBtn = this.FindControl<Button>("LaunchGameButton");
            if (launchBtn != null)
            {
                if (_isLaunching)
                {
                    if (_gameProcess != null && !_gameProcess.HasExited)
                    {
                        _userTerminatedGame = true;
                        var procToKill = _gameProcess;
                        _ = Task.Run(() => { try { procToKill.Kill(entireProcessTree: true); } catch { } });
                    }
                    _launchCancellationTokenSource?.Cancel();
                    _isLaunching = false;
                    UpdateLaunchButton("LAUNCH GAME", "SeaGreen");
                    return;
                }

                var selectedVersionInfo = _allVersions.FirstOrDefault(v => v.FullVersion == _currentSettings.SelectedSubVersion);
                if (selectedVersionInfo == null)
                {
                    UpdateLaunchButton("SELECT VERSION", "OrangeRed");
                    return;
                }

                bool isFabric = selectedVersionInfo.Loader.Equals("Fabric", StringComparison.OrdinalIgnoreCase);
                await LaunchGameAsync(selectedVersionInfo.FullVersion, isFabric);
            }
        }

        private async void LaunchGameToServer(ServerInfo server)
        {
            if (_isLaunching || _launcher == null)
            {
                LeafLog.Info("Launch", "Game is already launching or launcher is not initialized. Aborting new launch request.");
                return;
            }

            _currentSettings.QuickJoinServerAddress = server.Address;
            _currentSettings.QuickJoinServerPort = server.Port.ToString();
            await _settingsService.SaveSettingsAsync(_currentSettings);

            LeafClient.Services.LeafLog.Info("Server", $"Preparing to join {server.Name} at {server.Address}:{server.Port}");

            AnimateSelectionIndicator(0);
            _currentSelectedIndex = 0;
            SwitchToPage(0);

            await Task.Delay(300);

            var launchBtn = this.FindControl<Button>("LaunchGameButton");
            if (launchBtn != null)
            {
                var selectedVersionInfo = _allVersions.FirstOrDefault(v => v.FullVersion == _currentSettings.SelectedSubVersion);
                if (selectedVersionInfo == null)
                {
                    UpdateLaunchButton("SELECT VERSION", "OrangeRed");
                    ShowLaunchErrorBanner("Please select a Minecraft version before joining a server.");
                    return;
                }

                bool isFabric = selectedVersionInfo.Loader.Equals("Fabric", StringComparison.OrdinalIgnoreCase);
                await LaunchGameAsync(selectedVersionInfo.FullVersion, isFabric);
            }
        }

        private async Task UpdateServerButtonStates()
        {
            await Dispatcher.UIThread.InvokeAsync(() =>
            {
                bool isAnyLaunchInProgress = _isLaunching || _isInstalling;

                if (_quickPlayServersContainer != null)
                {
                    foreach (var child in _quickPlayServersContainer.Children)
                    {
                        if (child is Button qpBtn && qpBtn.Tag is ServerInfo qpServer)
                        {
                            qpBtn.IsEnabled = true;

                            bool statusKnown = !string.IsNullOrEmpty(qpServer.StatusText)
                                               && qpServer.StatusText != "Checking..."
                                               && qpServer.StatusText != "Refreshing...";
                            bool dim = isAnyLaunchInProgress || (statusKnown && !qpServer.IsOnline);
                            qpBtn.Opacity = dim ? 0.3 : 1.0;
                        }
                    }
                }

                if (_serversWrapPanel != null)
                {
                    foreach (var card in _serversWrapPanel.Children.OfType<Border>())
                    {
                        if (card.Child is Grid grid)
                        {
                            var actionStack = grid.Children.OfType<StackPanel>()
                                .FirstOrDefault(sp => Grid.GetColumn(sp) == 2);
                            if (actionStack != null)
                            {
                                var joinButton = actionStack.Children.OfType<Button>().FirstOrDefault();
                                if (joinButton != null && card.Tag is string serverId)
                                {
                                    var server = _currentSettings.CustomServers.FirstOrDefault(s => s.Id == serverId);
                                    if (server != null)
                                    {
                                        joinButton.IsEnabled = !isAnyLaunchInProgress && server.IsOnline;
                                        joinButton.Background = server.IsOnline
                                            ? GetBrush("PrimaryAccentBrush")
                                            : GetBrush("HoverBackgroundBrush");
                                        joinButton.Foreground = server.IsOnline
                                            ? GetBrush("AccentButtonForegroundBrush")
                                            : GetBrush("DisabledForegroundBrush");
                                        joinButton.Opacity = 1.0;
                                    }
                                    else
                                    {
                                        joinButton.IsEnabled = false;
                                        joinButton.Background = GetBrush("HoverBackgroundBrush");
                                        joinButton.Foreground = GetBrush("DisabledForegroundBrush");
                                        joinButton.Opacity = 1.0;
                                    }
                                }
                            }
                        }
                    }
                }
            });
        }

        private async Task LaunchGameAsync(string version, bool isFabric = false)
        {
            if (_isLaunching) return;

            if (!await _launchPrepSemaphore.WaitAsync(TimeSpan.FromSeconds(30)))
            {
                ToastService.Show("Another launch is still preparing. Try again in a moment.", ToastType.Info);
                return;
            }

            LeafLog.Info("Launch", $"Starting game: version={version}, fabric={isFabric}, user={_currentUsername ?? "(none)"}");
            try
            {
                var p = GetActiveProfile();
                long avMb = -1;
                try { avMb = GC.GetTotalMemory(false) / (1024 * 1024); } catch { }
                LeafLog.Info("Launch/Ctx", $"profile=\"{p?.Name ?? "(default)"}\" id={p?.Id ?? "(none)"} mcv={version} fabric={isFabric}");
                LeafLog.Info("Launch/Ctx", $"preset={p?.ModPreset ?? "none"} engine={(p?.RenderEngine ?? "(empty)")} overrides={(p?.CoreModOverrides?.Count ?? 0)} memGb={p?.AllocatedMemoryGb ?? 0:0.0}");
                LeafLog.Info("Launch/Ctx", $"java={p?.JavaSetting ?? "bundled"} customJava={(string.IsNullOrEmpty(p?.CustomJavaPath) ? "(none)" : p!.CustomJavaPath)}");
                LeafLog.Info("Launch/Ctx", $"jvmExtra=\"{p?.JvmArgumentsOverride ?? ""}\" resOverride={(p?.UseCustomResolutionOverride == true ? $"{p.GameResolutionWidthOverride}x{p.GameResolutionHeightOverride}" : "(no)")}");
                LeafClient.Services.LeafLog.Info("Launch/Ctx", $"mcDir={_minecraftFolder} gcMem={avMb}MB");
            }
            catch (Exception ex) { LeafClient.Services.LeafLog.Error("Launch/Ctx", $"context log failed: {ex.Message}"); }
            InitializeLauncher();

            _isLaunching = true;
            _userTerminatedGame = false;
            _gameStartingBannerShownForCurrentLaunch = false;
            _launchFailureBannerShownForCurrentLaunch = false;

            try
            {
                var appData = Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData);
                var dir = System.IO.Path.Combine(appData, "LeafClient");
                foreach (var name in new[] { "account_session.json", "account_request.json" })
                {
                    var p = System.IO.Path.Combine(dir, name);
                    try { if (System.IO.File.Exists(p)) System.IO.File.Delete(p); } catch { }
                }
            }
            catch { }

            await UpdateServerButtonStates();

            ShowProgress(false);

            _launchCancellationTokenSource = new CancellationTokenSource();
            var cancellationToken = _launchCancellationTokenSource.Token;
            _activeLaunchToken = cancellationToken;

            HideLaunchErrorBanner();
            HideLaunchFailureBanner();

            await LoadSessionAsync();

            if (_session == null)
            {
                if (_currentSettings?.IsLoggedIn == true && _currentSettings.AccountType == "microsoft")
                {
                    bool reAuthed = await TryInteractiveReAuthAsync();
                    if (reAuthed)
                    {
                        await LoadSessionAsync();
                    }
                }

                if (_session == null)
                {
                    HideLaunchAnimation();
                    UpdateLaunchButton("LOGIN REQUIRED", "OrangeRed");
                    ShowLaunchErrorBanner("Session expired. Please log out and log back in.");
                    _isLaunching = false;
                    await UpdateServerButtonStates();
                    return;
                }
            }

            bool isNetworkAvailable = System.Net.NetworkInformation.NetworkInterface.GetIsNetworkAvailable();
            if (!isNetworkAvailable && _currentSettings.AccountType != "offline")
            {
                HideLaunchAnimation();
                UpdateLaunchButton("YOU'RE OFFLINE", "Gray");
                ShowLaunchErrorBanner("No internet connection. Cannot launch online game.");
                _isLaunching = false;
                await UpdateServerButtonStates();
                return;
            }

            string versionToLaunch = version;

            try
            {
                if (_gameOutputWindow == null)
                {
                    _gameOutputWindow = new GameOutputWindow();
                    _gameOutputWindow.SetIsLeafPlus(_isLeafPlus);

                    _gameOutputWindow.Closing += (s, args) =>
                    {
                        if (_gameProcess != null && !_gameProcess.HasExited)
                        {
                            args.Cancel = true;
                            _gameOutputWindow.Hide();
                        }
                    };

                    _gameOutputWindow.Closed += (s, e) =>
                    {
                        LeafClient.Services.LeafLog.UnregisterWindowSink();
                        _gameOutputWindow = null;
                    };

                    _gameOutputWindow.KillGameRequested += (s, e) =>
                    {
                        if (_gameProcess != null && !_gameProcess.HasExited)
                        {
                            _userTerminatedGame = true;
                            var procToKill = _gameProcess;
                            _gameOutputWindow?.AppendLog("Kill signal sent to game process.", "WARN");
                            _ = Task.Run(() =>
                            {
                                try { procToKill.Kill(entireProcessTree: true); }
                                catch (Exception ex) { LeafLog.Error("Launcher", $"Kill error (output window): {ex.Message}"); }
                            });
                        }
                    };
                }

                _gameOutputWindow.ClearLog();
                _gameOutputWindow.BeginNewSession();
                _gameOutputWindow.SetSessionInfo(versionToLaunch, _session.Username, _logFolderPath);
                if (_currentSettings?.ShowGameOutputWindow ?? true)
                {
                    _gameOutputWindow.Show();
                    _gameOutputWindow.Activate();
                }

                var sinkWindow = _gameOutputWindow;
                LeafClient.Services.LeafLog.RegisterWindowSink((msg, lvl) => sinkWindow?.AppendLogFromConsole(msg, lvl));

                _gameOutputWindow.AppendLog($"Initializing launch sequence for {version}...", "INFO");

                try
                {
                    var ap = _currentSettings.Profiles?.FirstOrDefault(p => p.Id == _currentSettings.ActiveProfileId)
                          ?? _currentSettings.Profiles?.FirstOrDefault();
                    string apName = ap?.Name ?? "<none>";
                    string apEngine = string.IsNullOrEmpty(ap?.RenderEngine) ? "<unset>" : ap.RenderEngine;
                    string apPreset = string.IsNullOrEmpty(ap?.ModPreset) ? "<unset>" : ap.ModPreset;
                    int overrideCount = ap?.CoreModOverrides?.Count ?? 0;
                    _gameOutputWindow.AppendLog($"[LaunchEnv] Profile='{apName}' Preset='{apPreset}' RenderEngine='{apEngine}' Overrides={overrideCount}", "INFO");
                    _gameOutputWindow.AppendLog($"[LaunchEnv] MinecraftFolder='{_minecraftFolder}'", "INFO");
                    _gameOutputWindow.AppendLog($"[LaunchEnv] LegacyIsVulkanModEnabled={_currentSettings.IsVulkanModEnabled} RenderBackendChoice='{_currentSettings.RenderBackendChoice ?? "<unset>"}'", "INFO");
                }
                catch (Exception envEx)
                {
                    _gameOutputWindow.AppendLog($"[LaunchEnv] Failed to summarize launch env: {envEx.Message}", "WARN");
                }

                UpdateLaunchButton("PREPARING...", "DeepSkyBlue");
                cancellationToken.ThrowIfCancellationRequested();
                await PrepareModsFolderAsync(version);
                cancellationToken.ThrowIfCancellationRequested();

                string leafModPath = GetLeafOfflineJarPath(version);

                bool leafSupported = IsLeafRuntimeVersion(version);

                string disableFlagPath = System.IO.Path.Combine(_minecraftFolder, "disable_leaf_mod.flag");
                if (System.IO.File.Exists(disableFlagPath) || Environment.GetEnvironmentVariable("LEAF_DISABLE_MOD") == "1")
                {
                    leafSupported = false;
                    _gameOutputWindow?.AppendLog("[LaunchDiag] disable_leaf_mod.flag present - Leaf mod injection disabled for FPS A/B test.", "WARN");
                }

                _gameOutputWindow?.AppendLog($"[LaunchDiag] Mode: {(_currentSettings.IsTestMode ? "TEST (local build)" : "NORMAL (github download)")}", "INFO");
                _gameOutputWindow?.AppendLog($"[LaunchDiag] LeafClient mod support for {version}: {(leafSupported ? "YES" : "NO (launching vanilla)")}", "INFO");
                if (leafSupported)
                    LogLaunchPreBuildDiagnostics(leafModPath, version);

                bool isModern = Version.TryParse(version, out var v) && v >= new Version(1, 17);
                if (isModern && leafSupported)
                {
                    try
                    {
                        if (_currentSettings.IsTestMode)
                        {
                            if (File.Exists(leafModPath)) File.Delete(leafModPath);
                            await BuildAndCopyLocalModAsync(version, leafModPath);
                        }
                        else
                        {
                            var manifest = await LeafApiService.GetModManifestAsync(version);
                            if (manifest != null && !string.IsNullOrWhiteSpace(manifest.Sha256) && !string.IsNullOrWhiteSpace(manifest.JarUrl))
                            {
                                _gameOutputWindow?.AppendLog($"[LaunchDiag] Using verified CDN manifest (v{manifest.Version}) for Leaf Core.", "INFO");
                                bool needsDownload = true;
                                if (File.Exists(leafModPath))
                                {
                                    try
                                    {
                                        var localHash = await LeafClient.Services.ModFolderManagement.ModHasher.ComputeSha256Async(leafModPath);
                                        if (!string.IsNullOrEmpty(localHash) && string.Equals(localHash, manifest.Sha256, StringComparison.OrdinalIgnoreCase))
                                        {
                                            needsDownload = false;
                                            _gameOutputWindow?.AppendLog("[LaunchDiag] Local jar hash matches CDN manifest - skipping redownload.", "INFO");
                                        }
                                    }
                                    catch (IOException) { needsDownload = true; }
                                }
                                if (needsDownload)
                                {
                                    try { if (File.Exists(leafModPath)) File.Delete(leafModPath); }
                                    catch (IOException ioEx)
                                    {
                                        throw new IOException($"Cannot replace {System.IO.Path.GetFileName(leafModPath)} - another Minecraft instance is still running and has it open. Close it first.", ioEx);
                                    }
                                    await LeafApiService.DownloadVerifiedModJarAsync(manifest, leafModPath);
                                    LogJarFileInfo("leafModPath (post-download)", leafModPath);
                                }
                            }
                            else
                            {
                                _gameOutputWindow?.AppendLog($"LeafClient doesn't support {version} yet - launching vanilla.", "WARN");
                                leafSupported = false;
                            }
                        }
                    }
                    catch (InvalidOperationException integrityEx) when (integrityEx.Message == "Jar integrity check failed")
                    {
                        _gameOutputWindow?.AppendLog("[JarVerify] Integrity check FAILED - aborting launch.", "ERROR");
                        ShowProgress(false);
                        await ShowAccountActionErrorDialog("Could not verify client files. Please restart the launcher.");
                        return;
                    }
                    catch (Exception ex)
                    {
                        _gameOutputWindow?.AppendLog($"Failed to prepare core mod: {ex.Message}", "ERROR");
                        ShowProgress(false);
                        if (_currentSettings.IsTestMode)
                        {
                            await ShowAccountActionErrorDialog($"Developer test mode build failed - launch aborted.\n\n{ex.Message}");
                            return;
                        }
                        leafSupported = false;
                        _gameOutputWindow?.AppendLog($"[LaunchDiag] LeafClient jar unavailable for {version} - falling back to vanilla launch.", "WARN");
                    }

                    if (leafSupported && (!File.Exists(leafModPath) || new FileInfo(leafModPath).Length < 1024))
                    {
                        leafSupported = false;
                        _gameOutputWindow?.AppendLog($"[LaunchDiag] LeafClient jar not present on disk after prep for {version} - falling back to vanilla launch.", "WARN");
                    }

                    ShowProgress(false);
                }

                if (GetSelectedAddon(version).Equals("Fabric", StringComparison.OrdinalIgnoreCase))
                {
                    cancellationToken.ThrowIfCancellationRequested();
                    versionToLaunch = await EnsureFabricProfileAsync(version);

                    if (string.IsNullOrEmpty(versionToLaunch))
                    {
                        throw new Exception("Fabric installation failed.");
                    }

                    cancellationToken.ThrowIfCancellationRequested();

                    if (_currentSettings.IsOptiFineEnabled)
                        await InstallOptiFineForFabricIfNeededAsync(version, versionToLaunch, true);

                    cancellationToken.ThrowIfCancellationRequested();

                    await ApplyModPresetForLaunchAsync(version, versionToLaunch);

                    cancellationToken.ThrowIfCancellationRequested();

                    if (_currentSettings.IsFirstLaunch)
                    {
                        await FirstLaunchDefaultsService.Instance.ApplyDefaultsIfNeededAsync(_minecraftFolder);
                        _currentSettings.IsFirstLaunch = false;
                        await _settingsService.SaveSettingsAsync(_currentSettings);
                        _ = Dispatcher.UIThread.InvokeAsync(() => ShowFirstLaunchDefaultsPopup());
                    }

                    cancellationToken.ThrowIfCancellationRequested();

                    await InstallUserModsAsync(version);

                    cancellationToken.ThrowIfCancellationRequested();

                    if (!VerifyFabricApiPresent(version))
                    {
                        ShowProgress(false);
                        UpdateLaunchButton("LAUNCH GAME", "SeaGreen");
                        string baseMsg = $"Fabric API for Minecraft {version} is not installed.";
                        string detail = !string.IsNullOrEmpty(_lastFabricApiInstallError)
                            ? $" Install failed: {_lastFabricApiInstallError}."
                            : " The download may have failed silently. Check your internet connection.";
                        ShowLaunchErrorBanner(baseMsg + detail + " Close any running Minecraft instance and click Launch again.");
                        _gameOutputWindow?.AppendLog($"[LaunchAbort] Fabric API missing for {version}. LastInstallError={_lastFabricApiInstallError ?? "<none>"}", "ERROR");
                        _isLaunching = false;
                        return;
                    }

                    ShowProgress(false);
                }

                SyncLauncherManagedMods(version);

                if (_currentSettings != null && _currentSettings.EnableModMigrationCheck)
                {
                    try
                    {
                        var migrationOutcome = await RunModMigrationCheckBeforeLaunchAsync(version);
                        if (migrationOutcome == ModMigrationOutcome.Cancel)
                        {
                            ShowProgress(false);
                            UpdateLaunchButton("LAUNCH GAME", "SeaGreen");
                            _isLaunching = false;
                            _gameOutputWindow?.AppendLog("[ModMigration] User cancelled launch.", "INFO");
                            return;
                        }
                    }
                    catch (Exception ex)
                    {
                        _gameOutputWindow?.AppendLog($"[ModMigration] Skipped due to error: {ex.Message}", "WARN");
                    }
                }

                if (_currentSettings != null && _currentSettings.EnablePreLaunchCheck)
                {
                    try
                    {
                        var preLaunchDecision = await RunPreLaunchCompatibilityCheckAsync(version);
                        if (preLaunchDecision == PreLaunchCheckDecision.Cancel)
                        {
                            ShowProgress(false);
                            UpdateLaunchButton("LAUNCH GAME", "SeaGreen");
                            _isLaunching = false;
                            _gameOutputWindow?.AppendLog("[PreLaunchCheck] User cancelled launch.", "INFO");
                            return;
                        }
                    }
                    catch (Exception ex)
                    {
                        _gameOutputWindow?.AppendLog($"[PreLaunchCheck] Skipped due to error: {ex.Message}", "WARN");
                    }
                }

                try
                {
                    string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                    if (Directory.Exists(modsFolder))
                    {
                        var rogueLeafJars = Directory.GetFiles(modsFolder, "*.jar", SearchOption.TopDirectoryOnly)
                            .Concat(Directory.GetFiles(modsFolder, "*.jar.disabled", SearchOption.TopDirectoryOnly))
                            .Where(p =>
                            {
                                var n = System.IO.Path.GetFileName(p);
                                return n.StartsWith("leafclient", StringComparison.OrdinalIgnoreCase) ||
                                       n.StartsWith("leaf-", StringComparison.OrdinalIgnoreCase) ||
                                       n.Equals("leaf.jar", StringComparison.OrdinalIgnoreCase);
                            })
                            .ToList();
                        foreach (var rogue in rogueLeafJars)
                        {
                            try
                            {
                                File.Delete(rogue);
                                _gameOutputWindow?.AppendLog(
                                    $"[LaunchDiag] Deleted rogue leaf jar from mods folder: {System.IO.Path.GetFileName(rogue)}",
                                    "WARN");
                            }
                            catch (Exception ex)
                            {
                                _gameOutputWindow?.AppendLog(
                                    $"[LaunchDiag] FAILED to delete rogue leaf jar '{System.IO.Path.GetFileName(rogue)}': {ex.Message}",
                                    "ERROR");
                            }
                        }
                    }
                }
                catch (Exception ex)
                {
                    _gameOutputWindow?.AppendLog($"[LaunchDiag] Rogue leaf jar sweep failed: {ex.Message}", "ERROR");
                }

                try
                {
                    var backend = GetActiveRenderBackend();
                    _gameOutputWindow?.AppendLog($"[RenderBackend] Resolved active backend: {backend} (from active profile RenderEngine)", "INFO");

                    string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                    if (Directory.Exists(modsFolder))
                    {
                        string[] toRemovePrefixes;
                        string reason;
                        switch (backend)
                        {
                            case RenderBackend.VulkanMod:
                                toRemovePrefixes = new[] { "sodium-", "sodium-fabric-", "sodiumextra-", "sodium-extra-", "reeses-sodium-options-", "reeses-sodium-", "indium-", "iris-", "immediatelyfast-" };
                                reason = "VulkanMod is incompatible with Sodium-family mods";
                                break;
                            case RenderBackend.Sodium:
                                toRemovePrefixes = new[] { "vulkanmod-" };
                                reason = "Sodium is incompatible with VulkanMod";
                                break;
                            default:
                                toRemovePrefixes = new[] { "vulkanmod-", "sodium-", "sodium-fabric-", "sodiumextra-", "sodium-extra-", "reeses-sodium-options-", "reeses-sodium-", "indium-", "iris-" };
                                reason = "No render backend selected; clearing all render-axis mods";
                                break;
                        }

                        int deletedCount = 0;
                        foreach (var f in Directory.GetFiles(modsFolder, "*.jar"))
                        {
                            string fn = System.IO.Path.GetFileName(f).ToLowerInvariant();
                            bool match = false;
                            foreach (var p in toRemovePrefixes)
                            {
                                if (fn.StartsWith(p)) { match = true; break; }
                            }
                            if (!match) continue;
                            try
                            {
                                File.Delete(f);
                                deletedCount++;
                                _gameOutputWindow?.AppendLog($"[RenderBackend] Pre-launch delete: {System.IO.Path.GetFileName(f)} - reason: {reason}", "WARN");
                            }
                            catch (Exception delEx)
                            {
                                _gameOutputWindow?.AppendLog($"[RenderBackend] Failed to delete {System.IO.Path.GetFileName(f)}: {delEx.Message}", "ERROR");
                            }
                        }

                        if (deletedCount == 0)
                            _gameOutputWindow?.AppendLog($"[RenderBackend] Pre-launch sweep: nothing to remove for backend {backend}", "INFO");
                        else
                            _gameOutputWindow?.AppendLog($"[RenderBackend] Pre-launch sweep removed {deletedCount} jar(s) incompatible with backend {backend}", "WARN");
                    }
                }
                catch (Exception ex)
                {
                    _gameOutputWindow?.AppendLog($"[RenderBackend] Pre-launch cleanup failed: {ex.Message}", "ERROR");
                }

                if (leafSupported)
                    LogLaunchPreLaunchDiagnostics(leafModPath);

                var jvmArguments = new List<MArgument>
        {
            new($"-Dleaf.testmode={(_currentSettings.IsTestMode ? "true" : "false")}"),
            new("-XX:+UnlockExperimentalVMOptions"),
            new("-XX:+UseG1GC"),
            new("-XX:MaxGCPauseMillis=130"),
            new("-XX:G1NewSizePercent=30"),
            new("-XX:G1MaxNewSizePercent=40"),
            new("-XX:G1HeapRegionSize=8M"),
            new("-XX:G1ReservePercent=20"),
            new("-XX:+AlwaysPreTouch"),
            new("-XX:AllocatePrefetchStyle=1"),
            new("-XX:+DisableExplicitGC"),
        };

                if (leafSupported)
                {
                    jvmArguments.Insert(0, new MArgument($"-Dfabric.addMods={leafModPath}"));
                    jvmArguments.Insert(0, new MArgument("-Dleaf.version=1.6.0"));
                    jvmArguments.Insert(0, new MArgument("-Dleaf.client=true"));
                    string accountTypeArg = _currentSettings.AccountType == "microsoft" ? "premium"
                        : _currentSettings.AccountType == "offline" ? "offline"
                        : "";
                    if (!string.IsNullOrEmpty(accountTypeArg))
                    {
                        jvmArguments.Insert(0, new MArgument($"-Dleaf.account_type={accountTypeArg}"));
                    }
                    if (!string.IsNullOrEmpty(_currentSettings.LeafApiJwt))
                    {
                        string? sessionFile = WriteSessionJwtFile(_currentSettings.LeafApiJwt);
                        if (!string.IsNullOrEmpty(sessionFile))
                        {
                            jvmArguments.Insert(0, new MArgument($"-Dleaf.api_jwt_file={sessionFile}"));
                        }
                    }
                }

                if (OperatingSystem.IsMacOS())
                {
                    jvmArguments.Insert(0, new MArgument("-XstartOnFirstThread"));
                }

                jvmArguments.Insert(0, new MArgument("-Xss2M"));
                jvmArguments.Insert(0, new MArgument("-Dorg.lwjgl.system.stackSize=512"));
                LeafClient.Services.LeafLog.Info("Launch", $"Injected -Xss2M and -Dorg.lwjgl.system.stackSize=512 for MC {version} (VulkanMod LWJGL MemoryStack overflow workaround for dual-GPU systems).");
                _gameOutputWindow?.AppendLog($"[Launch] -Xss2M + LWJGL stackSize=512KB applied for {version} (VulkanMod dual-GPU safety)", "INFO");

                if (OperatingSystem.IsLinux())
                {
                    var systemGlfw = FindSystemGlfwLibrary();
                    string userExtra = GetEffectiveExtraJvmArgs() ?? "";
                    bool userAlreadySet =
                        userExtra.IndexOf("-Dorg.lwjgl.glfw.libname", StringComparison.OrdinalIgnoreCase) >= 0
                        || userExtra.IndexOf("-Dorg.lwjgl.librarypath", StringComparison.OrdinalIgnoreCase) >= 0;
                    if (systemGlfw != null && !userAlreadySet)
                    {
                        jvmArguments.Add(new MArgument($"-Dorg.lwjgl.glfw.libname={systemGlfw}"));
                        LeafClient.Services.LeafLog.Info("GLFW", $"Linux: using system GLFW at {systemGlfw}");
                        _gameOutputWindow?.AppendLog($"[GLFW] Linux: using system GLFW at {systemGlfw} (avoids GLXBadFBConfig on newer Mesa)", "INFO");
                    }
                    else if (systemGlfw == null)
                    {
                        LeafLog.Info("GLFW", "Linux: no system libglfw.so found in standard paths - using bundled LWJGL native");
                        _gameOutputWindow?.AppendLog("[GLFW] No system libglfw.so found - using bundled LWJGL native", "INFO");
                    }
                }

                var effectiveExtraJvmArgs = GetEffectiveExtraJvmArgs();
                if (!string.IsNullOrWhiteSpace(effectiveExtraJvmArgs))
                {
                    var customArgs = effectiveExtraJvmArgs.Split(' ', StringSplitOptions.RemoveEmptyEntries);
                    foreach (var arg in customArgs)
                        jvmArguments.Add(new MArgument(arg));
                }

                try
                {
                    _gameOutputWindow?.AppendLog($"[LaunchDiag] ===== FINAL JVM ARGS ({jvmArguments.Count}) =====", "INFO");
                    for (int i = 0; i < jvmArguments.Count; i++)
                    {
                        _gameOutputWindow?.AppendLog($"[LaunchDiag]   [{i}] {RenderMArgumentRedacted(jvmArguments[i])}", "INFO");
                    }
                    _gameOutputWindow?.AppendLog("[LaunchDiag] ===== END FINAL JVM ARGS =====", "INFO");
                }
                catch (Exception ex)
                {
                    _gameOutputWindow?.AppendLog($"[LaunchDiag] Failed to dump JVM args: {ex.GetType().Name}: {ex.Message}", "ERROR");
                }

                if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
                {
                    jvmArguments.Add(new MArgument("-Doshi.util.wmi.timeout=3000"));
                    jvmArguments.Add(new MArgument("-Doshi.os.windows.loadaverage=false"));
                }

                if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
                {
                    LogHealthEvent("prelaunch_probe_begin");
                    bool wmiOk = await ProbeWmiHealthAsync();
                    LogHealthEvent(wmiOk ? "prelaunch_probe_ok" : "prelaunch_probe_failed");
                    if (!wmiOk)
                    {
                        _gameOutputWindow?.AppendLog("[LaunchDiag] WMI health probe FAILED - proceeding anyway (oshi mitigations applied).", "WARN");
                    }
                }

                var (resUseCustom, resWidth, resHeight) = GetEffectiveResolution();
                var (qjAddress, qjPort) = GetEffectiveQuickJoin();
                if (RunningInstanceCount > 0)
                {
                    qjAddress = null;
                }

                var launchOption = new MLaunchOption
                {
                    Session = _session,
                    MaximumRamMb = GetEffectiveMaxRamMb(),
                    MinimumRamMb = GetEffectiveMinRamMb(),
                    JvmArgumentOverrides = jvmArguments,
                    ScreenHeight = resUseCustom ? resHeight : 0,
                    ScreenWidth  = resUseCustom ? resWidth  : 0,
                    ServerIp     = qjAddress,
                    ServerPort   = qjPort,
                };

                UpdateLaunchButton("LAUNCHING...", "SeaGreen");
                ShowProgress(false);

                ForceVulkanModNvidiaDevice();

                if (!OperatingSystem.IsWindows())
                {
                    try
                    {
                        LeafClient.Services.JreManager.EnsureRuntimeExecutableBits(_minecraftFolder);
                        _gameOutputWindow?.AppendLog("[LaunchDiag] Ensured runtime executable bits for JRE.", "INFO");
                    }
                    catch (Exception jreEx)
                    {
                        _gameOutputWindow?.AppendLog($"[LaunchDiag] JreManager.EnsureRuntimeExecutableBits failed: {jreEx.Message}", "WARN");
                    }
                }

                try
                {
                    string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                    int javaMajor = ResolveActiveJavaMajor();
                    _gameOutputWindow?.AppendLog($"[ModCompat] Pre-launch filter starting for MC '{_currentSettings.SelectedSubVersion}' (java={javaMajor}) folder='{modsFolder}'", "INFO");

                    var filterReport = await LeafClient.Services.ModCompatFilter.FilterAndRenameAsync(
                        modsFolder, _currentSettings.SelectedSubVersion ?? "", javaMajor);

                    if (filterReport.Restored.Count > 0)
                        _gameOutputWindow?.AppendLog($"[ModCompat] Restored {filterReport.Restored.Count} previously-disabled jar(s).", "INFO");

                    if (filterReport.Disabled.Count > 0)
                    {
                        _gameOutputWindow?.AppendLog($"[ModCompat] Disabled {filterReport.Disabled.Count} incompatible jar(s) for this launch:", "WARN");
                        foreach (var d in filterReport.Disabled)
                            _gameOutputWindow?.AppendLog($"[ModCompat]   {d.OriginalFileName} - {d.Reason}", "WARN");
                    }
                    else
                    {
                        _gameOutputWindow?.AppendLog("[ModCompat] No incompatible jars detected.", "INFO");
                    }
                }
                catch (Exception filterEx)
                {
                    _gameOutputWindow?.AppendLog($"[ModCompat] Pre-launch filter EXCEPTION: {filterEx.GetType().Name}: {filterEx.Message}", "ERROR");
                    LeafClient.Services.LeafLog.Warn("ModCompatFilter", $"Pre-launch filter failed: {filterEx.Message}");
                }

                var process = await _launcher.CreateProcessAsync(versionToLaunch, launchOption);

                ForceHighPerformanceGpu(process);

                process.StartInfo.UseShellExecute = false;
                process.StartInfo.RedirectStandardOutput = true;
                process.StartInfo.RedirectStandardError = true;
                process.StartInfo.CreateNoWindow = true;

                try
                {
                    LeafClient.Services.LeafLog.Info("Launch/Process", $"javaExe={process.StartInfo.FileName}");
                    LeafClient.Services.LeafLog.Info("Launch/Process", $"workingDir={process.StartInfo.WorkingDirectory}");
                    var sanitizedArgs = (process.StartInfo.Arguments ?? "");
                    foreach (var redact in new[] { _session?.AccessToken, _currentSettings?.SessionAccessToken, _currentSettings?.LeafApiJwt })
                    {
                        if (!string.IsNullOrEmpty(redact)) sanitizedArgs = sanitizedArgs.Replace(redact, "<REDACTED>");
                    }
                    LeafClient.Services.LeafLog.Info("Launch/Process", $"args.length={sanitizedArgs.Length}");
                    LeafClient.Services.LeafLog.Info("Launch/Process", $"args={sanitizedArgs}");
                }
                catch (Exception ex) { LeafClient.Services.LeafLog.Error("Launch/Process", $"arg log failed: {ex.Message}"); }
                process.EnableRaisingEvents = true;
                process.Exited += OnGameExited;

                var launchVersionInfo = _allVersions.FirstOrDefault(v => v.FullVersion == _currentSettings.SelectedSubVersion);
                _leafModExpected = leafSupported && launchVersionInfo?.IsLeafClientModSupported == true;
                _leafModLoaded = false;
                _lastLaunchVersion = _currentSettings.SelectedSubVersion;

                process.OutputDataReceived += (s, e) =>
                {
                    if (string.IsNullOrEmpty(e.Data)) return;
                    _gameOutputWindow?.AppendLog(e.Data, "INFO");
                    LeafClient.Services.LeafLog.Info("Game", $"{e.Data}");
                    if (_leafModExpected && !_leafModLoaded &&
                        (e.Data.Contains("leafclient", StringComparison.OrdinalIgnoreCase) &&
                         (e.Data.Contains("loaded", StringComparison.OrdinalIgnoreCase) ||
                          e.Data.Contains("initialized", StringComparison.OrdinalIgnoreCase) ||
                          e.Data.Contains("onInitialize", StringComparison.OrdinalIgnoreCase))))
                    {
                        _leafModLoaded = true;
                        LeafLog.Info("Launch", "Leaf Client mod successfully loaded.");
                    }
                };
                process.ErrorDataReceived += (s, e) =>
                {
                    if (string.IsNullOrEmpty(e.Data)) return;
                    _gameOutputWindow?.AppendLog(e.Data, "ERROR");
                    LeafLog.Error("GameErr", $"{e.Data}");
                    if (_leafModExpected && !_leafModLoaded &&
                        (e.Data.Contains("leafclient", StringComparison.OrdinalIgnoreCase) &&
                         (e.Data.Contains("loaded", StringComparison.OrdinalIgnoreCase) ||
                          e.Data.Contains("initialized", StringComparison.OrdinalIgnoreCase) ||
                          e.Data.Contains("onInitialize", StringComparison.OrdinalIgnoreCase))))
                    {
                        _leafModLoaded = true;
                        LeafLog.Info("Launch", "Leaf Client mod successfully loaded (from stderr).");
                    }
                };

                process.Start();
                try { process.PriorityClass = System.Diagnostics.ProcessPriorityClass.High; } catch { }
                process.BeginOutputReadLine();
                process.BeginErrorReadLine();
                _gameProcess = process;
                RegisterRunningInstance(process);
                try { _launchPrepSemaphore.Release(); } catch { }

                try { _ingameHeartbeat?.Start(_session?.Username ?? _currentSettings?.SessionUsername ?? ""); } catch { }

                try { if (_drp.IsInitialized) _drp.ClearPresence(); } catch { }

                _sessionStartUtc = DateTime.UtcNow;
                _sessionReportedMinutes = 0;
                _lastLocalPlaytimeCheckpointUtc = DateTime.UtcNow;
                StartGameplayPlaytimePolling();
                if (_currentSettings != null)
                {
                    _currentSettings.LastLaunchTime  = DateTime.Now;
                    _currentSettings.TotalLaunchCount++;

                    var mcVer = _currentSettings.SelectedSubVersion;
                    if (!string.IsNullOrEmpty(mcVer))
                    {
                        _currentSettings.LaunchCountByVersion.TryGetValue(mcVer, out int lc);
                        _currentSettings.LaunchCountByVersion[mcVer] = lc + 1;
                    }

                    var activeProfile = GetActiveProfile();
                    if (activeProfile != null)
                    {
                        activeProfile.LaunchCount++;
                        activeProfile.LastUsed = DateTime.Now;
                    }

                    try { _ = _settingsService.SaveSettingsAsync(_currentSettings); } catch { }
                }

                _ = Task.Delay(1200).ContinueWith(_ => Dispatcher.UIThread.Post(HideLaunchAnimation));

                _isLaunching = false;
                UpdateLaunchButton("LAUNCH GAME", "SeaGreen");
                await UpdateServerButtonStates();

                if (_currentSettings.LauncherVisibilityOnGameLaunch == LauncherVisibility.Hide)
                {
                    Dispatcher.UIThread.Post(() =>
                    {
                        MinimizeToTray();
                        NotificationWindow.Show("Game Starting", "Launcher hidden while game runs", "Restore", () => RestoreFromTray());
                    });
                }
            }
            catch (OperationCanceledException)
            {
                HideLaunchAnimation();
                _isLaunching = false;
                ShowProgress(false);
                UpdateLaunchButton("LAUNCH GAME", "SeaGreen");
                await UpdateServerButtonStates();
            }
            catch (Exception ex)
            {
                Console.Error.WriteLine($"Launch Error: {ex}");
                HideLaunchAnimation();
                UpdateLaunchButton("LAUNCH FAILED", "Red");
                ShowLaunchErrorBanner(ex.Message);
                _isLaunching = false;
                ShowProgress(false);
                await UpdateServerButtonStates();

                _ = Task.Delay(3000).ContinueWith(_ => Dispatcher.UIThread.Post(() => UpdateLaunchButton("LAUNCH GAME", "SeaGreen")));
            }
            finally
            {
                _launchCancellationTokenSource?.Dispose();
                _launchCancellationTokenSource = null;
                if (_launchPrepSemaphore.CurrentCount == 0) { try { _launchPrepSemaphore.Release(); } catch { } }
            }
        }

        private async Task ManageOptiFineForFabricMods(string mcVersion, bool enable)
        {
            string[] optifineModNames = new[] {
                "optifine", "optifabric", "modmenu", "sodium", "iris", "lithium", "starlight"
            };

            var relevantMods = _currentSettings.InstalledMods
                .Where(m => m.MinecraftVersion.Equals(mcVersion, StringComparison.OrdinalIgnoreCase) &&
                            optifineModNames.Any(name => m.Name.Contains(name, StringComparison.OrdinalIgnoreCase)))
                .ToList();

            bool settingsChanged = false;
            foreach (var mod in relevantMods)
            {
                if (mod.Enabled != enable)
                {
                    mod.Enabled = enable;
                    settingsChanged = true;
                    LeafClient.Services.LeafLog.Info("OptiFineForFabric", $"Setting '{mod.Name}' to enabled={enable} in settings.");
                }
            }

            if (settingsChanged)
            {
                await _settingsService.SaveSettingsAsync(_currentSettings);
            }
        }

        private void UpdateSidebarDetails(string subVersion)
        {
            var versionInfo = _allVersions.FirstOrDefault(v => v.FullVersion == subVersion);
            if (versionInfo != null)
            {
                if (_versionType != null) _versionType.Text = versionInfo.Type;
                if (_versionLoader != null) _versionLoader.Text = versionInfo.Loader;
                if (_versionDate != null) _versionDate.Text = versionInfo.ReleaseDate;

                if (_versionDescription != null)
                {
                    _versionDescription.Text = versionInfo.Description;
                }
            }
            else
            {
                if (_versionType != null) _versionType.Text = "N/A";
                if (_versionLoader != null) _versionLoader.Text = "N/A";
                if (_versionDate != null) _versionDate.Text = "N/A";
                if (_versionDescription != null) _versionDescription.Text = "Details not available.";
            }
        }

        private int ResolveActiveJavaMajor()
        {
            try
            {
                var p = GetActiveProfile();
                if (!string.IsNullOrEmpty(p?.CustomJavaPath))
                {
                    int probed = ProbeJavaExeMajor(p.CustomJavaPath);
                    if (probed > 0) return probed;
                }
                string versionId = _currentSettings?.SelectedSubVersion ?? "";
                if (string.IsNullOrEmpty(versionId)) return 0;
                string versionJsonPath = System.IO.Path.Combine(_minecraftFolder, "versions", versionId, $"{versionId}.json");
                if (!File.Exists(versionJsonPath)) return 0;
                using var doc = JsonDocument.Parse(File.ReadAllText(versionJsonPath));
                if (doc.RootElement.TryGetProperty("javaVersion", out var jv)
                    && jv.TryGetProperty("majorVersion", out var mv)
                    && mv.ValueKind == JsonValueKind.Number)
                {
                    return mv.GetInt32();
                }
                return 0;
            }
            catch { return 0; }
        }

        private static int ProbeJavaExeMajor(string javaExePath)
        {
            try
            {
                if (string.IsNullOrEmpty(javaExePath)) return 0;
                if (!File.Exists(javaExePath)) return 0;
                using var p = new Process
                {
                    StartInfo = new ProcessStartInfo
                    {
                        FileName = javaExePath,
                        Arguments = "-version",
                        UseShellExecute = false,
                        RedirectStandardError = true,
                        CreateNoWindow = true,
                    }
                };
                p.Start();
                string err = p.StandardError.ReadToEnd();
                p.WaitForExit(2000);
                var m = System.Text.RegularExpressions.Regex.Match(err, "version \"([0-9]+)(?:\\.([0-9]+))?");
                if (m.Success)
                {
                    int a = int.Parse(m.Groups[1].Value);
                    return a == 1 && m.Groups[2].Success ? int.Parse(m.Groups[2].Value) : a;
                }
                return 0;
            }
            catch { return 0; }
        }

        private void OnGameExited(object? sender, EventArgs e)
        {
            Process? exitingProcess = sender as Process;
            bool wasLastInstance = !AnyGameRunning;

            try { Dispatcher.UIThread.Post(UpdateInstancesPill); } catch { }

            try
            {
                string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                int restored = LeafClient.Services.ModCompatFilter.RestoreAll(modsFolder);
                if (restored > 0)
                    LeafClient.Services.LeafLog.Info("ModCompatFilter", $"Restored {restored} compat-disabled jar(s) after game exit.");
            }
            catch (Exception restoreEx)
            {
                LeafClient.Services.LeafLog.Warn("ModCompatFilter", $"Post-exit restore failed: {restoreEx.Message}");
            }

            if (!wasLastInstance)
            {
                LeafClient.Services.LeafLog.Info("Launcher", $"One MC instance exited but {RunningInstanceCount} instance(s) still running - skipping session-end UI work.");
                return;
            }

            try { _ingameHeartbeat?.Stop(); } catch { }

            StopGameplayPlaytimePolling();

            DateTime? sessionStartCopy = _sessionStartUtc;

            try
            {
                if (sessionStartCopy.HasValue && _currentSettings != null)
                {
                    long sessionSeconds = (long)(DateTime.UtcNow - sessionStartCopy.Value).TotalSeconds;
                    if (sessionSeconds < 0) sessionSeconds = 0;
                    if (sessionSeconds > 86400) sessionSeconds = 86400;

                    long checkpointBaseSeconds = _lastLocalPlaytimeCheckpointUtc.HasValue
                        ? (long)(DateTime.UtcNow - _lastLocalPlaytimeCheckpointUtc.Value).TotalSeconds
                        : sessionSeconds;
                    if (checkpointBaseSeconds < 0) checkpointBaseSeconds = 0;
                    if (checkpointBaseSeconds > 86400) checkpointBaseSeconds = 86400;

                    _currentSettings.CurrentSessionSeconds = sessionSeconds;
                    _currentSettings.TotalPlaytimeSeconds += checkpointBaseSeconds;
                    _currentSettings.LastExitTime = DateTime.Now;

                    var mcVersion = _currentSettings.SelectedSubVersion;
                    if (!string.IsNullOrEmpty(mcVersion))
                    {
                        _currentSettings.PlaytimeByVersion.TryGetValue(mcVersion, out long cur);
                        _currentSettings.PlaytimeByVersion[mcVersion] = cur + checkpointBaseSeconds;
                    }

                    var server = _currentSettings.QuickJoinServerAddress;
                    if (!string.IsNullOrEmpty(server))
                    {
                        _currentSettings.PlaytimeByServer.TryGetValue(server, out long curS);
                        _currentSettings.PlaytimeByServer[server] = curS + checkpointBaseSeconds;
                    }

                    var activeProfile = GetActiveProfile();
                    if (activeProfile != null)
                    {
                        activeProfile.PlaytimeSeconds += checkpointBaseSeconds;
                    }

                    _sessionStartUtc = null;
                    _lastLocalPlaytimeCheckpointUtc = null;
                    int finalTotalMinutes = (int)(sessionSeconds / 60);
                    int unreportedMinutes = finalTotalMinutes - _sessionReportedMinutes;
                    _sessionReportedMinutes = 0;
                    _ = _settingsService.SaveSettingsAsync(_currentSettings);
                    LeafClient.Services.LeafLog.Info("Playtime", $"Session: {sessionSeconds}s, total: {_currentSettings.TotalPlaytimeSeconds}s");

                    if (unreportedMinutes >= 1)
                    {
                        var jwt = _currentSettings.LeafApiJwt;
                        if (!string.IsNullOrEmpty(jwt))
                        {
                            _ = Task.Run(async () =>
                            {
                                try
                                {
                                    await LeafClient.Services.LeafApiService.SendHeartbeatAsync(jwt);
                                    var result = await LeafClient.Services.LeafApiService.ReportPlaytimeAsync(jwt, unreportedMinutes);
                                    if (result != null && result.Awarded > 0)
                                    {
                                        _currentCoinBalance = result.Coins;
                                        Dispatcher.UIThread.Post(() =>
                                        {
                                            _leafsBalanceText ??= this.FindControl<TextBlock>("LeafsBalanceText");
                                            if (_leafsBalanceText != null)
                                                _leafsBalanceText.Text = result.Coins.ToString("N0");
                                        });
                                        ToastService.Show($"+{result.Awarded} \U0001F343 Leaf Points earned!", ToastType.Success);
                                    }
                                }
                                catch (Exception apiEx)
                                {
                                    LeafClient.Services.LeafLog.Error("Playtime", $"Final API claim failed: {apiEx.Message}");
                                }
                            });
                        }
                    }

                    Dispatcher.UIThread.Post(RefreshPlaytimeStatsCard);
                }
            }
            catch (Exception ex)
            {
                LeafLog.Error("Playtime", $"Failed to record session: {ex.Message}");
            }

            Dispatcher.UIThread.Post(async () =>
            {
                if (_isShuttingDown) return;
                string logoutSignalPath = System.IO.Path.Combine(_minecraftFolder, "logout.signal");
                if (System.IO.File.Exists(logoutSignalPath))
                {
                    try
                    {
                        System.IO.File.Delete(logoutSignalPath);
                        LeafLog.Info("Launcher", "Logout signal detected from game. Performing logout...");

                        LogoutButton_Click(null, new RoutedEventArgs());
                        return;
                    }
                    catch (Exception ex)
                    {
                        LeafLog.Error("Launcher", $"Error processing logout signal: {ex.Message}");
                    }
                }

                int exitCode = -1;
                try { exitCode = exitingProcess?.ExitCode ?? _gameProcess?.ExitCode ?? -1; } catch { }
                _gameOutputWindow?.AppendLog($"Game exited with code {exitCode}.", exitCode == 0 ? "INFO" : "ERROR");
                try { _gameOutputWindow?.MarkSessionEnded(exitCode); } catch (Exception markEx) { LeafLog.Error("GameOutput", $"MarkSessionEnded failed: {markEx.Message}"); }

                if (exitCode != 0 && _leafModExpected && !_leafModLoaded && !_autoRestartAttempted && !_userTerminatedGame && !AnyGameRunning)
                {
                    LeafLog.Error("Launch", "Leaf Client mod failed to load. Auto-restarting...");
                    _gameOutputWindow?.AppendLog("Leaf Client mod did not load. Auto-restarting game...", "WARN");
                    _autoRestartAttempted = true;
                    _gameProcess = null;
                    _isLaunching = false;

                    await Task.Delay(1500);
                    UpdateLaunchButton("RESTARTING...", "Orange");
                    _ = LaunchGameAsync(_lastLaunchVersion ?? _currentSettings.SelectedSubVersion, true);
                    return;
                }
                _autoRestartAttempted = false;

                if (exitCode != 0)
                {
                    LeafLog.Error("Launcher", $"Game process exited with error code: {exitCode}");

                    if (!_userTerminatedGame)
                    {
                        bool postmortemShown = false;
                        try
                        {
                            postmortemShown = TryShowCrashPostmortem();
                        }
                        catch (Exception pmEx)
                        {
                            LeafLog.Error("CrashPostmortem", $"failed: {pmEx.Message}");
                        }

                        if (!postmortemShown)
                        {
                            if (!this.IsVisible)
                            {
                                RestoreFromTray();
                                NotificationWindow.Show("Launch Failed", "Game exited unexpectedly.", "View Logs", () => OpenLauncherLogsFolder(null, new RoutedEventArgs()), true);
                            }
                            else
                            {
                                ShowLaunchFailureBanner("Failed to launch Minecraft. Please check logs.");
                            }
                        }

                        UpdateLaunchButton("LAUNCH FAILED", "Red");

                        _ = Task.Run(async () =>
                        {
                            await Task.Delay(5000);
                            await Dispatcher.UIThread.InvokeAsync(() =>
                            {
                                if (!_isLaunching && !_isInstalling && _gameProcess == null)
                                {
                                    UpdateLaunchButton("LAUNCH GAME", "SeaGreen");
                                    HideLaunchFailureBanner();
                                }
                            });
                        });
                    }
                }
                else
                {
                    if (_leafModExpected && !_leafModLoaded && !_autoRestartAttempted && !_userTerminatedGame && !AnyGameRunning)
                    {
                        LeafLog.Info("Launch", "Game exited cleanly but Leaf Client mod was not detected. Auto-restarting...");
                        _gameOutputWindow?.AppendLog("Leaf Client mod was not detected. Auto-restarting game...", "WARN");
                        _autoRestartAttempted = true;
                        _gameProcess = null;
                        _isLaunching = false;

                        await Task.Delay(1500);
                        UpdateLaunchButton("RESTARTING...", "Orange");
                        _ = LaunchGameAsync(_lastLaunchVersion ?? _currentSettings.SelectedSubVersion, true);
                        return;
                    }
                    _autoRestartAttempted = false;

                    UpdateLaunchButton("LAUNCH GAME", "SeaGreen");
                    HideLaunchFailureBanner();
                }

                _ = Task.Run(async () =>
                {
                    try { await ReportSessionPlaytimeAsync(); } catch (Exception ex) { LeafClient.Services.LeafLog.Info("PlaytimeReport", $"{ex.Message}"); }
                });

                _gameProcess = null;
                _isLaunching = false;
                _isInstalling = false;
                _gameStartingBannerShownForCurrentLaunch = false;

                if (!AnyGameRunning) _runningInstancesVersion = null;
                UpdateInstancesPill();

                _ = Task.Run(() => { try { StartRichPresenceIfEnabled(); } catch (Exception drpEx) { LeafClient.Services.LeafLog.Error("DRP", $"Failed to restore launcher presence after game exit: {drpEx.Message}"); } });

                await UpdateServerButtonStates();
                HideGameStartingBanner();
                HideLaunchAnimation();

                if (_currentSettings.LockGameAspectRatio)
                {
                    try
                    {
                        await Task.Delay(1000);

                        string optionsPath = System.IO.Path.Combine(_minecraftFolder, "options.txt");
                        if (System.IO.File.Exists(optionsPath))
                        {
                            var lines = await System.IO.File.ReadAllLinesAsync(optionsPath);
                            int? width = null;
                            int? height = null;

                            foreach (var line in lines)
                            {
                                if (line.StartsWith("overrideWidth:"))
                                {
                                    if (int.TryParse(line.Split(':')[1], out int w))
                                        width = w;
                                }
                                else if (line.StartsWith("overrideHeight:"))
                                {
                                    if (int.TryParse(line.Split(':')[1], out int h))
                                        height = h;
                                }
                            }

                            if (width.HasValue && height.HasValue && width > 0 && height > 0)
                            {
                                LeafClient.Services.LeafLog.Info("Resolution Lock", $"Game closed with resolution: {width}x{height}");

                                _currentSettings.GameResolutionWidth = width.Value;
                                _currentSettings.GameResolutionHeight = height.Value;
                                await _settingsService.SaveSettingsAsync(_currentSettings);

                                if (_gameResolutionWidthTextBox != null)
                                    _gameResolutionWidthTextBox.Text = width.Value.ToString();
                                if (_gameResolutionHeightTextBox != null)
                                    _gameResolutionHeightTextBox.Text = height.Value.ToString();

                                LeafClient.Services.LeafLog.Info("Resolution Lock", $"Saved new resolution: {width}x{height}");
                            }
                        }
                    }
                    catch (Exception ex)
                    {
                        LeafLog.Error("Resolution Lock", $"Failed to read game resolution: {ex.Message}");
                    }
                }

                if (!this.IsVisible)
                {
                    LeafLog.Info("Launch", "Game closed - restoring launcher from tray");
                    RestoreFromTray();
                }
            });
        }

        private int GetMaxRam()
        {
            if (_maxRamSlider != null)
                return (int)_maxRamSlider.Value;
            return 4096;
        }

        private int GetMinRam()
        {
            if (_minRamSlider != null)
                return (int)_minRamSlider.Value;
            return 1024;
        }

        private Models.LauncherProfile? GetActiveProfile()
        {
            if (_currentSettings?.Profiles == null || _currentSettings.Profiles.Count == 0)
                return null;
            return _currentSettings.Profiles.FirstOrDefault(p => p.Id == _currentSettings.ActiveProfileId)
                ?? _currentSettings.Profiles[0];
        }

        private int GetEffectiveMaxRamMb()
        {
            var profile = GetActiveProfile();
            int requested;
            if (profile != null && profile.AllocatedMemoryGb > 0)
                requested = (int)Math.Round(profile.AllocatedMemoryGb * 1024.0);
            else
                requested = GetMaxRam();

            try
            {
                long totalMb = GetTotalPhysicalMemoryMb();
                if (totalMb > 0)
                {
                    int safeCap = (int)Math.Max(2048, totalMb - 2560);
                    if (requested > safeCap)
                    {
                        LeafClient.Services.LeafLog.Info("Launcher", $"Capping requested heap {requested}MB to {safeCap}MB (system has {totalMb}MB; reserving 2.5GB for native).");
                        return safeCap;
                    }
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Info("Launcher", $"Could not query system RAM: {ex.Message}");
            }

            return requested;
        }

        [System.Runtime.InteropServices.StructLayout(System.Runtime.InteropServices.LayoutKind.Sequential, CharSet = System.Runtime.InteropServices.CharSet.Auto)]
        private struct MEMORYSTATUSEX
        {
            public uint dwLength;
            public uint dwMemoryLoad;
            public ulong ullTotalPhys;
            public ulong ullAvailPhys;
            public ulong ullTotalPageFile;
            public ulong ullAvailPageFile;
            public ulong ullTotalVirtual;
            public ulong ullAvailVirtual;
            public ulong ullAvailExtendedVirtual;
        }

        [System.Runtime.InteropServices.DllImport("kernel32.dll", CharSet = System.Runtime.InteropServices.CharSet.Auto, SetLastError = true)]
        [return: System.Runtime.InteropServices.MarshalAs(System.Runtime.InteropServices.UnmanagedType.Bool)]
        private static extern bool GlobalMemoryStatusEx(ref MEMORYSTATUSEX lpBuffer);

        private static long GetTotalPhysicalMemoryMb()
        {
            try
            {
                if (System.Runtime.InteropServices.RuntimeInformation.IsOSPlatform(System.Runtime.InteropServices.OSPlatform.Windows))
                {
                    var mem = new MEMORYSTATUSEX { dwLength = (uint)System.Runtime.InteropServices.Marshal.SizeOf<MEMORYSTATUSEX>() };
                    if (GlobalMemoryStatusEx(ref mem)) return (long)(mem.ullTotalPhys / (1024UL * 1024UL));
                    return 0;
                }
                if (System.Runtime.InteropServices.RuntimeInformation.IsOSPlatform(System.Runtime.InteropServices.OSPlatform.Linux))
                {
                    foreach (var line in System.IO.File.ReadAllLines("/proc/meminfo"))
                    {
                        if (line.StartsWith("MemTotal:", StringComparison.Ordinal))
                        {
                            var parts = line.Split(new[] { ' ', '	' }, StringSplitOptions.RemoveEmptyEntries);
                            if (parts.Length >= 2 && long.TryParse(parts[1], out var kb)) return kb / 1024L;
                            break;
                        }
                    }
                    return 0;
                }
                if (System.Runtime.InteropServices.RuntimeInformation.IsOSPlatform(System.Runtime.InteropServices.OSPlatform.OSX))
                {
                    var psi = new System.Diagnostics.ProcessStartInfo("sysctl", "-n hw.memsize")
                    {
                        RedirectStandardOutput = true, UseShellExecute = false, CreateNoWindow = true
                    };
                    using var proc = System.Diagnostics.Process.Start(psi);
                    if (proc != null)
                    {
                        var output = proc.StandardOutput.ReadToEnd().Trim();
                        proc.WaitForExit(2000);
                        if (long.TryParse(output, out var bytes)) return bytes / (1024L * 1024L);
                    }
                    return 0;
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Info("Launcher", $"Could not query system RAM: {ex.Message}");
            }
            return 0;
        }

        private void ApplyRamSliderCaps()
        {
            try
            {
                long totalMb = GetTotalPhysicalMemoryMb();
                if (totalMb <= 0) return;

                long reserveMb = 2048;
                long capMb = Math.Max(1024, totalMb - reserveMb);
                double capGb = capMb / 1024.0;

                if (_minRamSlider != null)
                {
                    double newMax = Math.Min(_minRamSlider.Maximum, Math.Max(_minRamSlider.Minimum, capMb));
                    _minRamSlider.Maximum = newMax;
                    if (_minRamSlider.Value > newMax) _minRamSlider.Value = newMax;
                }
                if (_maxRamSlider != null)
                {
                    double newMax = Math.Min(_maxRamSlider.Maximum, Math.Max(_maxRamSlider.Minimum, capMb));
                    _maxRamSlider.Maximum = newMax;
                    if (_maxRamSlider.Value > newMax) _maxRamSlider.Value = newMax;
                }
                if (_po_MemSlider != null)
                {
                    double newMax = Math.Min(_po_MemSlider.Maximum, Math.Max(_po_MemSlider.Minimum, capGb));
                    _po_MemSlider.Maximum = newMax;
                    if (_po_MemSlider.Value > newMax) _po_MemSlider.Value = newMax;
                }
                LeafClient.Services.LeafLog.Info("Launcher", $"RAM sliders capped: system={totalMb}MB, reserve={reserveMb}MB, cap={capMb}MB ({capGb:0.##}GB).");
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Launcher", $"ApplyRamSliderCaps failed: {ex.Message}");
            }
        }

        private int GetEffectiveMinRamMb()
        {
            return GetMinRam();
        }

        private string GetEffectiveExtraJvmArgs()
        {
            var global = _currentSettings?.JvmArguments ?? "";
            var profile = GetActiveProfile();
            var overrideArgs = profile?.JvmArgumentsOverride ?? "";
            if (string.IsNullOrWhiteSpace(global))   return overrideArgs.Trim();
            if (string.IsNullOrWhiteSpace(overrideArgs)) return global.Trim();
            return (global.Trim() + " " + overrideArgs.Trim()).Trim();
        }

        private (bool useCustom, int width, int height) GetEffectiveResolution()
        {
            var profile = GetActiveProfile();
            if (profile?.UseCustomResolutionOverride == true)
            {
                return (
                    true,
                    profile.GameResolutionWidthOverride  ?? _currentSettings.GameResolutionWidth,
                    profile.GameResolutionHeightOverride ?? _currentSettings.GameResolutionHeight
                );
            }
            return (
                _currentSettings?.UseCustomGameResolution ?? false,
                _currentSettings?.GameResolutionWidth  ?? 1280,
                _currentSettings?.GameResolutionHeight ?? 720
            );
        }

        private (string? address, int port) GetEffectiveQuickJoin()
        {
            var profile = GetActiveProfile();
            if (profile != null && !string.IsNullOrWhiteSpace(profile.QuickJoinServerAddressOverride))
            {
                int.TryParse(profile.QuickJoinServerPortOverride ?? "25565", out int pOv);
                if (pOv <= 0) pOv = 25565;
                return (profile.QuickJoinServerAddressOverride, pOv);
            }

            if (_currentSettings?.QuickLaunchEnabled == true && !string.IsNullOrWhiteSpace(_currentSettings.QuickJoinServerAddress))
            {
                int.TryParse(_currentSettings.QuickJoinServerPort ?? "25565", out int p);
                if (p <= 0) p = 25565;
                return (_currentSettings.QuickJoinServerAddress, p);
            }

            return (null, 25565);
        }

        private Color DarkenColor(Color color, float factor)
        {
            factor = Math.Clamp(factor, 0f, 1f);

            byte r = (byte)Math.Max(0, color.R * (1f - factor));
            byte g = (byte)Math.Max(0, color.G * (1f - factor));
            byte b = (byte)Math.Max(0, color.B * (1f - factor));
            return Color.FromArgb(color.A, r, g, b);
        }

        private void UpdateLaunchButton(string text, string colorName)
        {
            _currentOperationText = text;
            _currentOperationColor = colorName;

            if (text == "LAUNCH GAME" || text.StartsWith("LAUNCH FAILED") || text == "SELECT VERSION" || text == "LOGIN REQUIRED" || text == "LAUNCH CANCELLED" || text == "YOU'RE OFFLINE" || text == "FABRIC INSTALL FAILED")
            {
                _isLaunching = false;
                _isInstalling = false;
            }

            ApplyLaunchButtonState();
        }

        private void ApplyLaunchButtonState()
        {
            if (this.FindControl<Button>("LaunchGameButton") is { } btn)
            {
                string displayText;
                string colorName;
                bool isButtonEnabled = true;
                bool isGameRunning = false;

                if (_cancelLaunchButton != null)
                {
                    _cancelLaunchButton.IsVisible = (_isLaunching || _isInstalling) && (_gameProcess == null || _gameProcess.HasExited);
                }

                if (_isLaunching || _isInstalling)
                {
                    displayText = _currentOperationText;
                    colorName = _currentOperationColor;
                    isButtonEnabled = true;
                    HideLaunchFailureBanner();
                }
                else if (!System.Net.NetworkInformation.NetworkInterface.GetIsNetworkAvailable())
                {
                    displayText = "YOU'RE OFFLINE";
                    colorName = "Gray";
                    isButtonEnabled = false;
                    HideLaunchFailureBanner();
                }
                else if (_currentOperationText == "LAUNCH CANCELLED" ||
                         _currentOperationText == "SELECT VERSION" ||
                         _currentOperationText == "LOGIN REQUIRED" ||
                         _currentOperationText == "FABRIC INSTALL FAILED" ||
                         _currentOperationText.StartsWith("LAUNCH FAILED"))
                {
                    displayText = _currentOperationText;
                    colorName = _currentOperationColor;
                    isButtonEnabled = true;

                    if (_currentOperationText.StartsWith("LAUNCH FAILED")) { }
                    else { HideLaunchFailureBanner(); }
                }
                else
                {
                    displayText = AnyGameRunning ? "LAUNCH ANOTHER INSTANCE" : "LAUNCH GAME";
                    colorName = "SeaGreen";
                    isButtonEnabled = true;
                    HideLaunchFailureBanner();
                }

                if (_gameWindowPendingText != null)
                {
                    _gameWindowPendingText.IsVisible = isGameRunning;
                }

                btn.IsEnabled = isButtonEnabled;

                Color baseColor = colorName switch
                {
                    "Purple" => Colors.Purple,
                    "OrangeRed" => Colors.OrangeRed,
                    "Firebrick" => Colors.Firebrick,
                    "Red" => Colors.Red,
                    "SeaGreen" => Color.FromRgb(50, 205, 50),
                    "DeepSkyBlue" => Colors.DeepSkyBlue,
                    "Gray" => Colors.Gray,
                    "Orange" => Colors.Orange,
                    _ => Colors.White
                };

                btn.Background = new SolidColorBrush(baseColor);
                _launchButtonGlowColor = baseColor;
                btn.Effect = BuildLaunchGlow(baseColor, _launchButtonHovered);

                if (this.FindControl<Border>("LaunchButtonOuterBorder") is { } outerBorder)
                {
                    Color borderColor = DarkenColor(baseColor, 0.2f);
                    outerBorder.BorderBrush = new SolidColorBrush(borderColor);
                    outerBorder.BorderThickness = new Thickness(1);
                }

                if (btn.Content is StackPanel contentStack && contentStack.Children.OfType<TextBlock>().FirstOrDefault() is TextBlock mainTextBlock)
                {
                    mainTextBlock.Text = displayText;
                }
                if (btn.Content is StackPanel contentStackWithSub && contentStackWithSub.Children.OfType<StackPanel>().FirstOrDefault() is StackPanel subStack && subStack.Children.OfType<TextBlock>().LastOrDefault() is TextBlock subTextBlock)
                {
                    subTextBlock.Text = _launchVersionText?.Text ?? "Leaf Client";
                }
            }
        }

        private static DropShadowEffect BuildLaunchGlow(Color baseColor, bool hovered)
        {
            byte hoverAlpha = 0xAA;
            byte idleAlpha = 0x2A;
            var glow = Color.FromArgb(hovered ? hoverAlpha : idleAlpha, baseColor.R, baseColor.G, baseColor.B);
            return new DropShadowEffect
            {
                BlurRadius = hovered ? 32 : 8,
                Color = glow,
                OffsetX = 0,
                OffsetY = hovered ? 8 : 0,
                Opacity = 1.0
            };
        }

        private static void WriteSessionJson(string? jwt)
        {
            try
            {
                var dir = System.IO.Path.Combine(
                    Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),
                    "LeafClient");
                Directory.CreateDirectory(dir);
                var path = System.IO.Path.Combine(dir, "session.json");
                var json = $"{{\"jwt\":\"{jwt ?? ""}\"}}";

                File.WriteAllText(path, json);
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Session", $"Failed to write session.json: {ex.Message}");
            }
        }

