        private static void WriteEquippedJson(EquippedCosmetics? eq, string? sub)
        {
            try
            {
                var dir = System.IO.Path.Combine(
                    Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),
                    "LeafClient");
                Directory.CreateDirectory(dir);
                var path = System.IO.Path.Combine(dir, "equipped.json");
                var snapshot = new EquippedCosmetics
                {
                    Sub = sub,
                    CapeId = eq?.CapeId,
                    HatId = eq?.HatId,
                    WingsId = eq?.WingsId,
                    BackItemId = eq?.BackItemId,
                    AuraId = eq?.AuraId,
                    FaceId = eq?.FaceId,
                    CapeVariant = eq?.CapeVariant, HatVariant = eq?.HatVariant, WingsVariant = eq?.WingsVariant, AuraVariant = eq?.AuraVariant, FaceVariant = eq?.FaceVariant,
                    CapeScale = eq?.CapeScale, HatScale = eq?.HatScale, WingsScale = eq?.WingsScale, AuraScale = eq?.AuraScale, FaceScale = eq?.FaceScale,
                    CapeOffsetX = eq?.CapeOffsetX, CapeOffsetY = eq?.CapeOffsetY, CapeOffsetZ = eq?.CapeOffsetZ,
                    HatOffsetX = eq?.HatOffsetX, HatOffsetY = eq?.HatOffsetY, HatOffsetZ = eq?.HatOffsetZ,
                    WingsOffsetX = eq?.WingsOffsetX, WingsOffsetY = eq?.WingsOffsetY, WingsOffsetZ = eq?.WingsOffsetZ,
                    AuraOffsetX = eq?.AuraOffsetX, AuraOffsetY = eq?.AuraOffsetY, AuraOffsetZ = eq?.AuraOffsetZ,
                    FaceOffsetX = eq?.FaceOffsetX, FaceOffsetY = eq?.FaceOffsetY, FaceOffsetZ = eq?.FaceOffsetZ,
                };
                var json = System.Text.Json.JsonSerializer.Serialize(snapshot, JsonContext.Default.EquippedCosmetics);
                File.WriteAllText(path, json);
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Equipped", $"Failed to write equipped.json: {ex.Message}");
            }
        }

        private static void WriteEquippedJson(EquippedCosmetics? eq)
