                    .FirstOrDefault(l => string.Equals(l.Code, saved, StringComparison.OrdinalIgnoreCase))
                    ?? LeafClient.Services.LocalizationService.SupportedLanguages[0];
                _languageComboBox.SelectedItem = match;
                _languageComboBox.SelectionChanged += OnLanguageChanged;
            }
            if (_discordRichPresenceToggle != null)
            {
                _discordRichPresenceToggle.Checked += (_, __) =>
