                    StopRichPresence();
                };
            }
        }

        private Task UpdateSkinPreviewsAsync(string? username, string? uuid) =>
            UpdateSkinPreviewsAsync(username, uuid, forceFresh: false);

        private async Task RefreshSkinPreviewsWithRetryAsync(string? username, string? uuid)
        {
            try
            {
                int[] delaysMs = { 0, 3000, 8000, 20000, 45000, 90000 };
                foreach (var d in delaysMs)
                {
                    if (d > 0) await Task.Delay(d);
                    _skinRenderService?.InvalidateCacheFor(username, uuid);
                    InvalidateAndRefreshSkinHeads(username);
                    InvalidateAndRefreshSkinHeads(uuid);
                    await UpdateSkinPreviewsAsync(username, uuid, forceFresh: true);
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Skin Upload", $"Refresh-with-retry failed: {ex.Message}");
            }
        }

        private async Task UpdateSkinPreviewsAsync(string? username, string? uuid, bool forceFresh)
        {
            if (string.IsNullOrWhiteSpace(username) && string.IsNullOrWhiteSpace(uuid))
                return;

            if (forceFresh)
            {
                InvalidateAndRefreshSkinHeads(username);
                InvalidateAndRefreshSkinHeads(uuid);
            }

            var smallShimmer = this.FindControl<Border>("PlayingAsImageBorder");
            var largeShimmer = this.FindControl<Border>("AccountCharacterImageShimmer");

            Dispatcher.UIThread.Post(() =>
            {
                if (_playingAsImage?.Source == null && smallShimmer != null)
                    LeafClient.Services.ShimmerService.Start(smallShimmer);
                if (_accountCharacterImage?.Source == null && largeShimmer != null)
                {
                    largeShimmer.IsVisible = true;
                    LeafClient.Services.ShimmerService.Start(largeShimmer);
                }
            });

            try
            {
                var smallPose = _skinRenderService.GetRandomSmallPoseName();
                var largePose = _skinRenderService.GetRandomLargePoseName();
                _lastSmallPose = smallPose;

                var id = username ?? uuid ?? "Player";

                string? localSkinFile = null;
                var selectedId = _currentSettings?.SelectedSkinId;
                if (!string.IsNullOrEmpty(selectedId) && _currentSettings?.CustomSkins != null)
                {
                    var sel = _currentSettings.CustomSkins.FirstOrDefault(s => s.Id == selectedId);
                    if (sel != null)
                    {
                        var resolved = ResolveSkinFilePath(sel);
                        if (!string.IsNullOrEmpty(resolved) && System.IO.File.Exists(resolved))
                            localSkinFile = resolved;
                    }
                }

                Bitmap? smallResult = null;
                Bitmap? largeResult = null;

                if (localSkinFile != null)
                {
                    var smallLocal = _skinRenderService.LoadSkinHeadFromFileAsync(localSkinFile, 128);
                    var largeLocal = _skinRenderService.LoadSkinImageFromFileAsync(localSkinFile, smallPose, "full");
                    await Task.WhenAll(smallLocal, largeLocal);
                    smallResult = smallLocal.Result;
                    largeResult = largeLocal.Result;
                }

                if (smallResult == null)
                {
                    bool isOffline = string.Equals(_currentSettings?.AccountType, "offline", StringComparison.OrdinalIgnoreCase);
                    if (isOffline || string.IsNullOrEmpty(uuid))
                        smallResult = await _skinRenderService.LoadSkinHeadByUsernameAsync(username, 128, forceFresh);
                    else
                        smallResult = await _skinRenderService.LoadSkinHeadFromUuidAsync(uuid, username, 128, forceFresh);
                }

                if (largeResult == null)
                {
                    largeResult = await _skinRenderService.LoadSkinImageAsync(id, largePose, "full", uuid, forceFresh);
                }

                Dispatcher.UIThread.Post(() =>
                {
                    if (_playingAsImage != null && smallResult != null)
                        _playingAsImage.Source = smallResult;

                    if (_accountCharacterImage != null && largeResult != null)
                        _accountCharacterImage.Source = largeResult;

                    if (smallShimmer != null)
                        LeafClient.Services.ShimmerService.Stop(smallShimmer);
                    if (largeShimmer != null)
                    {
                        LeafClient.Services.ShimmerService.Stop(largeShimmer);
                        largeShimmer.IsVisible = false;
                    }
                });

                UpdateRichPresenceFromState();
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Skins", $"Error updating skin previews: {ex.Message}");
                Dispatcher.UIThread.Post(() =>
                {
                    if (smallShimmer != null) LeafClient.Services.ShimmerService.Stop(smallShimmer);
                    if (largeShimmer != null)
                    {
                        LeafClient.Services.ShimmerService.Stop(largeShimmer);
                        largeShimmer.IsVisible = false;
                    }
                });
            }
        }

        private async Task LoadUserInfoAsync()
        {
            try
            {
                await LoadSessionAsync();

                var settings = await _settingsService.LoadSettingsAsync();

                var username = _session?.Username ?? settings.SessionUsername;
                LeafLog.Info("UserInfo", $"Refreshing user info: username={username ?? "(none)"}, type={settings.AccountType}");
                var uuid = _session?.UUID ?? settings.SessionUuid;

                _currentUsername = username;
                _loggedIn = !string.IsNullOrWhiteSpace(uuid);

                if (_accountUsernameDisplay != null)
                    _accountUsernameDisplay.Text = (username ?? "Player").ToUpper();

                if (_accountUuidDisplay != null)
                    _accountUuidDisplay.Text = _loggedIn ? uuid : "N/A (Offline)";

                if (_playingAsUsername != null)
                    _playingAsUsername.Text = (username ?? "Player").ToUpper();

                await UpdateSkinPreviewsAsync(username ?? "Player", uuid);

                UpdateRichPresenceFromState();
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("UserInfo", $"Error loading user info: {ex.Message}");
            }
        }

        private async void LinkWebsiteButton_Click(object? sender, RoutedEventArgs e)
        {
            if (!_currentSettings.IsLoggedIn || _currentSettings.AccountType != "microsoft")
            {
                await ShowAccountActionErrorDialog("Link Website is only available for Microsoft accounts.");
                return;
            }

            var uuid = _currentSettings.SessionUuid;
            var accessToken = _currentSettings.SessionAccessToken;
            if (string.IsNullOrEmpty(uuid) || string.IsNullOrEmpty(accessToken))
            {
                await ShowAccountActionErrorDialog("Your session is missing credentials. Please log out and log back in.");
                return;
            }

            if (WebLinkInlinePanel != null && AccountFooterButtonsPanel != null)
            {
                WebLinkCodeTextBox.Text = string.Empty;
                AccountFooterButtonsPanel.IsVisible = false;
                WebLinkInlinePanel.IsVisible = true;
                WebLinkCodeTextBox.Focus();
            }
        }

        private async void WebLinkConfirmButton_Click(object? sender, RoutedEventArgs e)
        {
            var code = WebLinkCodeTextBox?.Text?.Trim().ToUpperInvariant() ?? string.Empty;
            if (code.Length != 6)
            {
                ShowWebLinkResult(false, "Please enter the 6-character code from the website.");
                return;
            }

            var uuid = _currentSettings.SessionUuid;
            var accessToken = _currentSettings.SessionAccessToken;

            if (string.IsNullOrEmpty(uuid) || string.IsNullOrEmpty(accessToken))
            {
                ShowWebLinkResult(false, "Your session is missing credentials. Please log out and log back in.");
                return;
            }

            var tokenValid = await ValidateMinecraftTokenAsync(accessToken);
            if (!tokenValid)
            {
                if (!string.IsNullOrWhiteSpace(_currentSettings.MicrosoftRefreshToken))
                {
                    var refreshed = await TryDirectTokenRefreshAsync(_currentSettings.MicrosoftRefreshToken);
                    if (refreshed != null)
                    {
                        _currentSettings.SessionUuid = refreshed.UUID;
                        _currentSettings.SessionAccessToken = refreshed.AccessToken;
                        await _settingsService.SaveSettingsAsync(_currentSettings);
                        uuid = refreshed.UUID;
                        accessToken = refreshed.AccessToken;
                    }
                    else
                    {
                        ShowWebLinkResult(false, "Your session has expired. Please log out and log back in.");
                        return;
                    }
                }
                else
                {
                    ShowWebLinkResult(false, "Your session has expired. Please log out and log back in.");
                    return;
                }
            }

            var (success, error) = await LeafApiService.WebLinkCompleteAsync(code, uuid, accessToken);

            if (success)
                ShowWebLinkResult(true, "Account linked! You are now signed in on the website.");
            else
                ShowWebLinkResult(false, error ?? "Failed to link account. Check the code and try again.");
        }

        private void ShowWebLinkResult(bool success, string message)
        {
            if (WebLinkCodeEntryPanel != null) WebLinkCodeEntryPanel.IsVisible = false;
            if (WebLinkResultPanel != null) WebLinkResultPanel.IsVisible = true;
            if (WebLinkResultIcon != null)
            {
                WebLinkResultIcon.Text = success ? "✓" : "✕";
                WebLinkResultIcon.Foreground = success
                    ? new Avalonia.Media.SolidColorBrush(Avalonia.Media.Color.Parse("#6BDF9F"))
                    : new Avalonia.Media.SolidColorBrush(Avalonia.Media.Color.Parse("#FF6B6B"));
            }
            if (WebLinkResultText != null)
            {
                WebLinkResultText.Text = message;
                WebLinkResultText.Foreground = success
                    ? new Avalonia.Media.SolidColorBrush(Avalonia.Media.Color.Parse("#6BDF9F"))
                    : new Avalonia.Media.SolidColorBrush(Avalonia.Media.Color.Parse("#FF6B6B"));
            }
        }

