        private async void LogoutButton_Click(object? sender, RoutedEventArgs e)
        {
            try
            {
                LeafLog.Info("MainWindow", "Starting logout process...");

                string activeId = _currentSettings?.ActiveAccountId ?? "";

                _currentSettings?.SavedAccounts.RemoveAll(a => a.Id == activeId);

                await _sessionService.LogoutAsync();

                var remaining = _currentSettings?.SavedAccounts;
                if (remaining != null && remaining.Count > 0)
                {
                    var next = remaining[0];
                    LeafClient.Services.LeafLog.Info("MainWindow", $"Auto-selecting next account: {next.Username} ({next.AccountType})");
                    await ApplyAccountSelectionAsync(next, saveCurrentFirst: false);
                    LeafLog.Info("MainWindow", "Switched to next account successfully");
                }
                else
                {
                    LeafLog.Info("MainWindow", "No accounts remaining, showing LoginWindow...");

                    if (Application.Current is App app)
                    {
                        app.IsSwapToLogin = true;
                    }

                    if (_currentSettings != null)
                    {
                        _currentSettings.IsLoggedIn = false;
                        _currentSettings.AccountType = null;
                        _currentSettings.SessionUsername = null;
                        _currentSettings.SessionUuid = null;
                        _currentSettings.SessionAccessToken = null;
                        _currentSettings.SessionXuid = null;
                        _currentSettings.OfflineUsername = null;
                        _currentSettings.ActiveAccountId = null;
                        await _settingsService.SaveSettingsAsync(_currentSettings);
                    }

                    _loggedIn = false;
                    _currentUsername = null;
                    _lastSmallPose = null;
                    _session = null;

                    StopHeartbeatLoop();
                    StopRichPresence();

                    if (Application.Current?.ApplicationLifetime is IClassicDesktopStyleApplicationLifetime desktop)
                    {
                        this.Hide();

                        var loginWindow = new LoginWindow();

                        loginWindow.LoginCompleted += (success) =>
                        {
                            LeafClient.Services.LeafLog.Info("MainWindow", $"Login completed with success: {success}");
                            if (success)
                            {
                                Dispatcher.UIThread.Post(() =>
                                {
                                    var newMainWindow = new MainWindow();
                                    newMainWindow.Show();
                                    desktop.MainWindow = newMainWindow;
                                    loginWindow.Close();
                                    this.Close();
                                });
                            }
                        };

                        loginWindow.Closed += (_, __) =>
                        {
                            if (!loginWindow.LoginSuccessful)
                            {
                                Dispatcher.UIThread.Post(() =>
                                {
                                    this.Close();
                                });
                            }
                        };

                        desktop.MainWindow = loginWindow;
                        loginWindow.Show();
                        loginWindow.Activate();
                    }
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("MainWindow", $"Error during logout: {ex.Message}");
                LeafClient.Services.LeafLog.Info("MainWindow", $"Stack trace: {ex.StackTrace}");
            }
        }

