        private void HookLocalizationRehydrate()
        {
            if (_localizationRehydrateHooked) return;
            _localizationRehydrateHooked = true;
            LeafClient.Services.LocalizationService.Instance.PropertyChanged += (_, e) =>
            {
                if (e.PropertyName != nameof(LeafClient.Services.LocalizationService.ActiveLocale)
                    && e.PropertyName != "Item[]") return;
                Dispatcher.UIThread.Post(RehydrateLiveValuesAfterLocaleChange, DispatcherPriority.Background);
            };
        }

        private void RehydrateLiveValuesAfterLocaleChange()
        {
            try
            {
                if (_currentSettings != null) UpdateLaunchVersionText();
            }
            catch { }

            try
            {
                _onlineCountTextBlock ??= this.FindControl<TextBlock>("OnlineCountTextBlock");
                _onlineStatusDot     ??= this.FindControl<Ellipse>("OnlineStatusDot");
                if (_onlineCountTextBlock != null && _lastOnlineCount.HasValue)
                {
                    int c = _lastOnlineCount.Value;
                    if (c == int.MinValue)
                    {
                        _onlineCountTextBlock.Text = "N/A";
                        if (_onlineStatusDot != null) _onlineStatusDot.Fill = new SolidColorBrush(Colors.Gray);
                    }
                    else if (c >= 0)
                    {
                        _onlineCountTextBlock.Text = $"{c} Online";
                        if (_onlineStatusDot != null) _onlineStatusDot.Fill = new SolidColorBrush(c > 0 ? Colors.Green : Colors.Gray);
                    }
                    else
                    {
                        _onlineCountTextBlock.Text = "You're offline";
                        if (_onlineStatusDot != null) _onlineStatusDot.Fill = new SolidColorBrush(Colors.Red);
                    }
                }
                _motdTextBlock ??= this.FindControl<TextBlock>("MotdTextBlock");
                if (_motdTextBlock != null && !string.IsNullOrEmpty(_lastMotd))
                    _motdTextBlock.Text = _lastMotd;
            }
            catch { }

            try
            {
                _leafsBalanceText ??= this.FindControl<TextBlock>("LeafsBalanceText");
                if (_leafsBalanceText != null)
                    _leafsBalanceText.Text = _currentCoinBalance.ToString("N0");
            }
            catch { }

            try { ApplyLeafPlusUiState(); } catch { }

            try
            {
                if (_lastDiskUsageValues.HasValue)
                {
                    var v = _lastDiskUsageValues.Value;
                    ApplyDiskUsage(v.Logs, v.Profiles, v.Assets, v.Cache, v.Other);
                }
            }
            catch { }
        }

