        private async Task FetchAndMergeMojangVersionsAsync()
        {
            try
            {
                string cacheDir = System.IO.Path.Combine(
                    Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),
                    "LeafClient");
                System.IO.Directory.CreateDirectory(cacheDir);
                string cachePath = System.IO.Path.Combine(cacheDir, "mojang-versions-cache.json");

                string? cachedJson = null;
                if (System.IO.File.Exists(cachePath))
                {
                    var age = DateTime.UtcNow - System.IO.File.GetLastWriteTimeUtc(cachePath);
                    if (age.TotalHours < 6)
                    {
                        try { cachedJson = await System.IO.File.ReadAllTextAsync(cachePath); }
                        catch { cachedJson = null; }
                    }
                }

                CmlLib.Core.VersionMetadata.JsonVersionManifestModel? manifest = null;
                if (!string.IsNullOrWhiteSpace(cachedJson))
                {
                    try
                    {
                        manifest = System.Text.Json.JsonSerializer.Deserialize(
                            cachedJson,
                            CmlLib.Core.Json.CmlLibJsonContext.Default.JsonVersionManifestModel);
                    }
                    catch { manifest = null; }
                }

                if (manifest == null)
                {
                    var loader = new CmlLib.Core.VersionLoader.MojangJsonVersionLoader(
                        _httpClient,
                        CmlLib.Core.MojangServer.VersionV2);
                    using var cts = new System.Threading.CancellationTokenSource(TimeSpan.FromSeconds(10));
                    manifest = await loader.GetManifestAsync(cts.Token);
                    if (manifest != null)
                    {
                        try
                        {
                            var freshJson = System.Text.Json.JsonSerializer.Serialize(
                                manifest,
                                CmlLib.Core.Json.CmlLibJsonContext.Default.JsonVersionManifestModel);
                            await System.IO.File.WriteAllTextAsync(cachePath, freshJson);
                        }
                        catch { }
                    }
                }

                if (manifest?.Versions == null) return;

                var known = new HashSet<string>(
                    _allVersions.Select(v => v.FullVersion ?? "").Where(s => !string.IsNullOrEmpty(s)),
                    StringComparer.OrdinalIgnoreCase);

                var toAdd = new List<VersionInfo>();
                foreach (var meta in manifest.Versions)
                {
                    if (meta?.Id == null) continue;
                    if (!string.Equals(meta.Type, "release", StringComparison.OrdinalIgnoreCase)) continue;
                    if (known.Contains(meta.Id)) continue;

                    string major = ExtractMajorVersion(meta.Id);
                    string releaseDate = meta.ReleaseTime != default
                        ? meta.ReleaseTime.UtcDateTime.ToString("MMMM d, yyyy", System.Globalization.CultureInfo.InvariantCulture)
                        : "Release";

                    var info = new VersionInfo(meta.Id, major, "Release", "Vanilla", releaseDate,
                        "Mojang release. Vanilla only - Leaf Client mod is not yet available for this version.")
                    {
                        SupportLevel = SupportLevel.VanillaOnly,
                        IsFullySupported = false,
                        IsLeafClientModSupported = false
                    };
                    toAdd.Add(info);
                    known.Add(meta.Id);
                }

                if (toAdd.Count == 0) return;

                await Avalonia.Threading.Dispatcher.UIThread.InvokeAsync(() =>
                {
                    foreach (var info in toAdd) _allVersions.Add(info);
                    try { PO_PopulateVersionDropdown(); } catch { }
                });

                LeafClient.Services.LeafLog.Info("MojangVersions", $"Merged {toAdd.Count} new release(s) from Mojang manifest.");
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("MojangVersions", $"Fetch failed: {ex.Message}");
            }
        }

        private static string ExtractMajorVersion(string fullVersion)
        {
            if (string.IsNullOrWhiteSpace(fullVersion)) return fullVersion ?? "";
            var parts = fullVersion.Split('.');
            return parts.Length >= 2 ? $"{parts[0]}.{parts[1]}" : fullVersion;
        }

        private void AnimateSelectionIndicator(int index)
        {
            if (_selectionIndicator == null) return;

            bool animationsEnabled = AreAnimationsEnabled();

            if (animationsEnabled && _savedSelectionIndicatorTransitions != null)
            {
                var newTransitions = new Transitions();
                foreach (var t in _savedSelectionIndicatorTransitions) newTransitions.Add(t);
                _selectionIndicator.Transitions = newTransitions;
            }
            else
            {
                _selectionIndicator.Transitions = new Transitions();
            }

            int visualPosition = index switch
            {
                3 => 2,
                2 => 3,
                6 => 4,
                7 => 5,
                8 => 6,
                4 => 7,
                _ => index
            };
            double leftOffset = visualPosition * 60 + 9;

            _selectionIndicator.Opacity = 1.0;
            _selectionIndicator.Margin = new Thickness(leftOffset, 0, 0, 2);
        }

        private void PositionTooltipNextTo(Border button)
        {
            if (_sidebarHoverTooltip == null) return;

            var origin = button.TranslatePoint(new Point(0, 0), this);
            if (!origin.HasValue) return;

            _sidebarHoverTooltip.InvalidateMeasure();
            _sidebarHoverTooltip.Measure(Avalonia.Size.Infinity);
            double tooltipWidth = _sidebarHoverTooltip.DesiredSize.Width;
            if (tooltipWidth <= 0)
                tooltipWidth = _sidebarHoverTooltip.Bounds.Width > 0 ? _sidebarHoverTooltip.Bounds.Width : 80;

            double buttonCenterX = origin.Value.X + (button.Bounds.Width / 2.0);
            double left = buttonCenterX - (tooltipWidth / 2.0);

            double top = origin.Value.Y + button.Bounds.Height + 10;

            Canvas.SetLeft(_sidebarHoverTooltip, left);
            Canvas.SetTop(_sidebarHoverTooltip, top);

            Avalonia.Threading.Dispatcher.UIThread.Post(() =>
            {
                if (_sidebarHoverTooltip == null) return;
                double realWidth = _sidebarHoverTooltip.Bounds.Width;
                if (realWidth <= 0) return;
                double fixedLeft = buttonCenterX - (realWidth / 2.0);
                Canvas.SetLeft(_sidebarHoverTooltip, fixedLeft);
            }, Avalonia.Threading.DispatcherPriority.Render);
        }

        private void MinimizeWindow(object? s, RoutedEventArgs e)
        {
            WindowState = WindowState.Minimized;
        }

        private void MaximizeWindow(object? s, RoutedEventArgs e)
        {
            try
            {
                WindowState = WindowState == WindowState.Maximized
                    ? WindowState.Normal
                    : WindowState.Maximized;
            }
            catch (Exception ex)
            {
                LeafLog.Error("Window", $"MaximizeWindow failed: {ex.Message}");
            }
        }

        private void UpdateMaximizeIcon()
        {
            try
            {
                var icon = this.FindControl<TextBlock>("MaximizeIcon");
                if (icon == null) return;
                icon.Text = WindowState == WindowState.Maximized ? "\u2750" : "\u25A1";
            }
            catch { }
        }

        private void WireDragDropImport()
        {
            try
            {
                Avalonia.Input.DragDrop.SetAllowDrop(this, true);
                this.AddHandler(Avalonia.Input.DragDrop.DragEnterEvent, OnDragEnterImport);
                this.AddHandler(Avalonia.Input.DragDrop.DragOverEvent,  OnDragOverImport);
                this.AddHandler(Avalonia.Input.DragDrop.DragLeaveEvent, OnDragLeaveImport);
                this.AddHandler(Avalonia.Input.DragDrop.DropEvent,      OnDropImport);
            }
            catch (Exception ex)
            {
                LeafLog.Error("DragDrop", $"Wire failed: {ex.Message}");
            }
        }

        private void OnDragEnterImport(object? sender, Avalonia.Input.DragEventArgs e)
        {
            if (!e.Data.Contains(Avalonia.Input.DataFormats.Files)) { e.DragEffects = Avalonia.Input.DragDropEffects.None; return; }
            e.DragEffects = Avalonia.Input.DragDropEffects.Copy;
            ShowDropOverlay(e);
        }

        private void OnDragOverImport(object? sender, Avalonia.Input.DragEventArgs e)
        {
            if (!e.Data.Contains(Avalonia.Input.DataFormats.Files)) { e.DragEffects = Avalonia.Input.DragDropEffects.None; return; }
            e.DragEffects = Avalonia.Input.DragDropEffects.Copy;
        }

        private void OnDragLeaveImport(object? sender, Avalonia.Input.DragEventArgs e)
        {
            HideDropOverlay();
        }

        private async void OnDropImport(object? sender, Avalonia.Input.DragEventArgs e)
        {
            HideDropOverlay();
            try
            {
                if (!e.Data.Contains(Avalonia.Input.DataFormats.Files)) return;
                var files = e.Data.GetFiles();
                if (files == null) return;

                var paths = LeafClient.Services.DragDropImportService.ResolveLocalPaths(files);
                if (paths.Count == 0) return;

                var items = LeafClient.Services.DragDropImportService.Inspect(paths);
                if (items.Count == 0) return;

                var result = await LeafClient.Services.DragDropImportService.ImportAsync(
                    items, _minecraftFolder,
                    installModpackAsync: (path, title) => InstallLocalMrpackAsync(path, title),
                    launcherManagedModIds: _launcherManagedModIds,
                    onManagedOverrideAsync: HandleManagedModOverrideAsync);
                AnnounceImportResult(result);
                RefreshAfterImport(result);
            }
            catch (Exception ex)
            {
                LeafLog.Error("DragDrop", $"Drop failed: {ex.Message}");
                LeafClient.Services.ToastService.Show($"Drop failed\n{ex.Message}", LeafClient.Services.ToastType.Error);
            }
        }

        private void ShowDropOverlay(Avalonia.Input.DragEventArgs e)
        {
            try
            {
                var overlay = this.FindControl<Border>("DropOverlay");
                var title   = this.FindControl<TextBlock>("DropOverlayTitle");
                var sub     = this.FindControl<TextBlock>("DropOverlaySubtitle");
                if (overlay == null) return;

                int modCount = 0, rpCount = 0, shaderCount = 0, modpackCount = 0, unsupportedModpack = 0, unknown = 0;
                try
                {
                    var files = e.Data.GetFiles();
                    if (files != null)
                    {
                        var paths = LeafClient.Services.DragDropImportService.ResolveLocalPaths(files);
                        var inspected = LeafClient.Services.DragDropImportService.Inspect(paths);
                        foreach (var it in inspected)
                        {
                            switch (it.Kind)
                            {
                                case LeafClient.Services.DropTargetKind.Mod: modCount++; break;
                                case LeafClient.Services.DropTargetKind.ResourcePack: rpCount++; break;
                                case LeafClient.Services.DropTargetKind.Shader: shaderCount++; break;
                                case LeafClient.Services.DropTargetKind.Modpack: modpackCount++; break;
                                case LeafClient.Services.DropTargetKind.ModpackUnsupported: unsupportedModpack++; break;
                                default: unknown++; break;
                            }
                        }
                    }
                }
                catch { }

                if (title != null) title.Text = "Drop to install";
                if (sub != null)
                {
                    var parts = new List<string>();
                    if (modCount > 0) parts.Add($"{modCount} mod{(modCount == 1 ? "" : "s")}");
                    if (rpCount > 0) parts.Add($"{rpCount} resource pack{(rpCount == 1 ? "" : "s")}");
                    if (shaderCount > 0) parts.Add($"{shaderCount} shader{(shaderCount == 1 ? "" : "s")}");
                    if (modpackCount > 0) parts.Add($"{modpackCount} modpack{(modpackCount == 1 ? "" : "s")}");
                    if (parts.Count == 0)
                    {
                        if (unsupportedModpack > 0) sub.Text = "CurseForge / MultiMC modpack - not supported";
                        else if (unknown > 0) sub.Text = "Unsupported file type";
                        else sub.Text = "Mods, resource packs, shaders, or modpacks";
                    }
                    else sub.Text = string.Join(" + ", parts);
                }

                overlay.IsVisible = true;
                overlay.Opacity = 1.0;
            }
            catch (Exception ex)
            {
                LeafLog.Error("DragDrop", $"ShowOverlay: {ex.Message}");
            }
        }

        private void HideDropOverlay()
        {
            try
            {
                var overlay = this.FindControl<Border>("DropOverlay");
                if (overlay == null) return;
                overlay.Opacity = 0.0;
                Avalonia.Threading.DispatcherTimer.RunOnce(() =>
                {
                    if (overlay.Opacity <= 0.01) overlay.IsVisible = false;
                }, TimeSpan.FromMilliseconds(220));
            }
            catch { }
        }

        private void AnnounceImportResult(LeafClient.Services.DropImportResult r)
        {
            int totalInstalled = r.ModsInstalled + r.ResourcePacksInstalled + r.ShadersInstalled + r.ModpacksInstalled;

            if (r.ManagedModsOverwritten > 0)
            {
                string names = string.Join(", ",
                    r.ManagedModsOverwrittenNames
                        .Distinct(StringComparer.OrdinalIgnoreCase)
                        .Select(n => char.ToUpperInvariant(n[0]) + n.Substring(1)));
                LeafClient.Services.ToastService.Show(
                    $"Replaced bundled {names} with your version\nDelete from Installed Mods to undo",
                    LeafClient.Services.ToastType.Success);
            }

            if (totalInstalled == 0 && r.ManagedModsOverwritten == 0)
            {
                if (r.Errors.Count == 0 && r.Skipped > 0)
                    LeafClient.Services.ToastService.Show($"Skipped {r.Skipped} unsupported file{(r.Skipped == 1 ? "" : "s")}", LeafClient.Services.ToastType.Info);
                if (r.Errors.Count > 0)
                    LeafClient.Services.ToastService.Show(r.Errors[0], LeafClient.Services.ToastType.Error);
                return;
            }

            if (totalInstalled > 0)
            {
                var parts = new List<string>();
                if (r.ModsInstalled > 0) parts.Add($"{r.ModsInstalled} mod{(r.ModsInstalled == 1 ? "" : "s")}");
                if (r.ResourcePacksInstalled > 0) parts.Add($"{r.ResourcePacksInstalled} resource pack{(r.ResourcePacksInstalled == 1 ? "" : "s")}");
                if (r.ShadersInstalled > 0) parts.Add($"{r.ShadersInstalled} shader{(r.ShadersInstalled == 1 ? "" : "s")}");
                if (r.ModpacksInstalled > 0) parts.Add($"{r.ModpacksInstalled} modpack{(r.ModpacksInstalled == 1 ? "" : "s")}");
                string msg = $"Installed {string.Join(" + ", parts)}";
                if (r.Skipped > 0) msg += $" - skipped {r.Skipped}";
                LeafClient.Services.ToastService.Show(msg, LeafClient.Services.ToastType.Success);
            }

            if (r.Errors.Count > 0)
                LeafClient.Services.ToastService.Show($"{r.Errors.Count} error{(r.Errors.Count == 1 ? "" : "s")} during import", LeafClient.Services.ToastType.Error);
        }

        private void RefreshAfterImport(LeafClient.Services.DropImportResult r)
        {
            try
            {
                if (r.ModsInstalled > 0 || r.ManagedModsOverwritten > 0)
                {
                    try { LoadUserMods(); } catch { }
                }
                if (r.ShadersInstalled > 0)
                {
                    try { RefreshInstalledShaders(); } catch { }
                }
                if (r.ResourcePacksInstalled > 0)
                {
                    try
                    {
                        var rpPage = this.FindControl<LeafClient.Views.Pages.ResourcePacksPageView>("ResourcePacksPage");
                        var refresh = rpPage?.GetType().GetMethod("Refresh");
                        refresh?.Invoke(rpPage, null);
                    }
                    catch { }
                }
                if (r.ModpacksInstalled > 0)
                {
                    try { RefreshInstalledModpacks(); } catch { }
                }

                NavigateToImportedTab(r.InstalledKinds);
            }
            catch (Exception ex)
            {
                LeafLog.Error("DragDrop", $"RefreshAfterImport: {ex.Message}");
            }
        }

        private LeafClient.Services.CrashSuspect? _activeCrashSuspect;

        private bool TryShowCrashPostmortem()
        {
            try
            {
                var recentLog = _gameOutputWindow?.GetRecentLogText();
                var suspects = LeafClient.Services.LaunchCrashAnalyzer.AnalyzeCrash(_minecraftFolder, recentLog);
                if (suspects == null || suspects.Count == 0) return false;

                var primary = suspects[0];
                _activeCrashSuspect = primary;

                var overlay = this.FindControl<Grid>("CrashPostmortemOverlay");
                var modLine = this.FindControl<TextBlock>("CrashPostmortemModLine");
                var reason  = this.FindControl<TextBlock>("CrashPostmortemReason");
                var disableBtn = this.FindControl<Button>("CrashPostmortemDisableBtn");

                if (overlay == null) return false;

                if (modLine != null) modLine.Text = $"Mod: {primary.DisplayName}" + (suspects.Count > 1 ? $"  (+{suspects.Count - 1} other suspect{(suspects.Count - 1 == 1 ? "" : "s")})" : "");
                if (reason != null) reason.Text = primary.Reason;
                if (disableBtn != null) disableBtn.IsEnabled = !string.IsNullOrEmpty(primary.FilePath);

                overlay.IsVisible = true;
                return true;
            }
            catch (Exception ex)
            {
                LeafLog.Error("CrashPostmortem", $"TryShow failed: {ex.Message}");
                return false;
            }
        }

        private void HideCrashPostmortem()
        {
            try
            {
                var overlay = this.FindControl<Grid>("CrashPostmortemOverlay");
                if (overlay != null) overlay.IsVisible = false;
            }
            catch { }
        }

        private async void OnCrashPostmortemDisableRetry(object? sender, RoutedEventArgs e)
        {
            try
            {
                var suspect = _activeCrashSuspect;
                if (suspect == null) { HideCrashPostmortem(); return; }

                if (!string.IsNullOrEmpty(suspect.FilePath))
                {
                    if (!LeafClient.Services.LaunchCrashAnalyzer.DisableMod(suspect.FilePath))
                    {
                        LeafClient.Services.ToastService.Show($"Couldn't disable {suspect.DisplayName}. File may be locked.", LeafClient.Services.ToastType.Error);
                        HideCrashPostmortem();
                        return;
                    }
                }

                if (_launcherManagedModIds.Contains(suspect.ModId))
                {
                    var profile = GetActiveProfile();
                    if (profile != null)
                    {
                        profile.DisabledRequiredMods ??= new();
                        profile.DisabledRequiredMods[suspect.ModId] = true;
                        await _settingsService.SaveSettingsAsync(_currentSettings);
                    }
                }

                LeafClient.Services.ToastService.Show($"Disabled {suspect.DisplayName} - relaunching", LeafClient.Services.ToastType.Info);
                HideCrashPostmortem();
                _activeCrashSuspect = null;

                await Task.Delay(800);
                _ = LaunchGameAsync(_lastLaunchVersion ?? _currentSettings.SelectedSubVersion, true);
            }
            catch (Exception ex)
            {
                LeafLog.Error("CrashPostmortem", $"DisableRetry failed: {ex.Message}");
                HideCrashPostmortem();
            }
        }

        private void OnCrashPostmortemKeep(object? sender, RoutedEventArgs e)
        {
            HideCrashPostmortem();
            _activeCrashSuspect = null;
        }

        private void OnCrashPostmortemOpenReport(object? sender, RoutedEventArgs e)
        {
            try
            {
                var dir = System.IO.Path.Combine(_minecraftFolder, "crash-reports");
                if (Directory.Exists(dir))
                {
                    var newest = Directory.EnumerateFiles(dir, "crash-*.txt")
                        .OrderByDescending(p => File.GetLastWriteTimeUtc(p))
                        .FirstOrDefault();
                    if (newest != null)
                    {
                        System.Diagnostics.Process.Start(new System.Diagnostics.ProcessStartInfo(newest) { UseShellExecute = true });
                        return;
                    }
                }
                OpenLauncherLogsFolder(null, new RoutedEventArgs());
            }
            catch (Exception ex)
            {
                LeafLog.Error("CrashPostmortem", $"OpenReport failed: {ex.Message}");
            }
        }

        private async Task HandleManagedModOverrideAsync(IReadOnlyList<string> managedIds)
        {
            try
            {
                if (managedIds == null || managedIds.Count == 0) return;

                var profile = GetActiveProfile();
                if (profile == null) return;

                profile.DisabledRequiredMods ??= new();

                foreach (var id in managedIds)
                    profile.DisabledRequiredMods[id] = true;

                await _settingsService.SaveSettingsAsync(_currentSettings);

                string modsFolder = System.IO.Path.Combine(_minecraftFolder, "mods");
                if (!Directory.Exists(modsFolder)) return;
                foreach (var path in Directory.EnumerateFiles(modsFolder, "*.jar", SearchOption.TopDirectoryOnly))
                {
                    var stem = System.IO.Path.GetFileNameWithoutExtension(path).ToLowerInvariant();
                    foreach (var id in managedIds)
                    {
                        if (!stem.Contains(id, StringComparison.OrdinalIgnoreCase)) continue;

                        var matchesTracked = _currentSettings.InstalledMods.Any(m =>
                            m.IsAutoInstalled
                            && !string.IsNullOrEmpty(m.FileName)
                            && string.Equals(m.FileName, System.IO.Path.GetFileName(path), StringComparison.OrdinalIgnoreCase));
                        if (!matchesTracked) continue;

                        try { File.Delete(path); LeafClient.Services.LeafLog.Info("DragDrop", $"Removed bundled managed jar: {System.IO.Path.GetFileName(path)}"); }
                        catch (Exception ex) { LeafLog.Error("DragDrop", $"Failed to delete bundled {path}: {ex.Message}"); }
                        break;
                    }
                }

                _currentSettings.InstalledMods.RemoveAll(m =>
                    m.IsAutoInstalled
                    && managedIds.Any(id => m.ModId != null && m.ModId.Equals(id, StringComparison.OrdinalIgnoreCase)));
                await _settingsService.SaveSettingsAsync(_currentSettings);
            }
            catch (Exception ex)
            {
                LeafLog.Error("DragDrop", $"HandleManagedModOverride: {ex.Message}");
            }
        }

        private void NavigateToImportedTab(IReadOnlyList<LeafClient.Services.DropTargetKind> kinds)
        {
            if (kinds == null || kinds.Count == 0) return;
            try
            {
                string tag = kinds[0] switch
                {
                    LeafClient.Services.DropTargetKind.ResourcePack => "rp",
                    LeafClient.Services.DropTargetKind.Shader => "shaders",
                    LeafClient.Services.DropTargetKind.Modpack => "modpacks",
                    _ => "mods"
                };

                SwitchToPage(3);

                _activeModsTab = tag;
                ApplyModsTabSwitch(tag);
            }
            catch (Exception ex)
            {
                LeafLog.Error("DragDrop", $"NavigateToImportedTab: {ex.Message}");
            }
        }

        private void ApplyResponsiveHeader()
        {
            try
            {
                double w = Bounds.Width;
                if (double.IsNaN(w) || w <= 0) return;

                var wordmark = this.FindControl<Image>("HeaderWordmark");
                var socials  = this.FindControl<StackPanel>("HeaderSocialGroup");
                var leafPlus = this.FindControl<Border>("LeafPlusActivePill");
                var leafs    = this.FindControl<Border>("LeafsCurrencyWidget");
                var labels   = this.FindControl<StackPanel>("PlayingAsLabelStack");

                if (wordmark != null) wordmark.IsVisible = true;
                if (socials  != null) socials.IsVisible  = true;
                if (labels   != null) labels.IsVisible   = true;
                if (leafs    != null) leafs.IsVisible    = _leafsCurrencyShouldBeVisible;
                if (leafPlus != null) leafPlus.IsVisible = _leafPlusPillShouldBeVisible;

                Dispatcher.UIThread.Post(CollapseHeaderUntilNoOverlap, Avalonia.Threading.DispatcherPriority.Background);
            }
            catch (Exception ex)
            {
                LeafLog.Error("ResponsiveHeader", $"{ex.Message}");
            }
        }

        private void CollapseHeaderUntilNoOverlap()
        {
            try
            {
                var nav   = this.FindControl<Border>("FloatingNavBorder");
                var right = this.FindControl<StackPanel>("HeaderRightCluster");
                if (nav == null || right == null) return;

                var hideOrder = new Control?[]
                {
                    this.FindControl<StackPanel>("PlayingAsLabelStack"),
                    this.FindControl<Border>("LeafsCurrencyWidget"),
                    this.FindControl<Border>("LeafPlusActivePill"),
                    this.FindControl<StackPanel>("HeaderSocialGroup"),
                    this.FindControl<Image>("HeaderWordmark"),
                };

                int safety = hideOrder.Length + 1;
                while (safety-- > 0 && HasHeaderOverlap(nav, right))
                {
                    Control? hidden = null;
                    foreach (var c in hideOrder)
                    {
                        if (c == null) continue;
                        if (c.IsVisible)
                        {
                            c.IsVisible = false;
                            hidden = c;
                            break;
                        }
                    }
                    if (hidden == null) break;
                    UpdateLayout();
                }
            }
            catch (Exception ex)
            {
                LeafLog.Error("CollapseHeader", $"{ex.Message}");
            }
        }

        private bool HasHeaderOverlap(Control nav, Control right)
        {
            try
            {
                var navTopLeft = nav.TranslatePoint(new Point(0, 0), this);
                var rightTopLeft = right.TranslatePoint(new Point(0, 0), this);
                if (navTopLeft == null || rightTopLeft == null) return false;

                var navRect = new Rect(navTopLeft.Value.X, navTopLeft.Value.Y, nav.Bounds.Width, nav.Bounds.Height);
                var rightRect = new Rect(rightTopLeft.Value.X, rightTopLeft.Value.Y, right.Bounds.Width, right.Bounds.Height);
                if (navRect.Width <= 0 || rightRect.Width <= 0) return false;

                const double minGap = 12;
                bool xOverlap = (rightRect.X - minGap) < navRect.Right;
                bool yOverlap = navRect.Bottom > rightRect.Y && navRect.Y < rightRect.Bottom;
                return xOverlap && yOverlap;
            }
            catch
            {
                return false;
            }
        }

