        private void AdaptInitialSizeToScreen()
        {
            try
            {
                var screen = Screens?.ScreenFromWindow(this) ?? Screens?.Primary;
                if (screen == null) return;
                double scaling = screen.Scaling > 0 ? screen.Scaling : 1.0;
                double areaW = screen.WorkingArea.Width / scaling;
                double areaH = screen.WorkingArea.Height / scaling;

                double desiredW = Math.Min(Width, areaW * 0.96);
                double desiredH = Math.Min(Height, areaH * 0.94);
                desiredW = Math.Max(MinWidth, desiredW);
                desiredH = Math.Max(MinHeight, desiredH);

                if (Math.Abs(desiredW - Width) > 1) Width = desiredW;
                if (Math.Abs(desiredH - Height) > 1) Height = desiredH;

                if (WindowState == WindowState.Normal)
                {
                    var wa = screen.WorkingArea;
                    int pxW = (int)Math.Round(desiredW * scaling);
                    int pxH = (int)Math.Round(desiredH * scaling);
                    int x = wa.X + Math.Max(0, (wa.Width - pxW) / 2);
                    int y = wa.Y + Math.Max(0, (wa.Height - pxH) / 2);
                    Position = new PixelPoint(x, y);
                }
            }
            catch (Exception ex)
            {
                LeafLog.Error("Window", $"AdaptInitialSizeToScreen failed: {ex.Message}");
            }
        }
