        private static Color ParseColorOrDefault(string? hex, Color fallback)
        {
            if (string.IsNullOrWhiteSpace(hex)) return fallback;
            try { return Color.Parse(hex.Trim()); }
            catch { return fallback; }
        }

        private static readonly HashSet<string> NewsImageHostAllowlist = new(System.StringComparer.OrdinalIgnoreCase)
        {
            "api.leafclient.com",
            "cdn.leafclient.com"
        };

        private static bool IsAllowedNewsImageUrl(string url)
        {
            if (string.IsNullOrWhiteSpace(url)) return false;
            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri)) return false;
            if (uri.Scheme != Uri.UriSchemeHttps) return false;
            return NewsImageHostAllowlist.Contains(uri.Host);
        }

        private async Task<Bitmap?> DownloadBitmapAsync(string url)
        {
            if (!IsAllowedNewsImageUrl(url))
            {
                LeafClient.Services.LeafLog.Info("News", $"image URL rejected: {url}");
                return null;
            }
            try
            {
                var bytes = await _httpClient.GetByteArrayAsync(url);
                if (bytes == null || bytes.Length > 8 * 1024 * 1024) return null;
                using var ms = new MemoryStream(bytes);
                return new Bitmap(ms);
            }
            catch
            {
                return null;
            }
        }

        private static Bitmap? LoadBundledBitmap(string avaresUri)
        {
            try
            {
                using var s = Avalonia.Platform.AssetLoader.Open(new Uri(avaresUri));
                return new Bitmap(s);
            }
            catch
            {
                return null;
            }
        }

        private void ApplyNewsItem(int slot, LeafClient.Services.LeafApiNewsItem? item, Bitmap? bitmap)
        {
            var image       = slot == 1 ? _newsItem1Image     : _newsItem2Image;
            var content     = slot == 1 ? _newsItem1Content   : _newsItem2Content;
            var titleTb     = slot == 1 ? _newsItem1Title     : _newsItem2Title;
            var subtitleTb  = slot == 1 ? _newsItem1Subtitle  : _newsItem2Subtitle;
            var tagTextTb   = slot == 1 ? _newsItem1TagText   : _newsItem2TagText;
            var badgeBorder = slot == 1 ? _majorUpdateBadge   : _newsItem2Badge;

            if (image != null && bitmap != null) image.Source = bitmap;

            if (item != null)
            {
                if (titleTb    != null) titleTb.Text    = item.Title    ?? string.Empty;
                if (subtitleTb != null) subtitleTb.Text = item.Subtitle ?? string.Empty;
                string tagUpper = (item.TagText ?? string.Empty).Trim().ToUpperInvariant();
                if (tagTextTb  != null) tagTextTb.Text  = tagUpper;
                if (badgeBorder != null) badgeBorder.IsVisible = !string.IsNullOrEmpty(tagUpper);

                if (slot == 1)
                {
                    _majorUpdateBadgeCts?.Cancel();
                    _majorUpdateBadgeCts = null;
                }

                if (badgeBorder?.Background is LinearGradientBrush lgb && lgb.GradientStops.Count >= 2)
                {
                    lgb.GradientStops[0].Color = ParseColorOrDefault(item.TagColorStart, Color.FromRgb(0x7B, 0x1F, 0xA2));
                    lgb.GradientStops[lgb.GradientStops.Count - 1].Color = ParseColorOrDefault(item.TagColorEnd, Color.FromRgb(0xCE, 0x93, 0xD8));
                }
            }

            if (content != null) content.Opacity = 1;
        }

        private async Task LoadNewsAsync()
        {
            if (_newsLoadStarted) return;
            _newsLoadStarted = true;

            try
            {
                if (_newsItem1Border != null) LeafClient.Services.ShimmerService.Start(_newsItem1Border);
                if (_newsItem2Border != null) LeafClient.Services.ShimmerService.Start(_newsItem2Border);

                var fetchTask = LeafClient.Services.LeafApiService.GetNewsAsync();
                var delayTask = Task.Delay(1200);
                await Task.WhenAll(fetchTask, delayTask);

                var items = await fetchTask;
                LeafClient.Services.LeafApiNewsItem? item1 = null;
                LeafClient.Services.LeafApiNewsItem? item2 = null;
                if (items != null)
                {
                    foreach (var i in items)
                    {
                        if (i.Slot == 1) item1 = i;
                        else if (i.Slot == 2) item2 = i;
                    }
                }

                Bitmap? bmp1 = null;
                Bitmap? bmp2 = null;
                var dl1 = item1 != null && !string.IsNullOrWhiteSpace(item1.ImageUrl)
                    ? DownloadBitmapAsync(item1.ImageUrl!)
                    : Task.FromResult<Bitmap?>(null);
                var dl2 = item2 != null && !string.IsNullOrWhiteSpace(item2.ImageUrl)
                    ? DownloadBitmapAsync(item2.ImageUrl!)
                    : Task.FromResult<Bitmap?>(null);
                await Task.WhenAll(dl1, dl2);
                bmp1 = await dl1;
                bmp2 = await dl2;

                if (bmp1 == null) bmp1 = LoadBundledBitmap("avares://LeafClient/Assets/NewLookNewFeelBanner.jpg");
                if (bmp2 == null) bmp2 = LoadBundledBitmap("avares://LeafClient/Assets/LeafPlusLauncherBanner.jpg");

                await Avalonia.Threading.Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (_newsItem1Border != null) LeafClient.Services.ShimmerService.Stop(_newsItem1Border);
                    if (_newsItem2Border != null) LeafClient.Services.ShimmerService.Stop(_newsItem2Border);
                    ApplyNewsItem(1, item1, bmp1);
                    ApplyNewsItem(2, item2, bmp2);
                });
            }
            catch
            {
                try
                {
                    await Avalonia.Threading.Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        if (_newsItem1Border != null) LeafClient.Services.ShimmerService.Stop(_newsItem1Border);
                        if (_newsItem2Border != null) LeafClient.Services.ShimmerService.Stop(_newsItem2Border);
                        ApplyNewsItem(1, null, LoadBundledBitmap("avares://LeafClient/Assets/NewLookNewFeelBanner.jpg"));
                        ApplyNewsItem(2, null, LoadBundledBitmap("avares://LeafClient/Assets/LeafPlusLauncherBanner.jpg"));
                    });
                }
                catch { }
            }
        }

        private void StartMajorUpdateBadgeAnimation()
        {
            if (_majorUpdateBadge == null) return;
            if (_majorUpdateBadge.Background is not LinearGradientBrush brush) return;
            if (brush.GradientStops == null || brush.GradientStops.Count < 2) return;

            var stop1 = brush.GradientStops[0];
            var stop2 = brush.GradientStops[1];

            _majorUpdateBadgeCts?.Cancel();
            _majorUpdateBadgeCts = new CancellationTokenSource();
            var token = _majorUpdateBadgeCts.Token;

            var anchors = new[]
            {
                Color.FromRgb(0x16, 0xA3, 0x4A),
                Color.FromRgb(0x22, 0xC5, 0x5E),
                Color.FromRgb(0x86, 0xEF, 0xAC),
            };

            Task.Run(async () =>
            {
                var sw = System.Diagnostics.Stopwatch.StartNew();
                const double periodSec = 3.2;

                while (!token.IsCancellationRequested)
                {
                    double t = (sw.Elapsed.TotalSeconds / periodSec) % 1.0;
                    double phase1 = t * anchors.Length;
                    double phase2 = (t + 0.33) * anchors.Length;

                    Color c1 = SampleColorCycle(anchors, phase1);
                    Color c2 = SampleColorCycle(anchors, phase2);

                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        stop1.Color = c1;
                        stop2.Color = c2;
                    });

                    try { await Task.Delay(16, token); }
                    catch (TaskCanceledException) { break; }
                }
            }, token);
        }

        private static Color SampleColorCycle(Color[] anchors, double phase)
        {
            int n = anchors.Length;
            phase = ((phase % n) + n) % n;
            int i = (int)phase;
            double frac = phase - i;
            Color a = anchors[i];
            Color b = anchors[(i + 1) % n];
            return Color.FromRgb(
                (byte)(a.R + (b.R - a.R) * frac),
                (byte)(a.G + (b.G - a.G) * frac),
                (byte)(a.B + (b.B - a.B) * frac));
        }

        private async Task AnimateScaleTransform(
            ScaleTransform? st,
            double target,
            int durationMs,
            Action<CancellationTokenSource?> setCtsAction,
            Func<CancellationTokenSource?> getCtsFunc
        )
        {
            if (st == null) return;

            CancellationTokenSource? currentCts = getCtsFunc();

            if (!AreAnimationsEnabled())
            {
                st.ScaleX = st.ScaleY = target;
                currentCts?.Cancel();
                currentCts?.Dispose();
                setCtsAction(null);
                return;
            }

            currentCts?.Cancel();
            currentCts?.Dispose();

            CancellationTokenSource newCts = new CancellationTokenSource();
            setCtsAction(newCts);
            var ct = newCts.Token;

            double start = st.ScaleX;
            double delta = target - start;

            if (Math.Abs(delta) < 0.001)
            {
                st.ScaleX = st.ScaleY = target;
                newCts.Dispose();
                setCtsAction(null);
                return;
            }

            const int steps = 16;
            int delayMs = durationMs / steps;

            try
            {
                for (int i = 1; i <= steps; i++)
                {
                    ct.ThrowIfCancellationRequested();

                    double t = (double)i / steps;
                    double eased = 1 - Math.Pow(1 - t, 3);

                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        if (st != null)
                        {
                            st.ScaleX = st.ScaleY = start + (delta * eased);
                        }
                    });

                    await Task.Delay(delayMs, ct);
                }
                await Dispatcher.UIThread.InvokeAsync(() =>
                {
                    if (st != null)
                    {
                        st.ScaleX = st.ScaleY = target;
                    }
                });
            }
            catch (OperationCanceledException)
            {
            }
            finally
            {
                newCts.Dispose();
                if (getCtsFunc() == newCts)
                {
                    setCtsAction(null);
                }
            }
        }

        private async Task AnimateBgScale(ScaleTransform? st, double target, int ms)
        {
            if (st == null) return;

            if (!AreAnimationsEnabled())
            {
                st.ScaleX = st.ScaleY = target;
                return;
            }

            _launchBgCts?.Cancel();
            _launchBgCts = new CancellationTokenSource();
            var ct = _launchBgCts.Token;
            double start = st.ScaleX;
            double delta = target - start;

            try
            {
                for (int i = 1; i <= 16; i++)
                {
                    if (ct.IsCancellationRequested) break;
                    double t = (double)i / 16;
                    double eased = 1 - Math.Pow(1 - t, 3);
                    st.ScaleX = st.ScaleY = start + (delta * eased);
                    await Task.Delay(ms / 16, ct);
                }
            }
            catch (OperationCanceledException)
            {
                if (st.ScaleX != 1.00)
                {
                    double currentScale = st.ScaleX;
                    double resetDelta = 1.00 - currentScale;
                    for (int i = 1; i <= 8; i++)
                    {
                        double t = (double)i / 8;
                        double eased = 1 - Math.Pow(1 - t, 3);
                        st.ScaleX = st.ScaleY = currentScale + (resetDelta * eased);
                        await Task.Delay(ms / 32);
                    }
                    st.ScaleX = st.ScaleY = 1.00;
                }
            }
            finally
            {
                if (!ct.IsCancellationRequested) { st.ScaleX = st.ScaleY = target; }
            }
        }

        private async Task AnimateNewsImageScale(ScaleTransform? st, double target, int ms, CancellationTokenSource? cts)
        {
            if (st == null) return;

            if (!AreAnimationsEnabled())
            {
                st.ScaleX = st.ScaleY = target;
                return;
            }

            cts?.Cancel();
            cts = new CancellationTokenSource();
            var ct = cts.Token;
            double start = st.ScaleX;
            double delta = target - start;

            try
            {
                for (int i = 1; i <= 12; i++)
                {
                    if (ct.IsCancellationRequested) break;
                    double t = (double)i / 12;
                    double eased = 1 - Math.Pow(1 - t, 3);
                    st.ScaleX = st.ScaleY = start + (delta * eased);
                    await Task.Delay(ms / 12, ct);
                }
            }
            catch (OperationCanceledException)
            {
                if (st.ScaleX != 1.00)
                {
                    double currentScale = st.ScaleX;
                    double resetDelta = 1.00 - currentScale;
                    for (int i = 1; i <= 8; i++)
                    {
                        double t = (double)i / 8;
                        double eased = 1 - Math.Pow(1 - t, 3);
                        st.ScaleX = st.ScaleY = currentScale + (resetDelta * eased);
                        await Task.Delay(ms / 32);
                    }
                    st.ScaleX = st.ScaleY = 1.00;
                }
            }
            finally
            {
                if (!ct.IsCancellationRequested) { st.ScaleX = st.ScaleY = target; }
            }
        }

        private void OpenAccountPanel(object? s, RoutedEventArgs e)
        {
            OpenAccountPanelClick();
            UpdateRichPresenceFromState();
        }

        private LeafClient.Controls.SkinRendererControl? _accountPanelRenderer;

        private async Task RefreshAccountPanelPoseAsync()
        {
            try
            {
                var host = this.FindControl<Border>("AccountSkinRendererHost");
                if (host != null && _accountPanelRenderer == null)
                {
                    try
                    {
                        _accountPanelRenderer = new LeafClient.Controls.SkinRendererControl
                        {
                            HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Stretch,
                            VerticalAlignment = Avalonia.Layout.VerticalAlignment.Stretch
                        };
                        host.Child = _accountPanelRenderer;
                    }
                    catch (Exception ex)
                    {
                        LeafClient.Services.LeafLog.Info("AccountPanel", $"3D renderer init failed, falling back to 2D: {ex.Message}");
                        _accountPanelRenderer = null;
                    }
                }

                if (_accountPanelRenderer != null)
                {
                    byte[]? skinBytes = null;
                    try { skinBytes = await FetchSkinBytesAsync(); } catch { }
                    if (skinBytes != null)
                    {
                        try { _accountPanelRenderer.UpdateSkinTexture(skinBytes); } catch { }
                    }
                    var eq = _currentSettings?.Equipped;
                    if (eq != null)
                    {
                        try
                        {
                            await LeafClient.Services.CosmeticHelpers.ApplyEquippedToRendererAsync(
                                _accountPanelRenderer, eq, _currentSettings?.SessionAccessToken);
                        }
                        catch (Exception ex)
                        {
                            LeafClient.Services.LeafLog.Info("AccountPanel", $"Cosmetics apply failed: {ex.Message}");
                        }
                    }
                    if (_accountCharacterImage != null) _accountCharacterImage.IsVisible = false;
                    return;
                }

                var username = _session?.Username ?? _currentSettings?.SessionUsername;
                var uuid = _session?.UUID ?? _currentSettings?.SessionUuid;

                if (string.IsNullOrWhiteSpace(username) && string.IsNullOrWhiteSpace(uuid))
                {
                    await Task.Delay(250);
                    username = _session?.Username ?? _currentSettings?.SessionUsername;
                    uuid = _session?.UUID ?? _currentSettings?.SessionUuid;
                }

                var largePose = _skinRenderService.GetRandomLargePoseName();
                Bitmap? largeBitmap = null;
                var localFile = GetActiveLocalSkinFile();
                if (localFile != null)
                    largeBitmap = await _skinRenderService.LoadSkinImageFromFileAsync(localFile, largePose, "full");
                if (largeBitmap == null)
                    largeBitmap = await _skinRenderService.LoadSkinImageAsync(username ?? "Player", largePose, "full", uuid);

                if (_accountCharacterImage != null && largeBitmap != null)
                {
                    _accountCharacterImage.Source = largeBitmap;
                    _accountCharacterImage.IsVisible = true;
                }
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("AccountPanel", $"RefreshPose failed: {ex.Message}");
            }
        }

        private bool _accountPanelOpen = false;

        private void OnAccountButtonClick(object? sender, RoutedEventArgs e)
        {
            if (_accountPanelOpen)
                CloseAccountPanel();
            else
                OpenAccountPanelClick();
        }

        private void OpenAccountPanelClick()
        {
            if (_accountPanelOverlay == null || _accountPanel == null) return;
            _accountPanelOpen = true;

            PopulateAccountsListPanel();

            _accountPanel.Transitions = null;
            _accountPanel.Opacity = 0;
            _accountPanelOverlay.Opacity = 0;
            _accountPanelOverlay.IsVisible = true;

            Dispatcher.UIThread.Post(() =>
            {
                _accountPanel.Transitions = new Transitions
                {
                    new DoubleTransition { Property = Visual.OpacityProperty, Duration = TimeSpan.FromMilliseconds(180), Easing = new CubicEaseOut() }
                };
                _accountPanelOverlay.Opacity = 1;
                _accountPanel.Opacity = 1;
            }, DispatcherPriority.Render);

            _ = RefreshAccountPanelPoseAsync();
            _ = RefreshReferralCardAsync();

            var apb = this.FindControl<TextBlock>("AccountPanelLeafsBalanceText");
            if (apb != null) apb.Text = _currentCoinBalance.ToString("N0");
        }

        private async void CloseAccountPanel()
        {
            if (_accountPanelOverlay == null || _accountPanel == null) return;
            _accountPanelOpen = false;

            _accountPanel.Opacity = 0;
            _accountPanelOverlay.Opacity = 0;

            await Task.Delay(180);
            if (!_accountPanelOpen)
                _accountPanelOverlay.IsVisible = false;
        }

        private void PopulateAccountsListPanel()
        {
            try { WriteSavedAccountsForMod(); } catch { }

            var panel = _accountsListPanel;
            if (panel == null) return;

            EnsureActiveAccountInList();

            var accounts = _currentSettings?.SavedAccounts ?? new List<AccountEntry>();
            string activeId = _currentSettings?.ActiveAccountId ?? "";

            try
            {
                var activeAcct = accounts.FirstOrDefault(a => a.Id == activeId);
                if (activeAcct != null)
                {
                    if (!string.IsNullOrWhiteSpace(activeAcct.Uuid))      _skinHeadCache.Remove(activeAcct.Uuid);
                    if (!string.IsNullOrWhiteSpace(activeAcct.Username))  _skinHeadCache.Remove(activeAcct.Username);
                }
            }
            catch { }

            var newCards = new List<Control>();
            foreach (var account in accounts)
            {
                newCards.Add(CreateAccountCard(account, account.Id == activeId));
            }

            if (accounts.Count == 0)
            {
                newCards.Add(new TextBlock
                {
                    Text = "No accounts added yet",
                    Foreground = SolidColorBrush.Parse("#4B5563"),
                    FontSize = 12,
                    HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                    Margin = new Thickness(0, 20)
                });
            }

            panel.IsVisible = false;
            panel.Children.Clear();
            foreach (var card in newCards)
                panel.Children.Add(card);
            panel.IsVisible = true;

            var activeAccount = accounts.FirstOrDefault(a => a.Id == activeId);
            if (_accountTypeLabel != null)
                _accountTypeLabel.Text = activeAccount?.AccountType == "microsoft" ? "Microsoft Account" : "Offline";
            if (_accountOnlineDot != null)
                _accountOnlineDot.Fill = SolidColorBrush.Parse("#22C55E");
            if (EditSkinButton != null)
                EditSkinButton.IsVisible = activeAccount?.AccountType != "offline";
        }

        private void EnsureActiveAccountInList()
        {
            if (_currentSettings == null) return;
            if (!_currentSettings.IsLoggedIn || string.IsNullOrWhiteSpace(_currentSettings.SessionUsername)) return;

            string sessionType = _currentSettings.AccountType ?? "offline";
            string sessionName = _currentSettings.SessionUsername ?? "Player";
            string? sessionUuid = _currentSettings.SessionUuid;

            AccountEntry? existing = null;
            if (!string.IsNullOrWhiteSpace(sessionUuid))
            {
                existing = _currentSettings.SavedAccounts.FirstOrDefault(a =>
                    a.AccountType == sessionType &&
                    !string.IsNullOrWhiteSpace(a.Uuid) &&
                    string.Equals(a.Uuid, sessionUuid, StringComparison.OrdinalIgnoreCase));
            }
            if (existing == null)
            {
                existing = _currentSettings.SavedAccounts.FirstOrDefault(a =>
                    a.AccountType == sessionType &&
                    string.Equals(a.Username, sessionName, StringComparison.OrdinalIgnoreCase));
            }

            if (existing == null)
            {
                var entry = new AccountEntry
                {
                    AccountType = sessionType,
                    Username = sessionName,
                    Uuid = sessionUuid,
                    AccessToken = _currentSettings.SessionAccessToken,
                    Xuid = _currentSettings.SessionXuid
                };
                _currentSettings.SavedAccounts.Add(entry);
                _currentSettings.ActiveAccountId = entry.Id;
                _ = _settingsService.SaveSettingsAsync(_currentSettings);
                return;
            }

            bool mutated = false;
            if (!string.Equals(existing.Username, sessionName, StringComparison.Ordinal))
            {
                existing.Username = sessionName;
                mutated = true;
            }
            if (!string.IsNullOrWhiteSpace(_currentSettings.SessionAccessToken) &&
                existing.AccessToken != _currentSettings.SessionAccessToken)
            {
                existing.AccessToken = _currentSettings.SessionAccessToken;
                mutated = true;
            }
            if (!string.IsNullOrWhiteSpace(_currentSettings.SessionXuid) &&
                existing.Xuid != _currentSettings.SessionXuid)
            {
                existing.Xuid = _currentSettings.SessionXuid;
                mutated = true;
            }

            int duplicates = 0;
            if (!string.IsNullOrWhiteSpace(sessionUuid))
            {
                duplicates = _currentSettings.SavedAccounts.RemoveAll(a =>
                    a.AccountType == sessionType &&
                    !string.IsNullOrWhiteSpace(a.Uuid) &&
                    string.Equals(a.Uuid, sessionUuid, StringComparison.OrdinalIgnoreCase) &&
                    a.Id != existing.Id);
            }

            if (string.IsNullOrWhiteSpace(_currentSettings.ActiveAccountId))
                _currentSettings.ActiveAccountId = existing.Id;

            if (mutated || duplicates > 0)
                _ = _settingsService.SaveSettingsAsync(_currentSettings);
        }

        private Border CreateAccountCard(AccountEntry account, bool isActive)
        {
            var card = new Border
            {
                Background = isActive ? SolidColorBrush.Parse("#150D20") : SolidColorBrush.Parse("#0F1A24"),
                CornerRadius = new CornerRadius(12),
                Padding = new Thickness(14, 10),
                BorderThickness = new Thickness(isActive ? 2 : 1.5),
                BorderBrush = isActive ? SolidColorBrush.Parse("#22C55E") : SolidColorBrush.Parse("#1C2A38"),
                Cursor = new Avalonia.Input.Cursor(Avalonia.Input.StandardCursorType.Hand),
                Tag = account.Id
            };

            var row = new Grid();
            row.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Auto });
            row.ColumnDefinitions.Add(new ColumnDefinition { Width = new GridLength(1, GridUnitType.Star) });
            row.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Auto });

            var avatar = MakeSkinHeadAvatarBorder(account, 36, 10);
            avatar.Margin = new Thickness(0, 0, 12, 0);
            Grid.SetColumn(avatar, 0);
            row.Children.Add(avatar);

            var info = new StackPanel { Spacing = 2, VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center };
            info.Children.Add(new TextBlock
            {
                Text = account.Username,
                Foreground = Brushes.White,
                FontWeight = FontWeight.SemiBold,
                FontSize = 13
            });
            info.Children.Add(new TextBlock
            {
                Text = account.AccountType == "microsoft" ? "Microsoft" : "Offline",
                Foreground = SolidColorBrush.Parse("#6B7280"),
                FontSize = 11
            });
            Grid.SetColumn(info, 1);
            row.Children.Add(info);

            if (isActive)
            {
                var check = new Border
                {
                    Width = 24, Height = 24,
                    CornerRadius = new CornerRadius(12),
                    Background = SolidColorBrush.Parse("#22C55E"),
                    VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center
                };
                check.Child = new TextBlock
                {
                    Text = "✓", Foreground = Brushes.White, FontSize = 12, FontWeight = FontWeight.Bold,
                    HorizontalAlignment = Avalonia.Layout.HorizontalAlignment.Center,
                    VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center
                };
                Grid.SetColumn(check, 2);
                row.Children.Add(check);
            }
            else
            {
                var removeBtn = new Button
                {
                    Content = "✕",
                    Foreground = SolidColorBrush.Parse("#6B7280"),
                    Background = Brushes.Transparent,
                    BorderThickness = new Thickness(0),
                    FontSize = 12,
                    Padding = new Thickness(6),
                    Cursor = new Avalonia.Input.Cursor(Avalonia.Input.StandardCursorType.Hand),
                    VerticalAlignment = Avalonia.Layout.VerticalAlignment.Center,
                    Tag = account.Id
                };
                removeBtn.Click += OnRemoveAccount;
                Grid.SetColumn(removeBtn, 2);
                row.Children.Add(removeBtn);
            }

            card.Child = row;

            if (!isActive)
            {
                card.Tapped += OnSwitchAccount;
            }

            return card;
        }

        private void SaveCurrentAccountState()
        {
            if (_currentSettings == null) return;
            var entry = _currentSettings.SavedAccounts.FirstOrDefault(a => a.Id == _currentSettings.ActiveAccountId);
            if (entry == null) return;
            entry.LeafApiJwt = _currentSettings.LeafApiJwt;
            entry.LeafApiRefreshToken = _currentSettings.LeafApiRefreshToken;
            entry.OwnedCosmeticIds = new List<string>(_ownedCosmeticIds);
            if (_currentSettings.Equipped != null)
                entry.Equipped = new EquippedCosmetics
                {
                    CapeId = _currentSettings.Equipped.CapeId,
                    HatId = _currentSettings.Equipped.HatId,
                    WingsId = _currentSettings.Equipped.WingsId,
                    BackItemId = _currentSettings.Equipped.BackItemId,
                    AuraId = _currentSettings.Equipped.AuraId
                };
            entry.CosmeticPresets = (_currentSettings.CosmeticPresets ?? new List<CosmeticPreset>())
                .Select(p => new CosmeticPreset
                {
                    Id = p.Id, Name = p.Name, CreatedDate = p.CreatedDate,
                    Equipped = new EquippedCosmetics
                    {
                        Sub = p.Equipped?.Sub,
                        CapeId = p.Equipped?.CapeId, HatId = p.Equipped?.HatId,
                        WingsId = p.Equipped?.WingsId, BackItemId = p.Equipped?.BackItemId,
                        AuraId = p.Equipped?.AuraId
                    }
                }).ToList();
            entry.CustomSkins = (_currentSettings.CustomSkins ?? new List<SkinInfo>())
                .Select(s => new SkinInfo
                {
                    Id = s.Id, Name = s.Name, FilePath = s.FilePath,
                    CreatedDate = s.CreatedDate, ModifiedDate = s.ModifiedDate
                }).ToList();
            entry.SelectedSkinId = _currentSettings.SelectedSkinId;
        }

        private void LoadAccountState(AccountEntry account)
        {
            if (_currentSettings == null) return;
            _currentSettings.LeafApiJwt = account.LeafApiJwt;
            _currentSettings.LeafApiRefreshToken = account.LeafApiRefreshToken;
            _onlineCountService?.UpdateAccessToken(account.LeafApiJwt);
            WriteSessionJson(account.LeafApiJwt);
            var sub = DecodeJwtSub(account.LeafApiJwt);
            _currentSettings.Equipped = new EquippedCosmetics
            {
                Sub = sub,
                CapeId = account.Equipped.CapeId,
                HatId = account.Equipped.HatId,
                WingsId = account.Equipped.WingsId,
                BackItemId = account.Equipped.BackItemId,
                AuraId = account.Equipped.AuraId
            };
            WriteEquippedJson(_currentSettings.Equipped, sub);
            _ownedCosmeticIds.Clear();
            foreach (var id in account.OwnedCosmeticIds)
                _ownedCosmeticIds.Add(id);
            SaveOwnedJson();
            _currentSettings.CosmeticPresets = (account.CosmeticPresets ?? new List<CosmeticPreset>())
                .Select(p => new CosmeticPreset
                {
                    Id = p.Id, Name = p.Name, CreatedDate = p.CreatedDate,
                    Equipped = new EquippedCosmetics
                    {
                        Sub = p.Equipped?.Sub,
                        CapeId = p.Equipped?.CapeId, HatId = p.Equipped?.HatId,
                        WingsId = p.Equipped?.WingsId, BackItemId = p.Equipped?.BackItemId,
                        AuraId = p.Equipped?.AuraId
                    }
                }).ToList();
            _currentSettings.CustomSkins = (account.CustomSkins ?? new List<SkinInfo>())
                .Select(s => new SkinInfo
                {
                    Id = s.Id, Name = s.Name, FilePath = s.FilePath,
                    CreatedDate = s.CreatedDate, ModifiedDate = s.ModifiedDate
                }).ToList();
            _currentSettings.SelectedSkinId = account.SelectedSkinId;
            Dispatcher.UIThread.Post(() =>
            {
                _cosmeticsPage?.RefreshOwnedList(_ownedCosmeticIds);
                _storePage?.RefreshOwnedList(_ownedCosmeticIds);
                _cosmeticsPage?.OnAccountChanged();
                _storePage?.OnAccountChanged();
                LoadSkins();
            });
        }

        private async void OnSwitchAccount(object? sender, TappedEventArgs e)
        {
            if (sender is not Border b || b.Tag is not string accountId) return;
            var account = _currentSettings?.SavedAccounts.FirstOrDefault(a => a.Id == accountId);
            if (account == null) return;
            int runningAtClick = RunningInstanceCount;
            LeafClient.Services.LeafLog.Info("Accounts", $"OnSwitchAccount: running={runningAtClick}, target={account.Username} ({account.AccountType}) id={accountId}");
            if (runningAtClick > 0)
            {
                await ApplyAccountSwitchAsync(accountId);
                return;
            }
            await ApplyAccountSelectionAsync(account, saveCurrentFirst: true);
        }

