        private async System.Threading.Tasks.Task ApplyAccountSelectionAsync(AccountEntry account, bool saveCurrentFirst)
        {
            if (account == null || _currentSettings == null) return;
            LeafClient.Services.LeafLog.Info("Accounts", $"Applying selection: {account.Username} (type: {account.AccountType})");

            if (saveCurrentFirst) SaveCurrentAccountState();

            _currentSettings.ActiveAccountId = account.Id;
            _currentSettings.AccountType = account.AccountType;
            _currentSettings.SessionUsername = account.Username;
            _currentSettings.SessionUuid = account.Uuid;
            _currentSettings.SessionAccessToken = account.AccessToken;
            _currentSettings.SessionXuid = account.Xuid;
            _currentSettings.IsLoggedIn = true;

            ResetInMemoryLeafState();
            _ownedCosmeticIds.Clear();
            _currentSettings.Equipped = new EquippedCosmetics();
            _currentSettings.CosmeticPresets = new List<CosmeticPreset>();
            _currentSettings.CustomSkins = new List<SkinInfo>();
            _currentSettings.SelectedSkinId = null;

            if (account.AccountType == "offline")
            {
                _currentSettings.OfflineUsername = account.Username;
                _session = MSession.CreateOfflineSession(account.Username);
            }
            else
            {
                _currentSettings.OfflineUsername = null;
                _session = new MSession
                {
                    Username = account.Username,
                    UUID = account.Uuid ?? "",
                    AccessToken = account.AccessToken ?? "",
                    Xuid = account.Xuid
                };
            }

            _loggedIn = true;
            _currentUsername = account.Username;

            LoadAccountState(account);

            _skinRenderService?.InvalidateAllCache();
            if (_playingAsImage != null) _playingAsImage.Source = null;
            if (_accountCharacterImage != null) _accountCharacterImage.Source = null;

            var saveTask = _settingsService.SaveSettingsAsync(_currentSettings);
            PopulateAccountsListPanel();
            var loadInfoTask = LoadUserInfoAsync();
            SwitchToPage(_currentSelectedIndex);
            _ = RefreshAccountPanelPoseAsync();

            await saveTask;

            var liveAccount = _currentSettings?.SavedAccounts.FirstOrDefault(a => a.Id == account.Id) ?? account;
            if (_currentSettings != null)
            {
                _currentSettings.LeafApiJwt = liveAccount.LeafApiJwt;
                _currentSettings.LeafApiRefreshToken = liveAccount.LeafApiRefreshToken;
                _currentSettings.ActiveAccountId = liveAccount.Id;
                WriteSessionJson(liveAccount.LeafApiJwt);
                _onlineCountService?.UpdateAccessToken(liveAccount.LeafApiJwt);
            }

            _ = System.Threading.Tasks.Task.Run(async () =>
            {
                try
                {
                    await EnsureFreshJwtForAccountAsync(liveAccount);
                    var ownedTask   = SyncOwnedCosmeticsFromApiAsync();
                    var balanceTask = UpdateLeafsBalanceAsync();
                    await Task.WhenAll(ownedTask, balanceTask);
                    Dispatcher.UIThread.Post(ApplyLeafPlusUiState);
                }
                catch (Exception ex) { LeafClient.Services.LeafLog.Error("Accounts", $"Post-switch refresh failed: {ex.Message}"); }
            });

            try { await loadInfoTask; } catch { }
        }

        private async void OnRemoveAccount(object? sender, RoutedEventArgs e)
        {
            if (sender is not Button btn || btn.Tag is not string accountId) return;
            if (_currentSettings == null) return;

            _currentSettings.SavedAccounts.RemoveAll(a => a.Id == accountId);
            await _settingsService.SaveSettingsAsync(_currentSettings);
            PopulateAccountsListPanel();
        }

        private System.Threading.CancellationTokenSource? _msAuthCts;

        private System.Threading.CancellationTokenSource? _accountIpcWatcherCts;

        private static string EscapeJsonString(string s)
        {
            if (string.IsNullOrEmpty(s)) return "";
            var sb = new System.Text.StringBuilder(s.Length + 4);
            foreach (var c in s)
            {
                switch (c)
                {
                    case '"': sb.Append("\\\""); break;
                    case '\\': sb.Append("\\\\"); break;
                    case '\b': sb.Append("\\b"); break;
                    case '\f': sb.Append("\\f"); break;
                    case '\n': sb.Append("\\n"); break;
                    case '\r': sb.Append("\\r"); break;
                    case '\t': sb.Append("\\t"); break;
                    default:
                        if (c < 0x20)
                            sb.Append($"\\u{(int)c:X4}");
                        else
                            sb.Append(c);
                        break;
                }
            }
            return sb.ToString();
        }

        private void WriteSavedAccountsForMod()
        {
            try
            {
                var appData = Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData);
                var dir = System.IO.Path.Combine(appData, "LeafClient");
                System.IO.Directory.CreateDirectory(dir);
                var path = System.IO.Path.Combine(dir, "saved_accounts.json");

                var accounts = _currentSettings?.SavedAccounts ?? new List<AccountEntry>();
                string activeId = _currentSettings?.ActiveAccountId ?? "";

                var sb = new System.Text.StringBuilder();
                sb.Append("{\"active_id\":\"");
                sb.Append(EscapeJsonString(activeId));
                sb.Append("\",\"accounts\":[");
                bool first = true;
                foreach (var a in accounts)
                {
                    if (!first) sb.Append(",");
                    first = false;
                    sb.Append("{\"id\":\"");
                    sb.Append(EscapeJsonString(a.Id ?? ""));
                    sb.Append("\",\"username\":\"");
                    sb.Append(EscapeJsonString(a.Username ?? ""));
                    sb.Append("\",\"uuid\":\"");
                    sb.Append(EscapeJsonString(a.Uuid ?? ""));
                    sb.Append("\",\"type\":\"");
                    sb.Append(EscapeJsonString(a.AccountType ?? "offline"));
                    sb.Append("\"}");
                }
                sb.Append("]}");

                var tmp = path + ".tmp";
                System.IO.File.WriteAllText(tmp, sb.ToString());
                if (System.IO.File.Exists(path)) System.IO.File.Delete(path);
                System.IO.File.Move(tmp, path);
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("AccountIpc", $"WriteSavedAccountsForMod failed: {ex.Message}");
            }
        }

        private async Task ApplyAccountSwitchAsync(string accountId)
        {
            try
            {
                if (_currentSettings == null) return;
                var target = _currentSettings.SavedAccounts.FirstOrDefault(a => a.Id == accountId);
                if (target == null)
                {
                    LeafClient.Services.LeafLog.Error("AccountIpc", $"switch_account: id {accountId} not found");
                    return;
                }

                bool mcRunning = RunningInstanceCount > 0;

                await ApplyAccountSelectionAsync(target, saveCurrentFirst: true);

                WriteSavedAccountsForMod();

                if (mcRunning)
                {
                    var prelive = _currentSettings.SavedAccounts.FirstOrDefault(a => a.Id == accountId) ?? target;
                    try { await EnsureFreshJwtForAccountAsync(prelive); }
                    catch (Exception jex) { LeafClient.Services.LeafLog.Error("AccountIpc", $"EnsureFreshJwt pre-blob failed: {jex.Message}"); }

                    var live = _currentSettings.SavedAccounts.FirstOrDefault(a => a.Id == accountId) ?? prelive;
                    int jwtLen = (live.LeafApiJwt ?? "").Length;
                    if (WriteAccountSessionBlob(live))
                    {
                        LeafClient.Services.LeafLog.Info("AccountIpc", $"In-game session swap for {live.Username} ({live.AccountType}) jwtLen={jwtLen} - launcher active updated, MC stays open.");
                    }
                    else
                    {
                        LeafClient.Services.LeafLog.Error("AccountIpc", "Session blob write failed - launcher active updated, MC not signaled.");
                    }
                    return;
                }

                LeafClient.Services.LeafLog.Info("AccountIpc", $"Account switched to {target.Username} ({target.AccountType}) - MC not running.");
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("AccountIpc", $"ApplyAccountSwitchAsync failed: {ex.Message}");
            }
        }

        private bool WriteAccountSessionBlob(AccountEntry target)
        {
            try
            {
                var appData = Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData);
                var dir = System.IO.Path.Combine(appData, "LeafClient");
                if (!System.IO.Directory.Exists(dir)) System.IO.Directory.CreateDirectory(dir);
                var blobPath = System.IO.Path.Combine(dir, "account_session.json");
                var tmpPath = blobPath + ".tmp";

                var sb = new System.Text.StringBuilder(256);
                sb.Append('{');
                sb.Append("\"uuid\":\"").Append(EscapeJsonString(target.Uuid ?? "")).Append("\",");
                sb.Append("\"username\":\"").Append(EscapeJsonString(target.Username ?? "")).Append("\",");
                sb.Append("\"accessToken\":\"").Append(EscapeJsonString(target.AccessToken ?? "")).Append("\",");
                sb.Append("\"type\":\"").Append(EscapeJsonString((target.AccountType ?? "microsoft").ToLowerInvariant())).Append("\",");
                sb.Append("\"jwt\":\"").Append(EscapeJsonString(target.LeafApiJwt ?? "")).Append("\",");
                sb.Append("\"ts\":").Append(DateTimeOffset.UtcNow.ToUnixTimeMilliseconds());
                sb.Append('}');

                System.IO.File.WriteAllText(tmpPath, sb.ToString());
                try
                {
                    if (System.IO.File.Exists(blobPath)) System.IO.File.Delete(blobPath);
                }
                catch { }
                System.IO.File.Move(tmpPath, blobPath);
                return true;
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("AccountIpc", $"WriteAccountSessionBlob failed: {ex.Message}");
                return false;
            }
        }

        private void StartAccountIpcWatcher()
        {
            if (_accountIpcWatcherCts != null) return;
            _accountIpcWatcherCts = new System.Threading.CancellationTokenSource();
            var token = _accountIpcWatcherCts.Token;

            try { WriteSavedAccountsForMod(); } catch { }

            string requestPath;
            try
            {
                var appData = Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData);
                requestPath = System.IO.Path.Combine(appData, "LeafClient", "account_request.json");
            }
            catch
            {
                return;
            }

            _ = Task.Run(async () =>
            {
                while (!token.IsCancellationRequested)
                {
                    try
                    {
                        if (System.IO.File.Exists(requestPath))
                        {
                            string content;
                            try { content = System.IO.File.ReadAllText(requestPath); }
                            catch { content = ""; }
                            try { System.IO.File.Delete(requestPath); } catch { }

                            if (!string.IsNullOrWhiteSpace(content))
                            {
                                string action = "";
                                try
                                {
                                    using var doc = System.Text.Json.JsonDocument.Parse(content);
                                    if (doc.RootElement.TryGetProperty("action", out var a) && a.ValueKind == System.Text.Json.JsonValueKind.String)
                                    {
                                        action = a.GetString() ?? "";
                                    }
                                }
                                catch { }

                                if (!string.IsNullOrEmpty(action))
                                {
                                    bool keepBackground = action == "switch_account";
                                    await Dispatcher.UIThread.InvokeAsync(() =>
                                    {
                                        if (!keepBackground)
                                        {
                                            try
                                            {
                                                this.Activate();
                                                ForceWindowToForeground();
                                                if (WindowState == WindowState.Minimized) WindowState = WindowState.Normal;
                                            }
                                            catch { }
                                        }

                                        try
                                        {
                                            switch (action)
                                            {
                                                case "add_microsoft":
                                                    AddMicrosoftAccountClick(null, new RoutedEventArgs());
                                                    break;
                                                case "add_offline":
                                                    AddLocalAccountClick(null, new RoutedEventArgs());
                                                    break;
                                                case "manage_accounts":
                                                    try { PopulateAccountsListPanel(); } catch { }
                                                    try
                                                    {
                                                        var panel = this.FindControl<Border>("AccountsPanel");
                                                        if (panel != null) panel.IsVisible = true;
                                                    }
                                                    catch { }
                                                    break;
                                                case "switch_account":
                                                    string switchId = "";
                                                    try
                                                    {
                                                        using var doc2 = System.Text.Json.JsonDocument.Parse(content);
                                                        if (doc2.RootElement.TryGetProperty("account_id", out var aid)
                                                            && aid.ValueKind == System.Text.Json.JsonValueKind.String)
                                                        {
                                                            switchId = aid.GetString() ?? "";
                                                        }
                                                    }
                                                    catch { }
                                                    if (!string.IsNullOrEmpty(switchId))
                                                    {
                                                        _ = ApplyAccountSwitchAsync(switchId);
                                                    }
                                                    break;
                                            }
                                        }
                                        catch (Exception ex)
                                        {
                                            LeafClient.Services.LeafLog.Error("AccountIpc", $"Failed to dispatch {action}: {ex.Message}");
                                        }
                                    });
                                }
                            }
                        }
                    }
                    catch (Exception ex)
                    {
                        LeafClient.Services.LeafLog.Error("AccountIpc", $"Watcher loop error: {ex.Message}");
                    }
                    try { await Task.Delay(500, token); } catch { break; }
                }
            }, token);
        }

        private async void AddMicrosoftAccountClick(object? sender, RoutedEventArgs e)
        {
            var statusPanel = this.FindControl<Border>("MsAuthStatusPanel");
            var statusText = this.FindControl<TextBlock>("MsAuthStatusText");
            var statusSub = this.FindControl<TextBlock>("MsAuthSubText");
            if (statusPanel != null) statusPanel.IsVisible = true;
            if (statusText != null) statusText.Text = "Opening browser for Microsoft login...";
            if (statusSub != null) statusSub.Text = "Complete the sign-in in your browser";

            _msAuthCts = new System.Threading.CancellationTokenSource();

            try
            {
                XboxAuthNet.Game.Msal.MsalSerializationConfig.DefaultSerializerOptions = LeafClient.Json.Options;
                XboxAuthNet.JsonConfig.DefaultOptions = LeafClient.Json.Options;

                var app = await MsalClientHelper.BuildApplicationWithCache(LeafClient.Services.AuthConfig.MicrosoftClientId, LeafClient.Services.AuthConfig.BuildMsalCacheSettings());

                string? capturedRefreshToken = null;
                app.UserTokenCache.SetAfterAccess(notification =>
                {
                    if (notification.HasStateChanged && capturedRefreshToken == null)
                    {
                        try
                        {
                            var cacheBytes = notification.TokenCache.SerializeMsalV3();
                            using var cacheDoc = System.Text.Json.JsonDocument.Parse(cacheBytes);
                            if (cacheDoc.RootElement.TryGetProperty("RefreshToken", out var rtSection))
                            {
                                foreach (var rtEntry in rtSection.EnumerateObject())
                                {
                                    if (rtEntry.Value.TryGetProperty("secret", out var secret))
                                    {
                                        capturedRefreshToken = secret.GetString();
                                        break;
                                    }
                                }
                            }
                        }
                        catch { }
                    }
                });

                LeafClient.Services.EmbeddedAuthUiHost.SetHostProvider(() => this);
                bool fellBack = false;
                MSession? newSession = null;

                async Task RunAddAccountMsalAsync()
                {
                    var loginHandler = JELoginHandlerBuilder.BuildDefault();
                    var authenticator = loginHandler.CreateAuthenticatorWithNewAccount();
                    authenticator.AddMsalOAuth(app, msal => msal.Interactive(LeafClient.Services.AuthConfig.ApplyInteractiveOptions));
                    authenticator.AddXboxAuthForJE(xbox => xbox.Basic());
                    authenticator.AddForceJEAuthenticator();
                    newSession = await authenticator.ExecuteForLauncherAsync();
                }

                try
                {
                    if (statusText != null) statusText.Text = "Opening Microsoft login window...";
                    await RunAddAccountMsalAsync();
                }
                catch (Exception bex) when (LeafClient.Services.EmbeddedAuthUiHost.IsBrokerFailure(bex))
                {
                    LeafClient.Services.LeafLog.Warn("Auth", $"Embedded webview failed, falling back to system browser: {bex.Message}");
                    LeafClient.Services.EmbeddedAuthUiHost.ClearHost();
                    fellBack = true;
                    if (statusText != null) statusText.Text = "Embedded login unavailable, opening system browser...";
                    await RunAddAccountMsalAsync();
                }
                finally
                {
                    if (!fellBack) LeafClient.Services.EmbeddedAuthUiHost.ClearHost();
                }

                if (newSession != null && newSession.CheckIsValid())
                {
                    var entry = new AccountEntry
                    {
                        AccountType = "microsoft",
                        Username = newSession.Username,
                        Uuid = newSession.UUID,
                        AccessToken = newSession.AccessToken,
                        Xuid = newSession.Xuid
                    };

                    _currentSettings?.SavedAccounts.RemoveAll(a =>
                        a.AccountType == "microsoft" && a.Uuid == newSession.UUID);

                    _currentSettings?.SavedAccounts.Add(entry);

                    if (_currentSettings != null)
                    {
                        _currentSettings.ActiveAccountId = entry.Id;
                        _currentSettings.IsLoggedIn = true;
                        _currentSettings.AccountType = "microsoft";
                        _currentSettings.SessionUsername = newSession.Username;
                        _currentSettings.SessionUuid = newSession.UUID;
                        _currentSettings.SessionAccessToken = newSession.AccessToken;
                        _currentSettings.SessionXuid = newSession.Xuid;
                        if (!string.IsNullOrWhiteSpace(capturedRefreshToken))
                            _currentSettings.MicrosoftRefreshToken = capturedRefreshToken;
                        _currentSettings.LeafApiJwt = null;
                        _currentSettings.LeafApiRefreshToken = null;
                        _currentSettings.Equipped = new EquippedCosmetics();
                        _currentSettings.CosmeticPresets = new List<CosmeticPreset>();
                        _currentSettings.LastSeenCosmeticDropMonth = null;
                        _currentSettings.CustomSkins = new List<SkinInfo>();
                        _currentSettings.SelectedSkinId = null;
                        _ownedCosmeticIds.Clear();
                        ResetInMemoryLeafState();
                        WriteEquippedJson(new EquippedCosmetics(), null);
                        SaveOwnedJson();
                        WriteSessionJson(null);
                        await _settingsService.SaveSettingsAsync(_currentSettings);
                        Dispatcher.UIThread.Post(() =>
                        {
                            _cosmeticsPage?.RefreshOwnedList(_ownedCosmeticIds);
                            _storePage?.RefreshOwnedList(_ownedCosmeticIds);
                            _cosmeticsPage?.OnAccountChanged();
                            _storePage?.OnAccountChanged();
                        });
                    }

                    _ = System.Threading.Tasks.Task.Run(async () =>
                    {
                        try
                        {
                            if (!string.IsNullOrWhiteSpace(newSession.UUID) && !string.IsNullOrWhiteSpace(newSession.AccessToken))
                            {
                                var apiResult = await LeafApiService.MicrosoftLoginAsync(newSession.UUID, newSession.AccessToken);
                                if (apiResult != null && _currentSettings != null)
                                {
                                    _currentSettings.LeafApiJwt = apiResult.AccessToken;
                                    _currentSettings.LeafApiRefreshToken = apiResult.RefreshToken;
                                    var activeEntry = _currentSettings.SavedAccounts.FirstOrDefault(a => a.Id == _currentSettings.ActiveAccountId);
                                    if (activeEntry != null)
                                    {
                                        activeEntry.LeafApiJwt = apiResult.AccessToken;
                                        activeEntry.LeafApiRefreshToken = apiResult.RefreshToken;
                                    }
                                    await _settingsService.SaveSettingsAsync(_currentSettings);
                                    _onlineCountService?.UpdateAccessToken(apiResult.AccessToken);
                                    WriteSessionJson(apiResult.AccessToken);
                                    LeafLog.Info("Accounts", "LeafClient API linked for Microsoft account.");
                                    _ownedCosmeticIds.Clear();
                                    WriteEquippedJson(_currentSettings?.Equipped ?? new EquippedCosmetics(), DecodeJwtSub(apiResult.AccessToken));
                                    SaveOwnedJson();
                                    var ownedTask = SyncOwnedCosmeticsFromApiAsync();
                                    var balanceTask = UpdateLeafsBalanceAsync();
                                    await Task.WhenAll(ownedTask, balanceTask);
                                    Dispatcher.UIThread.Post(ApplyLeafPlusUiState);
                                }
                            }
                        }
                        catch (Exception ex2)
                        {
                            LeafClient.Services.LeafLog.Error("Accounts", $"LeafClient API link failed (non-critical): {ex2.Message}");
                        }
                    });

                    _session = newSession;
                    PopulateAccountsListPanel();
                    await LoadUserInfoAsync();
                    SwitchToPage(_currentSelectedIndex);
                    _ = RefreshAccountPanelPoseAsync();
                }
            }
            catch (OperationCanceledException)
            {
                LeafLog.Info("Accounts", "Microsoft auth cancelled.");
                if (statusText != null) statusText.Text = "Sign-in cancelled.";
                if (statusSub != null) statusSub.Text = "You can try again anytime.";
                await System.Threading.Tasks.Task.Delay(1500);
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("Accounts", $"Microsoft auth failed: {ex}");
                if (statusText != null) statusText.Text = "Authentication failed. Try again.";
                if (statusSub != null) statusSub.Text = ex.Message.Length > 80 ? ex.Message[..80] + "\u2026" : ex.Message;
                await System.Threading.Tasks.Task.Delay(3000);
            }
            finally
            {
                if (statusPanel != null) statusPanel.IsVisible = false;
                _msAuthCts = null;
            }
        }

