        private static string? DecodeJwtMinecraftUsername(string? jwt)
        {
            if (string.IsNullOrWhiteSpace(jwt)) return null;
            try
            {
                var parts = jwt.Split('.');
                if (parts.Length < 2) return null;
                var payload = parts[1];
                var padded = payload.PadRight(payload.Length + (4 - payload.Length % 4) % 4, '=');
                var json = System.Text.Encoding.UTF8.GetString(Convert.FromBase64String(padded));
                using var doc = System.Text.Json.JsonDocument.Parse(json);
                if (doc.RootElement.TryGetProperty("minecraft_username", out var el))
                    return el.GetString();
            }
            catch { }
            return null;
        }

        private static string? DecodeJwtSub(string? jwt)
        {
            if (string.IsNullOrWhiteSpace(jwt)) return null;
            try
            {
                var parts = jwt.Split('.');
                if (parts.Length < 2) return null;
                var payload = parts[1];
                var padded = payload.PadRight(payload.Length + (4 - payload.Length % 4) % 4, '=');
                var json = System.Text.Encoding.UTF8.GetString(Convert.FromBase64String(padded));
                using var doc = System.Text.Json.JsonDocument.Parse(json);
                if (doc.RootElement.TryGetProperty("sub", out var el))
                    return el.GetString();
            }
            catch { }
            return null;
        }

        private async Task<byte[]?> FetchSkinBytesAsync()
        {
            string? uuid = null;
            string? username = null;

            try
            {
                var activeEntry = _currentSettings?.SavedAccounts
                    ?.FirstOrDefault(a => a.Id == _currentSettings.ActiveAccountId);
                if (activeEntry != null)
                {
                    uuid = activeEntry.Uuid;
                    username = activeEntry.Username;

                    var selectedId = _currentSettings?.SelectedSkinId;
                    if (!string.IsNullOrEmpty(selectedId) && _currentSettings?.CustomSkins != null)
                    {
                        var custom = _currentSettings.CustomSkins.FirstOrDefault(s => s.Id == selectedId);
                        if (custom != null && !string.IsNullOrEmpty(custom.FilePath) && System.IO.File.Exists(custom.FilePath))
                        {
                            try { return await System.IO.File.ReadAllBytesAsync(custom.FilePath); } catch { }
                        }
                    }
                }
            }
            catch { }

            if (string.IsNullOrWhiteSpace(uuid)) uuid = _session?.UUID ?? _currentSettings?.SessionUuid;
            if (string.IsNullOrWhiteSpace(username)) username = _session?.Username ?? _currentSettings?.SessionUsername;
            if (string.IsNullOrWhiteSpace(uuid) && string.IsNullOrWhiteSpace(username)) return null;

            using var http = new System.Net.Http.HttpClient { Timeout = TimeSpan.FromSeconds(8) };
            http.DefaultRequestHeaders.UserAgent.ParseAdd("LeafClient/1.0");

            if (!string.IsNullOrWhiteSpace(uuid))
            {
                try
                {
                    string clean = uuid.Replace("-", "");
                    var json = await http.GetStringAsync($"https://sessionserver.mojang.com/session/minecraft/profile/{clean}");
                    var url  = ExtractSkinUrlFromProfile(json);
                    if (!string.IsNullOrWhiteSpace(url)) return await http.GetByteArrayAsync(url);
                }
                catch { }
            }
            if (!string.IsNullOrWhiteSpace(username))
            {
                try { return await http.GetByteArrayAsync($"https://minotar.net/skin/{username}"); } catch { }
            }
            return null;
        }

        private bool _maintenanceVisible;
        private CancellationTokenSource? _maintenanceRecheckCts;

        private async Task CheckApiHealthAndMaybeShowMaintenanceAsync()
        {
            try
            {
                bool reachable = await MaintenanceService.IsApiReachableAsync();
                if (reachable)
                {
                    if (_maintenanceVisible)
                    {
                        await Dispatcher.UIThread.InvokeAsync(HideMaintenanceOverlay);
                    }
                    return;
                }
                await ShowMaintenanceOverlayAsync();
            }
            catch (Exception ex)
            {
                LeafLog.Error("Maintenance", $"health-check error: {ex.Message}");
            }
        }

        private async Task ShowMaintenanceOverlayAsync()
        {
            MaintenanceStatus status = new MaintenanceStatus { ApiReachable = false };
            try { status = await MaintenanceService.FetchStatusAsync(); } catch { }

            await Dispatcher.UIThread.InvokeAsync(() =>
            {
                var overlay = this.FindControl<Border>("MaintenanceOverlay");
                if (overlay == null) return;

                var card     = this.FindControl<Border>("MaintenanceIncidentCard");
                var titleTb  = this.FindControl<TextBlock>("MaintenanceIncidentTitle");
                var bodyTb   = this.FindControl<TextBlock>("MaintenanceIncidentBody");
                var dateTb   = this.FindControl<TextBlock>("MaintenanceIncidentDate");

                if (status.HasIncident)
                {
                    if (titleTb != null) titleTb.Text = status.IncidentTitle;
                    if (bodyTb  != null) bodyTb.Text  = string.IsNullOrWhiteSpace(status.IncidentBody) ? "" : status.IncidentBody;
                    if (dateTb  != null) dateTb.Text  = status.IncidentDate;
                    if (card    != null) card.IsVisible = true;
                }
                else
                {
                    if (card != null) card.IsVisible = false;
                }

                overlay.IsVisible = true;
                _maintenanceVisible = true;
            });

            _maintenanceRecheckCts?.Cancel();
            _maintenanceRecheckCts = new CancellationTokenSource();
            var ct = _maintenanceRecheckCts.Token;
            _ = Task.Run(async () =>
            {
                while (!ct.IsCancellationRequested)
                {
                    try { await Task.Delay(TimeSpan.FromSeconds(30), ct); } catch { return; }
                    try
                    {
                        if (await MaintenanceService.IsApiReachableAsync(ct))
                        {
                            await Dispatcher.UIThread.InvokeAsync(HideMaintenanceOverlay);
                            return;
                        }
                    }
                    catch { }
                }
            }, ct);
        }

        private void HideMaintenanceOverlay()
        {
            var overlay = this.FindControl<Border>("MaintenanceOverlay");
            if (overlay != null) overlay.IsVisible = false;
            bool wasVisible = _maintenanceVisible;
            _maintenanceVisible = false;
            _maintenanceRecheckCts?.Cancel();
            _maintenanceRecheckCts = null;
            if (wasVisible)
            {
                _ = ReloadAfterApiRecoveryAsync();
            }
        }

        private async Task ReloadAfterApiRecoveryAsync()
        {
            try
            {
                LeafLog.Info("Maintenance", "API recovered - reloading API-dependent state");

                try { await LoadUserInfoAsync(); } catch (Exception ex) { LeafLog.Error("Maintenance reload", $"LoadUserInfoAsync: {ex.Message}"); }
                try { await LoadNewsAsync(); } catch (Exception ex) { LeafLog.Error("Maintenance reload", $"LoadNewsAsync: {ex.Message}"); }
                try { await LoadFeaturedServersFromApiAsync(); } catch (Exception ex) { LeafLog.Error("Maintenance reload", $"LoadFeaturedServersFromApiAsync: {ex.Message}"); }

                try
                {
                    await Dispatcher.UIThread.InvokeAsync(() =>
                    {
                        try { _cosmeticsPage?.LoadCosmeticsPage(); } catch (Exception ex) { LeafLog.Error("Maintenance reload", $"cosmetics page: {ex.Message}"); }
                        try { RefreshLeafPlusPrices(); } catch (Exception ex) { LeafLog.Error("Maintenance reload", $"RefreshLeafPlusPrices: {ex.Message}"); }
                        try { _ = RefreshAccountPanelPoseAsync(); } catch (Exception ex) { LeafLog.Error("Maintenance reload", $"RefreshAccountPanelPoseAsync: {ex.Message}"); }
                    });
                }
                catch (Exception ex) { LeafLog.Error("Maintenance reload", $"UI dispatch: {ex.Message}"); }

                try
                {
                    if (_onlineCountService != null)
                    {
                        var mcUsername = _currentSettings?.SessionUsername
                            ?? DecodeJwtMinecraftUsername(_currentSettings?.LeafApiJwt);
                        if (!string.IsNullOrWhiteSpace(mcUsername))
                        {
                            _onlineCountService.Start(mcUsername!, _currentSettings?.LeafApiJwt);
                        }
                    }
                }
                catch (Exception ex) { LeafLog.Error("Maintenance reload", $"OnlineCountService restart: {ex.Message}"); }

                LeafLog.Info("Maintenance", "reload complete");
            }
            catch (Exception ex)
            {
                LeafLog.Error("Maintenance reload", $"outer error: {ex.Message}");
            }
        }

