        private async void OnMaintenanceRetry(object? sender, Avalonia.Input.TappedEventArgs e)
        {
            var label = this.FindControl<TextBlock>("MaintenanceRetryLabel");
            if (label != null) label.Text = "CHECKING...";
            try
            {
                bool reachable = await MaintenanceService.IsApiReachableAsync();
                if (reachable)
                {
                    HideMaintenanceOverlay();
                    return;
                }
                await ShowMaintenanceOverlayAsync();
            }
            catch (Exception ex) { LeafLog.Error("Maintenance", $"retry error: {ex.Message}"); }
            finally
            {
                if (label != null) label.Text = "RETRY";
            }
        }

        private readonly List<Image> _bgImages = new();
        private readonly Dictionary<string, Avalonia.Controls.Border> _bgThemeCards = new();

        private void InitializeBackgroundThemeBindings()
        {
            _bgImages.Clear();
            foreach (var name in new[] { "BgImage", "LaunchBgImage", "AccountPanelBgImage", "StartupBg" })
            {
                var img = this.FindControl<Image>(name);
                if (img == null) continue;
                if (img.Transitions == null) img.Transitions = new Avalonia.Animation.Transitions();
                if (!img.Transitions.Any(t => t is Avalonia.Animation.DoubleTransition dt && dt.Property == Avalonia.Controls.Image.OpacityProperty))
                {
                    img.Transitions.Add(new Avalonia.Animation.DoubleTransition
                    {
                        Property = Avalonia.Controls.Image.OpacityProperty,
                        Duration = TimeSpan.FromMilliseconds(250),
                        Easing = new Avalonia.Animation.Easings.CubicEaseInOut()
                    });
                }
                _bgImages.Add(img);
            }
            string slug = _currentSettings?.BackgroundTheme ?? "aurora";
            LeafClient.Services.BackgroundThemeService.Instance.SetTheme(slug);
            ApplyBackgroundThemeImmediate(slug);
            LeafClient.Services.BackgroundThemeService.Instance.ThemeChanged += OnBackgroundThemeChanged;
        }

        private void ApplyBackgroundThemeImmediate(string slug)
        {
            var bmp = LeafClient.Services.BackgroundThemeService.Instance.GetBitmap(slug);
            if (bmp == null) return;
            foreach (var img in _bgImages) img.Source = bmp;
        }

        private async void OnBackgroundThemeChanged(object? sender, LeafClient.Services.BackgroundThemeService.Theme theme)
        {
            var newBmp = LeafClient.Services.BackgroundThemeService.Instance.GetBitmap(theme.Slug);
            if (newBmp == null) return;
            var fadeTargets = _bgImages.Where(i => i.Name != "StartupBg").ToList();
            var preFade = fadeTargets.ToDictionary(i => i, i => i.Opacity);
            foreach (var img in fadeTargets) img.Opacity = 0;
            await Task.Delay(260);
            foreach (var img in fadeTargets) img.Source = newBmp;
            foreach (var img in fadeTargets) img.Opacity = preFade.TryGetValue(img, out var o) ? o : 1.0;
        }

        private void PopulateBackgroundThemeList()
        {
            var list = this.FindControl<ItemsControl>("BackgroundThemeList");
            if (list == null) return;
            _bgThemeCards.Clear();
            var items = new List<Avalonia.Controls.Border>();
            string currentSlug = _currentSettings?.BackgroundTheme ?? "aurora";
            foreach (var theme in LeafClient.Services.BackgroundThemeService.Themes)
            {
                var bmp = LeafClient.Services.BackgroundThemeService.Instance.GetBitmap(theme.Slug);
                var thumb = new Avalonia.Controls.Image
                {
                    Source = bmp,
                    Stretch = Avalonia.Media.Stretch.UniformToFill,
                    Width = 150,
                    Height = 80,
                };
                var nameText = new TextBlock
                {
                    Text = theme.DisplayName,
                    Foreground = new Avalonia.Media.SolidColorBrush(Avalonia.Media.Colors.White),
                    FontWeight = Avalonia.Media.FontWeight.SemiBold,
                    FontSize = 13,
                    Margin = new Avalonia.Thickness(8, 6, 8, 8),
                };
                var thumbWrap = new Avalonia.Controls.Border
                {
                    CornerRadius = new Avalonia.CornerRadius(8, 8, 0, 0),
                    ClipToBounds = true,
                    Height = 80,
                    Child = thumb,
                };
                var stack = new StackPanel { Spacing = 0, Children = { thumbWrap, nameText } };
                var card = new Avalonia.Controls.Border
                {
                    Width = 160,
                    Margin = new Avalonia.Thickness(0, 0, 12, 12),
                    CornerRadius = new Avalonia.CornerRadius(10),
                    Background = new Avalonia.Media.SolidColorBrush(Avalonia.Media.Color.Parse("#10FFFFFF")),
                    BorderThickness = new Avalonia.Thickness(2),
                    BorderBrush = new Avalonia.Media.SolidColorBrush(Avalonia.Media.Color.Parse(
                        string.Equals(theme.Slug, currentSlug, StringComparison.OrdinalIgnoreCase) ? "#4CAF50" : "#1EFFFFFF")),
                    Cursor = new Avalonia.Input.Cursor(Avalonia.Input.StandardCursorType.Hand),
                    Child = stack,
                    Tag = theme.Slug,
                };
                card.PointerPressed += (s, e) => OnBackgroundThemeCardClicked(theme.Slug);
                _bgThemeCards[theme.Slug] = card;
                items.Add(card);
            }
            list.ItemsSource = items;
        }

        private async void OnBackgroundThemeCardClicked(string slug)
        {
            if (_currentSettings == null) return;
            if (string.Equals(_currentSettings.BackgroundTheme, slug, StringComparison.OrdinalIgnoreCase)) return;
            _currentSettings.BackgroundTheme = slug;
            foreach (var kv in _bgThemeCards)
            {
                kv.Value.BorderBrush = new Avalonia.Media.SolidColorBrush(Avalonia.Media.Color.Parse(
                    string.Equals(kv.Key, slug, StringComparison.OrdinalIgnoreCase) ? "#4CAF50" : "#1EFFFFFF"));
            }
            LeafClient.Services.BackgroundThemeService.Instance.SetTheme(slug);
            try { if (_settingsService != null) await _settingsService.SaveSettingsAsync(_currentSettings); } catch { }
        }

    }

    public enum SupportLevel
    {
        FullSupport,
        PartialSupport,
        VanillaOnly
    }

    public class VersionInfo
    {
        public string FullVersion { get; set; }
        public string MajorVersion { get; set; }
        public string Type { get; set; }
        public string Loader { get; set; }
        public string ReleaseDate { get; set; }
        public string Description { get; set; }
        public bool IsLeafClientModSupported { get; set; }
        public bool IsFullySupported { get; set; }
        public SupportLevel SupportLevel { get; set; }

        public string DisplayVersion
        {
            get
            {
                return SupportLevel switch
                {
                    SupportLevel.FullSupport => $"{FullVersion} ✓ Full Support",
                    SupportLevel.PartialSupport => $"{FullVersion} ⚠ Partial Support",
                    SupportLevel.VanillaOnly => $"{FullVersion} Vanilla Only",
                    _ => FullVersion
                };
            }
        }

        public VersionInfo(string fullVersion, string majorVersion, string type, string loader, string releaseDate, string description)
        {
            FullVersion = fullVersion;
            MajorVersion = majorVersion;
            Type = type;
            Loader = loader;
            ReleaseDate = releaseDate;
            Description = description;
            IsLeafClientModSupported = false;
            IsFullySupported = false;
            SupportLevel = SupportLevel.VanillaOnly;
        }
    }

    public class MinecraftServerChecker
    {

        private static readonly HttpClient _httpClient = new HttpClient();
        private const string ApiBaseUrl = "https://api.mcstatus.io/v2/status/java/";

        public async Task<ServerStatusResult> GetServerStatusAsync(string address, int port = 25565)
        {
            string url = $"{ApiBaseUrl}{address}:{port}";
            LeafClient.Services.LeafLog.Info("ServerCheck", $"Pinging {address}:{port} using mcstatus.io API...");

            try
            {
                var jsonResponse = await _httpClient.GetStringAsync(url);
                var response = JsonSerializer.Deserialize(jsonResponse, JsonContext.Default.ServerStatusResponse);

                if (response == null || !response.Online)
                {
                    return new ServerStatusResult
                    {
                        IsOnline = false,
                        CurrentPlayers = 0,
                        MaxPlayers = 0,
                        Motd = "No Response from the server, but the server may be online",
                        IconData = ""
                    };
                }

                return new ServerStatusResult
                {
                    IsOnline = true,
                    CurrentPlayers = response.Players?.Online ?? 0,
                    MaxPlayers = response.Players?.Max ?? 0,
                    Motd = response.Motd?.Clean ?? "Minecraft Server",
                    IconData = response.Icon ?? ""
                };
            }
            catch (HttpRequestException httpEx)
            {
                LeafClient.Services.LeafLog.Error("API HTTP Error", $"{address}:{port} -> {httpEx.Message}");
                return new ServerStatusResult { IsOnline = false, CurrentPlayers = 0, MaxPlayers = 0, Motd = $"Network Error: {httpEx.Message}", IconData = "" };
            }
            catch (Exception ex)
            {
                LeafClient.Services.LeafLog.Error("API General Error", $"{address}:{port} -> {ex.GetType().Name}: {ex.Message}");
                return new ServerStatusResult { IsOnline = false, CurrentPlayers = 0, MaxPlayers = 0, Motd = $"API Check Failed: {ex.GetType().Name}", IconData = "" };
            }
        }
    }
}

public class ServerStatusResult
{
    public bool IsOnline { get; set; }
    public int CurrentPlayers { get; set; }
    public int MaxPlayers { get; set; }
    public string? Motd { get; set; }
    public string? IconData { get; set; }
}

public static class UiUpdateService
{
    private static readonly SemaphoreSlim _uiUpdateLock = new(1, 1);
    private static readonly HashSet<string> _activeStatusUpdates = new();

    public static async Task SafeUpdateServerStatusUI(
        ServerInfo server,
        Action<ServerInfo, Action> uiUpdateAction,
        ILogger? logger = null)
    {
        string updateId = $"{server.Address}:{server.Port}:{DateTime.Now.Ticks}";

        try
        {
            await _uiUpdateLock.WaitAsync();
            _activeStatusUpdates.Add(updateId);

            try
            {
                uiUpdateAction(server, () => { });
            }
            catch (Exception ex)
            {
                logger?.LogError($"UI update failed for {server.Name}: {ex.Message}");
                LeafClient.Services.LeafLog.Error("UI UPDATE FAILED", $"{server.Name}: {ex.Message}");
            }
        }
        finally
        {
            _activeStatusUpdates.Remove(updateId);
            _uiUpdateLock.Release();
        }
    }

    public static bool IsUpdateInProgress(string address)
    {
        return _activeStatusUpdates.Any(u => u.StartsWith(address));
    }
}

public static class StreamExtensions
{
    public static async Task<int> ReadByteAsync(this Stream stream)
    {
        var buffer = new byte[1];
        await stream.ReadExactlyAsync(buffer, 0, 1);
        return buffer[0];
    }
}

